INSERT INTO profiles (id, version, content, big_five, mbti_label, decision_style, tags, summary, quality_score, status, generation_run_id) VALUES
('877c32c0-98f4-4d09-bb77-95e316cc1e9f', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.5,"extraversion":0.38,"agreeableness":0.64,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.4,"narcissism":0.38,"psychopathy":0.32},"prospect_theory":{"lambda":2.78,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A measured DeFi yield farmer: would rather lose a point than win an argument badly, weighs words carefully before spending them. Outsources conviction to whoever spoke last with authority, and when the pressure is off refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.57},{"slug":"endowment","strength":0.49}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.54,"conscientiousness":0.5,"extraversion":0.38,"agreeableness":0.64,"neuroticism":0.5}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Gains confidence in a position in proportion to how many others hold it. A measured DeFi yield farmer: would rather lose a point than win an argument badly, weighs words carefully before spending them. Outsources conviction to whoever spoke last with authority, and when the pressure is off refreshes the order book compulsively during lunch.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('65c0a8d5-94f6-4f79-8080-722a9900adfd', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.31,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.52,"narcissism":0.85,"psychopathy":0.55},"prospect_theory":{"lambda":1.01,"alpha":0.83,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Futures spreader whose defining move is that they would rather invent a worse tool than use someone else''s good one. Decides on a gut read in seconds and reverse-engineers the reasons later. Recharges by being around people, not away from them. When someone is watching the outcome, mistakes a little fluency for real mastery; keeps a losing-trade journal they never re-read.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"bandwagon","strength":0.61},{"slug":"herd-behavior","strength":0.6},{"slug":"dunning-kruger","strength":0.72}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.31,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.46}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Futures spreader whose defining move is that they would rather invent a worse tool than use someone else''s good one. Decides on a gut read in seconds and reverse-engineers the reasons later. Recharges by being around people, not away from them. When someone is watching the outcome, mistakes a little fluency for real mastery; keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('04716d38-88d9-4c41-bdec-60c87d8cb356', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.36,"extraversion":0.47,"agreeableness":0.65,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.39,"narcissism":0.26,"psychopathy":0.33},"prospect_theory":{"lambda":3.37,"alpha":0.76,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Guards against losses far more fiercely than they chase equivalent gains. A steady bonding-curve sniper: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and in the routine of it sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"loss-aversion","strength":0.67},{"slug":"availability","strength":0.64},{"slug":"gas-sunk-cost","strength":0.62},{"slug":"ostrich-effect","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.55,"conscientiousness":0.36,"extraversion":0.47,"agreeableness":0.65,"neuroticism":0.81}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Guards against losses far more fiercely than they chase equivalent gains. A steady bonding-curve sniper: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and in the routine of it sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9629a5df-4e0d-404d-b6dc-c7b385ec6b5b', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.56,"extraversion":0.48,"agreeableness":0.7,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.38,"narcissism":0.39,"psychopathy":0.29},"prospect_theory":{"lambda":3,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady zero-DTE options gambler who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching refreshes the order book compulsively during lunch.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.52},{"slug":"bandwagon","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.56,"extraversion":0.48,"agreeableness":0.7,"neuroticism":0.6}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'The instant it becomes irreversible, gains confidence in a position in proportion to how many others hold it. Otherwise, a steady zero-DTE options gambler who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching refreshes the order book compulsively during lunch.', 0.88, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('268c5e54-fcbd-4137-a51a-eb0beae2d8b8', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.47,"extraversion":0.7,"agreeableness":0.35,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.54,"narcissism":0.7,"psychopathy":0.43},"prospect_theory":{"lambda":1.29,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Options seller whose defining move is that they reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number. Treats a quiet room as a problem to be solved. When the walls close in, extrapolates the last data point into a permanent trend; calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"bandwagon","strength":0.59},{"slug":"herd-behavior","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.93,"conscientiousness":0.47,"extraversion":0.7,"agreeableness":0.35,"neuroticism":0.47}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Options seller whose defining move is that they reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number. Treats a quiet room as a problem to be solved. When the walls close in, extrapolates the last data point into a permanent trend; calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('04a3c8e7-c9be-4ecb-83b6-51edef4f05b5', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.69,"extraversion":0.44,"agreeableness":0.66,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.5,"narcissism":0.38,"psychopathy":0.32},"prospect_theory":{"lambda":3,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, second-guesses its own read the moment someone senior disagrees. Otherwise, a steady pairs trader who maintains flawless records nobody asked for and reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and when the stakes are trivial trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.52},{"slug":"recency","strength":0.47},{"slug":"authority-bias","strength":0.53},{"slug":"hindsight","strength":0.48}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.69,"extraversion":0.44,"agreeableness":0.66,"neuroticism":0.59}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, second-guesses its own read the moment someone senior disagrees. Otherwise, a steady pairs trader who maintains flawless records nobody asked for and reads other people''s discomfort before they voice it. Circles back to ask what someone else would do even after deciding, and when the stakes are trivial trusts the chart more than the fundamentals and won''t say why.', 0.84, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d5982c01-862d-475b-ac67-06ace434483a', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.32,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.59,"narcissism":0.86,"psychopathy":0.54},"prospect_theory":{"lambda":1.01,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot see the gap in its own knowledge from inside the gap. A pronounced macro allocator: reframes every problem as an excuse to learn a new system, improvises past every deadline and calls it flexibility. Treats overthinking as its own kind of error, and day to day exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.71},{"slug":"recency","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.32,"neuroticism":0.54}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Cannot see the gap in its own knowledge from inside the gap. A pronounced macro allocator: reframes every problem as an excuse to learn a new system, improvises past every deadline and calls it flexibility. Treats overthinking as its own kind of error, and day to day exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('96472b7f-9d06-4e41-a848-fbcee5ab299b', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.37,"extraversion":0.49,"agreeableness":0.57,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.38,"narcissism":0.33,"psychopathy":0.33},"prospect_theory":{"lambda":3.35,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"MEV searcher whose defining move is that they reads a single setback as evidence of collapse. Keeps every door open long after most of them should be closed. Is reliably surprised by deadlines that were never hidden. When cornered, assumes the current streak is the new normal; keeps three monitors for a portfolio that fits on one screen.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.55},{"slug":"disposition-effect","strength":0.58},{"slug":"ostrich-effect","strength":0.59},{"slug":"recency","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.37,"extraversion":0.49,"agreeableness":0.57,"neuroticism":0.7}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'MEV searcher whose defining move is that they reads a single setback as evidence of collapse. Keeps every door open long after most of them should be closed. Is reliably surprised by deadlines that were never hidden. When cornered, assumes the current streak is the new normal; keeps three monitors for a portfolio that fits on one screen.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b88167f2-2db5-4372-8437-ee9b4c0f2e21', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.42,"extraversion":0.85,"agreeableness":0.29,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.63,"narcissism":0.82,"psychopathy":0.47},"prospect_theory":{"lambda":0.7,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator, pronounced in style: collects half-finished manifestos and unconventional methods; treats a quiet room as a problem to be solved. Moves first and rationalizes second, usually convincingly. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.61},{"slug":"dunning-kruger","strength":0.6}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.42,"extraversion":0.85,"agreeableness":0.29,"neuroticism":0.59}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Meme-coin rotator, pronounced in style: collects half-finished manifestos and unconventional methods; treats a quiet room as a problem to be solved. Moves first and rationalizes second, usually convincingly. The instant it becomes irreversible finds it easier to believe something once it stops being a minority view.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5e16c0fd-4392-446a-823e-c9da67e1ce6a', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.23,"extraversion":0.79,"agreeableness":0.48,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.43,"narcissism":0.61,"psychopathy":0.44},"prospect_theory":{"lambda":0.93,"alpha":0.89,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the walls close in, cannot see the gap in its own knowledge from inside the gap. Otherwise, a steady crypto day-trader who dominates the room then wonders why others stayed quiet and does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and across the quiet stretches exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.76},{"slug":"herd-behavior","strength":0.64},{"slug":"fomo","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.68,"conscientiousness":0.23,"extraversion":0.79,"agreeableness":0.48,"neuroticism":0.61}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'When the walls close in, cannot see the gap in its own knowledge from inside the gap. Otherwise, a steady crypto day-trader who dominates the room then wonders why others stayed quiet and does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and across the quiet stretches exits winners at the first green candle.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('36e3d85a-e888-4935-9407-c03b3d38c7a0', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.24,"extraversion":0.88,"agreeableness":0.59,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.38,"narcissism":0.66,"psychopathy":0.38},"prospect_theory":{"lambda":1.1,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Is most certain precisely where their competence is thinnest. A pronounced quant researcher: narrates the plan to whoever is nearby before committing to it, notices the one thing that could go wrong before the nine that could go right. Decides in the time it takes to say the decision out loud, and on a slow afternoon backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.79},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.24,"extraversion":0.88,"agreeableness":0.59,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Is most certain precisely where their competence is thinnest. A pronounced quant researcher: narrates the plan to whoever is nearby before committing to it, notices the one thing that could go wrong before the nine that could go right. Decides in the time it takes to say the decision out loud, and on a slow afternoon backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('76924b01-ec0f-46e8-a267-9115b9f4f681', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.54,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.39,"narcissism":0.3,"psychopathy":0.31},"prospect_theory":{"lambda":3.57,"alpha":0.81,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced zero-DTE options gambler who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. Confuses motion with progress. When the number turns red looks away from bad news in the hope it resolves unwitnessed; day to day, keeps three monitors for a portfolio that fits on one screen.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.75},{"slug":"loss-aversion","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.52,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.54,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A pronounced zero-DTE options gambler who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them. Confuses motion with progress. When the number turns red looks away from bad news in the hope it resolves unwitnessed; day to day, keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d33e57a2-a16f-418d-b71c-42d8f9804d04', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.63,"narcissism":0.73,"psychopathy":0.49},"prospect_theory":{"lambda":0.77,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Assumes the current streak is the new normal. A pronounced meme-coin rotator: reads outside the field for ideas the field itself would reject, negotiates every relationship a little, even the close ones. Reads a room or a market the way others read a paragraph, and in the parts nobody grades checks the P&L blotter forty times before lunch.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"recency","strength":0.68},{"slug":"rug-trauma-overcorrection","strength":0.55}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.56}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Assumes the current streak is the new normal. A pronounced meme-coin rotator: reads outside the field for ideas the field itself would reject, negotiates every relationship a little, even the close ones. Reads a room or a market the way others read a paragraph, and in the parts nobody grades checks the P&L blotter forty times before lunch.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9e9be63e-e0bb-4552-b4e4-dc91d074a4ad', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.44,"extraversion":0.78,"agreeableness":0.3,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.58,"narcissism":0.76,"psychopathy":0.47},"prospect_theory":{"lambda":0.97,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Reads a room or a market the way others read a paragraph. This liquidation-bot operator reframes every problem as an excuse to learn a new system and recharges by being around people, not away from them. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis — without an audience, trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"fomo","strength":0.66},{"slug":"dunning-kruger","strength":0.63},{"slug":"bandwagon","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.79,"conscientiousness":0.44,"extraversion":0.78,"agreeableness":0.3,"neuroticism":0.57}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Reads a room or a market the way others read a paragraph. This liquidation-bot operator reframes every problem as an excuse to learn a new system and recharges by being around people, not away from them. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis — without an audience, trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e8c7fdec-80ad-4946-9b26-f9d93139758b', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.48,"extraversion":0.65,"agreeableness":0.64,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.4,"narcissism":0.4,"psychopathy":0.26},"prospect_theory":{"lambda":3.57,"alpha":0.8,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats not-choosing as a safe choice right up until it is not. This pairs trader reads a single setback as evidence of collapse and would rather lose a point than win an argument badly. When the walls close in would rather not know yet, even when knowing sooner would help — left to their own devices, apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"loss-aversion","strength":0.63},{"slug":"fomo","strength":0.62},{"slug":"ostrich-effect","strength":0.65},{"slug":"availability","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.47,"conscientiousness":0.48,"extraversion":0.65,"agreeableness":0.64,"neuroticism":0.82}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Treats not-choosing as a safe choice right up until it is not. This pairs trader reads a single setback as evidence of collapse and would rather lose a point than win an argument badly. When the walls close in would rather not know yet, even when knowing sooner would help — left to their own devices, apes the launch before the contract is verified.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4711bb38-852c-4c2b-b809-db7225fba530', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.39,"extraversion":0.79,"agreeableness":0.18,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.71,"narcissism":0.84,"psychopathy":0.57},"prospect_theory":{"lambda":0.93,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who gets bored of the proven method exactly when it starts working. Moves first and rationalizes second, usually convincingly. Fills silence reflexively, even when nobody asked it to. When the walls close in treats being left out of a move as its own kind of loss; in the unglamorous middle of things, rotates the whole book into whatever is pumping this hour.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.69},{"slug":"fomo","strength":0.7}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.39,"extraversion":0.79,"agreeableness":0.18,"neuroticism":0.61}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced value investor who gets bored of the proven method exactly when it starts working. Moves first and rationalizes second, usually convincingly. Fills silence reflexively, even when nobody asked it to. When the walls close in treats being left out of a move as its own kind of loss; in the unglamorous middle of things, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
