('131b164c-b17c-419d-8e70-6e8310f0d9e1', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.36,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.85,"narcissism":0.53,"psychopathy":0.49},"prospect_theory":{"lambda":2.19,"alpha":0.96,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Is surprised in the moment and certain in the retelling. A pronounced commodities speculator: treats a missed deadline as a personal failure regardless of cause, negotiates every relationship a little, even the close ones. Wants the base rate before the anecdote, and in the pattern nobody else tracks sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.58},{"slug":"overconfidence","strength":0.62},{"slug":"hindsight","strength":0.73}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.73,"conscientiousness":0.97,"extraversion":0.42,"agreeableness":0.36,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Is surprised in the moment and certain in the retelling. A pronounced commodities speculator: treats a missed deadline as a personal failure regardless of cause, negotiates every relationship a little, even the close ones. Wants the base rate before the anecdote, and in the pattern nobody else tracks sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
