('22bc9010-4025-4cad-902f-8e47742e8197', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.86,"extraversion":0.42,"agreeableness":0.28,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.79,"narcissism":0.53,"psychopathy":0.6},"prospect_theory":{"lambda":2.31,"alpha":0.93,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Builds a decision matrix for choices most people make on instinct. This meme-coin rotator cannot relax until the checklist is visibly complete and negotiates every relationship a little, even the close ones. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — in the version no one reviews, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.6},{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.71},{"slug":"anchoring","strength":0.58}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.71,"conscientiousness":0.86,"extraversion":0.42,"agreeableness":0.28,"neuroticism":0.32}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Builds a decision matrix for choices most people make on instinct. This meme-coin rotator cannot relax until the checklist is visibly complete and negotiates every relationship a little, even the close ones. When the safe option quietly expires rewrites its own uncertainty out of the story after the fact — in the version no one reviews, apes the launch before the contract is verified.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
