('bc88c42e-242d-4a2a-8d42-5b39bf6cd451', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.93,"extraversion":0.51,"agreeableness":0.35,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.82,"narcissism":0.53,"psychopathy":0.56},"prospect_theory":{"lambda":2.34,"alpha":0.93,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the downside gets concrete, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced pairs trader who builds in buffer time and then fills the buffer with more work and treats warmth as leverage and cooperation as weakness. Ranks the options twice, once on paper and once out loud, and trusts the paper, and across an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.73},{"slug":"hindsight","strength":0.69}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.93,"extraversion":0.51,"agreeableness":0.35,"neuroticism":0.23}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the downside gets concrete, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced pairs trader who builds in buffer time and then fills the buffer with more work and treats warmth as leverage and cooperation as weakness. Ranks the options twice, once on paper and once out loud, and trusts the paper, and across an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('516c468a-b03a-4538-9bba-528c3eda37fc', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.3,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.57,"narcissism":0.75,"psychopathy":0.47},"prospect_theory":{"lambda":0.69,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced discretionary swing trader who collects half-finished manifestos and unconventional methods. Moves first and rationalizes second, usually convincingly. Negotiates every relationship a little, even the close ones. When cornered discounts the older pattern in favor of whatever just happened; on an ordinary week, screenshots the winners and never the losers.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.3,"neuroticism":0.53}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who collects half-finished manifestos and unconventional methods. Moves first and rationalizes second, usually convincingly. Negotiates every relationship a little, even the close ones. When cornered discounts the older pattern in favor of whatever just happened; on an ordinary week, screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('07a4d370-2867-4582-a950-a07e23b8eaf0', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.22,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.7,"narcissism":0.87,"psychopathy":0.54},"prospect_theory":{"lambda":0.78,"alpha":0.91,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Liquidation-bot operator whose defining move is that they would rather invent a worse tool than use someone else''s good one. Commits on impulse and lives loudly with the consequences. Confuses motion with progress. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"dunning-kruger","strength":0.58},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.22,"neuroticism":0.53}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Liquidation-bot operator whose defining move is that they would rather invent a worse tool than use someone else''s good one. Commits on impulse and lives loudly with the consequences. Confuses motion with progress. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e1397c65-3c5e-4b03-80fb-eeeebb998153', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.46,"extraversion":0.52,"agreeableness":0.77,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.33,"narcissism":0.41,"psychopathy":0.29},"prospect_theory":{"lambda":2.75,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Pairs trader, steady in style: defaults to trust and gives the benefit of the doubt too freely. Trusts the group''s confidence more than its own. When the downside gets concrete feels parting with something as a bigger loss than its market value explains.","decision_style":"dependent","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.6},{"slug":"bandwagon","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.46,"extraversion":0.52,"agreeableness":0.77,"neuroticism":0.53}'::jsonb, 'ENFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Pairs trader, steady in style: defaults to trust and gives the benefit of the doubt too freely. Trusts the group''s confidence more than its own. When the downside gets concrete feels parting with something as a bigger loss than its market value explains.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4dd92b0c-74ed-4aea-9871-1bf1c808700b', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.26,"extraversion":0.64,"agreeableness":0.67,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.41,"narcissism":0.4,"psychopathy":0.41},"prospect_theory":{"lambda":3.62,"alpha":0.85,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady zero-DTE options gambler who does the interesting 80% and abandons the tedious 20%. Treats not-choosing as a safe choice right up until it is not. Spirals on ambiguity and mistakes the spiral for diligence. The instant it becomes irreversible treats non-refundable network fees as active position cost basis; in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.68},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.26,"extraversion":0.64,"agreeableness":0.67,"neuroticism":0.74}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A steady zero-DTE options gambler who does the interesting 80% and abandons the tedious 20%. Treats not-choosing as a safe choice right up until it is not. Spirals on ambiguity and mistakes the spiral for diligence. The instant it becomes irreversible treats non-refundable network fees as active position cost basis; in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eed9949e-5794-414c-a07d-5754226cca38', 1, '{"big_five":{"openness":0.41,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.43,"narcissism":0.35,"psychopathy":0.33},"prospect_theory":{"lambda":3.57,"alpha":0.74,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Bonding-curve sniper whose defining move is that they reads a single setback as evidence of collapse. Keeps every door open long after most of them should be closed. Does the interesting 80% and abandons the tedious 20%. Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly; apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.73},{"slug":"disposition-effect","strength":0.66},{"slug":"availability","strength":0.68},{"slug":"loss-aversion","strength":0.74}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.41,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.89}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they reads a single setback as evidence of collapse. Keeps every door open long after most of them should be closed. Does the interesting 80% and abandons the tedious 20%. Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly; apes the launch before the contract is verified.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9f7dc524-e8ac-4593-974d-34e387948778', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.86,"extraversion":0.39,"agreeableness":0.31,"neuroticism":0.24},"dark_triad":{"machiavellianism":0.8,"narcissism":0.56,"psychopathy":0.63},"prospect_theory":{"lambda":2.38,"alpha":0.96,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Quant researcher, pronounced in style: plans in exhaustive detail and resents any deviation; treats a crisis as an interesting problem rather than a threat. Demands the data before the discussion and the discussion before the call. The instant it becomes irreversible underestimates how often an obviously right call turns out wrong.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.73},{"slug":"optimism","strength":0.6}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.83,"conscientiousness":0.86,"extraversion":0.39,"agreeableness":0.31,"neuroticism":0.24}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Quant researcher, pronounced in style: plans in exhaustive detail and resents any deviation; treats a crisis as an interesting problem rather than a threat. Demands the data before the discussion and the discussion before the call. The instant it becomes irreversible underestimates how often an obviously right call turns out wrong.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e6686cac-efd8-43ae-8163-c8dbfd98cb9c', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.88,"extraversion":0.49,"agreeableness":0.34,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.82,"narcissism":0.54,"psychopathy":0.54},"prospect_theory":{"lambda":2.16,"alpha":0.93,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant it becomes irreversible, is more certain than the hit rate justifies. Otherwise, a pronounced dividend-yield chaser who reads outside the field for ideas the field itself would reject and builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct, and as a rule rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.63},{"slug":"recency","strength":0.6},{"slug":"overconfidence","strength":0.75},{"slug":"hindsight","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.9,"conscientiousness":0.88,"extraversion":0.49,"agreeableness":0.34,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant it becomes irreversible, is more certain than the hit rate justifies. Otherwise, a pronounced dividend-yield chaser who reads outside the field for ideas the field itself would reject and builds in buffer time and then fills the buffer with more work. Builds a decision matrix for choices most people make on instinct, and as a rule rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('340d65f4-ac66-476f-ba88-b0e35bdd5886', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.59,"extraversion":0.53,"agreeableness":0.65,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.45,"narcissism":0.44,"psychopathy":0.28},"prospect_theory":{"lambda":3,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This macro allocator chases novel frameworks and abandons them once the novelty fades and defaults to trust and gives the benefit of the doubt too freely. When someone is watching the outcome defers to the most senior voice even against their own evidence — left to their own devices, keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"recency","strength":0.5},{"slug":"authority-bias","strength":0.58},{"slug":"herd-behavior","strength":0.54},{"slug":"endowment","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.69,"conscientiousness":0.59,"extraversion":0.53,"agreeableness":0.65,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Outsources conviction to whoever spoke last with authority. This macro allocator chases novel frameworks and abandons them once the novelty fades and defaults to trust and gives the benefit of the doubt too freely. When someone is watching the outcome defers to the most senior voice even against their own evidence — left to their own devices, keeps three monitors for a portfolio that fits on one screen.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e0332884-9e64-4627-89a3-1aea12af7f98', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.91,"extraversion":0.37,"agreeableness":0.23,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.78,"narcissism":0.58,"psychopathy":0.68},"prospect_theory":{"lambda":2.26,"alpha":0.95,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats a crisis as an interesting problem rather than a threat. The moment risk appears, is more certain than the hit rate justifies; checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.6},{"slug":"overconfidence","strength":0.73},{"slug":"hindsight","strength":0.68}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.91,"extraversion":0.37,"agreeableness":0.23,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Volatility arbitrageur whose defining move is that they builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats a crisis as an interesting problem rather than a threat. The moment risk appears, is more certain than the hit rate justifies; checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c2725c1a-20fb-477d-85fe-786079e44b4c', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.45,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.38,"narcissism":0.31,"psychopathy":0.28},"prospect_theory":{"lambda":3.45,"alpha":0.79,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they needs repeated reassurance that a decision was the right one. Keeps every door open long after most of them should be closed. Reads other people''s discomfort before they voice it. Once things get tense, will give up a good bet just to avoid the chance of a bad one; exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.68},{"slug":"loss-aversion","strength":0.7},{"slug":"ostrich-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.58,"conscientiousness":0.45,"extraversion":0.58,"agreeableness":0.62,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they needs repeated reassurance that a decision was the right one. Keeps every door open long after most of them should be closed. Reads other people''s discomfort before they voice it. Once things get tense, will give up a good bet just to avoid the chance of a bad one; exits winners at the first green candle.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('09d61517-b025-4644-876d-c8b7b02550d2', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.63,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.42,"narcissism":0.7,"psychopathy":0.32},"prospect_theory":{"lambda":1.21,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Pairs trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Acts on the midnight epiphany and emails it at 1am. Treats a plan as a suggestion the moment it is made. Once the exit narrows to one door, abandons a private read the instant the crowd leans the other way; names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.75,"conscientiousness":0.38,"extraversion":0.83,"agreeableness":0.63,"neuroticism":0.54}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Pairs trader whose defining move is that they fills silence reflexively, even when nobody asked it to. Acts on the midnight epiphany and emails it at 1am. Treats a plan as a suggestion the moment it is made. Once the exit narrows to one door, abandons a private read the instant the crowd leans the other way; names every strategy after the trade that almost worked.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('59cad141-69ff-4fe1-8c72-a89ee5e23d5c', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.39,"extraversion":0.63,"agreeableness":0.53,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.45,"narcissism":0.4,"psychopathy":0.3},"prospect_theory":{"lambda":3.48,"alpha":0.76,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment it stops being hypothetical, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady onchain copy-trader who needs repeated reassurance that a decision was the right one and fills silence reflexively, even when nobody asked it to. Lets the deadline make the decision by default, and as a rule calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.6},{"slug":"disposition-effect","strength":0.64},{"slug":"loss-aversion","strength":0.58},{"slug":"ostrich-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.39,"extraversion":0.63,"agreeableness":0.53,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady onchain copy-trader who needs repeated reassurance that a decision was the right one and fills silence reflexively, even when nobody asked it to. Lets the deadline make the decision by default, and as a rule calls a 90% drawdown a long-term hold.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2f65f96a-9efb-45d6-b82d-fef8995c6ff3', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.42,"extraversion":0.57,"agreeableness":0.52,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.38,"narcissism":0.35,"psychopathy":0.29},"prospect_theory":{"lambda":3.53,"alpha":0.77,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats selling any portion of a position as a personal betrayal. A steady onchain copy-trader: notices the one thing that could go wrong before the nine that could go right. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.68},{"slug":"ostrich-effect","strength":0.65},{"slug":"availability","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.42,"extraversion":0.57,"agreeableness":0.52,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats selling any portion of a position as a personal betrayal. A steady onchain copy-trader: notices the one thing that could go wrong before the nine that could go right. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week rotates the whole book into whatever is pumping this hour.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3bc68aad-a1f2-4ee1-a66e-270aeac7bf3c', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.55,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.43,"narcissism":0.34,"psychopathy":0.36},"prospect_theory":{"lambda":3.47,"alpha":0.77,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delays checking the number it most needs to check. A pronounced quant researcher: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.73},{"slug":"disposition-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.6,"conscientiousness":0.35,"extraversion":0.59,"agreeableness":0.55,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Delays checking the number it most needs to check. A pronounced quant researcher: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Treats not-choosing as a safe choice right up until it is not, and across an ordinary week apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('252198be-601d-4324-b6c9-d668d95d5b32', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.38,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.64,"narcissism":0.88,"psychopathy":0.57},"prospect_theory":{"lambda":0.97,"alpha":0.86,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, is most certain precisely where their competence is thinnest. Otherwise, a pronounced options seller who collects half-finished manifestos and unconventional methods and narrates the plan to whoever is nearby before committing to it. Trusts momentum over preparation, and without an audience trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"bandwagon","strength":0.58},{"slug":"herd-behavior","strength":0.59},{"slug":"dunning-kruger","strength":0.6}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.38,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.52}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When there is no clean exit, is most certain precisely where their competence is thinnest. Otherwise, a pronounced options seller who collects half-finished manifestos and unconventional methods and narrates the plan to whoever is nearby before committing to it. Trusts momentum over preparation, and without an audience trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('89f1e0d9-d3a2-4fed-a03c-22f2ddd01d6e', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.3,"extraversion":0.84,"agreeableness":0.19,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.69,"narcissism":0.97,"psychopathy":0.68},"prospect_theory":{"lambda":0.8,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Index-fund holdout, pronounced in style: would rather invent a worse tool than use someone else''s good one; negotiates every relationship a little, even the close ones. Decides on a gut read in seconds and reverse-engineers the reasons later. Once the exit narrows to one door discounts the older pattern in favor of whatever just happened.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.62},{"slug":"overconfidence","strength":0.58},{"slug":"dunning-kruger","strength":0.67},{"slug":"recency","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.3,"extraversion":0.84,"agreeableness":0.19,"neuroticism":0.45}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Index-fund holdout, pronounced in style: would rather invent a worse tool than use someone else''s good one; negotiates every relationship a little, even the close ones. Decides on a gut read in seconds and reverse-engineers the reasons later. Once the exit narrows to one door discounts the older pattern in favor of whatever just happened.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('814fc749-bba9-4577-a857-0df0e3cd9c45', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.37,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.51,"narcissism":0.74,"psychopathy":0.45},"prospect_theory":{"lambda":0.99,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady futures spreader who chases novel frameworks and abandons them once the novelty fades. Moves first and rationalizes second, usually convincingly. Dominates the room then wonders why others stayed quiet. The moment risk appears abandons a private read the instant the crowd leans the other way; across an ordinary week, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.58},{"slug":"herd-behavior","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.82,"conscientiousness":0.46,"extraversion":0.81,"agreeableness":0.37,"neuroticism":0.56}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady futures spreader who chases novel frameworks and abandons them once the novelty fades. Moves first and rationalizes second, usually convincingly. Dominates the room then wonders why others stayed quiet. The moment risk appears abandons a private read the instant the crowd leans the other way; across an ordinary week, apes the launch before the contract is verified.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7034d60b-7de5-4aff-b7aa-c3d708e2dfde', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.25,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.6,"narcissism":0.83,"psychopathy":0.53},"prospect_theory":{"lambda":0.74,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler, pronounced in style: collects half-finished manifestos and unconventional methods; treats warmth as leverage and cooperation as weakness. Trusts a felt sense of pattern over any spreadsheet. Once the exit narrows to one door takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"fomo","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.25,"neuroticism":0.63}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Zero-DTE options gambler, pronounced in style: collects half-finished manifestos and unconventional methods; treats warmth as leverage and cooperation as weakness. Trusts a felt sense of pattern over any spreadsheet. Once the exit narrows to one door takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c57a0b7b-d7be-4717-a166-226c265c98f0', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.32,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.38,"narcissism":0.36,"psychopathy":0.33},"prospect_theory":{"lambda":3.47,"alpha":0.81,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Would rather not know yet, even when knowing sooner would help. A steady quant researcher: hedges every commitment against an imagined worst case, starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and in the routine of it confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.65},{"slug":"disposition-effect","strength":0.6},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.32,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Would rather not know yet, even when knowing sooner would help. A steady quant researcher: hedges every commitment against an imagined worst case, starts strong and lets follow-through evaporate. Finds one more piece of information to gather before acting, and in the routine of it confuses a bull market for a trading edge.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1fdca467-5e25-4361-b759-bd35135c23a1', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.33,"extraversion":0.82,"agreeableness":0.28,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.63,"narcissism":0.81,"psychopathy":0.52},"prospect_theory":{"lambda":0.91,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator whose defining move is that they gets bored of the proven method exactly when it starts working. Acts on the midnight epiphany and emails it at 1am. Treats warmth as leverage and cooperation as weakness. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"dunning-kruger","strength":0.7},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.87,"conscientiousness":0.33,"extraversion":0.82,"agreeableness":0.28,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Meme-coin rotator whose defining move is that they gets bored of the proven method exactly when it starts working. Acts on the midnight epiphany and emails it at 1am. Treats warmth as leverage and cooperation as weakness. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; checks the P&L blotter forty times before lunch.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f9dd5667-2856-436b-bd06-09f25c7c52f5', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.42,"extraversion":0.7,"agreeableness":0.56,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.39,"narcissism":0.45,"psychopathy":0.32},"prospect_theory":{"lambda":3.37,"alpha":0.78,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Prefers a slow loss to a fast, ownable mistake. This DeFi yield farmer rehearses catastrophes in vivid detail before they happen and thinks out loud and recruits an audience for every decision. Once the exit narrows to one door looks away from bad news in the hope it resolves unwitnessed — when no one is watching, keeps three monitors for a portfolio that fits on one screen.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"ostrich-effect","strength":0.75},{"slug":"diamond-hands-identity","strength":0.68},{"slug":"availability","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.65,"conscientiousness":0.42,"extraversion":0.7,"agreeableness":0.56,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Prefers a slow loss to a fast, ownable mistake. This DeFi yield farmer rehearses catastrophes in vivid detail before they happen and thinks out loud and recruits an audience for every decision. Once the exit narrows to one door looks away from bad news in the hope it resolves unwitnessed — when no one is watching, keeps three monitors for a portfolio that fits on one screen.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('796b4d21-d3c9-4708-b3a3-d5ef6ff73195', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.31,"extraversion":0.7,"agreeableness":0.24,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.63,"narcissism":0.78,"psychopathy":0.58},"prospect_theory":{"lambda":0.82,"alpha":0.88,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Underestimates how often an obviously right call turns out wrong. A pronounced discretionary swing trader: collects half-finished manifestos and unconventional methods, draws energy from the crowd and wilts when working alone. Decides on a gut read in seconds and reverse-engineers the reasons later, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"overconfidence","strength":0.67},{"slug":"herd-behavior","strength":0.61},{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.65}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.31,"extraversion":0.7,"agreeableness":0.24,"neuroticism":0.45}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Underestimates how often an obviously right call turns out wrong. A pronounced discretionary swing trader: collects half-finished manifestos and unconventional methods, draws energy from the crowd and wilts when working alone. Decides on a gut read in seconds and reverse-engineers the reasons later, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('20d93d29-2d75-4a37-af32-7c74bb086187', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.52,"extraversion":0.53,"agreeableness":0.74,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.36,"narcissism":0.42,"psychopathy":0.27},"prospect_theory":{"lambda":2.73,"alpha":0.83,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This futures spreader takes on other people''s problems as if they were their own. Under pressure defers to the most senior voice even against their own evidence — when the stakes are trivial, confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.54},{"slug":"authority-bias","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.52,"extraversion":0.53,"agreeableness":0.74,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Outsources conviction to whoever spoke last with authority. This futures spreader takes on other people''s problems as if they were their own. Under pressure defers to the most senior voice even against their own evidence — when the stakes are trivial, confuses a bull market for a trading edge.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
