('3323bd55-025e-40be-bcf0-71aa96df05d9', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.67,"extraversion":0.45,"agreeableness":0.71,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.46,"narcissism":0.41,"psychopathy":0.27},"prospect_theory":{"lambda":2.73,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A steady prop-desk scalper: takes on other people''s problems as if they were their own, plans in exhaustive detail and resents any deviation. Seeks a second, third, and fourth opinion before committing to anything, and across the quiet stretches backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.55},{"slug":"sunk-cost","strength":0.58},{"slug":"authority-bias","strength":0.51},{"slug":"endowment","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.61,"conscientiousness":0.67,"extraversion":0.45,"agreeableness":0.71,"neuroticism":0.5}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Would not buy back what it already owns at the price it would sell it for. A steady prop-desk scalper: takes on other people''s problems as if they were their own, plans in exhaustive detail and resents any deviation. Seeks a second, third, and fourth opinion before committing to anything, and across the quiet stretches backtests for months but front-runs the model on impulse.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('069a58ec-4c69-41bd-b742-97e5e008a667', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.29,"extraversion":0.54,"agreeableness":0.51,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.38,"narcissism":0.26,"psychopathy":0.37},"prospect_theory":{"lambda":3.6,"alpha":0.75,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats non-refundable network fees as active position cost basis. A pronounced onchain copy-trader: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Finds one more piece of information to gather before acting, and across an ordinary week screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.6},{"slug":"gas-sunk-cost","strength":0.75},{"slug":"disposition-effect","strength":0.71},{"slug":"ostrich-effect","strength":0.74}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.51,"conscientiousness":0.29,"extraversion":0.54,"agreeableness":0.51,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats non-refundable network fees as active position cost basis. A pronounced onchain copy-trader: hedges every commitment against an imagined worst case, treats a plan as a suggestion the moment it is made. Finds one more piece of information to gather before acting, and across an ordinary week screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e3971ebf-81e9-42b3-b7e1-4dbb787f55a5', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.59,"extraversion":0.7,"agreeableness":0.36,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.6,"narcissism":0.72,"psychopathy":0.45},"prospect_theory":{"lambda":1.07,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Pairs trader whose defining move is that they collects half-finished manifestos and unconventional methods. Demands the data before the discussion and the discussion before the call. Assumes self-interest in others because it is usually there in themselves. In a pinch, assumes the current streak is the new normal; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.62},{"slug":"optimism","strength":0.55},{"slug":"overconfidence","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.93,"conscientiousness":0.59,"extraversion":0.7,"agreeableness":0.36,"neuroticism":0.43}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Pairs trader whose defining move is that they collects half-finished manifestos and unconventional methods. Demands the data before the discussion and the discussion before the call. Assumes self-interest in others because it is usually there in themselves. In a pinch, assumes the current streak is the new normal; keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
