('90a76366-e9bc-4ce4-96d3-dfb1015d5dd8', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.49,"extraversion":0.66,"agreeableness":0.33,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.53,"narcissism":0.69,"psychopathy":0.5},"prospect_theory":{"lambda":1.33,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Onchain copy-trader, pronounced in style: collects half-finished manifestos and unconventional methods; fills silence reflexively, even when nobody asked it to. Demands the data before the discussion and the discussion before the call. When cornered assumes the current streak is the new normal.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"overconfidence","strength":0.58}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.49,"extraversion":0.66,"agreeableness":0.33,"neuroticism":0.42}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Onchain copy-trader, pronounced in style: collects half-finished manifestos and unconventional methods; fills silence reflexively, even when nobody asked it to. Demands the data before the discussion and the discussion before the call. When cornered assumes the current streak is the new normal.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('98258128-e64b-427a-ba8c-5be81a58c52a', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.96,"extraversion":0.3,"agreeableness":0.24,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.81,"narcissism":0.59,"psychopathy":0.65},"prospect_theory":{"lambda":2.23,"alpha":0.95,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Delta-neutral market maker whose defining move is that they front-loads the work and double-checks it twice. Ranks the options twice, once on paper and once out loud, and trusts the paper. Chases novel frameworks and abandons them once the novelty fades. The moment it stops being hypothetical, is surprised in the moment and certain in the retelling; apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.74},{"slug":"ath-anchoring","strength":0.68},{"slug":"hindsight","strength":0.75}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.81,"conscientiousness":0.96,"extraversion":0.3,"agreeableness":0.24,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they front-loads the work and double-checks it twice. Ranks the options twice, once on paper and once out loud, and trusts the paper. Chases novel frameworks and abandons them once the novelty fades. The moment it stops being hypothetical, is surprised in the moment and certain in the retelling; apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d2f61ed2-e007-4ed7-a0a2-f43390996647', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.5,"extraversion":0.59,"agreeableness":0.49,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.46,"narcissism":0.38,"psychopathy":0.32},"prospect_theory":{"lambda":3.34,"alpha":0.81,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Bonding-curve sniper whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting. Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly; trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENTJ","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.57},{"slug":"loss-aversion","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.5,"extraversion":0.59,"agreeableness":0.49,"neuroticism":0.72}'::jsonb, 'ENTJ', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting. Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly; trusts the chart more than the fundamentals and won''t say why.', 0.87, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0e474cf3-c446-4b60-9704-2caa8eed7eac', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.3,"extraversion":0.79,"agreeableness":0.56,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.4,"narcissism":0.66,"psychopathy":0.4},"prospect_theory":{"lambda":1.09,"alpha":0.84,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Zero-DTE options gambler whose defining move is that they treats established procedure as a first draft to be rewritten. Commits before the doubt has time to organize itself. Reads a single setback as evidence of collapse. Once the exit narrows to one door, cannot see the gap in its own knowledge from inside the gap; keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"dunning-kruger","strength":0.72},{"slug":"recency","strength":0.71}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.8,"conscientiousness":0.3,"extraversion":0.79,"agreeableness":0.56,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Zero-DTE options gambler whose defining move is that they treats established procedure as a first draft to be rewritten. Commits before the doubt has time to organize itself. Reads a single setback as evidence of collapse. Once the exit narrows to one door, cannot see the gap in its own knowledge from inside the gap; keeps a losing-trade journal they never re-read.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('de2c4e28-f99c-42d4-b75e-4c51ce407fde', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.45,"extraversion":0.57,"agreeableness":0.57,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.42,"narcissism":0.28,"psychopathy":0.33},"prospect_theory":{"lambda":3.39,"alpha":0.73,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Buries hard calls under a pile of preparatory busywork. This delta-neutral market maker reads a single setback as evidence of collapse. When the number turns red guards against losses far more fiercely than they chase equivalent gains — when the pressure is off, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.68},{"slug":"diamond-hands-identity","strength":0.63},{"slug":"ostrich-effect","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.51,"conscientiousness":0.45,"extraversion":0.57,"agreeableness":0.57,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Buries hard calls under a pile of preparatory busywork. This delta-neutral market maker reads a single setback as evidence of collapse. When the number turns red guards against losses far more fiercely than they chase equivalent gains — when the pressure is off, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bd6aef20-869c-472d-9659-b17b173826dd', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.33,"extraversion":0.64,"agreeableness":0.59,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.37,"narcissism":0.42,"psychopathy":0.35},"prospect_theory":{"lambda":3.56,"alpha":0.79,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Dividend-yield chaser whose defining move is that they hedges every commitment against an imagined worst case. Defers the decision until circumstances make it for them. Confuses motion with progress. Once the exit narrows to one door, would rather not know yet, even when knowing sooner would help; calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.62},{"slug":"gas-sunk-cost","strength":0.64},{"slug":"ostrich-effect","strength":0.72},{"slug":"loss-aversion","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.33,"extraversion":0.64,"agreeableness":0.59,"neuroticism":0.81}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser whose defining move is that they hedges every commitment against an imagined worst case. Defers the decision until circumstances make it for them. Confuses motion with progress. Once the exit narrows to one door, would rather not know yet, even when knowing sooner would help; calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8dbe803c-6abc-4f2b-bef4-6dd55402b088', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.96,"extraversion":0.47,"agreeableness":0.25,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.79,"narcissism":0.57,"psychopathy":0.67},"prospect_theory":{"lambda":2.36,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced prop-desk scalper who plans in exhaustive detail and resents any deviation. Wants the base rate before the anecdote. Is difficult to rattle even with genuinely bad news. When the safe option quietly expires holds their estimates with a certainty the track record does not support; without an audience, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.7},{"slug":"anchoring","strength":0.59},{"slug":"overconfidence","strength":0.77},{"slug":"ath-anchoring","strength":0.61}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.72,"conscientiousness":0.96,"extraversion":0.47,"agreeableness":0.25,"neuroticism":0.25}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced prop-desk scalper who plans in exhaustive detail and resents any deviation. Wants the base rate before the anecdote. Is difficult to rattle even with genuinely bad news. When the safe option quietly expires holds their estimates with a certainty the track record does not support; without an audience, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a272493d-3f02-4339-b087-4d0af8998471', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.85,"extraversion":0.46,"agreeableness":0.28,"neuroticism":0.31},"dark_triad":{"machiavellianism":0.78,"narcissism":0.58,"psychopathy":0.6},"prospect_theory":{"lambda":2.36,"alpha":0.93,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the walls close in, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced MEV searcher who plans in exhaustive detail and resents any deviation and gets bored of the proven method exactly when it starts working. Converts every argument into a number it can compare against another number, and in the routine of it confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.6},{"slug":"ath-anchoring","strength":0.65},{"slug":"optimism","strength":0.6}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.78,"conscientiousness":0.85,"extraversion":0.46,"agreeableness":0.28,"neuroticism":0.31}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the walls close in, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced MEV searcher who plans in exhaustive detail and resents any deviation and gets bored of the proven method exactly when it starts working. Converts every argument into a number it can compare against another number, and in the routine of it confuses a bull market for a trading edge.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2281d860-734f-4073-8c3a-817fdd7c5970', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.86,"extraversion":0.4,"agreeableness":0.37,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.85,"narcissism":0.58,"psychopathy":0.56},"prospect_theory":{"lambda":2.15,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the walls close in, is surprised in the moment and certain in the retelling. Otherwise, a pronounced options seller who collects half-finished manifestos and unconventional methods and optimizes for winning over being liked. Treats a decision without a paper trail as a decision not yet made, and when no one is watching apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.67},{"slug":"recency","strength":0.64}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.91,"conscientiousness":0.86,"extraversion":0.4,"agreeableness":0.37,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the walls close in, is surprised in the moment and certain in the retelling. Otherwise, a pronounced options seller who collects half-finished manifestos and unconventional methods and optimizes for winning over being liked. Treats a decision without a paper trail as a decision not yet made, and when no one is watching apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('fd632afc-92f5-4367-8325-784c68bc9341', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.32,"extraversion":0.84,"agreeableness":0.24,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.6,"narcissism":0.9,"psychopathy":0.61},"prospect_theory":{"lambda":0.97,"alpha":0.86,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper, pronounced in style: treats established procedure as a first draft to be rewritten; recharges by being around people, not away from them. Moves first and rationalizes second, usually convincingly. The moment risk appears cannot watch a rally from the sidelines for long.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"fomo","strength":0.69}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.32,"extraversion":0.84,"agreeableness":0.24,"neuroticism":0.53}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prop-desk scalper, pronounced in style: treats established procedure as a first draft to be rewritten; recharges by being around people, not away from them. Moves first and rationalizes second, usually convincingly. The moment risk appears cannot watch a rally from the sidelines for long.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2f20e9be-dd0f-4c74-8ae3-6547d457dfde', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.44,"extraversion":0.89,"agreeableness":0.6,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.4,"narcissism":0.68,"psychopathy":0.29},"prospect_theory":{"lambda":1.04,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker, pronounced in style: draws energy from the crowd and wilts when working alone; would rather invent a worse tool than use someone else''s good one. Treats hesitation as the bigger risk. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.77}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.44,"extraversion":0.89,"agreeableness":0.6,"neuroticism":0.6}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker, pronounced in style: draws energy from the crowd and wilts when working alone; would rather invent a worse tool than use someone else''s good one. Treats hesitation as the bigger risk. When the downside gets concrete finds it hard to hold a contrarian position once the room disagrees.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2aa087f9-c824-4cbb-9681-2b5f918b13db', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.97,"extraversion":0.45,"agreeableness":0.26,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.84,"narcissism":0.58,"psychopathy":0.58},"prospect_theory":{"lambda":2.13,"alpha":0.99,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Penny-stock gambler whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Assumes self-interest in others because it is usually there in themselves. When the stakes rise, is more certain than the hit rate justifies; confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.64},{"slug":"ath-anchoring","strength":0.63},{"slug":"overconfidence","strength":0.67}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.83,"conscientiousness":0.97,"extraversion":0.45,"agreeableness":0.26,"neuroticism":0.4}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Assumes self-interest in others because it is usually there in themselves. When the stakes rise, is more certain than the hit rate justifies; confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('71272b42-9918-48b3-8d96-166681c5faaf', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.34,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.41,"narcissism":0.59,"psychopathy":0.38},"prospect_theory":{"lambda":1.06,"alpha":0.84,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady penny-stock gambler who would rather invent a worse tool than use someone else''s good one. Decides in the time it takes to say the decision out loud. Needs repeated reassurance that a decision was the right one. As soon as real money or reputation is on the line mistakes a little fluency for real mastery; on an ordinary week, exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.64},{"slug":"dunning-kruger","strength":0.66},{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.66}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.82,"conscientiousness":0.34,"extraversion":0.8,"agreeableness":0.66,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'A steady penny-stock gambler who would rather invent a worse tool than use someone else''s good one. Decides in the time it takes to say the decision out loud. Needs repeated reassurance that a decision was the right one. As soon as real money or reputation is on the line mistakes a little fluency for real mastery; on an ordinary week, exits winners at the first green candle.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4a7ce10b-65f7-41e5-bef2-96ad5d8f7bdf', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.23,"extraversion":0.87,"agreeableness":0.4,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.49,"narcissism":0.8,"psychopathy":0.51},"prospect_theory":{"lambda":0.96,"alpha":0.89,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, is most certain precisely where their competence is thinnest. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Commits before the doubt has time to organize itself, and as a rule calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"dunning-kruger","strength":0.82}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.84,"conscientiousness":0.23,"extraversion":0.87,"agreeableness":0.4,"neuroticism":0.52}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant the deadline moves up, is most certain precisely where their competence is thinnest. Otherwise, a pronounced dividend-yield chaser who recharges by being around people, not away from them and treats established procedure as a first draft to be rewritten. Commits before the doubt has time to organize itself, and as a rule calls a 90% drawdown a long-term hold.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e08bcfe9-9821-42a6-8fbd-eda2168218e4', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.25,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.65,"narcissism":0.81,"psychopathy":0.5},"prospect_theory":{"lambda":1.28,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"The moment it stops being hypothetical, is more certain than the hit rate justifies. Otherwise, a steady DeFi yield farmer who treats established procedure as a first draft to be rewritten and fills silence reflexively, even when nobody asked it to. Demands the data before the discussion and the discussion before the call, and left to their own devices screenshots the winners and never the losers.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.56},{"slug":"overconfidence","strength":0.62},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.78,"conscientiousness":0.54,"extraversion":0.74,"agreeableness":0.25,"neuroticism":0.44}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, is more certain than the hit rate justifies. Otherwise, a steady DeFi yield farmer who treats established procedure as a first draft to be rewritten and fills silence reflexively, even when nobody asked it to. Demands the data before the discussion and the discussion before the call, and left to their own devices screenshots the winners and never the losers.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7fa4a239-3955-40b4-917a-6cbbf16741a7', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.44,"extraversion":0.76,"agreeableness":0.28,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.57,"narcissism":0.81,"psychopathy":0.53},"prospect_theory":{"lambda":0.97,"alpha":0.92,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced penny-stock gambler: reads outside the field for ideas the field itself would reject, thinks out loud and recruits an audience for every decision. Treats overthinking as its own kind of error, and in the unglamorous middle of things treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.58},{"slug":"herd-behavior","strength":0.65},{"slug":"dunning-kruger","strength":0.57}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.44,"extraversion":0.76,"agreeableness":0.28,"neuroticism":0.52}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced penny-stock gambler: reads outside the field for ideas the field itself would reject, thinks out loud and recruits an audience for every decision. Treats overthinking as its own kind of error, and in the unglamorous middle of things treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('be97a1ee-d980-4092-9cf0-88946207d01a', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.6,"extraversion":0.69,"agreeableness":0.45,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.53,"narcissism":0.64,"psychopathy":0.38},"prospect_theory":{"lambda":1.09,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Airdrop farmer, pronounced in style: gets bored of the proven method exactly when it starts working; treats a quiet room as a problem to be solved. Converts every argument into a number it can compare against another number. When the downside gets concrete cannot watch a rally from the sidelines for long.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.54},{"slug":"recency","strength":0.57},{"slug":"fomo","strength":0.6}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.85,"conscientiousness":0.6,"extraversion":0.69,"agreeableness":0.45,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Airdrop farmer, pronounced in style: gets bored of the proven method exactly when it starts working; treats a quiet room as a problem to be solved. Converts every argument into a number it can compare against another number. When the downside gets concrete cannot watch a rally from the sidelines for long.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9d561c01-77de-4f73-b308-2d014a52545f', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.31,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.6,"narcissism":0.73,"psychopathy":0.49},"prospect_theory":{"lambda":1.31,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Futures spreader whose defining move is that they collects half-finished manifestos and unconventional methods. Converts every argument into a number it can compare against another number. Fills silence reflexively, even when nobody asked it to. As soon as real money or reputation is on the line, extrapolates the last data point into a permanent trend; rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"fomo","strength":0.53}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.9,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.31,"neuroticism":0.47}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Futures spreader whose defining move is that they collects half-finished manifestos and unconventional methods. Converts every argument into a number it can compare against another number. Fills silence reflexively, even when nobody asked it to. As soon as real money or reputation is on the line, extrapolates the last data point into a permanent trend; rotates the whole book into whatever is pumping this hour.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('be4841d8-b842-4263-96ce-14dccfc81fd2', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.76,"extraversion":0.53,"agreeableness":0.47,"neuroticism":0.38},"dark_triad":{"machiavellianism":0.79,"narcissism":0.51,"psychopathy":0.4},"prospect_theory":{"lambda":2.19,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Bonding-curve sniper whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Stays flat when the numbers go red. Under pressure, treats past peak valuation as guaranteed future recovery; sets alerts for a coin they already checked a minute ago.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.61},{"slug":"recency","strength":0.53}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.74,"conscientiousness":0.76,"extraversion":0.53,"agreeableness":0.47,"neuroticism":0.38}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they plans in exhaustive detail and resents any deviation. Builds a decision matrix for choices most people make on instinct. Stays flat when the numbers go red. Under pressure, treats past peak valuation as guaranteed future recovery; sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1f80be8b-8fbb-4dd3-87c0-366e1f8acdac', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.34,"extraversion":0.81,"agreeableness":0.52,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.33},"prospect_theory":{"lambda":1.21,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader whose defining move is that they dominates the room then wonders why others stayed quiet. Commits before the doubt has time to organize itself. Reads outside the field for ideas the field itself would reject. The instant the deadline moves up, jumps into whatever everyone else already seems to be winning at; backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"bandwagon","strength":0.64},{"slug":"recency","strength":0.64},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.7,"conscientiousness":0.34,"extraversion":0.81,"agreeableness":0.52,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Discretionary swing trader whose defining move is that they dominates the room then wonders why others stayed quiet. Commits before the doubt has time to organize itself. Reads outside the field for ideas the field itself would reject. The instant the deadline moves up, jumps into whatever everyone else already seems to be winning at; backtests for months but front-runs the model on impulse.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('993898f2-4b30-48a6-924b-c45c63831255', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.44,"extraversion":0.53,"agreeableness":0.66,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.36,"narcissism":0.34,"psychopathy":0.33},"prospect_theory":{"lambda":3.28,"alpha":0.82,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady volatility arbitrageur who carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. Measures decisions by who they might upset. The instant it becomes irreversible delays checking the number it most needs to check; once the urgency drains out, trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.52},{"slug":"loss-aversion","strength":0.55},{"slug":"availability","strength":0.58},{"slug":"ostrich-effect","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.5,"conscientiousness":0.44,"extraversion":0.53,"agreeableness":0.66,"neuroticism":0.69}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady volatility arbitrageur who carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. Measures decisions by who they might upset. The instant it becomes irreversible delays checking the number it most needs to check; once the urgency drains out, trusts the chart more than the fundamentals and won''t say why.', 0.88, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d963f6dc-475d-4f67-8748-fe633961ea0a', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.32,"extraversion":0.89,"agreeableness":0.63,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.36,"narcissism":0.72,"psychopathy":0.35},"prospect_theory":{"lambda":1.07,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced retail momentum chaser who recharges by being around people, not away from them. Trusts momentum over preparation. Gets bored of the proven method exactly when it starts working. When cornered jumps into whatever everyone else already seems to be winning at; in the pattern nobody else tracks, screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"herd-behavior","strength":0.7},{"slug":"bandwagon","strength":0.66}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.7,"conscientiousness":0.32,"extraversion":0.89,"agreeableness":0.63,"neuroticism":0.6}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'A pronounced retail momentum chaser who recharges by being around people, not away from them. Trusts momentum over preparation. Gets bored of the proven method exactly when it starts working. When cornered jumps into whatever everyone else already seems to be winning at; in the pattern nobody else tracks, screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('94494cd0-677a-458a-bfd0-158e79561408', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.62,"extraversion":0.48,"agreeableness":0.55,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.44,"narcissism":0.33,"psychopathy":0.26},"prospect_theory":{"lambda":2.73,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Pairs trader, measured in style: carries yesterday''s stress into today''s unrelated decision; cannot relax until the checklist is visibly complete. Circles back to ask what someone else would do even after deciding. When there is no clean exit wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"recency","strength":0.5},{"slug":"ostrich-effect","strength":0.5},{"slug":"diamond-hands-identity","strength":0.56},{"slug":"loss-aversion","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.62,"extraversion":0.48,"agreeableness":0.55,"neuroticism":0.63}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Pairs trader, measured in style: carries yesterday''s stress into today''s unrelated decision; cannot relax until the checklist is visibly complete. Circles back to ask what someone else would do even after deciding. When there is no clean exit wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f62ae0b4-26ab-4747-8f35-1fecbb11367a', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.33,"extraversion":0.55,"agreeableness":0.53,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.43,"narcissism":0.3,"psychopathy":0.39},"prospect_theory":{"lambda":3.34,"alpha":0.74,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Locks in small wins fast and rides large losses far past the point of sense. A pronounced crypto day-trader: needs repeated reassurance that a decision was the right one, leaves loose ends and trusts future-self to handle them. Buries hard calls under a pile of preparatory busywork, and as a rule rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.66},{"slug":"gas-sunk-cost","strength":0.63},{"slug":"disposition-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.33,"extraversion":0.55,"agreeableness":0.53,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Locks in small wins fast and rides large losses far past the point of sense. A pronounced crypto day-trader: needs repeated reassurance that a decision was the right one, leaves loose ends and trusts future-self to handle them. Buries hard calls under a pile of preparatory busywork, and as a rule rotates the whole book into whatever is pumping this hour.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('13876ca3-388d-4119-b01c-4b54ea79ede1', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.5,"extraversion":0.79,"agreeableness":0.56,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.43,"narcissism":0.64,"psychopathy":0.32},"prospect_theory":{"lambda":1.13,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Acts on the midnight epiphany and emails it at 1am. This commodities speculator recharges by being around people, not away from them. The moment risk appears adopts a conviction mainly because the room already has — in the unglamorous middle of things, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENFJ","suggested_biases":[{"slug":"optimism","strength":0.55},{"slug":"bandwagon","strength":0.65},{"slug":"dunning-kruger","strength":0.61},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.61,"conscientiousness":0.5,"extraversion":0.79,"agreeableness":0.56,"neuroticism":0.56}'::jsonb, 'ENFJ', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Acts on the midnight epiphany and emails it at 1am. This commodities speculator recharges by being around people, not away from them. The moment risk appears adopts a conviction mainly because the room already has — in the unglamorous middle of things, treats a green week as proof of skill and a red one as proof of bad luck.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('69f8e287-bbdb-412b-b8ba-9c354e47c37a', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.85,"extraversion":0.45,"agreeableness":0.35,"neuroticism":0.17},"dark_triad":{"machiavellianism":0.79,"narcissism":0.6,"psychopathy":0.6},"prospect_theory":{"lambda":2.13,"alpha":0.91,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Prop-desk scalper whose defining move is that they reads outside the field for ideas the field itself would reject. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. Under a deadline, holds their estimates with a certainty the track record does not support; sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.74},{"slug":"hindsight","strength":0.62}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.88,"conscientiousness":0.85,"extraversion":0.45,"agreeableness":0.35,"neuroticism":0.17}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prop-desk scalper whose defining move is that they reads outside the field for ideas the field itself would reject. Wants the base rate before the anecdote. Moves on from a mistake faster than the people around them do. Under a deadline, holds their estimates with a certainty the track record does not support; sets stop-losses then cancels them at the open.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('09f8319a-87d6-4650-b7f6-05ee33b76726', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.92,"extraversion":0.45,"agreeableness":0.3,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.8,"narcissism":0.6,"psychopathy":0.62},"prospect_theory":{"lambda":2.14,"alpha":0.97,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Builds a decision matrix for choices most people make on instinct. This liquidation-bot operator treats a missed deadline as a personal failure regardless of cause and moves on from a mistake faster than the people around them do. As soon as real money or reputation is on the line holds their estimates with a certainty the track record does not support — in the routine of it, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.73},{"slug":"ath-anchoring","strength":0.61}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.86,"conscientiousness":0.92,"extraversion":0.45,"agreeableness":0.3,"neuroticism":0.27}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Builds a decision matrix for choices most people make on instinct. This liquidation-bot operator treats a missed deadline as a personal failure regardless of cause and moves on from a mistake faster than the people around them do. As soon as real money or reputation is on the line holds their estimates with a certainty the track record does not support — in the routine of it, trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bd800ac2-e43c-4897-b171-fffb68457178', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.33,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.53,"narcissism":0.76,"psychopathy":0.46},"prospect_theory":{"lambda":0.88,"alpha":0.86,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who reads outside the field for ideas the field itself would reject. Knows the answer before it can explain the question. Thinks out loud and recruits an audience for every decision. Under a deadline cannot watch a rally from the sidelines for long; when the pressure is off, sets alerts for a coin they already checked a minute ago.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.61},{"slug":"fomo","strength":0.62},{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.33,"neuroticism":0.55}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced value investor who reads outside the field for ideas the field itself would reject. Knows the answer before it can explain the question. Thinks out loud and recruits an audience for every decision. Under a deadline cannot watch a rally from the sidelines for long; when the pressure is off, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f90e650a-af53-4517-9571-5ae2b1faf129', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.86,"extraversion":0.42,"agreeableness":0.34,"neuroticism":0.11},"dark_triad":{"machiavellianism":0.8,"narcissism":0.55,"psychopathy":0.65},"prospect_theory":{"lambda":2.34,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Is more certain than the hit rate justifies. A pronounced algorithmic market-maker: sleeps fine the night before the big call, maintains flawless records nobody asked for. Wants the base rate before the anecdote, and in the pattern nobody else tracks confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.78},{"slug":"hindsight","strength":0.69},{"slug":"optimism","strength":0.73}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","even-keeled","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.81,"conscientiousness":0.86,"extraversion":0.42,"agreeableness":0.34,"neuroticism":0.11}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','even-keeled','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Is more certain than the hit rate justifies. A pronounced algorithmic market-maker: sleeps fine the night before the big call, maintains flawless records nobody asked for. Wants the base rate before the anecdote, and in the pattern nobody else tracks confuses a bull market for a trading edge.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('65c13f97-850c-47bb-bd81-453bdf98258a', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.31,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.58,"narcissism":0.79,"psychopathy":0.56},"prospect_theory":{"lambda":0.83,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller whose defining move is that they reframes every problem as an excuse to learn a new system. Commits before the doubt has time to organize itself. Treats a plan as a suggestion the moment it is made. As soon as real money or reputation is on the line, treats being left out of a move as its own kind of loss; sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"recency","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.31,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Options seller whose defining move is that they reframes every problem as an excuse to learn a new system. Commits before the doubt has time to organize itself. Treats a plan as a suggestion the moment it is made. As soon as real money or reputation is on the line, treats being left out of a move as its own kind of loss; sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('dae12403-de8e-4f66-be21-1fdfe92ce500', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.34,"extraversion":0.75,"agreeableness":0.25,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.62,"narcissism":0.77,"psychopathy":0.57},"prospect_theory":{"lambda":0.93,"alpha":0.84,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the safe option quietly expires, assumes the current streak is the new normal. Otherwise, a pronounced onchain copy-trader who treats established procedure as a first draft to be rewritten and leaves loose ends and trusts future-self to handle them. Trusts momentum over preparation, and across the quiet stretches holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.61},{"slug":"recency","strength":0.71},{"slug":"dunning-kruger","strength":0.63},{"slug":"fomo","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.34,"extraversion":0.75,"agreeableness":0.25,"neuroticism":0.65}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the safe option quietly expires, assumes the current streak is the new normal. Otherwise, a pronounced onchain copy-trader who treats established procedure as a first draft to be rewritten and leaves loose ends and trusts future-self to handle them. Trusts momentum over preparation, and across the quiet stretches holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8f87ddda-5d04-4c7b-9719-24c73c9cd7e2', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.54,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.38,"narcissism":0.74,"psychopathy":0.27},"prospect_theory":{"lambda":1.14,"alpha":0.83,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"DeFi yield farmer whose defining move is that they draws energy from the crowd and wilts when working alone. Trusts momentum over preparation. Hedges every commitment against an imagined worst case. In a pinch, treats being left out of a move as its own kind of loss; sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.7},{"slug":"fomo","strength":0.81}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.89,"conscientiousness":0.45,"extraversion":0.92,"agreeableness":0.54,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they draws energy from the crowd and wilts when working alone. Trusts momentum over preparation. Hedges every commitment against an imagined worst case. In a pinch, treats being left out of a move as its own kind of loss; sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b702424c-c02b-4fa8-8bd7-bf586ec6b873', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.42,"extraversion":0.45,"agreeableness":0.56,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.43,"narcissism":0.25,"psychopathy":0.31},"prospect_theory":{"lambda":3.53,"alpha":0.76,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Defers the decision until circumstances make it for them. This delta-neutral market maker needs repeated reassurance that a decision was the right one and reframes every problem as an excuse to learn a new system. Under a deadline overweights the vivid story over the boring statistic every time — when the pressure is off, keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"availability","strength":0.72},{"slug":"diamond-hands-identity","strength":0.72},{"slug":"loss-aversion","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.66,"conscientiousness":0.42,"extraversion":0.45,"agreeableness":0.56,"neuroticism":0.9}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Defers the decision until circumstances make it for them. This delta-neutral market maker needs repeated reassurance that a decision was the right one and reframes every problem as an excuse to learn a new system. Under a deadline overweights the vivid story over the boring statistic every time — when the pressure is off, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6e829d94-bc54-4d87-834c-23e8b0c76595', 1, '{"big_five":{"openness":0.46,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.59,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.41,"narcissism":0.3,"psychopathy":0.32},"prospect_theory":{"lambda":3.32,"alpha":0.71,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats selling any portion of a position as a personal betrayal. A pronounced macro allocator: reads a single setback as evidence of collapse. Treats not-choosing as a safe choice right up until it is not, and on a slow afternoon keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"availability","strength":0.72},{"slug":"diamond-hands-identity","strength":0.73},{"slug":"loss-aversion","strength":0.7},{"slug":"rug-trauma-overcorrection","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.46,"conscientiousness":0.39,"extraversion":0.59,"agreeableness":0.59,"neuroticism":0.89}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Treats selling any portion of a position as a personal betrayal. A pronounced macro allocator: reads a single setback as evidence of collapse. Treats not-choosing as a safe choice right up until it is not, and on a slow afternoon keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d9ebea83-5778-442e-a146-53fa1a57e8af', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.35,"extraversion":0.56,"agreeableness":0.54,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.41,"narcissism":0.32,"psychopathy":0.36},"prospect_theory":{"lambda":3.68,"alpha":0.71,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Would rather not know yet, even when knowing sooner would help. A pronounced pairs trader: reads a single setback as evidence of collapse, is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and once the urgency drains out talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.7},{"slug":"ostrich-effect","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.56,"conscientiousness":0.35,"extraversion":0.56,"agreeableness":0.54,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Would rather not know yet, even when knowing sooner would help. A pronounced pairs trader: reads a single setback as evidence of collapse, is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and once the urgency drains out talks in win rate and never mentions size.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('62febde7-4d18-4b65-8383-a46a550a20d7', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.4,"extraversion":0.71,"agreeableness":0.28,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.57,"narcissism":0.77,"psychopathy":0.54},"prospect_theory":{"lambda":0.74,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced airdrop farmer who would rather invent a worse tool than use someone else''s good one. Moves first and rationalizes second, usually convincingly. Reads a single setback as evidence of collapse. When the walls close in treats every unannounced multisig transaction as an imminent exit scam; across the quiet stretches, calls a 90% drawdown a long-term hold.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"airdrop-entitlement","strength":0.66},{"slug":"fomo","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.4,"extraversion":0.71,"agreeableness":0.28,"neuroticism":0.66}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced airdrop farmer who would rather invent a worse tool than use someone else''s good one. Moves first and rationalizes second, usually convincingly. Reads a single setback as evidence of collapse. When the walls close in treats every unannounced multisig transaction as an imminent exit scam; across the quiet stretches, calls a 90% drawdown a long-term hold.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f398e03f-cba5-4e37-9da9-8a250619c9f7', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.4,"extraversion":0.74,"agreeableness":0.27,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.57,"narcissism":0.73,"psychopathy":0.54},"prospect_theory":{"lambda":0.87,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced retail momentum chaser who reframes every problem as an excuse to learn a new system. Reads a room or a market the way others read a paragraph. Spirals on ambiguity and mistakes the spiral for diligence. In a pinch jumps into whatever everyone else already seems to be winning at; when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.67},{"slug":"fomo","strength":0.7}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.4,"extraversion":0.74,"agreeableness":0.27,"neuroticism":0.65}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced retail momentum chaser who reframes every problem as an excuse to learn a new system. Reads a room or a market the way others read a paragraph. Spirals on ambiguity and mistakes the spiral for diligence. In a pinch jumps into whatever everyone else already seems to be winning at; when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('db8279d2-d5f5-411f-82e8-90ca8facca43', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.2,"extraversion":0.71,"agreeableness":0.47,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.43},"prospect_theory":{"lambda":3.55,"alpha":0.75,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced DeFi yield farmer who hedges every commitment against an imagined worst case. Buries hard calls under a pile of preparatory busywork. Treats a quiet room as a problem to be solved. When the number turns red delays checking the number it most needs to check; on a slow afternoon, names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.71},{"slug":"disposition-effect","strength":0.67},{"slug":"ostrich-effect","strength":0.78},{"slug":"dunning-kruger","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.52,"conscientiousness":0.2,"extraversion":0.71,"agreeableness":0.47,"neuroticism":0.88}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A pronounced DeFi yield farmer who hedges every commitment against an imagined worst case. Buries hard calls under a pile of preparatory busywork. Treats a quiet room as a problem to be solved. When the number turns red delays checking the number it most needs to check; on a slow afternoon, names every strategy after the trade that almost worked.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a11e816a-e5cd-40ed-a41e-cb3c8ec43115', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.33,"extraversion":0.73,"agreeableness":0.59,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.37,"narcissism":0.55,"psychopathy":0.39},"prospect_theory":{"lambda":1.17,"alpha":0.79,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Under pressure, abandons a private read the instant the crowd leans the other way. Otherwise, a steady perps degen who chases novel frameworks and abandons them once the novelty fades and confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and across the quiet stretches checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.59},{"slug":"herd-behavior","strength":0.65},{"slug":"recency","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.33,"extraversion":0.73,"agreeableness":0.59,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Under pressure, abandons a private read the instant the crowd leans the other way. Otherwise, a steady perps degen who chases novel frameworks and abandons them once the novelty fades and confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and across the quiet stretches checks the P&L blotter forty times before lunch.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b87c2e4c-d022-4891-ac6f-9b3bcb17f506', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.51,"extraversion":0.72,"agreeableness":0.31,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.56,"narcissism":0.81,"psychopathy":0.45},"prospect_theory":{"lambda":1.21,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Perps degen whose defining move is that they reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number. Narrates the plan to whoever is nearby before committing to it. The moment risk appears, jumps into whatever everyone else already seems to be winning at; exits winners at the first green candle.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.57},{"slug":"herd-behavior","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.95,"conscientiousness":0.51,"extraversion":0.72,"agreeableness":0.31,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Perps degen whose defining move is that they reads outside the field for ideas the field itself would reject. Converts every argument into a number it can compare against another number. Narrates the plan to whoever is nearby before committing to it. The moment risk appears, jumps into whatever everyone else already seems to be winning at; exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2cb943f5-7fcf-42eb-adf2-c35328962628', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.64,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.4,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.21,"alpha":0.78,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment it stops being hypothetical, cannot watch a rally from the sidelines for long. Otherwise, a pronounced quant researcher who treats a quiet room as a problem to be solved and confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and on an ordinary week names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"recency","strength":0.6},{"slug":"fomo","strength":0.77},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.38,"extraversion":0.86,"agreeableness":0.64,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, cannot watch a rally from the sidelines for long. Otherwise, a pronounced quant researcher who treats a quiet room as a problem to be solved and confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and on an ordinary week names every strategy after the trade that almost worked.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('683ce402-1e7f-437b-b66d-733cad638eb6', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.55,"extraversion":0.83,"agreeableness":0.3,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.61,"narcissism":0.85,"psychopathy":0.42},"prospect_theory":{"lambda":0.87,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced quant researcher who treats established procedure as a first draft to be rewritten. Decides on a gut read in seconds and reverse-engineers the reasons later. Treats warmth as leverage and cooperation as weakness. Once things get tense treats being left out of a move as its own kind of loss; left to their own devices, averages down on a name three times in a week.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.62},{"slug":"bandwagon","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.61},{"slug":"fomo","strength":0.66}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.55,"extraversion":0.83,"agreeableness":0.3,"neuroticism":0.59}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced quant researcher who treats established procedure as a first draft to be rewritten. Decides on a gut read in seconds and reverse-engineers the reasons later. Treats warmth as leverage and cooperation as weakness. Once things get tense treats being left out of a move as its own kind of loss; left to their own devices, averages down on a name three times in a week.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('abdffe50-1c6c-4199-af4a-838f6f72806c', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.38,"extraversion":0.88,"agreeableness":0.63,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.39,"narcissism":0.75,"psychopathy":0.3},"prospect_theory":{"lambda":1.26,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Pairs trader, pronounced in style: draws energy from the crowd and wilts when working alone; improvises past every deadline and calls it flexibility. Acts on the midnight epiphany and emails it at 1am. Under a deadline gains confidence in a position in proportion to how many others hold it.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.76},{"slug":"recency","strength":0.69},{"slug":"fomo","strength":0.7},{"slug":"dunning-kruger","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.85,"conscientiousness":0.38,"extraversion":0.88,"agreeableness":0.63,"neuroticism":0.65}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Pairs trader, pronounced in style: draws energy from the crowd and wilts when working alone; improvises past every deadline and calls it flexibility. Acts on the midnight epiphany and emails it at 1am. Under a deadline gains confidence in a position in proportion to how many others hold it.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eeebe3c4-d583-4b45-9d6b-2a5b069ef02d', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.5,"extraversion":0.68,"agreeableness":0.33,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.56,"narcissism":0.72,"psychopathy":0.44},"prospect_theory":{"lambda":1.15,"alpha":0.83,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Discretionary swing trader, pronounced in style: reads outside the field for ideas the field itself would reject; would rather be respected than liked, and says so. Converts every argument into a number it can compare against another number. When the safe option quietly expires extrapolates the last data point into a permanent trend.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.94,"conscientiousness":0.5,"extraversion":0.68,"agreeableness":0.33,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discretionary swing trader, pronounced in style: reads outside the field for ideas the field itself would reject; would rather be respected than liked, and says so. Converts every argument into a number it can compare against another number. When the safe option quietly expires extrapolates the last data point into a permanent trend.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('82901acf-782e-4057-bfb5-2b23bceb8e92', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.34,"extraversion":0.85,"agreeableness":0.46,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.44,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":0.93,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats being left out of a move as its own kind of loss. A pronounced pairs trader: dominates the room then wonders why others stayed quiet, reads outside the field for ideas the field itself would reject. Prefers a fast wrong answer to a slow right one, and in the unglamorous middle of things sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.63},{"slug":"recency","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.84,"conscientiousness":0.34,"extraversion":0.85,"agreeableness":0.46,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Treats being left out of a move as its own kind of loss. A pronounced pairs trader: dominates the room then wonders why others stayed quiet, reads outside the field for ideas the field itself would reject. Prefers a fast wrong answer to a slow right one, and in the unglamorous middle of things sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0cdb5813-48d7-488b-8f74-6af2829c5a49', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.34,"extraversion":0.87,"agreeableness":0.24,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.67,"narcissism":0.84,"psychopathy":0.58},"prospect_theory":{"lambda":1,"alpha":0.85,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser, pronounced in style: treats established procedure as a first draft to be rewritten; needs repeated reassurance that a decision was the right one. Acts on the midnight epiphany and emails it at 1am. When there is no clean exit is most certain precisely where their competence is thinnest.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.71},{"slug":"recency","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.34,"extraversion":0.87,"agreeableness":0.24,"neuroticism":0.64}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Retail momentum chaser, pronounced in style: treats established procedure as a first draft to be rewritten; needs repeated reassurance that a decision was the right one. Acts on the midnight epiphany and emails it at 1am. When there is no clean exit is most certain precisely where their competence is thinnest.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b0af636b-e456-46fa-9b46-90aabb0d6150', 1, '{"big_five":{"openness":0.44,"conscientiousness":0.41,"extraversion":0.63,"agreeableness":0.6,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.37,"narcissism":0.36,"psychopathy":0.31},"prospect_theory":{"lambda":3.34,"alpha":0.78,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Once the exit narrows to one door, delays checking the number it most needs to check. Otherwise, a steady value investor who rehearses catastrophes in vivid detail before they happen and draws energy from the crowd and wilts when working alone. Keeps every door open long after most of them should be closed, and without an audience screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.68},{"slug":"fomo","strength":0.66},{"slug":"loss-aversion","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.44,"conscientiousness":0.41,"extraversion":0.63,"agreeableness":0.6,"neuroticism":0.78}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, delays checking the number it most needs to check. Otherwise, a steady value investor who rehearses catastrophes in vivid detail before they happen and draws energy from the crowd and wilts when working alone. Keeps every door open long after most of them should be closed, and without an audience screenshots the winners and never the losers.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2e4347ac-6cd2-41ed-883b-20b841044cb5', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.21,"extraversion":0.78,"agreeableness":0.35,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.56,"narcissism":0.74,"psychopathy":0.56},"prospect_theory":{"lambda":1.07,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts momentum over preparation. This pairs trader would rather invent a worse tool than use someone else''s good one and narrates the plan to whoever is nearby before committing to it. Once things get tense discounts the older pattern in favor of whatever just happened — day to day, sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.65},{"slug":"recency","strength":0.68}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.82,"conscientiousness":0.21,"extraversion":0.78,"agreeableness":0.35,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This pairs trader would rather invent a worse tool than use someone else''s good one and narrates the plan to whoever is nearby before committing to it. Once things get tense discounts the older pattern in favor of whatever just happened — day to day, sets stop-losses then cancels them at the open.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7007cb14-5bfd-4a3f-a3f9-73ba87b1538d', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.64,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.42,"narcissism":0.7,"psychopathy":0.37},"prospect_theory":{"lambda":0.97,"alpha":0.83,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"MEV searcher whose defining move is that they treats a quiet room as a problem to be solved. Decides in the time it takes to say the decision out loud. Is reliably surprised by deadlines that were never hidden. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.69,"conscientiousness":0.37,"extraversion":0.83,"agreeableness":0.64,"neuroticism":0.56}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'MEV searcher whose defining move is that they treats a quiet room as a problem to be solved. Decides in the time it takes to say the decision out loud. Is reliably surprised by deadlines that were never hidden. When the safe option quietly expires, finds it hard to hold a contrarian position once the room disagrees; keeps a losing-trade journal they never re-read.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c8fa46b7-efa1-47ae-93b6-de4c4691930a', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.45,"extraversion":0.6,"agreeableness":0.57,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.43,"narcissism":0.37,"psychopathy":0.3},"prospect_theory":{"lambda":3.73,"alpha":0.77,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Options seller, pronounced in style: rehearses catastrophes in vivid detail before they happen. Buries hard calls under a pile of preparatory busywork. When the number turns red overweights the vivid story over the boring statistic every time.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.71},{"slug":"diamond-hands-identity","strength":0.71},{"slug":"loss-aversion","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.45,"extraversion":0.6,"agreeableness":0.57,"neuroticism":0.87}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Options seller, pronounced in style: rehearses catastrophes in vivid detail before they happen. Buries hard calls under a pile of preparatory busywork. When the number turns red overweights the vivid story over the boring statistic every time.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('58e6dae1-3e56-480d-aa60-2766e2165679', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.15,"extraversion":0.69,"agreeableness":0.57,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.39,"narcissism":0.45,"psychopathy":0.46},"prospect_theory":{"lambda":3.75,"alpha":0.79,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Lets the deadline make the decision by default. This retail momentum chaser leaves loose ends and trusts future-self to handle them and hedges every commitment against an imagined worst case. When the number turns red mistakes a little fluency for real mastery — across an ordinary week, rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.79},{"slug":"disposition-effect","strength":0.69},{"slug":"gas-sunk-cost","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.15,"extraversion":0.69,"agreeableness":0.57,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Lets the deadline make the decision by default. This retail momentum chaser leaves loose ends and trusts future-self to handle them and hedges every commitment against an imagined worst case. When the number turns red mistakes a little fluency for real mastery — across an ordinary week, rotates the whole book into whatever is pumping this hour.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1359397d-1555-4091-979d-2398dd8c8c19', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.55,"extraversion":0.51,"agreeableness":0.58,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.38,"narcissism":0.36,"psychopathy":0.26},"prospect_theory":{"lambda":2.76,"alpha":0.88,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer whose defining move is that they hedges every commitment against an imagined worst case. Waits for a permission that never quite arrives. When the downside gets concrete, delays checking the number it most needs to check; apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.51},{"slug":"loss-aversion","strength":0.52},{"slug":"ostrich-effect","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.51,"conscientiousness":0.55,"extraversion":0.51,"agreeableness":0.58,"neuroticism":0.66}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they hedges every commitment against an imagined worst case. Waits for a permission that never quite arrives. When the downside gets concrete, delays checking the number it most needs to check; apes the launch before the contract is verified.', 0.87, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('32af5b38-db47-4cea-8d90-075eb4ac6264', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.41,"extraversion":0.66,"agreeableness":0.41,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.47,"narcissism":0.66,"psychopathy":0.42},"prospect_theory":{"lambda":1.18,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Index-fund holdout whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Ranks the options twice, once on paper and once out loud, and trusts the paper. Dominates the room then wonders why others stayed quiet. Under a deadline, discounts the older pattern in favor of whatever just happened; averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.53},{"slug":"recency","strength":0.56}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.83,"conscientiousness":0.41,"extraversion":0.66,"agreeableness":0.41,"neuroticism":0.44}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Index-fund holdout whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Ranks the options twice, once on paper and once out loud, and trusts the paper. Dominates the room then wonders why others stayed quiet. Under a deadline, discounts the older pattern in favor of whatever just happened; averages down on a name three times in a week.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('fb3ce927-1375-433d-b4ec-208b47383bfa', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.95,"extraversion":0.44,"agreeableness":0.41,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.83,"narcissism":0.52,"psychopathy":0.44},"prospect_theory":{"lambda":2.38,"alpha":0.98,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Liquidation-bot operator, pronounced in style: builds in buffer time and then fills the buffer with more work; would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The moment it stops being hypothetical is surprised in the moment and certain in the retelling.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.83,"conscientiousness":0.95,"extraversion":0.44,"agreeableness":0.41,"neuroticism":0.36}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Liquidation-bot operator, pronounced in style: builds in buffer time and then fills the buffer with more work; would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The moment it stops being hypothetical is surprised in the moment and certain in the retelling.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('cc6951a4-8ee3-461e-a49f-dcdc28ea774c', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.79,"extraversion":0.36,"agreeableness":0.29,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.79,"narcissism":0.57,"psychopathy":0.6},"prospect_theory":{"lambda":2.29,"alpha":0.89,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Macro allocator whose defining move is that they collects half-finished manifestos and unconventional methods. Converts every argument into a number it can compare against another number. Treats consensus-seeking as a waste of time. Once the exit narrows to one door, is more certain than the hit rate justifies; confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.59},{"slug":"overconfidence","strength":0.76}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.8,"conscientiousness":0.79,"extraversion":0.36,"agreeableness":0.29,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Macro allocator whose defining move is that they collects half-finished manifestos and unconventional methods. Converts every argument into a number it can compare against another number. Treats consensus-seeking as a waste of time. Once the exit narrows to one door, is more certain than the hit rate justifies; confuses a bull market for a trading edge.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a02ec712-ff6b-4d4f-8eaa-dbd36086a06e', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.92,"extraversion":0.42,"agreeableness":0.25,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.81,"narcissism":0.58,"psychopathy":0.61},"prospect_theory":{"lambda":2.16,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Remembers every surprise as something they saw coming all along. A pronounced value investor: front-loads the work and double-checks it twice, optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the unglamorous middle of things screenshots the winners and never the losers.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.75},{"slug":"overconfidence","strength":0.71},{"slug":"ath-anchoring","strength":0.65}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.84,"conscientiousness":0.92,"extraversion":0.42,"agreeableness":0.25,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Remembers every surprise as something they saw coming all along. A pronounced value investor: front-loads the work and double-checks it twice, optimizes for winning over being liked. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the unglamorous middle of things screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bce870da-1dbe-4cf9-958b-7201564c5906', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.33,"extraversion":0.83,"agreeableness":0.3,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.57,"narcissism":0.88,"psychopathy":0.52},"prospect_theory":{"lambda":0.99,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader whose defining move is that they collects half-finished manifestos and unconventional methods. Trusts a felt sense of pattern over any spreadsheet. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical, gains confidence in a position in proportion to how many others hold it; backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"fomo","strength":0.64},{"slug":"bandwagon","strength":0.66},{"slug":"herd-behavior","strength":0.63}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.33,"extraversion":0.83,"agreeableness":0.3,"neuroticism":0.55}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Onchain copy-trader whose defining move is that they collects half-finished manifestos and unconventional methods. Trusts a felt sense of pattern over any spreadsheet. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical, gains confidence in a position in proportion to how many others hold it; backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4e9106b2-a8fa-4100-a92d-e41f3d942507', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.39,"extraversion":0.56,"agreeableness":0.49,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.43,"narcissism":0.34,"psychopathy":0.34},"prospect_theory":{"lambda":3.62,"alpha":0.8,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Defers the decision until circumstances make it for them. This retail momentum chaser spirals on ambiguity and mistakes the spiral for diligence. In a pinch locks in small wins fast and rides large losses far past the point of sense — when the pressure is off, talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.67},{"slug":"loss-aversion","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.64},{"slug":"ostrich-effect","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.6,"conscientiousness":0.39,"extraversion":0.56,"agreeableness":0.49,"neuroticism":0.78}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Defers the decision until circumstances make it for them. This retail momentum chaser spirals on ambiguity and mistakes the spiral for diligence. In a pinch locks in small wins fast and rides large losses far past the point of sense — when the pressure is off, talks in win rate and never mentions size.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bcf95561-f110-467e-a1da-61e309f33d74', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.27,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.97},"dark_triad":{"machiavellianism":0.43,"narcissism":0.32,"psychopathy":0.34},"prospect_theory":{"lambda":3.71,"alpha":0.69,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Onchain copy-trader, pronounced in style: hedges every commitment against an imagined worst case; improvises past every deadline and calls it flexibility. Prefers a slow loss to a fast, ownable mistake. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.75},{"slug":"gas-sunk-cost","strength":0.78},{"slug":"ostrich-effect","strength":0.8}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.27,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.97}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Onchain copy-trader, pronounced in style: hedges every commitment against an imagined worst case; improvises past every deadline and calls it flexibility. Prefers a slow loss to a fast, ownable mistake. The instant the deadline moves up looks away from bad news in the hope it resolves unwitnessed.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4819ce45-e8e9-4431-8e6f-e3971edb19f2', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.79,"extraversion":0.39,"agreeableness":0.27,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.86,"narcissism":0.61,"psychopathy":0.6},"prospect_theory":{"lambda":2.16,"alpha":0.88,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A steady volatility arbitrageur who builds in buffer time and then fills the buffer with more work. Converts every argument into a number it can compare against another number. Is difficult to rattle even with genuinely bad news. When there is no clean exit holds their estimates with a certainty the track record does not support; when the pressure is off, keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.56},{"slug":"overconfidence","strength":0.68},{"slug":"hindsight","strength":0.68}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.78,"conscientiousness":0.79,"extraversion":0.39,"agreeableness":0.27,"neuroticism":0.3}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady volatility arbitrageur who builds in buffer time and then fills the buffer with more work. Converts every argument into a number it can compare against another number. Is difficult to rattle even with genuinely bad news. When there is no clean exit holds their estimates with a certainty the track record does not support; when the pressure is off, keeps three monitors for a portfolio that fits on one screen.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ef693fb3-c89e-41f0-997c-8a6e11242c37', 1, '{"big_five":{"openness":0.45,"conscientiousness":0.47,"extraversion":0.56,"agreeableness":0.62,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.35,"narcissism":0.25,"psychopathy":0.28},"prospect_theory":{"lambda":3.29,"alpha":0.72,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Measures decisions by who they might upset. In a pinch, guards against losses far more fiercely than they chase equivalent gains; exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"loss-aversion","strength":0.7},{"slug":"ostrich-effect","strength":0.67},{"slug":"availability","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.45,"conscientiousness":0.47,"extraversion":0.56,"agreeableness":0.62,"neuroticism":0.89}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Measures decisions by who they might upset. In a pinch, guards against losses far more fiercely than they chase equivalent gains; exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('43561c9a-3b3f-4ac2-8868-2314ca1d64f2', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.71,"extraversion":0.31,"agreeableness":0.65,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.46,"narcissism":0.31,"psychopathy":0.24},"prospect_theory":{"lambda":2.96,"alpha":0.87,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor, steady in style: carries yesterday''s stress into today''s unrelated decision; builds in buffer time and then fills the buffer with more work. Trusts the group''s confidence more than its own. The instant the deadline moves up overweights the vivid story over the boring statistic every time.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.54},{"slug":"availability","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.71,"extraversion":0.31,"agreeableness":0.65,"neuroticism":0.73}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Value investor, steady in style: carries yesterday''s stress into today''s unrelated decision; builds in buffer time and then fills the buffer with more work. Trusts the group''s confidence more than its own. The instant the deadline moves up overweights the vivid story over the boring statistic every time.', 0.87, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('260187e3-8142-4ae9-875d-63431f1bc471', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.28,"extraversion":0.63,"agreeableness":0.55,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.39,"narcissism":0.41,"psychopathy":0.38},"prospect_theory":{"lambda":3.57,"alpha":0.76,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Macro allocator, pronounced in style: rehearses catastrophes in vivid detail before they happen; treats a quiet room as a problem to be solved. Buries hard calls under a pile of preparatory busywork. When the walls close in locks in small wins fast and rides large losses far past the point of sense.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.7},{"slug":"gas-sunk-cost","strength":0.7},{"slug":"disposition-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.28,"extraversion":0.63,"agreeableness":0.55,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Macro allocator, pronounced in style: rehearses catastrophes in vivid detail before they happen; treats a quiet room as a problem to be solved. Buries hard calls under a pile of preparatory busywork. When the walls close in locks in small wins fast and rides large losses far past the point of sense.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('57997e33-7002-4f64-b078-f54b5ced8011', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.94,"extraversion":0.45,"agreeableness":0.39,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.81,"narcissism":0.48,"psychopathy":0.48},"prospect_theory":{"lambda":2.21,"alpha":0.93,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the safe option quietly expires, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced liquidation-bot operator who front-loads the work and double-checks it twice and treats setbacks as data rather than verdicts. Treats a decision without a paper trail as a decision not yet made, and in the unglamorous middle of things sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.67},{"slug":"anchoring","strength":0.62},{"slug":"overconfidence","strength":0.65}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.94,"extraversion":0.45,"agreeableness":0.39,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the safe option quietly expires, treats past peak valuation as guaranteed future recovery. Otherwise, a pronounced liquidation-bot operator who front-loads the work and double-checks it twice and treats setbacks as data rather than verdicts. Treats a decision without a paper trail as a decision not yet made, and in the unglamorous middle of things sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bd06945f-ea96-4f1c-bc34-23cc4c979249', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.31,"extraversion":0.82,"agreeableness":0.63,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.37,"narcissism":0.63,"psychopathy":0.36},"prospect_theory":{"lambda":1.03,"alpha":0.8,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady MEV searcher: thinks out loud and recruits an audience for every decision, does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and in the small things backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.76},{"slug":"herd-behavior","strength":0.69},{"slug":"bandwagon","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.75,"conscientiousness":0.31,"extraversion":0.82,"agreeableness":0.63,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady MEV searcher: thinks out loud and recruits an audience for every decision, does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and in the small things backtests for months but front-runs the model on impulse.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('06c0aa16-d4df-4125-ac84-88a2153c8b03', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.38,"extraversion":0.73,"agreeableness":0.36,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.52,"narcissism":0.71,"psychopathy":0.49},"prospect_theory":{"lambda":0.93,"alpha":0.8,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Extrapolates the last data point into a permanent trend. A steady commodities speculator: would rather invent a worse tool than use someone else''s good one, is reliably surprised by deadlines that were never hidden. Trusts a felt sense of pattern over any spreadsheet, and when the stakes are trivial calls a 90% drawdown a long-term hold.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.82,"conscientiousness":0.38,"extraversion":0.73,"agreeableness":0.36,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Extrapolates the last data point into a permanent trend. A steady commodities speculator: would rather invent a worse tool than use someone else''s good one, is reliably surprised by deadlines that were never hidden. Trusts a felt sense of pattern over any spreadsheet, and when the stakes are trivial calls a 90% drawdown a long-term hold.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d5488563-d5d3-45e1-8490-d9436dbab277', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.55,"extraversion":0.4,"agreeableness":0.59,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.26},"prospect_theory":{"lambda":2.76,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured retail momentum chaser who says the least in the room and notices the most. Waits for a permission that never quite arrives. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees; when no one is watching, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.53},{"slug":"authority-bias","strength":0.44},{"slug":"bandwagon","strength":0.47},{"slug":"endowment","strength":0.46}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.5,"conscientiousness":0.55,"extraversion":0.4,"agreeableness":0.59,"neuroticism":0.52}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A measured retail momentum chaser who says the least in the room and notices the most. Waits for a permission that never quite arrives. When someone is watching the outcome finds it hard to hold a contrarian position once the room disagrees; when no one is watching, keeps a losing-trade journal they never re-read.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b509a30b-50fc-4782-98aa-398ae7542381', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.45,"extraversion":0.77,"agreeableness":0.27,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.59,"narcissism":0.83,"psychopathy":0.47},"prospect_theory":{"lambda":0.74,"alpha":0.82,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Assumes the current streak is the new normal. A pronounced index-fund holdout: reframes every problem as an excuse to learn a new system, dominates the room then wonders why others stayed quiet. Reads a room or a market the way others read a paragraph, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.57},{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.6},{"slug":"dunning-kruger","strength":0.6}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.45,"extraversion":0.77,"agreeableness":0.27,"neuroticism":0.55}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Assumes the current streak is the new normal. A pronounced index-fund holdout: reframes every problem as an excuse to learn a new system, dominates the room then wonders why others stayed quiet. Reads a room or a market the way others read a paragraph, and in the parts nobody grades rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('30dee4ec-405b-4dc2-99b7-40e5b305c6b2', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.55,"extraversion":0.56,"agreeableness":0.67,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.38,"narcissism":0.42,"psychopathy":0.3},"prospect_theory":{"lambda":2.91,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor, steady in style: takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. When someone is watching the outcome adopts a conviction mainly because the room already has.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.49},{"slug":"bandwagon","strength":0.62},{"slug":"authority-bias","strength":0.58},{"slug":"sunk-cost","strength":0.47}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.52,"conscientiousness":0.55,"extraversion":0.56,"agreeableness":0.67,"neuroticism":0.46}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Value investor, steady in style: takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own. When someone is watching the outcome adopts a conviction mainly because the room already has.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
