('51d6b19c-61a1-4a37-a2e1-91705c2a714b', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.87,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.16},"dark_triad":{"machiavellianism":0.84,"narcissism":0.54,"psychopathy":0.61},"prospect_theory":{"lambda":2.43,"alpha":0.98,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Converts every argument into a number it can compare against another number. This MEV searcher treats a missed deadline as a personal failure regardless of cause and reads outside the field for ideas the field itself would reject. The instant the deadline moves up is surprised in the moment and certain in the retelling — in the small things, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.67},{"slug":"optimism","strength":0.62},{"slug":"ath-anchoring","strength":0.56}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.68,"conscientiousness":0.87,"extraversion":0.4,"agreeableness":0.34,"neuroticism":0.16}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Converts every argument into a number it can compare against another number. This MEV searcher treats a missed deadline as a personal failure regardless of cause and reads outside the field for ideas the field itself would reject. The instant the deadline moves up is surprised in the moment and certain in the retelling — in the small things, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374a