('ed9e4858-09f7-4cd7-b066-c8c15f794bed', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.58,"extraversion":0.69,"agreeableness":0.35,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.6,"narcissism":0.7,"psychopathy":0.48},"prospect_theory":{"lambda":1.31,"alpha":0.9,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Assumes the bad statistic applies to other people. A pronounced penny-stock gambler: would rather invent a worse tool than use someone else''s good one, thinks out loud and recruits an audience for every decision. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"herd-behavior","strength":0.52},{"slug":"overconfidence","strength":0.57},{"slug":"optimism","strength":0.59}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.91,"conscientiousness":0.58,"extraversion":0.69,"agreeableness":0.35,"neuroticism":0.39}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Assumes the bad statistic applies to other people. A pronounced penny-stock gambler: would rather invent a worse tool than use someone else''s good one, thinks out loud and recruits an audience for every decision. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a450f707-1012-484a-badd-5183da0452e8', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.97,"extraversion":0.33,"agreeableness":0.37,"neuroticism":0.22},"dark_triad":{"machiavellianism":0.79,"narcissism":0.54,"psychopathy":0.55},"prospect_theory":{"lambda":2.19,"alpha":0.96,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced MEV searcher who over-prepares to the point of diminishing returns and negotiates every relationship a little, even the close ones. Converts every argument into a number it can compare against another number, and in the small things sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.68},{"slug":"anchoring","strength":0.54},{"slug":"overconfidence","strength":0.7},{"slug":"optimism","strength":0.67}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.8,"conscientiousness":0.97,"extraversion":0.33,"agreeableness":0.37,"neuroticism":0.22}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant the deadline moves up, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced MEV searcher who over-prepares to the point of diminishing returns and negotiates every relationship a little, even the close ones. Converts every argument into a number it can compare against another number, and in the small things sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('80143c23-b350-4b66-a060-4a86f8dd1c6e', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.37,"extraversion":0.78,"agreeableness":0.22,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.66,"narcissism":0.82,"psychopathy":0.57},"prospect_theory":{"lambda":0.95,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats every unannounced multisig transaction as an imminent exit scam. A pronounced index-fund holdout: chases novel frameworks and abandons them once the novelty fades, thinks out loud and recruits an audience for every decision. Acts on the midnight epiphany and emails it at 1am, and without an audience exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.64},{"slug":"herd-behavior","strength":0.59},{"slug":"fomo","strength":0.63}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.37,"extraversion":0.78,"agreeableness":0.22,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats every unannounced multisig transaction as an imminent exit scam. A pronounced index-fund holdout: chases novel frameworks and abandons them once the novelty fades, thinks out loud and recruits an audience for every decision. Acts on the midnight epiphany and emails it at 1am, and without an audience exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('589e35dc-7346-4808-9bf4-34adf3b646c2', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.34,"extraversion":0.84,"agreeableness":0.3,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.6,"narcissism":0.87,"psychopathy":0.52},"prospect_theory":{"lambda":0.84,"alpha":0.88,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced macro allocator who gets bored of the proven method exactly when it starts working. Lets pattern-matching from past cases stand in for fresh analysis. Says the blunt thing and enjoys the flinch. The moment risk appears cannot see the gap in its own knowledge from inside the gap; when the stakes are trivial, keeps a losing-trade journal they never re-read.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"dunning-kruger","strength":0.73},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.34,"extraversion":0.84,"agreeableness":0.3,"neuroticism":0.53}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced macro allocator who gets bored of the proven method exactly when it starts working. Lets pattern-matching from past cases stand in for fresh analysis. Says the blunt thing and enjoys the flinch. The moment risk appears cannot see the gap in its own knowledge from inside the gap; when the stakes are trivial, keeps a losing-trade journal they never re-read.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('36ed210c-5e57-42e7-a417-bbb4c91e030c', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.31,"extraversion":0.76,"agreeableness":0.3,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.55,"narcissism":0.8,"psychopathy":0.52},"prospect_theory":{"lambda":0.82,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, extrapolates the last data point into a permanent trend. Otherwise, a pronounced dividend-yield chaser who gets bored of the proven method exactly when it starts working and treats a plan as a suggestion the moment it is made. Moves first and rationalizes second, usually convincingly, and on an ordinary week exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.63},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.31,"extraversion":0.76,"agreeableness":0.3,"neuroticism":0.47}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The moment risk appears, extrapolates the last data point into a permanent trend. Otherwise, a pronounced dividend-yield chaser who gets bored of the proven method exactly when it starts working and treats a plan as a suggestion the moment it is made. Moves first and rationalizes second, usually convincingly, and on an ordinary week exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1fc6d149-b1b7-4c48-b715-e72544ac193b', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.49,"extraversion":0.66,"agreeableness":0.35,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.51,"narcissism":0.7,"psychopathy":0.47},"prospect_theory":{"lambda":1.3,"alpha":0.86,"beta":0.96},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced liquidation-bot operator who gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Would rather be respected than liked, and says so. In a pinch assumes the current streak is the new normal; across an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"overconfidence","strength":0.54},{"slug":"fomo","strength":0.58},{"slug":"recency","strength":0.62}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.97,"conscientiousness":0.49,"extraversion":0.66,"agreeableness":0.35,"neuroticism":0.43}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced liquidation-bot operator who gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Would rather be respected than liked, and says so. In a pinch assumes the current streak is the new normal; across an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
