('94b46089-85a1-4ab6-8ea3-0fe49fab6287', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.38,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.58,"narcissism":0.62,"psychopathy":0.43},"prospect_theory":{"lambda":1.22,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Discounts the older pattern in favor of whatever just happened. A pronounced options seller: treats established procedure as a first draft to be rewritten, says the blunt thing and enjoys the flinch. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"recency","strength":0.64}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.59,"extraversion":0.6,"agreeableness":0.38,"neuroticism":0.39}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discounts the older pattern in favor of whatever just happened. A pronounced options seller: treats established procedure as a first draft to be rewritten, says the blunt thing and enjoys the flinch. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches backtests for months but front-runs the model on impulse.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3520fe9d-6a1a-4419-9140-282511687e10', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.45,"extraversion":0.78,"agreeableness":0.51,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.43,"narcissism":0.6,"psychopathy":0.27},"prospect_theory":{"lambda":1.18,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader, steady in style: fills silence reflexively, even when nobody asked it to; notices the one thing that could go wrong before the nine that could go right. Commits before the doubt has time to organize itself. When the number turns red jumps into whatever everyone else already seems to be winning at.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.65},{"slug":"fomo","strength":0.67}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.45,"extraversion":0.78,"agreeableness":0.51,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Discretionary swing trader, steady in style: fills silence reflexively, even when nobody asked it to; notices the one thing that could go wrong before the nine that could go right. Commits before the doubt has time to organize itself. When the number turns red jumps into whatever everyone else already seems to be winning at.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('110e931d-1034-41f5-b26f-4bb0e108a753', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.39,"extraversion":0.67,"agreeableness":0.17,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.7,"narcissism":0.75,"psychopathy":0.64},"prospect_theory":{"lambda":0.75,"alpha":0.82,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Reads a room or a market the way others read a paragraph. This airdrop farmer chases novel frameworks and abandons them once the novelty fades and dominates the room then wonders why others stayed quiet. Once the exit narrows to one door extrapolates the last data point into a permanent trend — in the pattern nobody else tracks, averages down on a name three times in a week.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.59},{"slug":"recency","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.39,"extraversion":0.67,"agreeableness":0.17,"neuroticism":0.59}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Reads a room or a market the way others read a paragraph. This airdrop farmer chases novel frameworks and abandons them once the novelty fades and dominates the room then wonders why others stayed quiet. Once the exit narrows to one door extrapolates the last data point into a permanent trend — in the pattern nobody else tracks, averages down on a name three times in a week.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5a16b7ed-b2d2-46e9-9fb3-38f400fa84f6', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.53,"extraversion":0.74,"agreeableness":0.25,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.62,"narcissism":0.87,"psychopathy":0.53},"prospect_theory":{"lambda":1.26,"alpha":0.91,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced macro allocator who gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Narrates the plan to whoever is nearby before committing to it. The moment risk appears holds their estimates with a certainty the track record does not support; day to day, sets alerts for a coin they already checked a minute ago.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"herd-behavior","strength":0.59},{"slug":"bandwagon","strength":0.58},{"slug":"overconfidence","strength":0.64}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.97,"conscientiousness":0.53,"extraversion":0.74,"agreeableness":0.25,"neuroticism":0.48}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced macro allocator who gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Narrates the plan to whoever is nearby before committing to it. The moment risk appears holds their estimates with a certainty the track record does not support; day to day, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
