('5b9322bf-ac2d-41c0-8067-660738e2c7c0', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.61,"extraversion":0.5,"agreeableness":0.75,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.42,"narcissism":0.4,"psychopathy":0.28},"prospect_theory":{"lambda":2.75,"alpha":0.86,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Outsources conviction to whoever spoke last with authority. This discretionary swing trader defaults to trust and gives the benefit of the doubt too freely and chases novel frameworks and abandons them once the novelty fades. When the walls close in finds it easier to believe something once it stops being a minority view — when no one is watching, keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.52},{"slug":"bandwagon","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.63,"conscientiousness":0.61,"extraversion":0.5,"agreeableness":0.75,"neuroticism":0.51}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Outsources conviction to whoever spoke last with authority. This discretionary swing trader defaults to trust and gives the benefit of the doubt too freely and chases novel frameworks and abandons them once the novelty fades. When the walls close in finds it easier to believe something once it stops being a minority view — when no one is watching, keeps a losing-trade journal they never re-read.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
