('31dedacd-b134-4f2d-a914-d1991ef90e41', 1, '{"big_five":{"openness":0.43,"conscientiousness":0.43,"extraversion":0.67,"agreeableness":0.54,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.38,"narcissism":0.42,"psychopathy":0.31},"prospect_theory":{"lambda":3.49,"alpha":0.75,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced prop-desk scalper who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Dominates the room then wonders why others stayed quiet. The instant the deadline moves up jumps into whatever everyone else already seems to be winning at; when the pressure is off, sizes every position at exactly 2% risk.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"availability","strength":0.66},{"slug":"loss-aversion","strength":0.65},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.43,"conscientiousness":0.43,"extraversion":0.67,"agreeableness":0.54,"neuroticism":0.87}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A pronounced prop-desk scalper who rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Dominates the room then wonders why others stayed quiet. The instant the deadline moves up jumps into whatever everyone else already seems to be winning at; when the pressure is off, sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
