('e52205f5-d82f-4ada-8203-b96ff8d2b337', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.4,"extraversion":0.89,"agreeableness":0.41,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.49,"narcissism":0.81,"psychopathy":0.43},"prospect_theory":{"lambda":0.99,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, assumes the current streak is the new normal. Otherwise, a pronounced airdrop farmer who gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. Knows the answer before it can explain the question, and when the pressure is off sizes every position at exactly 2% risk.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"recency","strength":0.7}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.4,"extraversion":0.89,"agreeableness":0.41,"neuroticism":0.6}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When someone is watching the outcome, assumes the current streak is the new normal. Otherwise, a pronounced airdrop farmer who gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. Knows the answer before it can explain the question, and when the pressure is off sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
