('b8e3f818-5a6c-4a4b-b539-0dc719022168', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.15,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.72,"narcissism":0.83,"psychopathy":0.59},"prospect_theory":{"lambda":0.92,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, treats testnet participation as a binding contract for mainnet equity. Otherwise, a pronounced volatility arbitrageur who negotiates every relationship a little, even the close ones and reads outside the field for ideas the field itself would reject. Reads a room or a market the way others read a paragraph, and as a rule apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.6},{"slug":"overconfidence","strength":0.57},{"slug":"fomo","strength":0.59}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","assertive","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.79,"conscientiousness":0.44,"extraversion":0.72,"agreeableness":0.15,"neuroticism":0.54}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','assertive','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, treats testnet participation as a binding contract for mainnet equity. Otherwise, a pronounced volatility arbitrageur who negotiates every relationship a little, even the close ones and reads outside the field for ideas the field itself would reject. Reads a room or a market the way others read a paragraph, and as a rule apes the launch before the contract is verified.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c3