('8dbf9aa5-1cfc-4348-bc1b-63e0c71cf342', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.5,"extraversion":0.5,"agreeableness":0.71,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.41,"narcissism":0.27,"psychopathy":0.28},"prospect_theory":{"lambda":3.46,"alpha":0.74,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced perps degen who notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible judges likelihood by how easily an example comes to mind, not by the base rate; in the unglamorous middle of things, exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENFJ","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.62},{"slug":"availability","strength":0.72},{"slug":"diamond-hands-identity","strength":0.68},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.5,"extraversion":0.5,"agreeableness":0.71,"neuroticism":0.87}'::jsonb, 'ENFJ', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A pronounced perps degen who notices the one thing that could go wrong before the nine that could go right. Finds one more piece of information to gather before acting. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible judges likelihood by how easily an example comes to mind, not by the base rate; in the unglamorous middle of things, exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac