('c9efcfad-6217-4b40-a6df-39ba6f5fbe5e', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.94,"extraversion":0.32,"agreeableness":0.32,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.82,"narcissism":0.58,"psychopathy":0.56},"prospect_theory":{"lambda":2.24,"alpha":0.96,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Once the exit narrows to one door, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced airdrop farmer who plans in exhaustive detail and resents any deviation and sleeps fine the night before the big call. Wants the base rate before the anecdote, and day to day talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.73},{"slug":"optimism","strength":0.64},{"slug":"ath-anchoring","strength":0.64},{"slug":"anchoring","strength":0.61}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.94,"extraversion":0.32,"agreeableness":0.32,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced airdrop farmer who plans in exhaustive detail and resents any deviation and sleeps fine the night before the big call. Wants the base rate before the anecdote, and day to day talks in win rate and never mentions size.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
