('6555d3f5-3c30-417b-a9a4-08c12d181e1e', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.53,"extraversion":0.51,"agreeableness":0.68,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.36,"narcissism":0.42,"psychopathy":0.29},"prospect_theory":{"lambda":2.95,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady crypto day-trader who takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right, and when the stakes are trivial apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"authority-bias","strength":0.55},{"slug":"endowment","strength":0.56},{"slug":"bandwagon","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.53,"extraversion":0.51,"agreeableness":0.68,"neuroticism":0.56}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'When cornered, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady crypto day-trader who takes on other people''s problems as if they were their own. Needs the room''s approval more than it needs to be right, and when the stakes are trivial apes the launch before the contract is verified.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
