('4d532a1c-2bf3-44f1-84f3-2bb47293610b', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.29,"extraversion":0.76,"agreeableness":0.27,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.58,"narcissism":0.77,"psychopathy":0.57},"prospect_theory":{"lambda":0.99,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced zero-DTE options gambler who gets bored of the proven method exactly when it starts working. Knows the answer before it can explain the question. Needs repeated reassurance that a decision was the right one. When the safe option quietly expires extrapolates the last data point into a permanent trend; without an audience, trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.29,"extraversion":0.76,"agreeableness":0.27,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced zero-DTE options gambler who gets bored of the proven method exactly when it starts working. Knows the answer before it can explain the question. Needs repeated reassurance that a decision was the right one. When the safe option quietly expires extrapolates the last data point into a permanent trend; without an audience, trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
