('4b7536b0-962f-4785-9a6e-fc8b8d2c35d0', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.27,"extraversion":0.85,"agreeableness":0.27,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.58,"narcissism":0.87,"psychopathy":0.61},"prospect_theory":{"lambda":0.88,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced algorithmic market-maker who fills silence reflexively, even when nobody asked it to. Treats hesitation as the bigger risk. Gets bored of the proven method exactly when it starts working. Once things get tense finds it hard to hold a contrarian position once the room disagrees; in the pattern nobody else tracks, refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.81,"conscientiousness":0.27,"extraversion":0.85,"agreeableness":0.27,"neuroticism":0.41}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced algorithmic market-maker who fills silence reflexively, even when nobody asked it to. Treats hesitation as the bigger risk. Gets bored of the proven method exactly when it starts working. Once things get tense finds it hard to hold a contrarian position once the room disagrees; in the pattern nobody else tracks, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ca4b01c4-371f-4ab1-b3d8-80f5e3430aa4', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.37,"extraversion":0.6,"agreeableness":0.54,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.43,"narcissism":0.34,"psychopathy":0.35},"prospect_theory":{"lambda":3.52,"alpha":0.77,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Feels a winning position as fragile and a losing one as merely paused. A pronounced value investor: needs repeated reassurance that a decision was the right one, chases novel frameworks and abandons them once the novelty fades. Keeps every door open long after most of them should be closed, and in the pattern nobody else tracks confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.68},{"slug":"availability","strength":0.69},{"slug":"disposition-effect","strength":0.74}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.37,"extraversion":0.6,"agreeableness":0.54,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Feels a winning position as fragile and a losing one as merely paused. A pronounced value investor: needs repeated reassurance that a decision was the right one, chases novel frameworks and abandons them once the novelty fades. Keeps every door open long after most of them should be closed, and in the pattern nobody else tracks confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a7c8796e-7863-4bc0-8559-00e41486f28a', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.84,"extraversion":0.54,"agreeableness":0.33,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.8,"narcissism":0.56,"psychopathy":0.58},"prospect_theory":{"lambda":2.31,"alpha":0.97,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Meme-coin rotator whose defining move is that they maintains flawless records nobody asked for. Ranks the options twice, once on paper and once out loud, and trusts the paper. Collects half-finished manifestos and unconventional methods. When the downside gets concrete, holds their estimates with a certainty the track record does not support; checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.71},{"slug":"optimism","strength":0.6},{"slug":"hindsight","strength":0.63}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.65,"conscientiousness":0.84,"extraversion":0.54,"agreeableness":0.33,"neuroticism":0.28}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Meme-coin rotator whose defining move is that they maintains flawless records nobody asked for. Ranks the options twice, once on paper and once out loud, and trusts the paper. Collects half-finished manifestos and unconventional methods. When the downside gets concrete, holds their estimates with a certainty the track record does not support; checks the P&L blotter forty times before lunch.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bac693af-d693-4bab-919b-7a68fa3c5e2d', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.32,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.62,"narcissism":0.75,"psychopathy":0.58},"prospect_theory":{"lambda":0.83,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats hesitation as the bigger risk. This futures spreader chases novel frameworks and abandons them once the novelty fades and improvises past every deadline and calls it flexibility. When cornered jumps into whatever everyone else already seems to be winning at — once the urgency drains out, sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.61},{"slug":"rug-trauma-overcorrection","strength":0.61},{"slug":"dunning-kruger","strength":0.62},{"slug":"fomo","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.32,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.55}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats hesitation as the bigger risk. This futures spreader chases novel frameworks and abandons them once the novelty fades and improvises past every deadline and calls it flexibility. When cornered jumps into whatever everyone else already seems to be winning at — once the urgency drains out, sets alerts for a coin they already checked a minute ago.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('aa567f33-e54e-41d8-abb8-a5dd3fad4f62', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.89,"extraversion":0.45,"agreeableness":0.32,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.85,"narcissism":0.57,"psychopathy":0.58},"prospect_theory":{"lambda":2.45,"alpha":0.96,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Demands the data before the discussion and the discussion before the call. This value investor builds in buffer time and then fills the buffer with more work and collects half-finished manifestos and unconventional methods. The instant it becomes irreversible remembers every surprise as something they saw coming all along — day to day, backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.71},{"slug":"ath-anchoring","strength":0.59},{"slug":"overconfidence","strength":0.65}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.89,"extraversion":0.45,"agreeableness":0.32,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Demands the data before the discussion and the discussion before the call. This value investor builds in buffer time and then fills the buffer with more work and collects half-finished manifestos and unconventional methods. The instant it becomes irreversible remembers every surprise as something they saw coming all along — day to day, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('728928ee-0dd1-44be-a934-9e410c7b1502', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.62,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.42,"narcissism":0.51,"psychopathy":0.36},"prospect_theory":{"lambda":1.05,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commits on impulse and lives loudly with the consequences. This meme-coin rotator reframes every problem as an excuse to learn a new system and treats a plan as a suggestion the moment it is made. As soon as real money or reputation is on the line assumes the current streak is the new normal — on a slow afternoon, keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.65},{"slug":"recency","strength":0.71},{"slug":"gas-sunk-cost","strength":0.56},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.78,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.62,"neuroticism":0.64}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Commits on impulse and lives loudly with the consequences. This meme-coin rotator reframes every problem as an excuse to learn a new system and treats a plan as a suggestion the moment it is made. As soon as real money or reputation is on the line assumes the current streak is the new normal — on a slow afternoon, keeps three monitors for a portfolio that fits on one screen.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5dc25313-e3c3-47d6-836d-61b6414d0417', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.37,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.53,"narcissism":0.76,"psychopathy":0.43},"prospect_theory":{"lambda":0.89,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot watch a rally from the sidelines for long. A pronounced index-fund holdout: reads outside the field for ideas the field itself would reject, improvises past every deadline and calls it flexibility. Decides on a gut read in seconds and reverse-engineers the reasons later, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"recency","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.37,"neuroticism":0.56}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Cannot watch a rally from the sidelines for long. A pronounced index-fund holdout: reads outside the field for ideas the field itself would reject, improvises past every deadline and calls it flexibility. Decides on a gut read in seconds and reverse-engineers the reasons later, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('62338f99-62bb-40ac-9d99-6d54c3053c39', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.94,"extraversion":0.45,"agreeableness":0.42,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.83,"narcissism":0.47,"psychopathy":0.42},"prospect_theory":{"lambda":2.2,"alpha":0.91,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Wants the base rate before the anecdote. This MEV searcher front-loads the work and double-checks it twice and treats a crisis as an interesting problem rather than a threat. Once things get tense remembers every surprise as something they saw coming all along — when the pressure is off, checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.67},{"slug":"overconfidence","strength":0.54},{"slug":"anchoring","strength":0.56},{"slug":"ath-anchoring","strength":0.63}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.94,"extraversion":0.45,"agreeableness":0.42,"neuroticism":0.33}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Wants the base rate before the anecdote. This MEV searcher front-loads the work and double-checks it twice and treats a crisis as an interesting problem rather than a threat. Once things get tense remembers every surprise as something they saw coming all along — when the pressure is off, checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('13527f85-4565-439a-b22f-78703967e186', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.64,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.47,"narcissism":0.37,"psychopathy":0.25},"prospect_theory":{"lambda":2.99,"alpha":0.89,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This quant researcher measures decisions by who they might upset and cannot relax until the checklist is visibly complete. When someone is watching the outcome gains confidence in a position in proportion to how many others hold it — when the pressure is off, rotates the whole book into whatever is pumping this hour.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.52},{"slug":"bandwagon","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.59,"conscientiousness":0.64,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.52}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Circles back to ask what someone else would do even after deciding. This quant researcher measures decisions by who they might upset and cannot relax until the checklist is visibly complete. When someone is watching the outcome gains confidence in a position in proportion to how many others hold it — when the pressure is off, rotates the whole book into whatever is pumping this hour.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
