('1b8a38c4-e70e-4e78-9ebc-4c8b87311b90', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.39,"extraversion":0.86,"agreeableness":0.24,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.67,"narcissism":0.92,"psychopathy":0.55},"prospect_theory":{"lambda":0.74,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats overthinking as its own kind of error. This algorithmic market-maker would rather invent a worse tool than use someone else''s good one and dominates the room then wonders why others stayed quiet. The moment risk appears extrapolates the last data point into a permanent trend — in the unglamorous middle of things, exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.68},{"slug":"fomo","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.39,"extraversion":0.86,"agreeableness":0.24,"neuroticism":0.47}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats overthinking as its own kind of error. This algorithmic market-maker would rather invent a worse tool than use someone else''s good one and dominates the room then wonders why others stayed quiet. The moment risk appears extrapolates the last data point into a permanent trend — in the unglamorous middle of things, exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c58b250d-193f-4221-a833-a0cd6e1d18d8', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.35,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.51,"narcissism":0.85,"psychopathy":0.42},"prospect_theory":{"lambda":0.97,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced volatility arbitrageur: would rather invent a worse tool than use someone else''s good one, fills silence reflexively, even when nobody asked it to. Treats overthinking as its own kind of error, and in the parts nobody grades confuses a bull market for a trading edge.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"fomo","strength":0.74},{"slug":"dunning-kruger","strength":0.61},{"slug":"bandwagon","strength":0.68}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.39,"extraversion":0.85,"agreeableness":0.35,"neuroticism":0.58}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced volatility arbitrageur: would rather invent a worse tool than use someone else''s good one, fills silence reflexively, even when nobody asked it to. Treats overthinking as its own kind of error, and in the parts nobody grades confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e74cc382-c536-417e-8a1a-836fe14bf0d1', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.25,"extraversion":0.87,"agreeableness":0.28,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.61,"narcissism":0.86,"psychopathy":0.59},"prospect_theory":{"lambda":0.97,"alpha":0.83,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced crypto day-trader who fills silence reflexively, even when nobody asked it to and starts strong and lets follow-through evaporate. Prefers a fast wrong answer to a slow right one, and without an audience sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"recency","strength":0.68},{"slug":"bandwagon","strength":0.63},{"slug":"fomo","strength":0.64}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.25,"extraversion":0.87,"agreeableness":0.28,"neuroticism":0.54}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced crypto day-trader who fills silence reflexively, even when nobody asked it to and starts strong and lets follow-through evaporate. Prefers a fast wrong answer to a slow right one, and without an audience sets alerts for a coin they already checked a minute ago.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2b4254c0-df55-4d4f-a8a6-55534b22c96c', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.47,"extraversion":0.65,"agreeableness":0.54,"neuroticism":0.83},"dark_triad":{"machiavellianism":0.4,"narcissism":0.43,"psychopathy":0.28},"prospect_theory":{"lambda":3.26,"alpha":0.76,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Once things get tense, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady quant researcher who hedges every commitment against an imagined worst case and thinks out loud and recruits an audience for every decision. Lets the deadline make the decision by default, and once the urgency drains out screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.68},{"slug":"fomo","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.47,"extraversion":0.65,"agreeableness":0.54,"neuroticism":0.83}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Once things get tense, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady quant researcher who hedges every commitment against an imagined worst case and thinks out loud and recruits an audience for every decision. Lets the deadline make the decision by default, and once the urgency drains out screenshots the winners and never the losers.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9905eaa8-ff43-431d-9f1f-f0081250ae93', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.62,"extraversion":0.41,"agreeableness":0.59,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.44,"narcissism":0.36,"psychopathy":0.25},"prospect_theory":{"lambda":3.05,"alpha":0.94,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prices every token against its all-time high, viewing current levels as an automatic discount. A measured prop-desk scalper: maintains flawless records nobody asked for. Needs the room''s approval more than it needs to be right, and in the parts nobody grades apes the launch before the contract is verified.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.53},{"slug":"authority-bias","strength":0.51},{"slug":"endowment","strength":0.5},{"slug":"hindsight","strength":0.45}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.47,"conscientiousness":0.62,"extraversion":0.41,"agreeableness":0.59,"neuroticism":0.49}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Prices every token against its all-time high, viewing current levels as an automatic discount. A measured prop-desk scalper: maintains flawless records nobody asked for. Needs the room''s approval more than it needs to be right, and in the parts nobody grades apes the launch before the contract is verified.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('21e66954-107e-4fe0-9f9d-62a6b4817850', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.31,"extraversion":0.65,"agreeableness":0.29,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.62,"narcissism":0.69,"psychopathy":0.58},"prospect_theory":{"lambda":0.75,"alpha":0.81,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Assumes the current streak is the new normal. A steady algorithmic market-maker: would rather invent a worse tool than use someone else''s good one, recharges by being around people, not away from them. Prefers a fast wrong answer to a slow right one, and on a slow afternoon holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"dunning-kruger","strength":0.61},{"slug":"airdrop-entitlement","strength":0.59},{"slug":"gas-sunk-cost","strength":0.64}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.81,"conscientiousness":0.31,"extraversion":0.65,"agreeableness":0.29,"neuroticism":0.6}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Assumes the current streak is the new normal. A steady algorithmic market-maker: would rather invent a worse tool than use someone else''s good one, recharges by being around people, not away from them. Prefers a fast wrong answer to a slow right one, and on a slow afternoon holds a bag from 2021 out of pure spite.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('35c20512-b225-4bbb-a04c-e4c4a64841f6', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.47,"extraversion":0.67,"agreeableness":0.61,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.43,"narcissism":0.41,"psychopathy":0.28},"prospect_theory":{"lambda":3.38,"alpha":0.77,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the number turns red, treats selling any portion of a position as a personal betrayal. Otherwise, a steady quant researcher who carries yesterday''s stress into today''s unrelated decision and narrates the plan to whoever is nearby before committing to it. Lets the deadline make the decision by default, and as a rule backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.6},{"slug":"loss-aversion","strength":0.65},{"slug":"diamond-hands-identity","strength":0.68},{"slug":"fomo","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.58,"conscientiousness":0.47,"extraversion":0.67,"agreeableness":0.61,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'When the number turns red, treats selling any portion of a position as a personal betrayal. Otherwise, a steady quant researcher who carries yesterday''s stress into today''s unrelated decision and narrates the plan to whoever is nearby before committing to it. Lets the deadline make the decision by default, and as a rule backtests for months but front-runs the model on impulse.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('851ffc07-50f3-4b91-98f5-c7a923f6d8fb', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.82,"extraversion":0.54,"agreeableness":0.3,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.85,"narcissism":0.64,"psychopathy":0.6},"prospect_theory":{"lambda":2.17,"alpha":0.9,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A steady zero-DTE options gambler who front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Optimizes for winning over being liked. When there is no clean exit holds their estimates with a certainty the track record does not support; left to their own devices, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.54},{"slug":"optimism","strength":0.62},{"slug":"overconfidence","strength":0.69}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.81,"conscientiousness":0.82,"extraversion":0.54,"agreeableness":0.3,"neuroticism":0.27}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady zero-DTE options gambler who front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Optimizes for winning over being liked. When there is no clean exit holds their estimates with a certainty the track record does not support; left to their own devices, treats a green week as proof of skill and a red one as proof of bad luck.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ed6cd0ab-d411-4a8c-a729-8496184bc943', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.32,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":0.99,"alpha":0.85,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Pairs trader whose defining move is that they draws energy from the crowd and wilts when working alone. Commits before the doubt has time to organize itself. Confuses motion with progress. When the stakes rise, finds it easier to believe something once it stops being a minority view; sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.65},{"slug":"bandwagon","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.69,"conscientiousness":0.37,"extraversion":0.8,"agreeableness":0.76,"neuroticism":0.61}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Pairs trader whose defining move is that they draws energy from the crowd and wilts when working alone. Commits before the doubt has time to organize itself. Confuses motion with progress. When the stakes rise, finds it easier to believe something once it stops being a minority view; sets alerts for a coin they already checked a minute ago.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('41ddd1b1-8068-4095-a38f-4d3291977d3d', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.31,"extraversion":0.53,"agreeableness":0.54,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.44,"narcissism":0.36,"psychopathy":0.4},"prospect_theory":{"lambda":3.55,"alpha":0.83,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Buries hard calls under a pile of preparatory busywork. Treats a plan as a suggestion the moment it is made. When the safe option quietly expires, discounts the older pattern in favor of whatever just happened; keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.6},{"slug":"framing","strength":0.63},{"slug":"ostrich-effect","strength":0.68},{"slug":"recency","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.65,"conscientiousness":0.31,"extraversion":0.53,"agreeableness":0.54,"neuroticism":0.76}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Buries hard calls under a pile of preparatory busywork. Treats a plan as a suggestion the moment it is made. When the safe option quietly expires, discounts the older pattern in favor of whatever just happened; keeps a losing-trade journal they never re-read.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4d558082-efb2-4a8a-9bc0-72479a4a3d16', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.6,"extraversion":0.52,"agreeableness":0.59,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.46,"narcissism":0.4,"psychopathy":0.26},"prospect_theory":{"lambda":2.87,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, extrapolates the last data point into a permanent trend. Otherwise, a measured meme-coin rotator who reads a single setback as evidence of collapse. Feels the weight of a decision lighten the moment someone else co-signs it, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.56},{"slug":"recency","strength":0.6},{"slug":"availability","strength":0.55},{"slug":"ostrich-effect","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.6,"extraversion":0.52,"agreeableness":0.59,"neuroticism":0.64}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Once things get tense, extrapolates the last data point into a permanent trend. Otherwise, a measured meme-coin rotator who reads a single setback as evidence of collapse. Feels the weight of a decision lighten the moment someone else co-signs it, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9c1542eb-572a-4c57-9f3b-ddd3492fecc1', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.41,"extraversion":0.51,"agreeableness":0.55,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.45,"narcissism":0.31,"psychopathy":0.36},"prospect_theory":{"lambda":3.26,"alpha":0.83,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Macro allocator, steady in style: hedges every commitment against an imagined worst case. Keeps every door open long after most of them should be closed. When someone is watching the outcome weights whatever happened most recently and vividly as if it were typical.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.62},{"slug":"diamond-hands-identity","strength":0.56},{"slug":"availability","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.41,"extraversion":0.51,"agreeableness":0.55,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Macro allocator, steady in style: hedges every commitment against an imagined worst case. Keeps every door open long after most of them should be closed. When someone is watching the outcome weights whatever happened most recently and vividly as if it were typical.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
