('ee4ff3a6-45e4-4e91-9a36-7eb476ccc671', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.37,"extraversion":0.66,"agreeableness":0.37,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.53,"narcissism":0.69,"psychopathy":0.42},"prospect_theory":{"lambda":0.8,"alpha":0.9,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced commodities speculator who gets bored of the proven method exactly when it starts working. Treats overthinking as its own kind of error. Starts strong and lets follow-through evaporate. Once the exit narrows to one door treats being left out of a move as its own kind of loss; when the stakes are trivial, backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.54},{"slug":"fomo","strength":0.57}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.37,"extraversion":0.66,"agreeableness":0.37,"neuroticism":0.58}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced commodities speculator who gets bored of the proven method exactly when it starts working. Treats overthinking as its own kind of error. Starts strong and lets follow-through evaporate. Once the exit narrows to one door treats being left out of a move as its own kind of loss; when the stakes are trivial, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('412f3e46-c796-42d2-be79-e6f122adbba6', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.96,"extraversion":0.41,"agreeableness":0.3,"neuroticism":0.18},"dark_triad":{"machiavellianism":0.83,"narcissism":0.58,"psychopathy":0.61},"prospect_theory":{"lambda":2.33,"alpha":0.96,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced onchain copy-trader who builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Would rather be respected than liked, and says so. The instant it becomes irreversible holds their estimates with a certainty the track record does not support; in the parts nobody grades, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"overconfidence","strength":0.72},{"slug":"optimism","strength":0.66}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.81,"conscientiousness":0.96,"extraversion":0.41,"agreeableness":0.3,"neuroticism":0.18}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced onchain copy-trader who builds in buffer time and then fills the buffer with more work. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Would rather be respected than liked, and says so. The instant it becomes irreversible holds their estimates with a certainty the track record does not support; in the parts nobody grades, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-