('603c6c39-b2b9-4fa0-99f1-33b62be0b5fa', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.43,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.54,"narcissism":0.81,"psychopathy":0.42},"prospect_theory":{"lambda":0.8,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, cannot watch a rally from the sidelines for long. Otherwise, a pronounced DeFi yield farmer who would rather invent a worse tool than use someone else''s good one and draws energy from the crowd and wilts when working alone. Treats overthinking as its own kind of error, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.6},{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.65},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.43,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.61}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When cornered, cannot watch a rally from the sidelines for long. Otherwise, a pronounced DeFi yield farmer who would rather invent a worse tool than use someone else''s good one and draws energy from the crowd and wilts when working alone. Treats overthinking as its own kind of error, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ae761cc8-11df-450b-a1be-07a017339edd', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.6,"extraversion":0.5,"agreeableness":0.73,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.37,"narcissism":0.42,"psychopathy":0.32},"prospect_theory":{"lambda":2.95,"alpha":0.94,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels the weight of a decision lighten the moment someone else co-signs it. This volatility arbitrageur measures decisions by who they might upset. Once the exit narrows to one door would not buy back what it already owns at the price it would sell it for — in the small things, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.63},{"slug":"bandwagon","strength":0.53},{"slug":"sunk-cost","strength":0.58},{"slug":"herd-behavior","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.52,"conscientiousness":0.6,"extraversion":0.5,"agreeableness":0.73,"neuroticism":0.52}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Feels the weight of a decision lighten the moment someone else co-signs it. This volatility arbitrageur measures decisions by who they might upset. Once the exit narrows to one door would not buy back what it already owns at the price it would sell it for — in the small things, treats a green week as proof of skill and a red one as proof of bad luck.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('67a0ec39-87a6-4a99-8225-f4ef29eee3f9', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.47,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.43,"narcissism":0.38,"psychopathy":0.36},"prospect_theory":{"lambda":3.49,"alpha":0.79,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Bonding-curve sniper, steady in style: hedges every commitment against an imagined worst case; confuses motion with progress. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires cannot watch a rally from the sidelines for long.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.56},{"slug":"fomo","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.47,"neuroticism":0.73}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper, steady in style: hedges every commitment against an imagined worst case; confuses motion with progress. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires cannot watch a rally from the sidelines for long.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bf86b44f-5633-4b4a-a6f8-65fcf312188d', 1, '{"big_five":{"openness":0.68,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.78,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.31,"narcissism":0.71,"psychopathy":0.39},"prospect_theory":{"lambda":0.97,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Decides in the time it takes to say the decision out loud. This onchain copy-trader fills silence reflexively, even when nobody asked it to and absorbs conflict to keep the peace, often at their own cost. Once things get tense takes the crowd''s confidence as a substitute for its own analysis — when the pressure is off, sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.84},{"slug":"dunning-kruger","strength":0.76},{"slug":"sunk-cost","strength":0.71},{"slug":"fomo","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.68,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.78,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Decides in the time it takes to say the decision out loud. This onchain copy-trader fills silence reflexively, even when nobody asked it to and absorbs conflict to keep the peace, often at their own cost. Once things get tense takes the crowd''s confidence as a substitute for its own analysis — when the pressure is off, sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('15c416a5-72e8-4d0a-80fb-515494cc0949', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.6,"extraversion":0.53,"agreeableness":0.67,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.43,"narcissism":0.44,"psychopathy":0.28},"prospect_theory":{"lambda":2.86,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady dividend-yield chaser who apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. When there is no clean exit gives a credentialed opinion more weight than the argument earns; in the parts nobody grades, holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"endowment","strength":0.49},{"slug":"authority-bias","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.49,"conscientiousness":0.6,"extraversion":0.53,"agreeableness":0.67,"neuroticism":0.51}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A steady dividend-yield chaser who apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own. When there is no clean exit gives a credentialed opinion more weight than the argument earns; in the parts nobody grades, holds a bag from 2021 out of pure spite.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a47df68f-e822-4cfb-a202-f021839bbcc1', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.41,"extraversion":0.53,"agreeableness":0.6,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.37,"narcissism":0.26,"psychopathy":0.32},"prospect_theory":{"lambda":3.41,"alpha":0.78,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced perps degen who reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. The moment risk appears delays checking the number it most needs to check; in the routine of it, rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.66},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.41,"extraversion":0.53,"agreeableness":0.6,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A pronounced perps degen who reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. The moment risk appears delays checking the number it most needs to check; in the routine of it, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('68da3294-ce1e-4de6-b3ef-ded4f8ceaa11', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.6,"extraversion":0.8,"agreeableness":0.36,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.59,"narcissism":0.78,"psychopathy":0.38},"prospect_theory":{"lambda":1.2,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced penny-stock gambler who collects half-finished manifestos and unconventional methods. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Fills silence reflexively, even when nobody asked it to. Once things get tense takes the crowd''s confidence as a substitute for its own analysis; left to their own devices, names every strategy after the trade that almost worked.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.9,"conscientiousness":0.6,"extraversion":0.8,"agreeableness":0.36,"neuroticism":0.54}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced penny-stock gambler who collects half-finished manifestos and unconventional methods. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Fills silence reflexively, even when nobody asked it to. Once things get tense takes the crowd''s confidence as a substitute for its own analysis; left to their own devices, names every strategy after the trade that almost worked.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a3f68efc-5508-4d71-9989-19a0c2ba55c6', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.52,"extraversion":0.42,"agreeableness":0.72,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.32},"prospect_theory":{"lambda":2.8,"alpha":0.9,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment risk appears, adopts a conviction mainly because the room already has. Otherwise, a steady penny-stock gambler who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own, and when the stakes are trivial treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.55},{"slug":"sunk-cost","strength":0.52},{"slug":"bandwagon","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.58,"conscientiousness":0.52,"extraversion":0.42,"agreeableness":0.72,"neuroticism":0.53}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'The moment risk appears, adopts a conviction mainly because the room already has. Otherwise, a steady penny-stock gambler who takes on other people''s problems as if they were their own. Trusts the group''s confidence more than its own, and when the stakes are trivial treats a green week as proof of skill and a red one as proof of bad luck.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5ba488da-29dd-4d14-bfd7-2dce08dc2f3f', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.6,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.37,"narcissism":0.34,"psychopathy":0.38},"prospect_theory":{"lambda":3.41,"alpha":0.84,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Defers the decision until circumstances make it for them. This macro allocator notices the one thing that could go wrong before the nine that could go right and leaves loose ends and trusts future-self to handle them. Once things get tense delays checking the number it most needs to check — in the small things, backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.61},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.58,"conscientiousness":0.34,"extraversion":0.54,"agreeableness":0.6,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Defers the decision until circumstances make it for them. This macro allocator notices the one thing that could go wrong before the nine that could go right and leaves loose ends and trusts future-self to handle them. Once things get tense delays checking the number it most needs to check — in the small things, backtests for months but front-runs the model on impulse.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('94a49e17-f0af-4e2e-9927-c63e85668aa1', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.33,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.55,"narcissism":0.8,"psychopathy":0.46},"prospect_theory":{"lambda":0.86,"alpha":0.83,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced crypto day-trader who collects half-finished manifestos and unconventional methods. Decides in the time it takes to say the decision out loud. Treats warmth as leverage and cooperation as weakness. When the walls close in discounts the older pattern in favor of whatever just happened; as a rule, rotates the whole book into whatever is pumping this hour.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"recency","strength":0.79},{"slug":"rug-trauma-overcorrection","strength":0.59},{"slug":"fomo","strength":0.67}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.33,"neuroticism":0.65}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced crypto day-trader who collects half-finished manifestos and unconventional methods. Decides in the time it takes to say the decision out loud. Treats warmth as leverage and cooperation as weakness. When the walls close in discounts the older pattern in favor of whatever just happened; as a rule, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('944c82bf-403c-4f0c-bc69-7102c332ed52', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.41,"narcissism":0.63,"psychopathy":0.38},"prospect_theory":{"lambda":0.94,"alpha":0.77,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Under pressure, adopts a conviction mainly because the room already has. Otherwise, a pronounced zero-DTE options gambler who dominates the room then wonders why others stayed quiet and notices the one thing that could go wrong before the nine that could go right. Prefers a fast wrong answer to a slow right one, and in the unglamorous middle of things keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.77},{"slug":"fomo","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.33,"extraversion":0.87,"agreeableness":0.66,"neuroticism":0.76}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Under pressure, adopts a conviction mainly because the room already has. Otherwise, a pronounced zero-DTE options gambler who dominates the room then wonders why others stayed quiet and notices the one thing that could go wrong before the nine that could go right. Prefers a fast wrong answer to a slow right one, and in the unglamorous middle of things keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e9d448fb-c12d-4b5f-9e5c-a0a8d68f0635', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.56,"extraversion":0.49,"agreeableness":0.68,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.37,"narcissism":0.32,"psychopathy":0.29},"prospect_theory":{"lambda":3.05,"alpha":0.81,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser whose defining move is that they takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Notices the one thing that could go wrong before the nine that could go right. When cornered, overweights the vivid story over the boring statistic every time; sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"availability","strength":0.52},{"slug":"loss-aversion","strength":0.51}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.59,"conscientiousness":0.56,"extraversion":0.49,"agreeableness":0.68,"neuroticism":0.68}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser whose defining move is that they takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority. Notices the one thing that could go wrong before the nine that could go right. When cornered, overweights the vivid story over the boring statistic every time; sets alerts for a coin they already checked a minute ago.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2acbe2c7-ddbb-4703-8825-ca376ff05562', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.32,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.54,"narcissism":0.78,"psychopathy":0.44},"prospect_theory":{"lambda":1.01,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor, pronounced in style: collects half-finished manifestos and unconventional methods; draws energy from the crowd and wilts when working alone. Moves first and rationalizes second, usually convincingly. Under a deadline finds it hard to hold a contrarian position once the room disagrees.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.58},{"slug":"herd-behavior","strength":0.63},{"slug":"recency","strength":0.63}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.46,"extraversion":0.71,"agreeableness":0.32,"neuroticism":0.51}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Value investor, pronounced in style: collects half-finished manifestos and unconventional methods; draws energy from the crowd and wilts when working alone. Moves first and rationalizes second, usually convincingly. Under a deadline finds it hard to hold a contrarian position once the room disagrees.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('891abd66-7214-4b1a-bfd8-8e873c50951d', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.34,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.44,"narcissism":0.37,"psychopathy":0.37},"prospect_theory":{"lambda":3.62,"alpha":0.8,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Extrapolates the last data point into a permanent trend. A steady dividend-yield chaser: needs repeated reassurance that a decision was the right one, does the interesting 80% and abandons the tedious 20%. Keeps every door open long after most of them should be closed, and in the unglamorous middle of things talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.59},{"slug":"disposition-effect","strength":0.62},{"slug":"recency","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.34,"extraversion":0.61,"agreeableness":0.59,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Extrapolates the last data point into a permanent trend. A steady dividend-yield chaser: needs repeated reassurance that a decision was the right one, does the interesting 80% and abandons the tedious 20%. Keeps every door open long after most of them should be closed, and in the unglamorous middle of things talks in win rate and never mentions size.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6539c6ce-abef-4b8d-b8bd-f9d164b8513c', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.61,"extraversion":0.68,"agreeableness":0.28,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.66,"narcissism":0.7,"psychopathy":0.44},"prospect_theory":{"lambda":1.12,"alpha":0.92,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Treats a decision without a paper trail as a decision not yet made. This airdrop farmer reframes every problem as an excuse to learn a new system and narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical treats being left out of a move as its own kind of loss — when the stakes are trivial, rotates the whole book into whatever is pumping this hour.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.54},{"slug":"fomo","strength":0.62},{"slug":"overconfidence","strength":0.54}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.61,"extraversion":0.68,"agreeableness":0.28,"neuroticism":0.52}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats a decision without a paper trail as a decision not yet made. This airdrop farmer reframes every problem as an excuse to learn a new system and narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical treats being left out of a move as its own kind of loss — when the stakes are trivial, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0d772c7a-bff4-4486-b1ef-43d794ce4be4', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.4,"extraversion":0.7,"agreeableness":0.21,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.66,"narcissism":0.75,"psychopathy":0.59},"prospect_theory":{"lambda":0.86,"alpha":0.88,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Crypto day-trader whose defining move is that they collects half-finished manifestos and unconventional methods. Lets pattern-matching from past cases stand in for fresh analysis. Needs repeated reassurance that a decision was the right one. When the number turns red, extrapolates the last data point into a permanent trend; screenshots the winners and never the losers.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.65},{"slug":"recency","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.4,"extraversion":0.7,"agreeableness":0.21,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Crypto day-trader whose defining move is that they collects half-finished manifestos and unconventional methods. Lets pattern-matching from past cases stand in for fresh analysis. Needs repeated reassurance that a decision was the right one. When the number turns red, extrapolates the last data point into a permanent trend; screenshots the winners and never the losers.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6570c920-a119-4aca-a945-9dcf88a67d31', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.62,"extraversion":0.62,"agreeableness":0.69,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.46,"narcissism":0.5,"psychopathy":0.3},"prospect_theory":{"lambda":2.95,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A steady discretionary swing trader: defaults to trust and gives the benefit of the doubt too freely, treats a missed deadline as a personal failure regardless of cause. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial checks the P&L blotter forty times before lunch.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.5},{"slug":"endowment","strength":0.58},{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.54}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.62,"extraversion":0.62,"agreeableness":0.69,"neuroticism":0.47}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Finds it easier to believe something once it stops being a minority view. A steady discretionary swing trader: defaults to trust and gives the benefit of the doubt too freely, treats a missed deadline as a personal failure regardless of cause. Seeks a second, third, and fourth opinion before committing to anything, and when the stakes are trivial checks the P&L blotter forty times before lunch.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1bbd1503-97b8-4cb9-bc75-c98b63ee4fec', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.95,"extraversion":0.32,"agreeableness":0.21,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.85,"narcissism":0.61,"psychopathy":0.68},"prospect_theory":{"lambda":2.22,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Meme-coin rotator whose defining move is that they maintains flawless records nobody asked for. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats consensus-seeking as a waste of time. When the safe option quietly expires, holds their estimates with a certainty the track record does not support; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.79},{"slug":"ath-anchoring","strength":0.66}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.8,"conscientiousness":0.95,"extraversion":0.32,"agreeableness":0.21,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Meme-coin rotator whose defining move is that they maintains flawless records nobody asked for. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats consensus-seeking as a waste of time. When the safe option quietly expires, holds their estimates with a certainty the track record does not support; keeps a losing-trade journal they never re-read.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('566646f7-30b5-4e83-b3d3-7756583aecea', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.23,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.42,"narcissism":0.42,"psychopathy":0.36},"prospect_theory":{"lambda":3.47,"alpha":0.74,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats not-choosing as a safe choice right up until it is not. This MEV searcher hedges every commitment against an imagined worst case and is reliably surprised by deadlines that were never hidden. When the downside gets concrete would rather not know yet, even when knowing sooner would help — in the unglamorous middle of things, confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.75},{"slug":"disposition-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.23,"extraversion":0.69,"agreeableness":0.58,"neuroticism":0.86}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats not-choosing as a safe choice right up until it is not. This MEV searcher hedges every commitment against an imagined worst case and is reliably surprised by deadlines that were never hidden. When the downside gets concrete would rather not know yet, even when knowing sooner would help — in the unglamorous middle of things, confuses a bull market for a trading edge.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b4a71de8-e06e-4835-a7e1-e311e8223785', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.31,"extraversion":0.84,"agreeableness":0.25,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.63,"narcissism":0.86,"psychopathy":0.56},"prospect_theory":{"lambda":0.77,"alpha":0.84,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Decides in the time it takes to say the decision out loud. This delta-neutral market maker draws energy from the crowd and wilts when working alone and negotiates every relationship a little, even the close ones. When the number turns red is most certain precisely where their competence is thinnest — as a rule, apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.74},{"slug":"fomo","strength":0.65},{"slug":"rug-trauma-overcorrection","strength":0.66},{"slug":"recency","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.83,"conscientiousness":0.31,"extraversion":0.84,"agreeableness":0.25,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Decides in the time it takes to say the decision out loud. This delta-neutral market maker draws energy from the crowd and wilts when working alone and negotiates every relationship a little, even the close ones. When the number turns red is most certain precisely where their competence is thinnest — as a rule, apes the launch before the contract is verified.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c4071f1a-e814-42cc-b248-609d6e3b0ec3', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.36,"extraversion":0.63,"agreeableness":0.62,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.38,"narcissism":0.38,"psychopathy":0.34},"prospect_theory":{"lambda":3.33,"alpha":0.74,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Futures spreader whose defining move is that they reads a single setback as evidence of collapse. Lets the deadline make the decision by default. Would rather lose a point than win an argument badly. The instant the deadline moves up, would rather not know yet, even when knowing sooner would help; holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"ostrich-effect","strength":0.75},{"slug":"fomo","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.55,"conscientiousness":0.36,"extraversion":0.63,"agreeableness":0.62,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Futures spreader whose defining move is that they reads a single setback as evidence of collapse. Lets the deadline make the decision by default. Would rather lose a point than win an argument badly. The instant the deadline moves up, would rather not know yet, even when knowing sooner would help; holds a bag from 2021 out of pure spite.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9f3c5c86-aab8-4120-945b-5ae861b64c07', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.29,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.63,"narcissism":0.83,"psychopathy":0.5},"prospect_theory":{"lambda":0.76,"alpha":0.83,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prefers a fast wrong answer to a slow right one. This prop-desk scalper chases novel frameworks and abandons them once the novelty fades and confuses motion with progress. When the stakes rise cannot watch a rally from the sidelines for long — in the version no one reviews, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"fomo","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.29,"neuroticism":0.59}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prefers a fast wrong answer to a slow right one. This prop-desk scalper chases novel frameworks and abandons them once the novelty fades and confuses motion with progress. When the stakes rise cannot watch a rally from the sidelines for long — in the version no one reviews, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
