('ca14bf29-ece5-4a1d-87ca-8834c37733eb', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.89,"extraversion":0.35,"agreeableness":0.33,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.79,"narcissism":0.54,"psychopathy":0.55},"prospect_theory":{"lambda":2.34,"alpha":0.96,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When there is no clean exit, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced penny-stock gambler who maintains flawless records nobody asked for and treats consensus-seeking as a waste of time. Treats a decision without a paper trail as a decision not yet made, and left to their own devices trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.58},{"slug":"overconfidence","strength":0.71}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.8,"conscientiousness":0.89,"extraversion":0.35,"agreeableness":0.33,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When there is no clean exit, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced penny-stock gambler who maintains flawless records nobody asked for and treats consensus-seeking as a waste of time. Treats a decision without a paper trail as a decision not yet made, and left to their own devices trusts the chart more than the fundamentals and won''t say why.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
