('34772df2-45e0-47d4-8033-64cda2f1ed92', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.38,"extraversion":0.74,"agreeableness":0.33,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.56,"narcissism":0.73,"psychopathy":0.47},"prospect_theory":{"lambda":0.95,"alpha":0.88,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats overthinking as its own kind of error. This index-fund holdout gets bored of the proven method exactly when it starts working and assumes self-interest in others because it is usually there in themselves. The moment it stops being hypothetical extrapolates the last data point into a permanent trend — without an audience, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.6},{"slug":"recency","strength":0.77},{"slug":"rug-trauma-overcorrection","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.38,"extraversion":0.74,"agreeableness":0.33,"neuroticism":0.64}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats overthinking as its own kind of error. This index-fund holdout gets bored of the proven method exactly when it starts working and assumes self-interest in others because it is usually there in themselves. The moment it stops being hypothetical extrapolates the last data point into a permanent trend — without an audience, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('572c7a26-f824-43b0-92bc-769fe9cddc40', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.36,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.55,"narcissism":0.79,"psychopathy":0.49},"prospect_theory":{"lambda":0.93,"alpha":0.84,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced discretionary swing trader who collects half-finished manifestos and unconventional methods. Lets pattern-matching from past cases stand in for fresh analysis. Dominates the room then wonders why others stayed quiet. When cornered discounts the older pattern in favor of whatever just happened; in the pattern nobody else tracks, keeps three monitors for a portfolio that fits on one screen.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.62},{"slug":"herd-behavior","strength":0.67},{"slug":"recency","strength":0.7},{"slug":"bandwagon","strength":0.58}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.32,"extraversion":0.77,"agreeableness":0.36,"neuroticism":0.54}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who collects half-finished manifestos and unconventional methods. Lets pattern-matching from past cases stand in for fresh analysis. Dominates the room then wonders why others stayed quiet. When cornered discounts the older pattern in favor of whatever just happened; in the pattern nobody else tracks, keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8bfd64e8-873f-46f1-9a1e-b1860104ac34', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.88,"extraversion":0.32,"agreeableness":0.28,"neuroticism":0.18},"dark_triad":{"machiavellianism":0.86,"narcissism":0.64,"psychopathy":0.67},"prospect_theory":{"lambda":2.35,"alpha":0.94,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Converts every argument into a number it can compare against another number. This delta-neutral market maker treats established procedure as a first draft to be rewritten and optimizes for winning over being liked. When the number turns red underestimates how often an obviously right call turns out wrong — in the routine of it, keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"hindsight","strength":0.73},{"slug":"optimism","strength":0.66},{"slug":"overconfidence","strength":0.75}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.92,"conscientiousness":0.88,"extraversion":0.32,"agreeableness":0.28,"neuroticism":0.18}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Converts every argument into a number it can compare against another number. This delta-neutral market maker treats established procedure as a first draft to be rewritten and optimizes for winning over being liked. When the number turns red underestimates how often an obviously right call turns out wrong — in the routine of it, keeps three monitors for a portfolio that fits on one screen.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e73eb2ab-625f-4115-be73-d243834482df', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.89,"extraversion":0.49,"agreeableness":0.3,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.81,"narcissism":0.6,"psychopathy":0.58},"prospect_theory":{"lambda":2.4,"alpha":0.96,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When the number turns red, is more certain than the hit rate justifies. Otherwise, a pronounced bonding-curve sniper who cannot relax until the checklist is visibly complete and says the blunt thing and enjoys the flinch. Wants the base rate before the anecdote, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.76},{"slug":"ath-anchoring","strength":0.64},{"slug":"hindsight","strength":0.69}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.89,"extraversion":0.49,"agreeableness":0.3,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the number turns red, is more certain than the hit rate justifies. Otherwise, a pronounced bonding-curve sniper who cannot relax until the checklist is visibly complete and says the blunt thing and enjoys the flinch. Wants the base rate before the anecdote, and once the urgency drains out trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('080a3d39-efeb-4e1f-928c-4939cbbe3750', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.96,"extraversion":0.37,"agreeableness":0.34,"neuroticism":0.24},"dark_triad":{"machiavellianism":0.83,"narcissism":0.48,"psychopathy":0.6},"prospect_theory":{"lambda":2.16,"alpha":0.93,"beta":0.84},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Index-fund holdout whose defining move is that they maintains flawless records nobody asked for. Demands the data before the discussion and the discussion before the call. Is difficult to rattle even with genuinely bad news. Once the exit narrows to one door, is more certain than the hit rate justifies; keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.72},{"slug":"optimism","strength":0.55},{"slug":"overconfidence","strength":0.74}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.69,"conscientiousness":0.96,"extraversion":0.37,"agreeableness":0.34,"neuroticism":0.24}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Index-fund holdout whose defining move is that they maintains flawless records nobody asked for. Demands the data before the discussion and the discussion before the call. Is difficult to rattle even with genuinely bad news. Once the exit narrows to one door, is more certain than the hit rate justifies; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8c539a91-bc44-4cae-ad5d-0ea517aacf04', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.59,"narcissism":0.79,"psychopathy":0.51},"prospect_theory":{"lambda":0.92,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady options seller who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Says the blunt thing and enjoys the flinch. When the walls close in cannot watch a rally from the sidelines for long; without an audience, sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"bandwagon","strength":0.65},{"slug":"dunning-kruger","strength":0.64},{"slug":"recency","strength":0.69}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.83,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.34,"neuroticism":0.55}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady options seller who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Says the blunt thing and enjoys the flinch. When the walls close in cannot watch a rally from the sidelines for long; without an audience, sets stop-losses then cancels them at the open.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
