('d0d8fd2f-ca81-432f-b3e6-36270bd2c68e', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.42,"extraversion":0.7,"agreeableness":0.35,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.52,"narcissism":0.68,"psychopathy":0.43},"prospect_theory":{"lambda":0.96,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Crypto day-trader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Decides on a gut read in seconds and reverse-engineers the reasons later. Thinks out loud and recruits an audience for every decision. When someone is watching the outcome, extrapolates the last data point into a permanent trend; talks in win rate and never mentions size.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.61},{"slug":"recency","strength":0.64},{"slug":"dunning-kruger","strength":0.61},{"slug":"herd-behavior","strength":0.53}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.79,"conscientiousness":0.42,"extraversion":0.7,"agreeableness":0.35,"neuroticism":0.57}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Crypto day-trader whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Decides on a gut read in seconds and reverse-engineers the reasons later. Thinks out loud and recruits an audience for every decision. When someone is watching the outcome, extrapolates the last data point into a permanent trend; talks in win rate and never mentions size.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c0f0f6f9-de30-40c2-9068-3b208b2d0c5f', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.34,"extraversion":0.64,"agreeableness":0.56,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.41,"narcissism":0.43,"psychopathy":0.34},"prospect_theory":{"lambda":3.62,"alpha":0.74,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Dividend-yield chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Finds one more piece of information to gather before acting. Starts strong and lets follow-through evaporate. When the safe option quietly expires, refuses to abandon failing transactions or dead claims because of high gas fees already burned; screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.7},{"slug":"disposition-effect","strength":0.7},{"slug":"fomo","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.34,"extraversion":0.64,"agreeableness":0.56,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Finds one more piece of information to gather before acting. Starts strong and lets follow-through evaporate. When the safe option quietly expires, refuses to abandon failing transactions or dead claims because of high gas fees already burned; screenshots the winners and never the losers.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('71ad4cf3-442e-4dc8-af62-e8b2208d0832', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.46,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.42,"narcissism":0.67,"psychopathy":0.27},"prospect_theory":{"lambda":0.97,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Bonding-curve sniper whose defining move is that they dominates the room then wonders why others stayed quiet. Trusts momentum over preparation. Reads outside the field for ideas the field itself would reject. The moment it stops being hypothetical, finds it hard to hold a contrarian position once the room disagrees; trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"optimism","strength":0.51},{"slug":"fomo","strength":0.62},{"slug":"dunning-kruger","strength":0.53}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.63,"conscientiousness":0.46,"extraversion":0.79,"agreeableness":0.67,"neuroticism":0.52}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they dominates the room then wonders why others stayed quiet. Trusts momentum over preparation. Reads outside the field for ideas the field itself would reject. The moment it stops being hypothetical, finds it hard to hold a contrarian position once the room disagrees; trusts the chart more than the fundamentals and won''t say why.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('17b44911-f586-42f2-8cc4-1abe05a84729', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.51,"extraversion":0.71,"agreeableness":0.17,"neuroticism":0.37},"dark_triad":{"machiavellianism":0.71,"narcissism":0.83,"psychopathy":0.64},"prospect_theory":{"lambda":1.3,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Dividend-yield chaser, pronounced in style: treats established procedure as a first draft to be rewritten; narrates the plan to whoever is nearby before committing to it. Builds a decision matrix for choices most people make on instinct. When someone is watching the outcome holds their estimates with a certainty the track record does not support.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.55},{"slug":"overconfidence","strength":0.75},{"slug":"airdrop-entitlement","strength":0.53},{"slug":"optimism","strength":0.65}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.85,"conscientiousness":0.51,"extraversion":0.71,"agreeableness":0.17,"neuroticism":0.37}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser, pronounced in style: treats established procedure as a first draft to be rewritten; narrates the plan to whoever is nearby before committing to it. Builds a decision matrix for choices most people make on instinct. When someone is watching the outcome holds their estimates with a certainty the track record does not support.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a378b90d-4cf1-4f1b-bb6c-4674698678c0', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.34,"extraversion":0.65,"agreeableness":0.56,"neuroticism":0.92},"dark_triad":{"machiavellianism":0.44,"narcissism":0.36,"psychopathy":0.34},"prospect_theory":{"lambda":3.63,"alpha":0.72,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Dividend-yield chaser whose defining move is that they needs repeated reassurance that a decision was the right one. Buries hard calls under a pile of preparatory busywork. Confuses motion with progress. The instant it becomes irreversible, would rather not know yet, even when knowing sooner would help; exits winners at the first green candle.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.74},{"slug":"ostrich-effect","strength":0.79}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.34,"extraversion":0.65,"agreeableness":0.56,"neuroticism":0.92}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser whose defining move is that they needs repeated reassurance that a decision was the right one. Buries hard calls under a pile of preparatory busywork. Confuses motion with progress. The instant it becomes irreversible, would rather not know yet, even when knowing sooner would help; exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('06942531-8d6f-4aa3-8dc5-dd567ba7cbac', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.24,"extraversion":0.83,"agreeableness":0.38,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.48,"narcissism":0.78,"psychopathy":0.47},"prospect_theory":{"lambda":0.96,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, cannot watch a rally from the sidelines for long. Otherwise, a steady options seller who thinks out loud and recruits an audience for every decision and does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and in the version no one reviews sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"fomo","strength":0.7}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.81,"conscientiousness":0.24,"extraversion":0.83,"agreeableness":0.38,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, cannot watch a rally from the sidelines for long. Otherwise, a steady options seller who thinks out loud and recruits an audience for every decision and does the interesting 80% and abandons the tedious 20%. Commits before the doubt has time to organize itself, and in the version no one reviews sets stop-losses then cancels them at the open.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1cff4349-c69a-4cae-98fa-b433da15a6d0', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.63,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.41,"narcissism":0.7,"psychopathy":0.4},"prospect_theory":{"lambda":0.95,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Penny-stock gambler, pronounced in style: narrates the plan to whoever is nearby before committing to it; confuses motion with progress. Acts on the midnight epiphany and emails it at 1am. Once the exit narrows to one door abandons a private read the instant the crowd leans the other way.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"dunning-kruger","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.76,"conscientiousness":0.32,"extraversion":0.88,"agreeableness":0.63,"neuroticism":0.61}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Penny-stock gambler, pronounced in style: narrates the plan to whoever is nearby before committing to it; confuses motion with progress. Acts on the midnight epiphany and emails it at 1am. Once the exit narrows to one door abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a453f23c-8402-427e-ab25-f7dd1835bc92', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.9,"extraversion":0.43,"agreeableness":0.32,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.82,"narcissism":0.55,"psychopathy":0.6},"prospect_theory":{"lambda":2.29,"alpha":0.97,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Delta-neutral market maker, pronounced in style: builds in buffer time and then fills the buffer with more work; reads outside the field for ideas the field itself would reject. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The instant it becomes irreversible is more certain than the hit rate justifies.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.69},{"slug":"ath-anchoring","strength":0.62},{"slug":"overconfidence","strength":0.71},{"slug":"recency","strength":0.55}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.86,"conscientiousness":0.9,"extraversion":0.43,"agreeableness":0.32,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker, pronounced in style: builds in buffer time and then fills the buffer with more work; reads outside the field for ideas the field itself would reject. Weighs options against explicit criteria and distrusts anything they cannot tabulate. The instant it becomes irreversible is more certain than the hit rate justifies.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6798aebd-994d-425d-a202-052785897dd9', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.61,"extraversion":0.82,"agreeableness":0.32,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.64,"narcissism":0.87,"psychopathy":0.47},"prospect_theory":{"lambda":1.31,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Abandons a private read the instant the crowd leans the other way. A pronounced futures spreader: would rather invent a worse tool than use someone else''s good one, assumes self-interest in others because it is usually there in themselves. Converts every argument into a number it can compare against another number, and when no one is watching refreshes the order book compulsively during lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.58},{"slug":"herd-behavior","strength":0.69},{"slug":"bandwagon","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.61,"extraversion":0.82,"agreeableness":0.32,"neuroticism":0.4}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Abandons a private read the instant the crowd leans the other way. A pronounced futures spreader: would rather invent a worse tool than use someone else''s good one, assumes self-interest in others because it is usually there in themselves. Converts every argument into a number it can compare against another number, and when no one is watching refreshes the order book compulsively during lunch.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8f0b81e5-7f6e-4b8d-b6f5-c12cfdd000d8', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.51,"extraversion":0.79,"agreeableness":0.35,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.51,"narcissism":0.79,"psychopathy":0.41},"prospect_theory":{"lambda":1.04,"alpha":0.85,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Wants the base rate before the anecdote. This liquidation-bot operator reframes every problem as an excuse to learn a new system and fills silence reflexively, even when nobody asked it to. When the safe option quietly expires adopts a conviction mainly because the room already has — when the pressure is off, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.58},{"slug":"bandwagon","strength":0.6},{"slug":"herd-behavior","strength":0.58}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.86,"conscientiousness":0.51,"extraversion":0.79,"agreeableness":0.35,"neuroticism":0.48}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Wants the base rate before the anecdote. This liquidation-bot operator reframes every problem as an excuse to learn a new system and fills silence reflexively, even when nobody asked it to. When the safe option quietly expires adopts a conviction mainly because the room already has — when the pressure is off, treats a green week as proof of skill and a red one as proof of bad luck.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('747d76cf-1b63-4ce6-a9ba-94e0ff51d03b', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.83,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.84,"narcissism":0.54,"psychopathy":0.53},"prospect_theory":{"lambda":2.33,"alpha":0.9,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Bonding-curve sniper whose defining move is that they maintains flawless records nobody asked for. Wants the base rate before the anecdote. Stays flat when the numbers go red. Under pressure, holds their estimates with a certainty the track record does not support; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.68},{"slug":"ath-anchoring","strength":0.54}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.83,"extraversion":0.48,"agreeableness":0.34,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they maintains flawless records nobody asked for. Wants the base rate before the anecdote. Stays flat when the numbers go red. Under pressure, holds their estimates with a certainty the track record does not support; treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8a37e8da-d987-4d79-a00c-a1239f1aafd6', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.92,"extraversion":0.61,"agreeableness":0.27,"neuroticism":0.31},"dark_triad":{"machiavellianism":0.78,"narcissism":0.66,"psychopathy":0.61},"prospect_theory":{"lambda":2.13,"alpha":0.92,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Underestimates how often an obviously right call turns out wrong. A pronounced pairs trader: over-prepares to the point of diminishing returns, moves on from a mistake faster than the people around them do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and when no one is watching calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.71},{"slug":"hindsight","strength":0.64}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.74,"conscientiousness":0.92,"extraversion":0.61,"agreeableness":0.27,"neuroticism":0.31}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Underestimates how often an obviously right call turns out wrong. A pronounced pairs trader: over-prepares to the point of diminishing returns, moves on from a mistake faster than the people around them do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and when no one is watching calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b86ad5c6-e863-4247-9b1d-29385aec12b5', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.65,"extraversion":0.49,"agreeableness":0.63,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.42,"narcissism":0.38,"psychopathy":0.27},"prospect_theory":{"lambda":2.9,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured perps degen who maintains flawless records nobody asked for. Needs the room''s approval more than it needs to be right. Measures decisions by who they might upset. Under pressure finds it easier to believe something once it stops being a minority view; without an audience, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.54},{"slug":"authority-bias","strength":0.51}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.65,"extraversion":0.49,"agreeableness":0.63,"neuroticism":0.6}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A measured perps degen who maintains flawless records nobody asked for. Needs the room''s approval more than it needs to be right. Measures decisions by who they might upset. Under pressure finds it easier to believe something once it stops being a minority view; without an audience, treats a green week as proof of skill and a red one as proof of bad luck.', 0.86, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
