('329745be-b35e-4fe2-a1e3-f8b6dbeff193', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.29,"extraversion":0.82,"agreeableness":0.3,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.56,"narcissism":0.78,"psychopathy":0.5},"prospect_theory":{"lambda":0.75,"alpha":0.8,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher whose defining move is that they gets bored of the proven method exactly when it starts working. Treats hesitation as the bigger risk. Dominates the room then wonders why others stayed quiet. In a pinch, assumes the current streak is the new normal; keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.66},{"slug":"bandwagon","strength":0.55},{"slug":"herd-behavior","strength":0.64},{"slug":"recency","strength":0.72}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.29,"extraversion":0.82,"agreeableness":0.3,"neuroticism":0.61}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Quant researcher whose defining move is that they gets bored of the proven method exactly when it starts working. Treats hesitation as the bigger risk. Dominates the room then wonders why others stayed quiet. In a pinch, assumes the current streak is the new normal; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d34dfc9a-f72d-4298-9d2c-cc0f4470b64a', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.33,"extraversion":0.59,"agreeableness":0.62,"neuroticism":0.97},"dark_triad":{"machiavellianism":0.4,"narcissism":0.34,"psychopathy":0.37},"prospect_theory":{"lambda":3.46,"alpha":0.74,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Under a deadline, delays checking the number it most needs to check. Otherwise, a pronounced volatility arbitrageur who carries yesterday''s stress into today''s unrelated decision and apologizes first in disputes regardless of fault. Treats not-choosing as a safe choice right up until it is not, and once the urgency drains out names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.72},{"slug":"disposition-effect","strength":0.69},{"slug":"availability","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.65,"conscientiousness":0.33,"extraversion":0.59,"agreeableness":0.62,"neuroticism":0.97}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Under a deadline, delays checking the number it most needs to check. Otherwise, a pronounced volatility arbitrageur who carries yesterday''s stress into today''s unrelated decision and apologizes first in disputes regardless of fault. Treats not-choosing as a safe choice right up until it is not, and once the urgency drains out names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f413b929-edd0-43c2-9eee-6488dbc914b1', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.45,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.6,"narcissism":0.78,"psychopathy":0.53},"prospect_theory":{"lambda":1.2,"alpha":0.92,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"DeFi yield farmer, pronounced in style: would rather invent a worse tool than use someone else''s good one; draws energy from the crowd and wilts when working alone. Weighs options against explicit criteria and distrusts anything they cannot tabulate. When the stakes rise abandons a private read the instant the crowd leans the other way.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"overconfidence","strength":0.55},{"slug":"herd-behavior","strength":0.64},{"slug":"dunning-kruger","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.96,"conscientiousness":0.45,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.48}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'DeFi yield farmer, pronounced in style: would rather invent a worse tool than use someone else''s good one; draws energy from the crowd and wilts when working alone. Weighs options against explicit criteria and distrusts anything they cannot tabulate. When the stakes rise abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6fdec4a0-4c65-484e-adde-a004b70333be', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.57,"extraversion":0.41,"agreeableness":0.64,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.42,"narcissism":0.35,"psychopathy":0.26},"prospect_theory":{"lambda":2.98,"alpha":0.89,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler whose defining move is that they takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding. Reads a single setback as evidence of collapse. The moment it stops being hypothetical, feels parting with something as a bigger loss than its market value explains; backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"ostrich-effect","strength":0.54},{"slug":"diamond-hands-identity","strength":0.48},{"slug":"endowment","strength":0.58},{"slug":"loss-aversion","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.57,"extraversion":0.41,"agreeableness":0.64,"neuroticism":0.62}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Zero-DTE options gambler whose defining move is that they takes on other people''s problems as if they were their own. Circles back to ask what someone else would do even after deciding. Reads a single setback as evidence of collapse. The moment it stops being hypothetical, feels parting with something as a bigger loss than its market value explains; backtests for months but front-runs the model on impulse.', 0.81, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2d30a9ed-6961-4ca6-b87b-3f4d5aeed6c0', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.92,"extraversion":0.31,"agreeableness":0.21,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.84,"narcissism":0.6,"psychopathy":0.62},"prospect_theory":{"lambda":2.2,"alpha":0.98,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced volatility arbitrageur who builds in buffer time and then fills the buffer with more work. Wants the base rate before the anecdote. Sleeps fine the night before the big call. When the number turns red is surprised in the moment and certain in the retelling; when no one is watching, backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.62},{"slug":"anchoring","strength":0.62},{"slug":"hindsight","strength":0.68},{"slug":"ath-anchoring","strength":0.6}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.72,"conscientiousness":0.92,"extraversion":0.31,"agreeableness":0.21,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced volatility arbitrageur who builds in buffer time and then fills the buffer with more work. Wants the base rate before the anecdote. Sleeps fine the night before the big call. When the number turns red is surprised in the moment and certain in the retelling; when no one is watching, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('aef8cea8-8fa8-4ed2-99d3-657dcbed83ae', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.3,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.36,"narcissism":0.64,"psychopathy":0.34},"prospect_theory":{"lambda":1.01,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Trusts momentum over preparation. This onchain copy-trader treats established procedure as a first draft to be rewritten and measures decisions by who they might upset. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it — once the urgency drains out, talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"recency","strength":0.71},{"slug":"bandwagon","strength":0.76},{"slug":"dunning-kruger","strength":0.67}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.83,"conscientiousness":0.3,"extraversion":0.83,"agreeableness":0.7,"neuroticism":0.67}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This onchain copy-trader treats established procedure as a first draft to be rewritten and measures decisions by who they might upset. When the safe option quietly expires gains confidence in a position in proportion to how many others hold it — once the urgency drains out, talks in win rate and never mentions size.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8a6fa5d8-aa04-4565-9272-5a6836dedbfc', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.29,"extraversion":0.61,"agreeableness":0.74,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.33,"narcissism":0.37,"psychopathy":0.37},"prospect_theory":{"lambda":3.36,"alpha":0.75,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment risk appears, delays checking the number it most needs to check. Otherwise, a steady crypto day-trader who rehearses catastrophes in vivid detail before they happen and apologizes first in disputes regardless of fault. Buries hard calls under a pile of preparatory busywork, and on an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.63},{"slug":"gas-sunk-cost","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.55,"conscientiousness":0.29,"extraversion":0.61,"agreeableness":0.74,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'The moment risk appears, delays checking the number it most needs to check. Otherwise, a steady crypto day-trader who rehearses catastrophes in vivid detail before they happen and apologizes first in disputes regardless of fault. Buries hard calls under a pile of preparatory busywork, and on an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('30043935-d1b3-4c3f-898b-48ed33be7de1', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.89,"extraversion":0.53,"agreeableness":0.33,"neuroticism":0.2},"dark_triad":{"machiavellianism":0.81,"narcissism":0.59,"psychopathy":0.58},"prospect_theory":{"lambda":2.27,"alpha":0.95,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Weighs options against explicit criteria and distrusts anything they cannot tabulate. This DeFi yield farmer builds in buffer time and then fills the buffer with more work and reframes every problem as an excuse to learn a new system. The moment it stops being hypothetical expects to be the exception to a risk it can otherwise describe accurately — in the version no one reviews, backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.64},{"slug":"optimism","strength":0.69}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.85,"conscientiousness":0.89,"extraversion":0.53,"agreeableness":0.33,"neuroticism":0.2}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Weighs options against explicit criteria and distrusts anything they cannot tabulate. This DeFi yield farmer builds in buffer time and then fills the buffer with more work and reframes every problem as an excuse to learn a new system. The moment it stops being hypothetical expects to be the exception to a risk it can otherwise describe accurately — in the version no one reviews, backtests for months but front-runs the model on impulse.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2f811ab0-8448-4e2e-a2d7-d5ed5a68f1f7', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.24,"extraversion":0.76,"agreeableness":0.32,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.54,"narcissism":0.76,"psychopathy":0.57},"prospect_theory":{"lambda":0.92,"alpha":0.85,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser, pronounced in style: reframes every problem as an excuse to learn a new system; spirals on ambiguity and mistakes the spiral for diligence. Trusts momentum over preparation. In a pinch is most certain precisely where their competence is thinnest.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.72},{"slug":"fomo","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.24,"extraversion":0.76,"agreeableness":0.32,"neuroticism":0.65}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Retail momentum chaser, pronounced in style: reframes every problem as an excuse to learn a new system; spirals on ambiguity and mistakes the spiral for diligence. Trusts momentum over preparation. In a pinch is most certain precisely where their competence is thinnest.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8d7d4af2-e44f-4030-977d-380992ca4fa8', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.4,"extraversion":0.65,"agreeableness":0.64,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.36,"narcissism":0.38,"psychopathy":0.34},"prospect_theory":{"lambda":3.72,"alpha":0.75,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment risk appears, refuses to take profits because holding has become core to their community identity. Otherwise, a pronounced discretionary swing trader who hedges every commitment against an imagined worst case and draws energy from the crowd and wilts when working alone. Prefers a slow loss to a fast, ownable mistake, and when no one is watching treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"loss-aversion","strength":0.69},{"slug":"diamond-hands-identity","strength":0.71},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.47,"conscientiousness":0.4,"extraversion":0.65,"agreeableness":0.64,"neuroticism":0.84}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'The moment risk appears, refuses to take profits because holding has become core to their community identity. Otherwise, a pronounced discretionary swing trader who hedges every commitment against an imagined worst case and draws energy from the crowd and wilts when working alone. Prefers a slow loss to a fast, ownable mistake, and when no one is watching treats a green week as proof of skill and a red one as proof of bad luck.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3f1e7101-2bcb-4fc5-8c72-faf040528cc0', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.44,"extraversion":0.66,"agreeableness":0.51,"neuroticism":0.95},"dark_triad":{"machiavellianism":0.4,"narcissism":0.41,"psychopathy":0.28},"prospect_theory":{"lambda":3.7,"alpha":0.74,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Lets the deadline make the decision by default. This DeFi yield farmer carries yesterday''s stress into today''s unrelated decision and fills silence reflexively, even when nobody asked it to. Under pressure treats being left out of a move as its own kind of loss — on an ordinary week, sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.75},{"slug":"loss-aversion","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.6,"conscientiousness":0.44,"extraversion":0.66,"agreeableness":0.51,"neuroticism":0.95}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Lets the deadline make the decision by default. This DeFi yield farmer carries yesterday''s stress into today''s unrelated decision and fills silence reflexively, even when nobody asked it to. Under pressure treats being left out of a move as its own kind of loss — on an ordinary week, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b4eae4ee-f4a9-493c-89be-bddaa4d02e5c', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.47,"extraversion":0.52,"agreeableness":0.52,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.3},"prospect_theory":{"lambda":3.36,"alpha":0.85,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady bonding-curve sniper who spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed. When the downside gets concrete guards against losses far more fiercely than they chase equivalent gains; on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.54},{"slug":"loss-aversion","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.61,"conscientiousness":0.47,"extraversion":0.52,"agreeableness":0.52,"neuroticism":0.69}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady bonding-curve sniper who spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed. When the downside gets concrete guards against losses far more fiercely than they chase equivalent gains; on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2cfc5497-ec23-41d0-a5c4-693669716073', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.42,"extraversion":0.78,"agreeableness":0.42,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.48,"narcissism":0.75,"psychopathy":0.41},"prospect_theory":{"lambda":0.82,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Knows the answer before it can explain the question. This onchain copy-trader gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. In a pinch treats being left out of a move as its own kind of loss — when the stakes are trivial, calls a 90% drawdown a long-term hold.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.64},{"slug":"herd-behavior","strength":0.66},{"slug":"fomo","strength":0.68}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.42,"extraversion":0.78,"agreeableness":0.42,"neuroticism":0.54}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Knows the answer before it can explain the question. This onchain copy-trader gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. In a pinch treats being left out of a move as its own kind of loss — when the stakes are trivial, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('896973dc-1100-411f-9bf5-b8c5b818fc12', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.42,"extraversion":0.68,"agreeableness":0.7,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.39,"narcissism":0.41,"psychopathy":0.31},"prospect_theory":{"lambda":3.44,"alpha":0.76,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"DeFi yield farmer whose defining move is that they reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. Thinks out loud and recruits an audience for every decision. When there is no clean exit, discounts the older pattern in favor of whatever just happened; confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"endowment","strength":0.64},{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.64,"conscientiousness":0.42,"extraversion":0.68,"agreeableness":0.7,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. Thinks out loud and recruits an audience for every decision. When there is no clean exit, discounts the older pattern in favor of whatever just happened; confuses a bull market for a trading edge.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1a24d035-fbc9-49b3-a0e9-72d2941fd086', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.9,"extraversion":0.45,"agreeableness":0.35,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.83,"narcissism":0.51,"psychopathy":0.52},"prospect_theory":{"lambda":2.37,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Quant researcher, pronounced in style: plans in exhaustive detail and resents any deviation; assumes self-interest in others because it is usually there in themselves. Weighs options against explicit criteria and distrusts anything they cannot tabulate. When the stakes rise remembers every surprise as something they saw coming all along.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.67},{"slug":"hindsight","strength":0.68},{"slug":"ath-anchoring","strength":0.6}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.75,"conscientiousness":0.9,"extraversion":0.45,"agreeableness":0.35,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Quant researcher, pronounced in style: plans in exhaustive detail and resents any deviation; assumes self-interest in others because it is usually there in themselves. Weighs options against explicit criteria and distrusts anything they cannot tabulate. When the stakes rise remembers every surprise as something they saw coming all along.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bdc3304e-ebe3-4ea3-ba10-9bedeea12f53', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.39,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.38,"narcissism":0.58,"psychopathy":0.29},"prospect_theory":{"lambda":1.25,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady macro allocator who collects half-finished manifestos and unconventional methods. Trusts momentum over preparation. Absorbs conflict to keep the peace, often at their own cost. The moment risk appears abandons a private read the instant the crowd leans the other way; when the stakes are trivial, screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.78},{"slug":"bandwagon","strength":0.76},{"slug":"fomo","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.79,"conscientiousness":0.39,"extraversion":0.79,"agreeableness":0.79,"neuroticism":0.71}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'A steady macro allocator who collects half-finished manifestos and unconventional methods. Trusts momentum over preparation. Absorbs conflict to keep the peace, often at their own cost. The moment risk appears abandons a private read the instant the crowd leans the other way; when the stakes are trivial, screenshots the winners and never the losers.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d4bbcc28-9fa3-447e-b4e8-8e1fc24843c5', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.54,"extraversion":0.73,"agreeableness":0.23,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.63,"narcissism":0.75,"psychopathy":0.47},"prospect_theory":{"lambda":1.17,"alpha":0.81,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A steady quant researcher who reads outside the field for ideas the field itself would reject. Treats a decision without a paper trail as a decision not yet made. Draws energy from the crowd and wilts when working alone. When the walls close in discounts the older pattern in favor of whatever just happened; without an audience, averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.6},{"slug":"airdrop-entitlement","strength":0.58},{"slug":"recency","strength":0.63}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.83,"conscientiousness":0.54,"extraversion":0.73,"agreeableness":0.23,"neuroticism":0.58}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady quant researcher who reads outside the field for ideas the field itself would reject. Treats a decision without a paper trail as a decision not yet made. Draws energy from the crowd and wilts when working alone. When the walls close in discounts the older pattern in favor of whatever just happened; without an audience, averages down on a name three times in a week.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
