('3bcb51a3-3bda-4bc6-b708-3b3d0e18a721', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.97,"extraversion":0.33,"agreeableness":0.18,"neuroticism":0.31},"dark_triad":{"machiavellianism":0.82,"narcissism":0.62,"psychopathy":0.65},"prospect_theory":{"lambda":2.17,"alpha":0.94,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Builds a decision matrix for choices most people make on instinct. This airdrop farmer front-loads the work and double-checks it twice and processes internally and surfaces conclusions fully formed. When there is no clean exit rewrites its own uncertainty out of the story after the fact — in the small things, calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.54},{"slug":"overconfidence","strength":0.67},{"slug":"hindsight","strength":0.71}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.97,"extraversion":0.33,"agreeableness":0.18,"neuroticism":0.31}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Builds a decision matrix for choices most people make on instinct. This airdrop farmer front-loads the work and double-checks it twice and processes internally and surfaces conclusions fully formed. When there is no clean exit rewrites its own uncertainty out of the story after the fact — in the small things, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
