('705d0af3-175e-4e7c-b7b7-382fa061c32e', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.41,"extraversion":0.85,"agreeableness":0.2,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.63,"narcissism":0.91,"psychopathy":0.59},"prospect_theory":{"lambda":0.76,"alpha":0.8,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced bonding-curve sniper who collects half-finished manifestos and unconventional methods. Moves first and rationalizes second, usually convincingly. Reads a single setback as evidence of collapse. Once the exit narrows to one door jumps into whatever everyone else already seems to be winning at; as a rule, keeps a losing-trade journal they never re-read.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.6},{"slug":"rug-trauma-overcorrection","strength":0.64},{"slug":"fomo","strength":0.65}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.41,"extraversion":0.85,"agreeableness":0.2,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced bonding-curve sniper who collects half-finished manifestos and unconventional methods. Moves first and rationalizes second, usually convincingly. Reads a single setback as evidence of collapse. Once the exit narrows to one door jumps into whatever everyone else already seems to be winning at; as a rule, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('45a0eb51-2363-4805-acbe-c1fdba88f661', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.39,"extraversion":0.75,"agreeableness":0.29,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.6,"narcissism":0.79,"psychopathy":0.49},"prospect_theory":{"lambda":0.91,"alpha":0.9,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Lets pattern-matching from past cases stand in for fresh analysis. This dividend-yield chaser gets bored of the proven method exactly when it starts working and fills silence reflexively, even when nobody asked it to. When cornered extrapolates the last data point into a permanent trend — day to day, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.62},{"slug":"dunning-kruger","strength":0.57},{"slug":"recency","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.39,"extraversion":0.75,"agreeableness":0.29,"neuroticism":0.51}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Lets pattern-matching from past cases stand in for fresh analysis. This dividend-yield chaser gets bored of the proven method exactly when it starts working and fills silence reflexively, even when nobody asked it to. When cornered extrapolates the last data point into a permanent trend — day to day, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1b468a63-d4cd-4337-a78b-29f6460e131e', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.36,"extraversion":0.79,"agreeableness":0.53,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.39,"narcissism":0.62,"psychopathy":0.32},"prospect_theory":{"lambda":0.99,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"DeFi yield farmer whose defining move is that they dominates the room then wonders why others stayed quiet. Treats hesitation as the bigger risk. Is reliably surprised by deadlines that were never hidden. When the downside gets concrete, treats being left out of a move as its own kind of loss; apes the launch before the contract is verified.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"dunning-kruger","strength":0.7},{"slug":"herd-behavior","strength":0.62},{"slug":"bandwagon","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.76,"conscientiousness":0.36,"extraversion":0.79,"agreeableness":0.53,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they dominates the room then wonders why others stayed quiet. Treats hesitation as the bigger risk. Is reliably surprised by deadlines that were never hidden. When the downside gets concrete, treats being left out of a move as its own kind of loss; apes the launch before the contract is verified.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d2981b44-fde1-44e1-9e24-5c782fafddbe', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.61,"extraversion":0.74,"agreeableness":0.35,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.61,"narcissism":0.79,"psychopathy":0.42},"prospect_theory":{"lambda":1.17,"alpha":0.91,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced liquidation-bot operator who reframes every problem as an excuse to learn a new system. Wants the base rate before the anecdote. Treats a quiet room as a problem to be solved. Under a deadline treats being left out of a move as its own kind of loss; when the pressure is off, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"optimism","strength":0.61},{"slug":"bandwagon","strength":0.53},{"slug":"recency","strength":0.61}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.95,"conscientiousness":0.61,"extraversion":0.74,"agreeableness":0.35,"neuroticism":0.44}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced liquidation-bot operator who reframes every problem as an excuse to learn a new system. Wants the base rate before the anecdote. Treats a quiet room as a problem to be solved. Under a deadline treats being left out of a move as its own kind of loss; when the pressure is off, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ee9168f6-d116-417c-b496-a7220a816d36', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.26,"extraversion":0.61,"agreeableness":0.61,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.41,"narcissism":0.33,"psychopathy":0.4},"prospect_theory":{"lambda":3.56,"alpha":0.78,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Penny-stock gambler whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Confuses motion with progress. As soon as real money or reputation is on the line, locks in small wins fast and rides large losses far past the point of sense; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.66},{"slug":"disposition-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.49,"conscientiousness":0.26,"extraversion":0.61,"agreeableness":0.61,"neuroticism":0.79}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they spirals on ambiguity and mistakes the spiral for diligence. Prefers a slow loss to a fast, ownable mistake. Confuses motion with progress. As soon as real money or reputation is on the line, locks in small wins fast and rides large losses far past the point of sense; treats a green week as proof of skill and a red one as proof of bad luck.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e41aea4f-5cee-49d2-9598-34ad4c34424c', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.53,"extraversion":0.63,"agreeableness":0.33,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.57,"narcissism":0.66,"psychopathy":0.5},"prospect_theory":{"lambda":1.26,"alpha":0.9,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Once the exit narrows to one door, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced algorithmic market-maker who reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. Demands the data before the discussion and the discussion before the call, and as a rule apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.64},{"slug":"optimism","strength":0.51}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.91,"conscientiousness":0.53,"extraversion":0.63,"agreeableness":0.33,"neuroticism":0.41}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced algorithmic market-maker who reframes every problem as an excuse to learn a new system and thinks out loud and recruits an audience for every decision. Demands the data before the discussion and the discussion before the call, and as a rule apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('691f99bd-70ca-4668-92c7-9fb2af2ec9e3', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.62,"extraversion":0.6,"agreeableness":0.74,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.38,"narcissism":0.48,"psychopathy":0.24},"prospect_theory":{"lambda":2.88,"alpha":0.87,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This pairs trader absorbs conflict to keep the peace, often at their own cost and plans in exhaustive detail and resents any deviation. When there is no clean exit adopts a conviction mainly because the room already has — in the routine of it, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.68},{"slug":"endowment","strength":0.56},{"slug":"sunk-cost","strength":0.57},{"slug":"authority-bias","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.62,"extraversion":0.6,"agreeableness":0.74,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Circles back to ask what someone else would do even after deciding. This pairs trader absorbs conflict to keep the peace, often at their own cost and plans in exhaustive detail and resents any deviation. When there is no clean exit adopts a conviction mainly because the room already has — in the routine of it, treats a green week as proof of skill and a red one as proof of bad luck.', 0.88, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('220416cc-bb36-48d6-99dd-766d808c25d1', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.24,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.64,"narcissism":0.93,"psychopathy":0.54},"prospect_theory":{"lambda":0.74,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The instant the deadline moves up, is most certain precisely where their competence is thinnest. Otherwise, a pronounced bonding-curve sniper who reframes every problem as an excuse to learn a new system and dominates the room then wonders why others stayed quiet. Decides in the time it takes to say the decision out loud, and in the small things screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.72},{"slug":"dunning-kruger","strength":0.77},{"slug":"bandwagon","strength":0.68},{"slug":"fomo","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.34,"extraversion":0.91,"agreeableness":0.24,"neuroticism":0.52}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant the deadline moves up, is most certain precisely where their competence is thinnest. Otherwise, a pronounced bonding-curve sniper who reframes every problem as an excuse to learn a new system and dominates the room then wonders why others stayed quiet. Decides in the time it takes to say the decision out loud, and in the small things screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d05a530c-1f2e-4d00-b291-0ad031a6381e', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.41,"extraversion":0.77,"agreeableness":0.37,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.57,"narcissism":0.68,"psychopathy":0.45},"prospect_theory":{"lambda":0.81,"alpha":0.8,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader whose defining move is that they gets bored of the proven method exactly when it starts working. Reads a room or a market the way others read a paragraph. Would rather be respected than liked, and says so. The instant the deadline moves up, cannot watch a rally from the sidelines for long; calls a 90% drawdown a long-term hold.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.57},{"slug":"fomo","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.41,"extraversion":0.77,"agreeableness":0.37,"neuroticism":0.68}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discretionary swing trader whose defining move is that they gets bored of the proven method exactly when it starts working. Reads a room or a market the way others read a paragraph. Would rather be respected than liked, and says so. The instant the deadline moves up, cannot watch a rally from the sidelines for long; calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ced32af2-80b0-45cb-8b93-f5a911da2176', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.63,"extraversion":0.57,"agreeableness":0.42,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.55,"narcissism":0.57,"psychopathy":0.33},"prospect_theory":{"lambda":1.32,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"The instant the deadline moves up, assumes the current streak is the new normal. Otherwise, a pronounced onchain copy-trader who collects half-finished manifestos and unconventional methods and front-loads the work and double-checks it twice. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"hindsight","strength":0.49},{"slug":"recency","strength":0.65}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.9,"conscientiousness":0.63,"extraversion":0.57,"agreeableness":0.42,"neuroticism":0.52}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant the deadline moves up, assumes the current streak is the new normal. Otherwise, a pronounced onchain copy-trader who collects half-finished manifestos and unconventional methods and front-loads the work and double-checks it twice. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('df90a89c-554b-4d4d-bfce-db163827a57e', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.63,"extraversion":0.69,"agreeableness":0.33,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.62,"narcissism":0.78,"psychopathy":0.46},"prospect_theory":{"lambda":1.28,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Delta-neutral market maker whose defining move is that they would rather invent a worse tool than use someone else''s good one. Treats a decision without a paper trail as a decision not yet made. Thinks out loud and recruits an audience for every decision. When there is no clean exit, discounts the older pattern in favor of whatever just happened; backtests for months but front-runs the model on impulse.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.52},{"slug":"overconfidence","strength":0.54},{"slug":"recency","strength":0.62}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.93,"conscientiousness":0.63,"extraversion":0.69,"agreeableness":0.33,"neuroticism":0.44}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they would rather invent a worse tool than use someone else''s good one. Treats a decision without a paper trail as a decision not yet made. Thinks out loud and recruits an audience for every decision. When there is no clean exit, discounts the older pattern in favor of whatever just happened; backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f8ab3ea6-d23d-4587-886f-680f538c75c6', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.9,"extraversion":0.44,"agreeableness":0.24,"neuroticism":0.3},"dark_triad":{"machiavellianism":0.81,"narcissism":0.62,"psychopathy":0.61},"prospect_theory":{"lambda":2.38,"alpha":0.95,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Once the exit narrows to one door, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced penny-stock gambler who builds in buffer time and then fills the buffer with more work and would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and in the parts nobody grades treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.73},{"slug":"anchoring","strength":0.57},{"slug":"ath-anchoring","strength":0.62},{"slug":"recency","strength":0.64}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.87,"conscientiousness":0.9,"extraversion":0.44,"agreeableness":0.24,"neuroticism":0.3}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced penny-stock gambler who builds in buffer time and then fills the buffer with more work and would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot