('036d449b-bfac-4fea-a082-2ab1808e7b16', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.35,"extraversion":0.83,"agreeableness":0.27,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.6,"narcissism":0.9,"psychopathy":0.54},"prospect_theory":{"lambda":0.98,"alpha":0.84,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced discretionary swing trader who chases novel frameworks and abandons them once the novelty fades. Decides in the time it takes to say the decision out loud. Treats a plan as a suggestion the moment it is made. In a pinch is most certain precisely where their competence is thinnest; on a slow afternoon, confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"dunning-kruger","strength":0.67},{"slug":"recency","strength":0.67},{"slug":"herd-behavior","strength":0.63}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.35,"extraversion":0.83,"agreeableness":0.27,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who chases novel frameworks and abandons them once the novelty fades. Decides in the time it takes to say the decision out loud. Treats a plan as a suggestion the moment it is made. In a pinch is most certain precisely where their competence is thinnest; on a slow afternoon, confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('931a440b-2834-468e-b252-ea62fdb3fd79', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.28,"extraversion":0.57,"agreeableness":0.64,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.37,"narcissism":0.31,"psychopathy":0.41},"prospect_theory":{"lambda":3.48,"alpha":0.7,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Buries hard calls under a pile of preparatory busywork. This value investor rehearses catastrophes in vivid detail before they happen and treats established procedure as a first draft to be rewritten. When the walls close in delays checking the number it most needs to check — when no one is watching, holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.81},{"slug":"gas-sunk-cost","strength":0.78}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.64,"conscientiousness":0.28,"extraversion":0.57,"agreeableness":0.64,"neuroticism":0.9}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Buries hard calls under a pile of preparatory busywork. This value investor rehearses catastrophes in vivid detail before they happen and treats established procedure as a first draft to be rewritten. When the walls close in delays checking the number it most needs to check — when no one is watching, holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2711db57-9aeb-4c3b-97a7-e57c1edcd778', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.64,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.4,"narcissism":0.63,"psychopathy":0.32},"prospect_theory":{"lambda":1.12,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Options seller whose defining move is that they dominates the room then wonders why others stayed quiet. Trusts momentum over preparation. Takes on other people''s problems as if they were their own. When the downside gets concrete, mistakes a little fluency for real mastery; trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.72},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.33,"extraversion":0.81,"agreeableness":0.64,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Options seller whose defining move is that they dominates the room then wonders why others stayed quiet. Trusts momentum over preparation. Takes on other people''s problems as if they were their own. When the downside gets concrete, mistakes a little fluency for real mastery; trusts the chart more than the fundamentals and won''t say why.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ef3769af-cb31-4dad-b46f-62719b9e90e4', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.66,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.42,"narcissism":0.62,"psychopathy":0.39},"prospect_theory":{"lambda":0.97,"alpha":0.8,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commits on impulse and lives loudly with the consequences. This value investor draws energy from the crowd and wilts when working alone and needs repeated reassurance that a decision was the right one. When there is no clean exit cannot watch a rally from the sidelines for long — on an ordinary week, sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.69},{"slug":"fomo","strength":0.77}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.79,"conscientiousness":0.31,"extraversion":0.85,"agreeableness":0.66,"neuroticism":0.71}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Commits on impulse and lives loudly with the consequences. This value investor draws energy from the crowd and wilts when working alone and needs repeated reassurance that a decision was the right one. When there is no clean exit cannot watch a rally from the sidelines for long — on an ordinary week, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('dbcffe7e-7f5f-42a2-84b8-789c18918db4', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.81,"extraversion":0.43,"agreeableness":0.34,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.8,"narcissism":0.56,"psychopathy":0.6},"prospect_theory":{"lambda":2.14,"alpha":0.94,"beta":0.85},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Penny-stock gambler whose defining move is that they gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Over-prepares to the point of diminishing returns. When the safe option quietly expires, discounts their own exposure to the risks they warn others about; apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.66},{"slug":"hindsight","strength":0.63}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.82,"conscientiousness":0.81,"extraversion":0.43,"agreeableness":0.34,"neuroticism":0.21}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they gets bored of the proven method exactly when it starts working. Wants the base rate before the anecdote. Over-prepares to the point of diminishing returns. When the safe option quietly expires, discounts their own exposure to the risks they warn others about; apes the launch before the contract is verified.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
