('8de35a0e-3ed9-4363-ae47-086b30e61e06', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.49,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.48,"narcissism":0.68,"psychopathy":0.4},"prospect_theory":{"lambda":1.08,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced delta-neutral market maker who collects half-finished manifestos and unconventional methods. Treats a decision without a paper trail as a decision not yet made. Fills silence reflexively, even when nobody asked it to. The instant it becomes irreversible is most certain precisely where their competence is thinnest; day to day, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"bandwagon","strength":0.51},{"slug":"dunning-kruger","strength":0.56},{"slug":"recency","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.49,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.5}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced delta-neutral market maker who collects half-finished manifestos and unconventional methods. Treats a decision without a paper trail as a decision not yet made. Fills silence reflexively, even when nobody asked it to. The instant it becomes irreversible is most certain precisely where their competence is thinnest; day to day, trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
