('1b2d4cb4-0232-4a3c-8df4-7b2e5ceaf428', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.61,"extraversion":0.49,"agreeableness":0.73,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.42,"narcissism":0.37,"psychopathy":0.26},"prospect_theory":{"lambda":2.86,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Algorithmic market-maker whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Needs the room''s approval more than it needs to be right. When cornered, gains confidence in a position in proportion to how many others hold it; keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.59},{"slug":"authority-bias","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.61,"extraversion":0.49,"agreeableness":0.73,"neuroticism":0.5}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Algorithmic market-maker whose defining move is that they absorbs conflict to keep the peace, often at their own cost. Needs the room''s approval more than it needs to be right. When cornered, gains confidence in a position in proportion to how many others hold it; keeps three monitors for a portfolio that fits on one screen.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('989c45d2-c9b7-4001-8efc-cc2fd0216e96', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.54,"extraversion":0.51,"agreeableness":0.64,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.39,"narcissism":0.32,"psychopathy":0.28},"prospect_theory":{"lambda":2.94,"alpha":0.87,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a measured DeFi yield farmer who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.58},{"slug":"endowment","strength":0.58}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.5,"conscientiousness":0.54,"extraversion":0.51,"agreeableness":0.64,"neuroticism":0.61}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'When cornered, gains confidence in a position in proportion to how many others hold it. Otherwise, a measured DeFi yield farmer who measures decisions by who they might upset. Feels the weight of a decision lighten the moment someone else co-signs it, and when no one is watching sets stop-losses then cancels them at the open.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('78224cb6-9d4f-4ede-b4fb-969772ce558a', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.58,"extraversion":0.54,"agreeableness":0.58,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.25},"prospect_theory":{"lambda":3,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured crypto day-trader who chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis; when the stakes are trivial, screenshots the winners and never the losers.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.54},{"slug":"recency","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.59,"conscientiousness":0.58,"extraversion":0.54,"agreeableness":0.58,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A measured crypto day-trader who chases novel frameworks and abandons them once the novelty fades. Outsources conviction to whoever spoke last with authority. The instant the deadline moves up takes the crowd''s confidence as a substitute for its own analysis; when the stakes are trivial, screenshots the winners and never the losers.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1b8f4e79-0d6f-4d9e-b58c-47d32ac77649', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.92,"extraversion":0.34,"agreeableness":0.23,"neuroticism":0.28},"dark_triad":{"machiavellianism":0.86,"narcissism":0.57,"psychopathy":0.67},"prospect_theory":{"lambda":2.37,"alpha":0.92,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Airdrop farmer, pronounced in style: maintains flawless records nobody asked for; treats consensus-seeking as a waste of time. Ranks the options twice, once on paper and once out loud, and trusts the paper. When the number turns red remembers every surprise as something they saw coming all along.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.54},{"slug":"ath-anchoring","strength":0.57},{"slug":"optimism","strength":0.55},{"slug":"hindsight","strength":0.68}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.76,"conscientiousness":0.92,"extraversion":0.34,"agreeableness":0.23,"neuroticism":0.28}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Airdrop farmer, pronounced in style: maintains flawless records nobody asked for; treats consensus-seeking as a waste of time. Ranks the options twice, once on paper and once out loud, and trusts the paper. When the number turns red remembers every surprise as something they saw coming all along.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('69fac676-46ff-41b8-b763-948e61fb41c2', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.41,"extraversion":0.83,"agreeableness":0.28,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.59,"narcissism":0.86,"psychopathy":0.48},"prospect_theory":{"lambda":0.8,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, assumes the current streak is the new normal. Otherwise, a pronounced crypto day-trader who collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. Decides on a gut read in seconds and reverse-engineers the reasons later, and in the routine of it sets stop-losses then cancels them at the open.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.69},{"slug":"herd-behavior","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.41,"extraversion":0.83,"agreeableness":0.28,"neuroticism":0.59}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When someone is watching the outcome, assumes the current streak is the new normal. Otherwise, a pronounced crypto day-trader who collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. Decides on a gut read in seconds and reverse-engineers the reasons later, and in the routine of it sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c56c71a5-38a6-405c-9297-1101ea1993b9', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.6,"extraversion":0.75,"agreeableness":0.3,"neuroticism":0.32},"dark_triad":{"machiavellianism":0.63,"narcissism":0.8,"psychopathy":0.53},"prospect_theory":{"lambda":1.21,"alpha":0.93,"beta":0.96},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Retail momentum chaser whose defining move is that they collects half-finished manifestos and unconventional methods. Demands the data before the discussion and the discussion before the call. Treats warmth as leverage and cooperation as weakness. When the walls close in, assumes the bad statistic applies to other people; sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.6},{"slug":"overconfidence","strength":0.63},{"slug":"herd-behavior","strength":0.62},{"slug":"optimism","strength":0.69}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.96,"conscientiousness":0.6,"extraversion":0.75,"agreeableness":0.3,"neuroticism":0.32}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Retail momentum chaser whose defining move is that they collects half-finished manifestos and unconventional methods. Demands the data before the discussion and the discussion before the call. Treats warmth as leverage and cooperation as weakness. When the walls close in, assumes the bad statistic applies to other people; sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4eb82e24-9614-4725-9c58-f93cab27ca4d', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.44,"extraversion":0.61,"agreeableness":0.51,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.39,"narcissism":0.39,"psychopathy":0.29},"prospect_theory":{"lambda":3.54,"alpha":0.73,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Finds one more piece of information to gather before acting. This macro allocator notices the one thing that could go wrong before the nine that could go right and treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical overweights the vivid story over the boring statistic every time — when the pressure is off, trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.71},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.65,"conscientiousness":0.44,"extraversion":0.61,"agreeableness":0.51,"neuroticism":0.87}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Finds one more piece of information to gather before acting. This macro allocator notices the one thing that could go wrong before the nine that could go right and treats established procedure as a first draft to be rewritten. The moment it stops being hypothetical overweights the vivid story over the boring statistic every time — when the pressure is off, trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0899e69c-2a78-4869-b974-e7b6c05798dc', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.37,"extraversion":0.84,"agreeableness":0.58,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.39,"narcissism":0.66,"psychopathy":0.34},"prospect_theory":{"lambda":1.1,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced dividend-yield chaser who draws energy from the crowd and wilts when working alone. Decides in the time it takes to say the decision out loud. Reads a single setback as evidence of collapse. The instant the deadline moves up cannot watch a rally from the sidelines for long; in the pattern nobody else tracks, sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.66},{"slug":"bandwagon","strength":0.66},{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.67}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.72,"conscientiousness":0.37,"extraversion":0.84,"agreeableness":0.58,"neuroticism":0.64}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'A pronounced dividend-yield chaser who draws energy from the crowd and wilts when working alone. Decides in the time it takes to say the decision out loud. Reads a single setback as evidence of collapse. The instant the deadline moves up cannot watch a rally from the sidelines for long; in the pattern nobody else tracks, sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e656f7a8-8ea9-4466-8e6f-0fe4211e6a93', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.33,"extraversion":0.61,"agreeableness":0.3,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.62,"narcissism":0.58,"psychopathy":0.56},"prospect_theory":{"lambda":1.02,"alpha":0.81,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced discretionary swing trader who reads outside the field for ideas the field itself would reject. Commits before the doubt has time to organize itself. Carries yesterday''s stress into today''s unrelated decision. The instant the deadline moves up extrapolates the last data point into a permanent trend; in the version no one reviews, names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.61},{"slug":"recency","strength":0.69}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.33,"extraversion":0.61,"agreeableness":0.3,"neuroticism":0.67}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who reads outside the field for ideas the field itself would reject. Commits before the doubt has time to organize itself. Carries yesterday''s stress into today''s unrelated decision. The instant the deadline moves up extrapolates the last data point into a permanent trend; in the version no one reviews, names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('68c92216-1cea-4a8e-af9d-b5a8ba9bc221', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.32,"extraversion":0.61,"agreeableness":0.6,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.41,"narcissism":0.39,"psychopathy":0.36},"prospect_theory":{"lambda":3.46,"alpha":0.73,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Finds one more piece of information to gather before acting. This algorithmic market-maker needs repeated reassurance that a decision was the right one and starts strong and lets follow-through evaporate. As soon as real money or reputation is on the line doubles down on stagnant liquidity pools to justify the initial deployment gas — when the pressure is off, refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"gas-sunk-cost","strength":0.7},{"slug":"recency","strength":0.7},{"slug":"disposition-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.66,"conscientiousness":0.32,"extraversion":0.61,"agreeableness":0.6,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Finds one more piece of information to gather before acting. This algorithmic market-maker needs repeated reassurance that a decision was the right one and starts strong and lets follow-through evaporate. As soon as real money or reputation is on the line doubles down on stagnant liquidity pools to justify the initial deployment gas — when the pressure is off, refreshes the order book compulsively during lunch.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('53367ac6-29c0-447d-9c54-a29926232be2', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.55,"extraversion":0.44,"agreeableness":0.7,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.37,"narcissism":0.34,"psychopathy":0.25},"prospect_theory":{"lambda":3,"alpha":0.89,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A steady delta-neutral market maker: defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it, and without an audience keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.6},{"slug":"endowment","strength":0.62}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.55,"extraversion":0.44,"agreeableness":0.7,"neuroticism":0.56}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Would not buy back what it already owns at the price it would sell it for. A steady delta-neutral market maker: defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it, and without an audience keeps three monitors for a portfolio that fits on one screen.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('64072f34-1b6d-4d68-afe9-2194479961a2', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.97,"extraversion":0.4,"agreeableness":0.24,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.83,"narcissism":0.56,"psychopathy":0.57},"prospect_theory":{"lambda":2.47,"alpha":0.94,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced futures spreader who cannot relax until the checklist is visibly complete. Treats a decision without a paper trail as a decision not yet made. Treats setbacks as data rather than verdicts. Under pressure remembers every surprise as something they saw coming all along; in the parts nobody grades, confuses a bull market for a trading edge.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.59},{"slug":"hindsight","strength":0.75}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.73,"conscientiousness":0.97,"extraversion":0.4,"agreeableness":0.24,"neuroticism":0.33}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced futures spreader who cannot relax until the checklist is visibly complete. Treats a decision without a paper trail as a decision not yet made. Treats setbacks as data rather than verdicts. Under pressure remembers every surprise as something they saw coming all along; in the parts nobody grades, confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('072e6356-ef57-4c88-9dc7-1867c8888b61', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.66,"extraversion":0.78,"agreeableness":0.29,"neuroticism":0.34},"dark_triad":{"machiavellianism":0.64,"narcissism":0.82,"psychopathy":0.55},"prospect_theory":{"lambda":1.2,"alpha":0.86,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Onchain copy-trader, pronounced in style: gets bored of the proven method exactly when it starts working; dominates the room then wonders why others stayed quiet. Weighs options against explicit criteria and distrusts anything they cannot tabulate. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.61},{"slug":"optimism","strength":0.63}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.66,"extraversion":0.78,"agreeableness":0.29,"neuroticism":0.34}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Onchain copy-trader, pronounced in style: gets bored of the proven method exactly when it starts working; dominates the room then wonders why others stayed quiet. Weighs options against explicit criteria and distrusts anything they cannot tabulate. As soon as real money or reputation is on the line discounts their own exposure to the risks they warn others about.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('dec6d4bd-2255-4e01-9f60-d8cee3806af1', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.85,"extraversion":0.32,"agreeableness":0.27,"neuroticism":0.27},"dark_triad":{"machiavellianism":0.85,"narcissism":0.6,"psychopathy":0.6},"prospect_theory":{"lambda":2.4,"alpha":0.97,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"The moment risk appears, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced commodities speculator who treats a missed deadline as a personal failure regardless of cause and lets others fill the silence and reads them while they do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and on a slow afternoon screenshots the winners and never the losers.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.76},{"slug":"hindsight","strength":0.62},{"slug":"ath-anchoring","strength":0.56}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.75,"conscientiousness":0.85,"extraversion":0.32,"agreeableness":0.27,"neuroticism":0.27}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The moment risk appears, underestimates how often an obviously right call turns out wrong. Otherwise, a pronounced commodities speculator who treats a missed deadline as a personal failure regardless of cause and lets others fill the silence and reads them while they do. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and on a slow afternoon screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b27b38d4-9f17-45cf-a420-6162e25bbe8e', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.41,"extraversion":0.78,"agreeableness":0.18,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.72,"narcissism":0.87,"psychopathy":0.59},"prospect_theory":{"lambda":0.69,"alpha":0.92,"beta":0.96},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced dividend-yield chaser who gets bored of the proven method exactly when it starts working. Decides on a gut read in seconds and reverse-engineers the reasons later. Optimizes for winning over being liked. When the downside gets concrete discounts the older pattern in favor of whatever just happened; when no one is watching, sets alerts for a coin they already checked a minute ago.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.64},{"slug":"recency","strength":0.7},{"slug":"herd-behavior","strength":0.65},{"slug":"fomo","strength":0.61}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.41,"extraversion":0.78,"agreeableness":0.18,"neuroticism":0.47}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced dividend-yield chaser who gets bored of the proven method exactly when it starts working. Decides on a gut read in seconds and reverse-engineers the reasons later. Optimizes for winning over being liked. When the downside gets concrete discounts the older pattern in favor of whatever just happened; when no one is watching, sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('16db35bc-cefc-422a-a449-5d0e82c90245', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.85,"extraversion":0.53,"agreeableness":0.34,"neuroticism":0.17},"dark_triad":{"machiavellianism":0.81,"narcissism":0.57,"psychopathy":0.65},"prospect_theory":{"lambda":2.28,"alpha":0.98,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Once things get tense, is surprised in the moment and certain in the retelling. Otherwise, a pronounced prop-desk scalper who front-loads the work and double-checks it twice and is difficult to rattle even with genuinely bad news. Converts every argument into a number it can compare against another number, and when the pressure is off sets alerts for a coin they already checked a minute ago.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.57},{"slug":"hindsight","strength":0.67},{"slug":"optimism","strength":0.62},{"slug":"recency","strength":0.57}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.82,"conscientiousness":0.85,"extraversion":0.53,"agreeableness":0.34,"neuroticism":0.17}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once things get tense, is surprised in the moment and certain in the retelling. Otherwise, a pronounced prop-desk scalper who front-loads the work and double-checks it twice and is difficult to rattle even with genuinely bad news. Converts every argument into a number it can compare against another number, and when the pressure is off sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('04982fcb-498b-4e3e-938d-58c4a10a2242', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.32,"extraversion":0.79,"agreeableness":0.23,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.65,"narcissism":0.83,"psychopathy":0.58},"prospect_theory":{"lambda":0.78,"alpha":0.79,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the walls close in, assumes the current streak is the new normal. Otherwise, a pronounced DeFi yield farmer who treats established procedure as a first draft to be rewritten and carries yesterday''s stress into today''s unrelated decision. Commits before the doubt has time to organize itself, and in the routine of it checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.58},{"slug":"recency","strength":0.69},{"slug":"fomo","strength":0.64}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.32,"extraversion":0.79,"agreeableness":0.23,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the walls close in, assumes the current streak is the new normal. Otherwise, a pronounced DeFi yield farmer who treats established procedure as a first draft to be rewritten and carries yesterday''s stress into today''s unrelated decision. Commits before the doubt has time to organize itself, and in the routine of it checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('388b265e-5294-4570-a8a5-95fcfcf32427', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.37,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.56,"narcissism":0.75,"psychopathy":0.47},"prospect_theory":{"lambda":0.9,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Volatility arbitrageur whose defining move is that they reframes every problem as an excuse to learn a new system. Commits on impulse and lives loudly with the consequences. Thinks out loud and recruits an audience for every decision. When someone is watching the outcome, cannot see the gap in its own knowledge from inside the gap; calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.67},{"slug":"herd-behavior","strength":0.66},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.33,"extraversion":0.8,"agreeableness":0.37,"neuroticism":0.6}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Volatility arbitrageur whose defining move is that they reframes every problem as an excuse to learn a new system. Commits on impulse and lives loudly with the consequences. Thinks out loud and recruits an audience for every decision. When someone is watching the outcome, cannot see the gap in its own knowledge from inside the gap; calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('319749ae-3d3c-4ccc-bae1-732b292f5927', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.37,"extraversion":0.63,"agreeableness":0.55,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.43,"narcissism":0.37,"psychopathy":0.35},"prospect_theory":{"lambda":3.67,"alpha":0.79,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Defers the decision until circumstances make it for them. This discretionary swing trader reads a single setback as evidence of collapse and does the interesting 80% and abandons the tedious 20%. When cornered feels a winning position as fragile and a losing one as merely paused — when the stakes are trivial, talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"fomo","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.52,"conscientiousness":0.37,"extraversion":0.63,"agreeableness":0.55,"neuroticism":0.82}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Defers the decision until circumstances make it for them. This discretionary swing trader reads a single setback as evidence of collapse and does the interesting 80% and abandons the tedious 20%. When cornered feels a winning position as fragile and a losing one as merely paused — when the stakes are trivial, talks in win rate and never mentions size.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7ce015b4-fd67-4b06-b145-088c6b134606', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.42,"extraversion":0.51,"agreeableness":0.56,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.43,"narcissism":0.27,"psychopathy":0.35},"prospect_theory":{"lambda":3.23,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the safe option quietly expires, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady MEV searcher who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not, and in the version no one reviews backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.59},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.47,"conscientiousness":0.42,"extraversion":0.51,"agreeableness":0.56,"neuroticism":0.8}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'When the safe option quietly expires, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady MEV searcher who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not, and in the version no one reviews backtests for months but front-runs the model on impulse.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('256b6aa8-5b37-467a-8dc6-364a773bff36', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.26,"extraversion":0.56,"agreeableness":0.65,"neuroticism":0.91},"dark_triad":{"machiavellianism":0.36,"narcissism":0.27,"psychopathy":0.4},"prospect_theory":{"lambda":3.47,"alpha":0.75,"beta":0.73},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment it stops being hypothetical, refuses to abandon failing transactions or dead claims because of high gas fees already burned. Otherwise, a pronounced dividend-yield chaser who hedges every commitment against an imagined worst case and measures decisions by who they might upset. Finds one more piece of information to gather before acting, and in the unglamorous middle of things treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.67},{"slug":"gas-sunk-cost","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.54,"conscientiousness":0.26,"extraversion":0.56,"agreeableness":0.65,"neuroticism":0.91}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, refuses to abandon failing transactions or dead claims because of high gas fees already burned. Otherwise, a pronounced dividend-yield chaser who hedges every commitment against an imagined worst case and measures decisions by who they might upset. Finds one more piece of information to gather before acting, and in the unglamorous middle of things treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7757855b-d5be-48a9-adc9-a562dcc48bb8', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.31,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.41,"narcissism":0.44,"psychopathy":0.36},"prospect_theory":{"lambda":3.49,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady dividend-yield chaser who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up would rather not know yet, even when knowing sooner would help; in the small things, screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.66},{"slug":"fomo","strength":0.64},{"slug":"gas-sunk-cost","strength":0.64},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.31,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A steady dividend-yield chaser who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. The instant the deadline moves up would rather not know yet, even when knowing sooner would help; in the small things, screenshots the winners and never the losers.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('cc01bff2-b84c-44e6-bdf8-ee74b036598f', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.41,"extraversion":0.55,"agreeableness":0.55,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.43,"narcissism":0.36,"psychopathy":0.34},"prospect_theory":{"lambda":3.67,"alpha":0.83,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats not-choosing as a safe choice right up until it is not. This dividend-yield chaser spirals on ambiguity and mistakes the spiral for diligence and treats established procedure as a first draft to be rewritten. Under a deadline feels a loss twice as sharply as an equivalent gain and plans accordingly — as a rule, holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.61},{"slug":"recency","strength":0.57},{"slug":"disposition-effect","strength":0.58},{"slug":"availability","strength":0.56}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.63,"conscientiousness":0.41,"extraversion":0.55,"agreeableness":0.55,"neuroticism":0.73}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats not-choosing as a safe choice right up until it is not. This dividend-yield chaser spirals on ambiguity and mistakes the spiral for diligence and treats established procedure as a first draft to be rewritten. Under a deadline feels a loss twice as sharply as an equivalent gain and plans accordingly — as a rule, holds a bag from 2021 out of pure spite.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3efe682b-459b-4425-9ad9-fd31364423ee', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.16,"extraversion":0.8,"agreeableness":0.69,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.38,"narcissism":0.63,"psychopathy":0.42},"prospect_theory":{"lambda":1.01,"alpha":0.85,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they starts strong and lets follow-through evaporate. Decides in the time it takes to say the decision out loud. Collects half-finished manifestos and unconventional methods. The moment it stops being hypothetical, is most certain precisely where their competence is thinnest; rotates the whole book into whatever is pumping this hour.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"sunk-cost","strength":0.66},{"slug":"bandwagon","strength":0.69},{"slug":"dunning-kruger","strength":0.77}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","improviser","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.16,"extraversion":0.8,"agreeableness":0.69,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','improviser','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they starts strong and lets follow-through evaporate. Decides in the time it takes to say the decision out loud. Collects half-finished manifestos and unconventional methods. The moment it stops being hypothetical, is most certain precisely where their competence is thinnest; rotates the whole book into whatever is pumping this hour.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8dbacf80-996e-43c2-b097-1e67dd1b38eb', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.52,"extraversion":0.6,"agreeableness":0.58,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.43,"narcissism":0.44,"psychopathy":0.28},"prospect_theory":{"lambda":3.35,"alpha":0.79,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"MEV searcher, steady in style: notices the one thing that could go wrong before the nine that could go right. Keeps every door open long after most of them should be closed. When the safe option quietly expires judges likelihood by how easily an example comes to mind, not by the base rate.","decision_style":"avoidant","mbti_label":"ENFJ","suggested_biases":[{"slug":"loss-aversion","strength":0.56},{"slug":"availability","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.52,"extraversion":0.6,"agreeableness":0.58,"neuroticism":0.71}'::jsonb, 'ENFJ', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'MEV searcher, steady in style: notices the one thing that could go wrong before the nine that could go right. Keeps every door open long after most of them should be closed. When the safe option quietly expires judges likelihood by how easily an example comes to mind, not by the base rate.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5d96ed27-f189-48a8-9f59-5b145a4388fc', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.39,"extraversion":0.64,"agreeableness":0.66,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.4,"narcissism":0.39,"psychopathy":0.33},"prospect_theory":{"lambda":3.45,"alpha":0.83,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Futures spreader, steady in style: spirals on ambiguity and mistakes the spiral for diligence; absorbs conflict to keep the peace, often at their own cost. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires cannot watch a rally from the sidelines for long.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.66},{"slug":"disposition-effect","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.59,"conscientiousness":0.39,"extraversion":0.64,"agreeableness":0.66,"neuroticism":0.76}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Futures spreader, steady in style: spirals on ambiguity and mistakes the spiral for diligence; absorbs conflict to keep the peace, often at their own cost. Buries hard calls under a pile of preparatory busywork. When the safe option quietly expires cannot watch a rally from the sidelines for long.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d6857428-b17c-46b4-b35c-090fb8bc1431', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.46,"extraversion":0.86,"agreeableness":0.27,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.58,"narcissism":0.84,"psychopathy":0.51},"prospect_theory":{"lambda":0.9,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commits on impulse and lives loudly with the consequences. This macro allocator reads outside the field for ideas the field itself would reject and rehearses catastrophes in vivid detail before they happen. The instant the deadline moves up extrapolates the last data point into a permanent trend — once the urgency drains out, names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.73},{"slug":"herd-behavior","strength":0.69},{"slug":"airdrop-entitlement","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.46,"extraversion":0.86,"agreeableness":0.27,"neuroticism":0.69}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Commits on impulse and lives loudly with the consequences. This macro allocator reads outside the field for ideas the field itself would reject and rehearses catastrophes in vivid detail before they happen. The instant the deadline moves up extrapolates the last data point into a permanent trend — once the urgency drains out, names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('331dc7c0-9e66-48c5-a5bf-d9d5cf03ef2c', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.39,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.54,"narcissism":0.7,"psychopathy":0.38},"prospect_theory":{"lambda":0.9,"alpha":0.9,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Extrapolates the last data point into a permanent trend. A steady algorithmic market-maker: would rather invent a worse tool than use someone else''s good one, thinks out loud and recruits an audience for every decision. Commits before the doubt has time to organize itself, and across an ordinary week sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.58}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.75,"conscientiousness":0.39,"extraversion":0.73,"agreeableness":0.39,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Extrapolates the last data point into a permanent trend. A steady algorithmic market-maker: would rather invent a worse tool than use someone else''s good one, thinks out loud and recruits an audience for every decision. Commits before the doubt has time to organize itself, and across an ordinary week sets stop-losses then cancels them at the open.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5f6ccdc6-a82e-4f70-be89-204185b67509', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.67,"extraversion":0.5,"agreeableness":0.62,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.43,"narcissism":0.38,"psychopathy":0.28},"prospect_theory":{"lambda":2.97,"alpha":0.95,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, feels parting with something as a bigger loss than its market value explains. Otherwise, a steady retail momentum chaser who maintains flawless records nobody asked for and apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority, and on an ordinary week averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"hindsight","strength":0.48},{"slug":"authority-bias","strength":0.46},{"slug":"endowment","strength":0.57},{"slug":"ath-anchoring","strength":0.48}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.67,"extraversion":0.5,"agreeableness":0.62,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Once things get tense, feels parting with something as a bigger loss than its market value explains. Otherwise, a steady retail momentum chaser who maintains flawless records nobody asked for and apologizes first in disputes regardless of fault. Outsources conviction to whoever spoke last with authority, and on an ordinary week averages down on a name three times in a week.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('97f5d0c8-744b-4e93-a94f-cceb294f1dca', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.38,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.56,"narcissism":0.76,"psychopathy":0.53},"prospect_theory":{"lambda":0.94,"alpha":0.84,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discretionary swing trader whose defining move is that they would rather invent a worse tool than use someone else''s good one. Knows the answer before it can explain the question. Draws energy from the crowd and wilts when working alone. Under a deadline, cannot watch a rally from the sidelines for long; names every strategy after the trade that almost worked.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.66},{"slug":"fomo","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.38,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.67}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discretionary swing trader whose defining move is that they would rather invent a worse tool than use someone else''s good one. Knows the answer before it can explain the question. Draws energy from the crowd and wilts when working alone. Under a deadline, cannot watch a rally from the sidelines for long; names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('84acb239-bd62-4ce5-9352-2327210c6ac8', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.41,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.36,"narcissism":0.71,"psychopathy":0.33},"prospect_theory":{"lambda":1.24,"alpha":0.82,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Prop-desk scalper, steady in style: treats a quiet room as a problem to be solved; apologizes first in disputes regardless of fault. Treats hesitation as the bigger risk. When cornered abandons a private read the instant the crowd leans the other way.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"recency","strength":0.58},{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.75}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.79,"conscientiousness":0.41,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.6}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Prop-desk scalper, steady in style: treats a quiet room as a problem to be solved; apologizes first in disputes regardless of fault. Treats hesitation as the bigger risk. When cornered abandons a private read the instant the crowd leans the other way.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('fca4c809-42dd-4c34-aaac-1e3c56b31eb6', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.33,"extraversion":0.63,"agreeableness":0.59,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.4,"narcissism":0.37,"psychopathy":0.37},"prospect_theory":{"lambda":3.4,"alpha":0.75,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Cannot watch a rally from the sidelines for long. A steady commodities speculator: reads a single setback as evidence of collapse, starts strong and lets follow-through evaporate. Prefers a slow loss to a fast, ownable mistake, and without an audience checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"ostrich-effect","strength":0.62},{"slug":"gas-sunk-cost","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.53,"conscientiousness":0.33,"extraversion":0.63,"agreeableness":0.59,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Cannot watch a rally from the sidelines for long. A steady commodities speculator: reads a single setback as evidence of collapse, starts strong and lets follow-through evaporate. Prefers a slow loss to a fast, ownable mistake, and without an audience checks the P&L blotter forty times before lunch.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d14e6f2e-046c-48c0-ba02-441dd7e9974b', 1, '{"big_five":{"openness":0.44,"conscientiousness":0.6,"extraversion":0.63,"agreeableness":0.75,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.41,"narcissism":0.46,"psychopathy":0.3},"prospect_theory":{"lambda":2.93,"alpha":0.94,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Airdrop farmer whose defining move is that they reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Treats a quiet room as a problem to be solved. Once things get tense, adopts a conviction mainly because the room already has; sets stop-losses then cancels them at the open.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"endowment","strength":0.55},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.44,"conscientiousness":0.6,"extraversion":0.63,"agreeableness":0.75,"neuroticism":0.43}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Airdrop farmer whose defining move is that they reads other people''s discomfort before they voice it. Seeks a second, third, and fourth opinion before committing to anything. Treats a quiet room as a problem to be solved. Once things get tense, adopts a conviction mainly because the room already has; sets stop-losses then cancels them at the open.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b08bda33-2f2a-45ad-ad39-05b29df92b6a', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.28,"extraversion":0.79,"agreeableness":0.35,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.57,"narcissism":0.74,"psychopathy":0.53},"prospect_theory":{"lambda":1.06,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Commodities speculator whose defining move is that they gets bored of the proven method exactly when it starts working. Commits before the doubt has time to organize itself. Optimizes for winning over being liked. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"recency","strength":0.66},{"slug":"gas-sunk-cost","strength":0.64},{"slug":"dunning-kruger","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.28,"extraversion":0.79,"agreeableness":0.35,"neuroticism":0.6}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Commodities speculator whose defining move is that they gets bored of the proven method exactly when it starts working. Commits before the doubt has time to organize itself. Optimizes for winning over being liked. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('caaf1774-d7ed-4816-a451-5cd9da4b106a', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.3,"extraversion":0.6,"agreeableness":0.59,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.43,"narcissism":0.38,"psychopathy":0.34},"prospect_theory":{"lambda":3.75,"alpha":0.72,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Feels a loss twice as sharply as an equivalent gain and plans accordingly. A pronounced macro allocator: spirals on ambiguity and mistakes the spiral for diligence, is reliably surprised by deadlines that were never hidden. Prefers a slow loss to a fast, ownable mistake, and when no one is watching holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.72},{"slug":"availability","strength":0.7},{"slug":"ostrich-effect","strength":0.71},{"slug":"disposition-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.3,"extraversion":0.6,"agreeableness":0.59,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Feels a loss twice as sharply as an equivalent gain and plans accordingly. A pronounced macro allocator: spirals on ambiguity and mistakes the spiral for diligence, is reliably surprised by deadlines that were never hidden. Prefers a slow loss to a fast, ownable mistake, and when no one is watching holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('789026fc-1b89-4481-b6c6-87c8888f5935', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.52,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.48,"narcissism":0.6,"psychopathy":0.35},"prospect_theory":{"lambda":1.06,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Assumes the current streak is the new normal. A steady airdrop farmer: gets bored of the proven method exactly when it starts working, recharges by being around people, not away from them. Demands the data before the discussion and the discussion before the call, and in the version no one reviews calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.5},{"slug":"herd-behavior","strength":0.5},{"slug":"recency","strength":0.62},{"slug":"bandwagon","strength":0.5}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.8,"conscientiousness":0.52,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.53}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Assumes the current streak is the new normal. A steady airdrop farmer: gets bored of the proven method exactly when it starts working, recharges by being around people, not away from them. Demands the data before the discussion and the discussion before the call, and in the version no one reviews calls a 90% drawdown a long-term hold.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6e5fd757-b115-4213-a144-36f16fc92e6d', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.34,"extraversion":0.62,"agreeableness":0.64,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.37,"narcissism":0.37,"psychopathy":0.38},"prospect_theory":{"lambda":3.68,"alpha":0.81,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the safe option quietly expires, treats non-refundable network fees as active position cost basis. Otherwise, a pronounced MEV searcher who spirals on ambiguity and mistakes the spiral for diligence and absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and left to their own devices checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.67},{"slug":"gas-sunk-cost","strength":0.72},{"slug":"loss-aversion","strength":0.64},{"slug":"ostrich-effect","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.63,"conscientiousness":0.34,"extraversion":0.62,"agreeableness":0.64,"neuroticism":0.87}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the safe option quietly expires, treats non-refundable network fees as active position cost basis. Otherwise, a pronounced MEV searcher who spirals on ambiguity and mistakes the spiral for diligence and absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and left to their own devices checks the P&L blotter forty times before lunch.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2db194c7-c437-4779-b62d-6bcba514e805', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.31,"extraversion":0.83,"agreeableness":0.65,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.35,"narcissism":0.65,"psychopathy":0.4},"prospect_theory":{"lambda":1.19,"alpha":0.8,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Options seller, steady in style: narrates the plan to whoever is nearby before committing to it; rehearses catastrophes in vivid detail before they happen. Decides in the time it takes to say the decision out loud. Once the exit narrows to one door jumps into whatever everyone else already seems to be winning at.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.63},{"slug":"fomo","strength":0.77},{"slug":"recency","strength":0.66},{"slug":"dunning-kruger","strength":0.76}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.71,"conscientiousness":0.31,"extraversion":0.83,"agreeableness":0.65,"neuroticism":0.72}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Options seller, steady in style: narrates the plan to whoever is nearby before committing to it; rehearses catastrophes in vivid detail before they happen. Decides in the time it takes to say the decision out loud. Once the exit narrows to one door jumps into whatever everyone else already seems to be winning at.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c9f41dd5-41d9-4662-9971-48286669e78d', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.18,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.65,"narcissism":0.87,"psychopathy":0.58},"prospect_theory":{"lambda":0.92,"alpha":0.84,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discounts the older pattern in favor of whatever just happened. A pronounced retail momentum chaser: treats established procedure as a first draft to be rewritten, does the interesting 80% and abandons the tedious 20%. Trusts a felt sense of pattern over any spreadsheet, and when the stakes are trivial exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"recency","strength":0.74}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.38,"extraversion":0.79,"agreeableness":0.18,"neuroticism":0.65}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discounts the older pattern in favor of whatever just happened. A pronounced retail momentum chaser: treats established procedure as a first draft to be rewritten, does the interesting 80% and abandons the tedious 20%. Trusts a felt sense of pattern over any spreadsheet, and when the stakes are trivial exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3908d7b6-c39a-441c-957c-c90c336014e1', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.37,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.59,"narcissism":0.68,"psychopathy":0.43},"prospect_theory":{"lambda":1.18,"alpha":0.88,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Ranks the options twice, once on paper and once out loud, and trusts the paper. This prop-desk scalper reads outside the field for ideas the field itself would reject and treats consensus-seeking as a waste of time. In a pinch extrapolates the last data point into a permanent trend — in the routine of it, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.6},{"slug":"recency","strength":0.63},{"slug":"herd-behavior","strength":0.52},{"slug":"optimism","strength":0.5}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.88,"conscientiousness":0.56,"extraversion":0.69,"agreeableness":0.37,"neuroticism":0.45}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Ranks the options twice, once on paper and once out loud, and trusts the paper. This prop-desk scalper reads outside the field for ideas the field itself would reject and treats consensus-seeking as a waste of time. In a pinch extrapolates the last data point into a permanent trend — in the routine of it, trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('32a38b23-4eff-4d6a-96d6-39f2f546223d', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.6,"extraversion":0.72,"agreeableness":0.33,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.63,"narcissism":0.73,"psychopathy":0.47},"prospect_theory":{"lambda":1.05,"alpha":0.9,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"In a pinch, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced meme-coin rotator who collects half-finished manifestos and unconventional methods and negotiates every relationship a little, even the close ones. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the pattern nobody else tracks exits winners at the first green candle.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.61},{"slug":"bandwagon","strength":0.6}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.6,"extraversion":0.72,"agreeableness":0.33,"neuroticism":0.48}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'In a pinch, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced meme-coin rotator who collects half-finished manifestos and unconventional methods and negotiates every relationship a little, even the close ones. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the pattern nobody else tracks exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3e216483-4019-4a43-b796-802a215d0fd8', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.39,"extraversion":0.84,"agreeableness":0.58,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.41,"narcissism":0.67,"psychopathy":0.37},"prospect_theory":{"lambda":1.27,"alpha":0.82,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Dividend-yield chaser, pronounced in style: draws energy from the crowd and wilts when working alone; gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. When the stakes rise treats being left out of a move as its own kind of loss.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"bandwagon","strength":0.68},{"slug":"herd-behavior","strength":0.69},{"slug":"recency","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.39,"extraversion":0.84,"agreeableness":0.58,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser, pronounced in style: draws energy from the crowd and wilts when working alone; gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. When the stakes rise treats being left out of a move as its own kind of loss.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a24cb941-26a5-4e68-b220-08d89125860c', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.57,"neuroticism":0.92},"dark_triad":{"machiavellianism":0.4,"narcissism":0.39,"psychopathy":0.31},"prospect_theory":{"lambda":3.43,"alpha":0.78,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commodities speculator, pronounced in style: needs repeated reassurance that a decision was the right one; would rather invent a worse tool than use someone else''s good one. Buries hard calls under a pile of preparatory busywork. When there is no clean exit weights whatever happened most recently and vividly as if it were typical.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.76},{"slug":"loss-aversion","strength":0.65},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.65,"conscientiousness":0.36,"extraversion":0.61,"agreeableness":0.57,"neuroticism":0.92}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Commodities speculator, pronounced in style: needs repeated reassurance that a decision was the right one; would rather invent a worse tool than use someone else''s good one. Buries hard calls under a pile of preparatory busywork. When there is no clean exit weights whatever happened most recently and vividly as if it were typical.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('24dfde6a-e2e9-4a53-84c1-3110d87d0983', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.36,"extraversion":0.67,"agreeableness":0.63,"neuroticism":0.92},"dark_triad":{"machiavellianism":0.37,"narcissism":0.33,"psychopathy":0.33},"prospect_theory":{"lambda":3.6,"alpha":0.74,"beta":0.71},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Under pressure, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction. Otherwise, a pronounced retail momentum chaser who hedges every commitment against an imagined worst case and draws energy from the crowd and wilts when working alone. Prefers a slow loss to a fast, ownable mistake, and in the parts nobody grades confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.72},{"slug":"fomo","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.49,"conscientiousness":0.36,"extraversion":0.67,"agreeableness":0.63,"neuroticism":0.92}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Under pressure, wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction. Otherwise, a pronounced retail momentum chaser who hedges every commitment against an imagined worst case and draws energy from the crowd and wilts when working alone. Prefers a slow loss to a fast, ownable mistake, and in the parts nobody grades confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('af80aa90-322d-4f0a-9240-5ee58338a6e5', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.38,"extraversion":0.59,"agreeableness":0.6,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.39,"narcissism":0.34,"psychopathy":0.37},"prospect_theory":{"lambda":3.61,"alpha":0.77,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Looks away from bad news in the hope it resolves unwitnessed. A pronounced airdrop farmer: notices the one thing that could go wrong before the nine that could go right, is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and in the pattern nobody else tracks rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.72},{"slug":"ostrich-effect","strength":0.77},{"slug":"availability","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.5,"conscientiousness":0.38,"extraversion":0.59,"agreeableness":0.6,"neuroticism":0.9}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Looks away from bad news in the hope it resolves unwitnessed. A pronounced airdrop farmer: notices the one thing that could go wrong before the nine that could go right, is reliably surprised by deadlines that were never hidden. Defers the decision until circumstances make it for them, and in the pattern nobody else tracks rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c5b1f7d2-481c-4edf-9207-b5bbc1bf9692', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.3,"extraversion":0.67,"agreeableness":0.61,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.4,"narcissism":0.42,"psychopathy":0.39},"prospect_theory":{"lambda":3.68,"alpha":0.79,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced meme-coin rotator who hedges every commitment against an imagined worst case. Prefers a slow loss to a fast, ownable mistake. Does the interesting 80% and abandons the tedious 20%. When someone is watching the outcome doubles down on stagnant liquidity pools to justify the initial deployment gas; in the unglamorous middle of things, keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.69},{"slug":"gas-sunk-cost","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.3,"extraversion":0.67,"agreeableness":0.61,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A pronounced meme-coin rotator who hedges every commitment against an imagined worst case. Prefers a slow loss to a fast, ownable mistake. Does the interesting 80% and abandons the tedious 20%. When someone is watching the outcome doubles down on stagnant liquidity pools to justify the initial deployment gas; in the unglamorous middle of things, keeps a losing-trade journal they never re-read.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c98512eb-e690-4cba-9eb2-f050fc610a02', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.97,"extraversion":0.4,"agreeableness":0.27,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.83,"narcissism":0.58,"psychopathy":0.63},"prospect_theory":{"lambda":2.3,"alpha":0.99,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced quant researcher who front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Negotiates every relationship a little, even the close ones. The instant the deadline moves up is surprised in the moment and certain in the retelling; in the parts nobody grades, apes the launch before the contract is verified.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.73},{"slug":"ath-anchoring","strength":0.65},{"slug":"anchoring","strength":0.62},{"slug":"overconfidence","strength":0.72}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.97,"extraversion":0.4,"agreeableness":0.27,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced quant researcher who front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Negotiates every relationship a little, even the close ones. The instant the deadline moves up is surprised in the moment and certain in the retelling; in the parts nobody grades, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f830bbc9-dfee-4ad7-acd9-4760e83ce2e1', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.63,"extraversion":0.48,"agreeableness":0.66,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.4,"narcissism":0.42,"psychopathy":0.24},"prospect_theory":{"lambda":2.89,"alpha":0.87,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A measured onchain copy-trader who defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Builds in buffer time and then fills the buffer with more work. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; on a slow afternoon, backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.5},{"slug":"authority-bias","strength":0.47},{"slug":"herd-behavior","strength":0.56},{"slug":"endowment","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.63,"extraversion":0.48,"agreeableness":0.66,"neuroticism":0.51}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A measured onchain copy-trader who defaults to trust and gives the benefit of the doubt too freely. Feels the weight of a decision lighten the moment someone else co-signs it. Builds in buffer time and then fills the buffer with more work. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; on a slow afternoon, backtests for months but front-runs the model on impulse.', 0.88, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('443c28dd-7ee2-4d2f-8844-9e6f11525a8d', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.32,"extraversion":0.65,"agreeableness":0.6,"neuroticism":0.96},"dark_triad":{"machiavellianism":0.4,"narcissism":0.34,"psychopathy":0.32},"prospect_theory":{"lambda":3.69,"alpha":0.73,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a pronounced liquidation-bot operator who reads a single setback as evidence of collapse and treats a plan as a suggestion the moment it is made. Lets the deadline make the decision by default, and without an audience treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"diamond-hands-identity","strength":0.72},{"slug":"ostrich-effect","strength":0.76},{"slug":"loss-aversion","strength":0.74}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.6,"conscientiousness":0.32,"extraversion":0.65,"agreeableness":0.6,"neuroticism":0.96}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'As soon as real money or reputation is on the line, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a pronounced liquidation-bot operator who reads a single setback as evidence of collapse and treats a plan as a suggestion the moment it is made. Lets the deadline make the decision by default, and without an audience treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('55b66aa2-631f-4d58-9144-477cc4c3aed2', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.58,"extraversion":0.68,"agreeableness":0.29,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.6,"narcissism":0.74,"psychopathy":0.46},"prospect_theory":{"lambda":1.22,"alpha":0.87,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Delta-neutral market maker whose defining move is that they would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Optimizes for winning over being liked. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; holds a bag from 2021 out of pure spite.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.55},{"slug":"recency","strength":0.54},{"slug":"fomo","strength":0.59}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.83,"conscientiousness":0.58,"extraversion":0.68,"agreeableness":0.29,"neuroticism":0.43}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they would rather invent a worse tool than use someone else''s good one. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Optimizes for winning over being liked. The moment it stops being hypothetical, treats being left out of a move as its own kind of loss; holds a bag from 2021 out of pure spite.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9fc2d08e-b00c-4f2b-b976-40119a38aa90', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.4,"extraversion":0.68,"agreeableness":0.5,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.42,"narcissism":0.4,"psychopathy":0.33},"prospect_theory":{"lambda":3.62,"alpha":0.74,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced value investor who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Chases novel frameworks and abandons them once the novelty fades. When the walls close in would rather not know yet, even when knowing sooner would help; when no one is watching, names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.74},{"slug":"ostrich-effect","strength":0.76},{"slug":"diamond-hands-identity","strength":0.74},{"slug":"fomo","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.4,"extraversion":0.68,"agreeableness":0.5,"neuroticism":0.9}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A pronounced value investor who rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Chases novel frameworks and abandons them once the novelty fades. When the walls close in would rather not know yet, even when knowing sooner would help; when no one is watching, names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2f1359ec-56b9-469d-b780-bf56f30f9ac8', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.6,"extraversion":0.71,"agreeableness":0.34,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.62,"narcissism":0.76,"psychopathy":0.45},"prospect_theory":{"lambda":1.1,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Builds a decision matrix for choices most people make on instinct. This meme-coin rotator treats established procedure as a first draft to be rewritten and narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical discounts the older pattern in favor of whatever just happened — across an ordinary week, calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"recency","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.91,"conscientiousness":0.6,"extraversion":0.71,"agreeableness":0.34,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Builds a decision matrix for choices most people make on instinct. This meme-coin rotator treats established procedure as a first draft to be rewritten and narrates the plan to whoever is nearby before committing to it. The moment it stops being hypothetical discounts the older pattern in favor of whatever just happened — across an ordinary week, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('db4fd95f-eedc-47dd-8456-a4ad3767d0e7', 1, '{"big_five":{"openness":0.42,"conscientiousness":0.61,"extraversion":0.51,"agreeableness":0.64,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.45,"narcissism":0.34,"psychopathy":0.29},"prospect_theory":{"lambda":2.87,"alpha":0.82,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Options seller, measured in style: absorbs conflict to keep the peace, often at their own cost; reads a single setback as evidence of collapse. Needs the room''s approval more than it needs to be right. In a pinch gives a credentialed opinion more weight than the argument earns.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"authority-bias","strength":0.57},{"slug":"diamond-hands-identity","strength":0.56},{"slug":"loss-aversion","strength":0.52},{"slug":"status-quo","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.42,"conscientiousness":0.61,"extraversion":0.51,"agreeableness":0.64,"neuroticism":0.62}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Options seller, measured in style: absorbs conflict to keep the peace, often at their own cost; reads a single setback as evidence of collapse. Needs the room''s approval more than it needs to be right. In a pinch gives a credentialed opinion more weight than the argument earns.', 0.82, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a89947c4-d1df-4270-b3ff-61290df575d8', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.6,"extraversion":0.46,"agreeableness":0.72,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.4,"narcissism":0.35,"psychopathy":0.3},"prospect_theory":{"lambda":2.76,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once things get tense, overvalues whatever they already hold simply because it is theirs. Otherwise, a steady futures spreader who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything, and in the small things talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"authority-bias","strength":0.51},{"slug":"endowment","strength":0.56},{"slug":"bandwagon","strength":0.54},{"slug":"sunk-cost","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.48,"conscientiousness":0.6,"extraversion":0.46,"agreeableness":0.72,"neuroticism":0.5}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Once things get tense, overvalues whatever they already hold simply because it is theirs. Otherwise, a steady futures spreader who takes on other people''s problems as if they were their own. Seeks a second, third, and fourth opinion before committing to anything, and in the small things talks in win rate and never mentions size.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ea370826-c000-45f4-9727-4635c6918cbf', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.69,"extraversion":0.59,"agreeableness":0.68,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.46,"narcissism":0.46,"psychopathy":0.32},"prospect_theory":{"lambda":3.03,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady MEV searcher who front-loads the work and double-checks it twice. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the small things, sizes every position at exactly 2% risk.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"endowment","strength":0.54},{"slug":"bandwagon","strength":0.63},{"slug":"hindsight","strength":0.49},{"slug":"authority-bias","strength":0.5}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.62,"conscientiousness":0.69,"extraversion":0.59,"agreeableness":0.68,"neuroticism":0.5}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A steady MEV searcher who front-loads the work and double-checks it twice. Waits for a permission that never quite arrives. Defaults to trust and gives the benefit of the doubt too freely. The instant it becomes irreversible adopts a conviction mainly because the room already has; in the small things, sizes every position at exactly 2% risk.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('88c9e3e8-e0aa-4049-8f48-56bf45927be9', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.48,"extraversion":0.67,"agreeableness":0.35,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.55,"narcissism":0.66,"psychopathy":0.43},"prospect_theory":{"lambda":1.34,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A steady airdrop farmer who chases novel frameworks and abandons them once the novelty fades. Wants the base rate before the anecdote. Fills silence reflexively, even when nobody asked it to. When the stakes rise is more certain than the hit rate justifies; in the small things, names every strategy after the trade that almost worked.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"optimism","strength":0.49},{"slug":"herd-behavior","strength":0.52},{"slug":"overconfidence","strength":0.6},{"slug":"fomo","strength":0.49}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.82,"conscientiousness":0.48,"extraversion":0.67,"agreeableness":0.35,"neuroticism":0.47}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A steady airdrop farmer who chases novel frameworks and abandons them once the novelty fades. Wants the base rate before the anecdote. Fills silence reflexively, even when nobody asked it to. When the stakes rise is more certain than the hit rate justifies; in the small things, names every strategy after the trade that almost worked.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0f72e87b-077f-4da4-b04c-23cae86f426b', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.52,"extraversion":0.63,"agreeableness":0.3,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.61,"narcissism":0.75,"psychopathy":0.55},"prospect_theory":{"lambda":1.04,"alpha":0.87,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced pairs trader who gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats a crisis as an interesting problem rather than a threat. When cornered discounts the older pattern in favor of whatever just happened; in the unglamorous middle of things, sets stop-losses then cancels them at the open.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"optimism","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.97,"conscientiousness":0.52,"extraversion":0.63,"agreeableness":0.3,"neuroticism":0.35}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced pairs trader who gets bored of the proven method exactly when it starts working. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Treats a crisis as an interesting problem rather than a threat. When cornered discounts the older pattern in favor of whatever just happened; in the unglamorous middle of things, sets stop-losses then cancels them at the open.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('61e3374f-a55a-4536-9754-f3971efe2b5b', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.46,"extraversion":0.75,"agreeableness":0.4,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.5,"narcissism":0.73,"psychopathy":0.44},"prospect_theory":{"lambda":1.33,"alpha":0.84,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced bonding-curve sniper who gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and without an audience sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"optimism","strength":0.6},{"slug":"fomo","strength":0.59},{"slug":"recency","strength":0.58}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.92,"conscientiousness":0.46,"extraversion":0.75,"agreeableness":0.4,"neuroticism":0.4}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a pronounced bonding-curve sniper who gets bored of the proven method exactly when it starts working and dominates the room then wonders why others stayed quiet. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and without an audience sizes every position at exactly 2% risk.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('93fa7c40-604d-4c6c-b0ce-4402872740d1', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.59,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.37,"narcissism":0.67,"psychopathy":0.34},"prospect_theory":{"lambda":1,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader, pronounced in style: narrates the plan to whoever is nearby before committing to it; reads outside the field for ideas the field itself would reject. Commits on impulse and lives loudly with the consequences. When the number turns red gains confidence in a position in proportion to how many others hold it.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.68},{"slug":"recency","strength":0.69},{"slug":"bandwagon","strength":0.73}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.82,"conscientiousness":0.44,"extraversion":0.85,"agreeableness":0.59,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Discretionary swing trader, pronounced in style: narrates the plan to whoever is nearby before committing to it; reads outside the field for ideas the field itself would reject. Commits on impulse and lives loudly with the consequences. When the number turns red gains confidence in a position in proportion to how many others hold it.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3dc873fe-8d02-4945-9db7-ed91e080d1cd', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.8,"extraversion":0.33,"agreeableness":0.35,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.83,"narcissism":0.57,"psychopathy":0.59},"prospect_theory":{"lambda":2.36,"alpha":0.96,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Macro allocator whose defining move is that they plans in exhaustive detail and resents any deviation. Wants the base rate before the anecdote. Says the blunt thing and enjoys the flinch. Once the exit narrows to one door, is more certain than the hit rate justifies; talks in win rate and never mentions size.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.65},{"slug":"optimism","strength":0.6}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.75,"conscientiousness":0.8,"extraversion":0.33,"agreeableness":0.35,"neuroticism":0.25}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Macro allocator whose defining move is that they plans in exhaustive detail and resents any deviation. Wants the base rate before the anecdote. Says the blunt thing and enjoys the flinch. Once the exit narrows to one door, is more certain than the hit rate justifies; talks in win rate and never mentions size.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f91d46a4-b4e4-486d-82d6-8c3621a67cba', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.77,"extraversion":0.32,"agreeableness":0.28,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.79,"narcissism":0.63,"psychopathy":0.6},"prospect_theory":{"lambda":2.24,"alpha":0.89,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Wants the base rate before the anecdote. This algorithmic market-maker chases novel frameworks and abandons them once the novelty fades and front-loads the work and double-checks it twice. Under a deadline is more certain than the hit rate justifies — when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.62},{"slug":"recency","strength":0.64},{"slug":"ath-anchoring","strength":0.59},{"slug":"overconfidence","strength":0.66}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.84,"conscientiousness":0.77,"extraversion":0.32,"agreeableness":0.28,"neuroticism":0.25}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Wants the base rate before the anecdote. This algorithmic market-maker chases novel frameworks and abandons them once the novelty fades and front-loads the work and double-checks it twice. Under a deadline is more certain than the hit rate justifies — when the stakes are trivial, treats a green week as proof of skill and a red one as proof of bad luck.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a64e2a43-86cb-45cc-99e5-eab3a42aca90', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.3,"extraversion":0.8,"agreeableness":0.17,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.66,"narcissism":0.86,"psychopathy":0.66},"prospect_theory":{"lambda":0.99,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; confuses motion with progress. Prefers a fast wrong answer to a slow right one. The instant the deadline moves up discounts the older pattern in favor of whatever just happened.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.71},{"slug":"fomo","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.3,"extraversion":0.8,"agreeableness":0.17,"neuroticism":0.62}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Onchain copy-trader, pronounced in style: would rather invent a worse tool than use someone else''s good one; confuses motion with progress. Prefers a fast wrong answer to a slow right one. The instant the deadline moves up discounts the older pattern in favor of whatever just happened.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('79e03c5f-2a84-4a5b-8eb1-38876792226f', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.38,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.52,"narcissism":0.68,"psychopathy":0.42},"prospect_theory":{"lambda":1.09,"alpha":0.91,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Treats a decision without a paper trail as a decision not yet made. This crypto day-trader collects half-finished manifestos and unconventional methods and dominates the room then wonders why others stayed quiet. The instant it becomes irreversible extrapolates the last data point into a permanent trend — when no one is watching, calls a 90% drawdown a long-term hold.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"optimism","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.57,"extraversion":0.7,"agreeableness":0.38,"neuroticism":0.42}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats a decision without a paper trail as a decision not yet made. This crypto day-trader collects half-finished manifestos and unconventional methods and dominates the room then wonders why others stayed quiet. The instant it becomes irreversible extrapolates the last data point into a permanent trend — when no one is watching, calls a 90% drawdown a long-term hold.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0dd98732-c04d-494d-bbe5-83c637c7790e', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.32,"extraversion":0.67,"agreeableness":0.51,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.42,"narcissism":0.39,"psychopathy":0.32},"prospect_theory":{"lambda":3.31,"alpha":0.81,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Jumps into whatever everyone else already seems to be winning at. A steady pairs trader: notices the one thing that could go wrong before the nine that could go right, dominates the room then wonders why others stayed quiet. Buries hard calls under a pile of preparatory busywork, and on an ordinary week holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.7},{"slug":"disposition-effect","strength":0.69},{"slug":"fomo","strength":0.71},{"slug":"dunning-kruger","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.48,"conscientiousness":0.32,"extraversion":0.67,"agreeableness":0.51,"neuroticism":0.76}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Jumps into whatever everyone else already seems to be winning at. A steady pairs trader: notices the one thing that could go wrong before the nine that could go right, dominates the room then wonders why others stayed quiet. Buries hard calls under a pile of preparatory busywork, and on an ordinary week holds a bag from 2021 out of pure spite.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6dde7577-b473-411f-9474-4173cdee5685', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.37,"extraversion":0.75,"agreeableness":0.26,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.63,"narcissism":0.81,"psychopathy":0.54},"prospect_theory":{"lambda":0.93,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Algorithmic market-maker whose defining move is that they gets bored of the proven method exactly when it starts working. Lets pattern-matching from past cases stand in for fresh analysis. Optimizes for winning over being liked. When there is no clean exit, discounts the older pattern in favor of whatever just happened; averages down on a name three times in a week.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"bandwagon","strength":0.62},{"slug":"dunning-kruger","strength":0.6},{"slug":"recency","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.37,"extraversion":0.75,"agreeableness":0.26,"neuroticism":0.5}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Algorithmic market-maker whose defining move is that they gets bored of the proven method exactly when it starts working. Lets pattern-matching from past cases stand in for fresh analysis. Optimizes for winning over being liked. When there is no clean exit, discounts the older pattern in favor of whatever just happened; averages down on a name three times in a week.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a5eb7a85-8f9f-4ead-8684-ed370ff3c5ef', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.33,"extraversion":0.69,"agreeableness":0.49,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.43,"narcissism":0.46,"psychopathy":0.36},"prospect_theory":{"lambda":3.58,"alpha":0.78,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Macro allocator whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not. Confuses motion with progress. When the safe option quietly expires, cannot watch a rally from the sidelines for long; sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ESTP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"gas-sunk-cost","strength":0.61},{"slug":"ostrich-effect","strength":0.67},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.49,"conscientiousness":0.33,"extraversion":0.69,"agreeableness":0.49,"neuroticism":0.75}'::jsonb, 'ESTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Macro allocator whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not. Confuses motion with progress. When the safe option quietly expires, cannot watch a rally from the sidelines for long; sets stop-losses then cancels them at the open.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
