('e5e955f3-a562-4e70-ad38-b1849f128411', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.34,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.55,"narcissism":0.8,"psychopathy":0.43},"prospect_theory":{"lambda":0.94,"alpha":0.86,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Jumps into whatever everyone else already seems to be winning at. A pronounced pairs trader: gets bored of the proven method exactly when it starts working, assumes self-interest in others because it is usually there in themselves. Lets pattern-matching from past cases stand in for fresh analysis, and in the unglamorous middle of things backtests for months but front-runs the model on impulse.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.7},{"slug":"dunning-kruger","strength":0.67},{"slug":"recency","strength":0.65},{"slug":"bandwagon","strength":0.68}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.44,"extraversion":0.84,"agreeableness":0.34,"neuroticism":0.55}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Jumps into whatever everyone else already seems to be winning at. A pronounced pairs trader: gets bored of the proven method exactly when it starts working, assumes self-interest in others because it is usually there in themselves. Lets pattern-matching from past cases stand in for fresh analysis, and in the unglamorous middle of things backtests for months but front-runs the model on impulse.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e4ed8014-4a27-4e37-b526-c4f660caa4aa', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.29,"extraversion":0.77,"agreeableness":0.7,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.4,"narcissism":0.6,"psychopathy":0.36},"prospect_theory":{"lambda":1.25,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Trusts momentum over preparation. This penny-stock gambler fills silence reflexively, even when nobody asked it to and notices the one thing that could go wrong before the nine that could go right. When cornered finds it hard to hold a contrarian position once the room disagrees — as a rule, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.74},{"slug":"recency","strength":0.63},{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.74}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.75,"conscientiousness":0.29,"extraversion":0.77,"agreeableness":0.7,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This penny-stock gambler fills silence reflexively, even when nobody asked it to and notices the one thing that could go wrong before the nine that could go right. When cornered finds it hard to hold a contrarian position once the room disagrees — as a rule, backtests for months but front-runs the model on impulse.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
