('6a008471-0a28-4a8a-b0e5-36b4d1192fdd', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.44,"extraversion":0.78,"agreeableness":0.36,"neuroticism":0.6},"dark_triad":{"machiavellianism":0.56,"narcissism":0.75,"psychopathy":0.41},"prospect_theory":{"lambda":0.89,"alpha":0.86,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser, pronounced in style: collects half-finished manifestos and unconventional methods; treats a quiet room as a problem to be solved. Reads a room or a market the way others read a paragraph. Under a deadline cannot watch a rally from the sidelines for long.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"fomo","strength":0.69},{"slug":"dunning-kruger","strength":0.58}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.44,"extraversion":0.78,"agreeableness":0.36,"neuroticism":0.6}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Retail momentum chaser, pronounced in style: collects half-finished manifestos and unconventional methods; treats a quiet room as a problem to be solved. Reads a room or a market the way others read a paragraph. Under a deadline cannot watch a rally from the sidelines for long.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('861bcc03-84e7-4b96-900c-beab71021f0f', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.41,"extraversion":0.7,"agreeableness":0.59,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.39,"narcissism":0.56,"psychopathy":0.31},"prospect_theory":{"lambda":1.08,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Futures spreader, steady in style: collects half-finished manifestos and unconventional methods; draws energy from the crowd and wilts when working alone. Commits on impulse and lives loudly with the consequences. When cornered assumes the current streak is the new normal.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"fomo","strength":0.56},{"slug":"herd-behavior","strength":0.6}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.41,"extraversion":0.7,"agreeableness":0.59,"neuroticism":0.57}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Futures spreader, steady in style: collects half-finished manifestos and unconventional methods; draws energy from the crowd and wilts when working alone. Commits on impulse and lives loudly with the consequences. When cornered assumes the current streak is the new normal.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('be3dd240-6c68-4b84-bdda-f4b2d9173151', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.48,"extraversion":0.57,"agreeableness":0.55,"neuroticism":0.95},"dark_triad":{"machiavellianism":0.41,"narcissism":0.29,"psychopathy":0.31},"prospect_theory":{"lambda":3.32,"alpha":0.77,"beta":0.72},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Under pressure, delays checking the number it most needs to check. Otherwise, a pronounced quant researcher who reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting, and in the parts nobody grades sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.71},{"slug":"loss-aversion","strength":0.7},{"slug":"rug-trauma-overcorrection","strength":0.73},{"slug":"ostrich-effect","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.57,"conscientiousness":0.48,"extraversion":0.57,"agreeableness":0.55,"neuroticism":0.95}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Under pressure, delays checking the number it most needs to check. Otherwise, a pronounced quant researcher who reads a single setback as evidence of collapse. Finds one more piece of information to gather before acting, and in the parts nobody grades sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d0c7c64c-7b20-4289-a67d-03cb5329e0c0', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.35,"extraversion":0.61,"agreeableness":0.55,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.44,"narcissism":0.38,"psychopathy":0.32},"prospect_theory":{"lambda":3.44,"alpha":0.83,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"DeFi yield farmer whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Treats not-choosing as a safe choice right up until it is not. Is reliably surprised by deadlines that were never hidden. Once the exit narrows to one door, sells the winners early and clings to the losers for far too long; keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.67},{"slug":"gas-sunk-cost","strength":0.62}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.35,"extraversion":0.61,"agreeableness":0.55,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they notices the one thing that could go wrong before the nine that could go right. Treats not-choosing as a safe choice right up until it is not. Is reliably surprised by deadlines that were never hidden. Once the exit narrows to one door, sells the winners early and clings to the losers for far too long; keeps a losing-trade journal they never re-read.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
