('e5307d6a-4381-4e3d-8073-30302ac5e1d1', 1, '{"big_five":{"openness":0.39,"conscientiousness":0.58,"extraversion":0.57,"agreeableness":0.48,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.46,"narcissism":0.46,"psychopathy":0.28},"prospect_theory":{"lambda":3.02,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This index-fund holdout treats untested approaches as risk to be avoided. The moment risk appears prices every token against its all-time high, viewing current levels as an automatic discount — in the version no one reviews, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"ESTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.6},{"slug":"anchoring","strength":0.51},{"slug":"confirmation","strength":0.48},{"slug":"gamblers-fallacy","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.39,"conscientiousness":0.58,"extraversion":0.57,"agreeableness":0.48,"neuroticism":0.53}'::jsonb, 'ESTJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Needs the room''s approval more than it needs to be right. This index-fund holdout treats untested approaches as risk to be avoided. The moment risk appears prices every token against its all-time high, viewing current levels as an automatic discount — in the version no one reviews, averages down on a name three times in a week.', 0.8, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c74232fb-19a2-4a99-ab96-58c62d75d853', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.51,"extraversion":0.68,"agreeableness":0.31,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.56,"narcissism":0.69,"psychopathy":0.44},"prospect_theory":{"lambda":1.01,"alpha":0.93,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, extrapolates the last data point into a permanent trend. Otherwise, a pronounced algorithmic market-maker who reads outside the field for ideas the field itself would reject and treats warmth as leverage and cooperation as weakness. Reads a room or a market the way others read a paragraph, and as a rule checks the P&L blotter forty times before lunch.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.5},{"slug":"recency","strength":0.57},{"slug":"overconfidence","strength":0.51},{"slug":"fomo","strength":0.54}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.84,"conscientiousness":0.51,"extraversion":0.68,"agreeableness":0.31,"neuroticism":0.47}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, extrapolates the last data point into a permanent trend. Otherwise, a pronounced algorithmic market-maker who reads outside the field for ideas the field itself would reject and treats warmth as leverage and cooperation as weakness. Reads a room or a market the way others read a paragraph, and as a rule checks the P&L blotter forty times before lunch.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('92d8880c-31eb-4d55-a6b9-eaa55b3ea17e', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.5,"extraversion":0.75,"agreeableness":0.21,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.63,"narcissism":0.81,"psychopathy":0.51},"prospect_theory":{"lambda":0.79,"alpha":0.92,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts a felt sense of pattern over any spreadsheet. This algorithmic market-maker treats established procedure as a first draft to be rewritten and treats consensus-seeking as a waste of time. The moment it stops being hypothetical is more certain than the hit rate justifies — in the unglamorous middle of things, talks in win rate and never mentions size.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.54},{"slug":"overconfidence","strength":0.65},{"slug":"herd-behavior","strength":0.55}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.5,"extraversion":0.75,"agreeableness":0.21,"neuroticism":0.51}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Trusts a felt sense of pattern over any spreadsheet. This algorithmic market-maker treats established procedure as a first draft to be rewritten and treats consensus-seeking as a waste of time. The moment it stops being hypothetical is more certain than the hit rate justifies — in the unglamorous middle of things, talks in win rate and never mentions size.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('31328def-09e8-4d8d-8e41-3822422d1ce5', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.15,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.7,"narcissism":0.89,"psychopathy":0.54},"prospect_theory":{"lambda":0.88,"alpha":0.9,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats overthinking as its own kind of error. This MEV searcher reads outside the field for ideas the field itself would reject and recharges by being around people, not away from them. When the walls close in underestimates how often an obviously right call turns out wrong — day to day, refreshes the order book compulsively during lunch.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.58},{"slug":"overconfidence","strength":0.62},{"slug":"recency","strength":0.6}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.51,"extraversion":0.73,"agreeableness":0.15,"neuroticism":0.55}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats overthinking as its own kind of error. This MEV searcher reads outside the field for ideas the field itself would reject and recharges by being around people, not away from them. When the walls close in underestimates how often an obviously right call turns out wrong — day to day, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6f07cfca-85c3-4024-aec6-ecb5eef1e0cb', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.34,"extraversion":0.78,"agreeableness":0.27,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.61,"narcissism":0.85,"psychopathy":0.58},"prospect_theory":{"lambda":1.06,"alpha":0.86,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper, pronounced in style: reframes every problem as an excuse to learn a new system; starts strong and lets follow-through evaporate. Prefers a fast wrong answer to a slow right one. Once things get tense abandons a private read the instant the crowd leans the other way.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"dunning-kruger","strength":0.65},{"slug":"fomo","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.34,"extraversion":0.78,"agreeableness":0.27,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prop-desk scalper, pronounced in style: reframes every problem as an excuse to learn a new system; starts strong and lets follow-through evaporate. Prefers a fast wrong answer to a slow right one. Once things get tense abandons a private read the instant the crowd leans the other way.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('aff1ca38-c1f0-40da-a8fe-5442b8c039ac', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.3,"extraversion":0.88,"agreeableness":0.37,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.49,"narcissism":0.83,"psychopathy":0.5},"prospect_theory":{"lambda":0.92,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot see the gap in its own knowledge from inside the gap. A pronounced value investor: thinks out loud and recruits an audience for every decision, starts strong and lets follow-through evaporate. Acts on the midnight epiphany and emails it at 1am, and in the version no one reviews keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"dunning-kruger","strength":0.73}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.85,"conscientiousness":0.3,"extraversion":0.88,"agreeableness":0.37,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Cannot see the gap in its own knowledge from inside the gap. A pronounced value investor: thinks out loud and recruits an audience for every decision, starts strong and lets follow-through evaporate. Acts on the midnight epiphany and emails it at 1am, and in the version no one reviews keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('602e2924-3244-4fdb-810f-4cc38e9d9827', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.35,"narcissism":0.71,"psychopathy":0.34},"prospect_theory":{"lambda":1.21,"alpha":0.84,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"DeFi yield farmer, pronounced in style: dominates the room then wonders why others stayed quiet; measures decisions by who they might upset. Acts on the midnight epiphany and emails it at 1am. As soon as real money or reputation is on the line finds it hard to hold a contrarian position once the room disagrees.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.72},{"slug":"herd-behavior","strength":0.81},{"slug":"bandwagon","strength":0.77}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.39,"extraversion":0.89,"agreeableness":0.68,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'DeFi yield farmer, pronounced in style: dominates the room then wonders why others stayed quiet; measures decisions by who they might upset. Acts on the midnight epiphany and emails it at 1am. As soon as real money or reputation is on the line finds it hard to hold a contrarian position once the room disagrees.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d568b2af-b8fe-4a39-836d-7ecb6c7b64b9', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.26,"extraversion":0.68,"agreeableness":0.58,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.41,"narcissism":0.43,"psychopathy":0.4},"prospect_theory":{"lambda":3.61,"alpha":0.71,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they hedges every commitment against an imagined worst case. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the downside gets concrete, treats being left out of a move as its own kind of loss; calls a 90% drawdown a long-term hold.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.74},{"slug":"gas-sunk-cost","strength":0.7},{"slug":"fomo","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.56,"conscientiousness":0.26,"extraversion":0.68,"agreeableness":0.58,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they hedges every commitment against an imagined worst case. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the downside gets concrete, treats being left out of a move as its own kind of loss; calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a8d352fd-cff7-4ccd-848a-38b20d1ea5e1', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.34,"extraversion":0.83,"agreeableness":0.22,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.64,"narcissism":0.91,"psychopathy":0.58},"prospect_theory":{"lambda":0.79,"alpha":0.86,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot see the gap in its own knowledge from inside the gap. A pronounced perps degen: collects half-finished manifestos and unconventional methods, assumes self-interest in others because it is usually there in themselves. Decides in the time it takes to say the decision out loud, and without an audience confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"fomo","strength":0.63},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.87,"conscientiousness":0.34,"extraversion":0.83,"agreeableness":0.22,"neuroticism":0.48}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Cannot see the gap in its own knowledge from inside the gap. A pronounced perps degen: collects half-finished manifestos and unconventional methods, assumes self-interest in others because it is usually there in themselves. Decides in the time it takes to say the decision out loud, and without an audience confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e22d568b-28fe-4eed-9eaa-235e8fb05e7a', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.24,"extraversion":0.85,"agreeableness":0.57,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.39,"narcissism":0.74,"psychopathy":0.43},"prospect_theory":{"lambda":0.95,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Trusts momentum over preparation. This delta-neutral market maker narrates the plan to whoever is nearby before committing to it and leaves loose ends and trusts future-self to handle them. The moment risk appears is most certain precisely where their competence is thinnest — in the routine of it, screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"herd-behavior","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.84,"conscientiousness":0.24,"extraversion":0.85,"agreeableness":0.57,"neuroticism":0.61}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This delta-neutral market maker narrates the plan to whoever is nearby before committing to it and leaves loose ends and trusts future-self to handle them. The moment risk appears is most certain precisely where their competence is thinnest — in the routine of it, screenshots the winners and never the losers.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('275f7922-bbe7-4e09-8703-527ce4554719', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.18,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.68,"narcissism":0.87,"psychopathy":0.59},"prospect_theory":{"lambda":0.68,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When someone is watching the outcome, extrapolates the last data point into a permanent trend. Otherwise, a pronounced zero-DTE options gambler who chases novel frameworks and abandons them once the novelty fades and assumes self-interest in others because it is usually there in themselves. Lets pattern-matching from past cases stand in for fresh analysis, and without an audience exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.59},{"slug":"recency","strength":0.63}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.38,"extraversion":0.76,"agreeableness":0.18,"neuroticism":0.46}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When someone is watching the outcome, extrapolates the last data point into a permanent trend. Otherwise, a pronounced zero-DTE options gambler who chases novel frameworks and abandons them once the novelty fades and assumes self-interest in others because it is usually there in themselves. Lets pattern-matching from past cases stand in for fresh analysis, and without an audience exits winners at the first green candle.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1df1ae5e-7487-4090-890e-e9c5e66fa839', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.4,"extraversion":0.92,"agreeableness":0.53,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.44,"narcissism":0.72,"psychopathy":0.33},"prospect_theory":{"lambda":1.15,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Futures spreader, pronounced in style: dominates the room then wonders why others stayed quiet; notices the one thing that could go wrong before the nine that could go right. Commits on impulse and lives loudly with the consequences. Once the exit narrows to one door takes the crowd''s confidence as a substitute for its own analysis.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.71},{"slug":"bandwagon","strength":0.62},{"slug":"dunning-kruger","strength":0.62},{"slug":"recency","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.78,"conscientiousness":0.4,"extraversion":0.92,"agreeableness":0.53,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Futures spreader, pronounced in style: dominates the room then wonders why others stayed quiet; notices the one thing that could go wrong before the nine that could go right. Commits on impulse and lives loudly with the consequences. Once the exit narrows to one door takes the crowd''s confidence as a substitute for its own analysis.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('92ddfd92-fcd0-48dc-92a3-95bfc7f2820e', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.35,"extraversion":0.82,"agreeableness":0.32,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.53,"narcissism":0.83,"psychopathy":0.52},"prospect_theory":{"lambda":0.86,"alpha":0.87,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Onchain copy-trader, pronounced in style: treats established procedure as a first draft to be rewritten; confuses motion with progress. Reads a room or a market the way others read a paragraph. Once the exit narrows to one door mistakes a little fluency for real mastery.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.63},{"slug":"fomo","strength":0.7},{"slug":"recency","strength":0.62},{"slug":"dunning-kruger","strength":0.71}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.35,"extraversion":0.82,"agreeableness":0.32,"neuroticism":0.54}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Onchain copy-trader, pronounced in style: treats established procedure as a first draft to be rewritten; confuses motion with progress. Reads a room or a market the way others read a paragraph. Once the exit narrows to one door mistakes a little fluency for real mastery.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9bf0c479-2bc8-4e62-8e19-45e08bf02842', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.66,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.48,"narcissism":0.36,"psychopathy":0.26},"prospect_theory":{"lambda":2.96,"alpha":0.91,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Retail momentum chaser whose defining move is that they builds in buffer time and then fills the buffer with more work. Waits for a permission that never quite arrives. Apologizes first in disputes regardless of fault. Under pressure, feels parting with something as a bigger loss than its market value explains; calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.54},{"slug":"authority-bias","strength":0.49}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.54,"conscientiousness":0.66,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.56}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Retail momentum chaser whose defining move is that they builds in buffer time and then fills the buffer with more work. Waits for a permission that never quite arrives. Apologizes first in disputes regardless of fault. Under pressure, feels parting with something as a bigger loss than its market value explains; calls a 90% drawdown a long-term hold.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f1aa5296-55e2-47f6-91a1-56264461e4c6', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.5,"extraversion":0.69,"agreeableness":0.33,"neuroticism":0.41},"dark_triad":{"machiavellianism":0.55,"narcissism":0.76,"psychopathy":0.45},"prospect_theory":{"lambda":1.31,"alpha":0.87,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"The instant the deadline moves up, assumes the bad statistic applies to other people. Otherwise, a pronounced zero-DTE options gambler who collects half-finished manifestos and unconventional methods and treats a quiet room as a problem to be solved. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.52},{"slug":"optimism","strength":0.61},{"slug":"recency","strength":0.61}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.5,"extraversion":0.69,"agreeableness":0.33,"neuroticism":0.41}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The instant the deadline moves up, assumes the bad statistic applies to other people. Otherwise, a pronounced zero-DTE options gambler who collects half-finished manifestos and unconventional methods and treats a quiet room as a problem to be solved. Builds a decision matrix for choices most people make on instinct, and on a slow afternoon trusts the chart more than the fundamentals and won''t say why.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('150fc500-dad4-4435-b7eb-d1671e68f523', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.25,"extraversion":0.64,"agreeableness":0.58,"neuroticism":0.75},"dark_triad":{"machiavellianism":0.42,"narcissism":0.45,"psychopathy":0.37},"prospect_theory":{"lambda":3.66,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady delta-neutral market maker who leaves loose ends and trusts future-self to handle them and spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed, and when the stakes are trivial trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.65},{"slug":"ostrich-effect","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.25,"extraversion":0.64,"agreeableness":0.58,"neuroticism":0.75}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed. Otherwise, a steady delta-neutral market maker who leaves loose ends and trusts future-self to handle them and spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed, and when the stakes are trivial trusts the chart more than the fundamentals and won''t say why.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('fb485cca-a5d8-4084-a974-dfebbfba5183', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.92,"extraversion":0.44,"agreeableness":0.35,"neuroticism":0.22},"dark_triad":{"machiavellianism":0.82,"narcissism":0.53,"psychopathy":0.61},"prospect_theory":{"lambda":2.37,"alpha":0.95,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Discretionary swing trader whose defining move is that they plans in exhaustive detail and resents any deviation. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats consensus-seeking as a waste of time. When there is no clean exit, refuses to exit positions until price returns to the previous cycle peak; sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.67},{"slug":"hindsight","strength":0.65}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.77,"conscientiousness":0.92,"extraversion":0.44,"agreeableness":0.35,"neuroticism":0.22}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discretionary swing trader whose defining move is that they plans in exhaustive detail and resents any deviation. Ranks the options twice, once on paper and once out loud, and trusts the paper. Treats consensus-seeking as a waste of time. When there is no clean exit, refuses to exit positions until price returns to the previous cycle peak; sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4a9a77e4-abc8-408f-bdaf-2470bc250844', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.35,"extraversion":0.69,"agreeableness":0.66,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.36,"narcissism":0.46,"psychopathy":0.33},"prospect_theory":{"lambda":3.51,"alpha":0.78,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delays checking the number it most needs to check. A steady prop-desk scalper: rehearses catastrophes in vivid detail before they happen, starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and when no one is watching treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.67},{"slug":"ostrich-effect","strength":0.73}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.35,"extraversion":0.69,"agreeableness":0.66,"neuroticism":0.82}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Delays checking the number it most needs to check. A steady prop-desk scalper: rehearses catastrophes in vivid detail before they happen, starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and when no one is watching treats a green week as proof of skill and a red one as proof of bad luck.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('70eb1292-4585-48b7-b118-d07dda27ef3f', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.35,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.52,"narcissism":0.79,"psychopathy":0.47},"prospect_theory":{"lambda":1,"alpha":0.85,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced meme-coin rotator who treats established procedure as a first draft to be rewritten. Prefers a fast wrong answer to a slow right one. Assumes self-interest in others because it is usually there in themselves. When cornered cannot watch a rally from the sidelines for long; across an ordinary week, sets stop-losses then cancels them at the open.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"fomo","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.3,"extraversion":0.81,"agreeableness":0.35,"neuroticism":0.58}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced meme-coin rotator who treats established procedure as a first draft to be rewritten. Prefers a fast wrong answer to a slow right one. Assumes self-interest in others because it is usually there in themselves. When cornered cannot watch a rally from the sidelines for long; across an ordinary week, sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a536f149-dddd-4dbb-8405-9c6d74f0f64e', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.43,"extraversion":0.71,"agreeableness":0.2,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.67,"narcissism":0.85,"psychopathy":0.54},"prospect_theory":{"lambda":0.72,"alpha":0.91,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Under a deadline, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced penny-stock gambler who treats established procedure as a first draft to be rewritten and treats a quiet room as a problem to be solved. Knows the answer before it can explain the question, and in the small things holds a bag from 2021 out of pure spite.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"overconfidence","strength":0.65}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.94,"conscientiousness":0.43,"extraversion":0.71,"agreeableness":0.2,"neuroticism":0.51}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Under a deadline, holds their estimates with a certainty the track record does not support. Otherwise, a pronounced penny-stock gambler who treats established procedure as a first draft to be rewritten and treats a quiet room as a problem to be solved. Knows the answer before it can explain the question, and in the small things holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0b9d8a47-cdf8-4805-a1b6-27cbd948444e', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.53,"extraversion":0.8,"agreeableness":0.28,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.62,"narcissism":0.81,"psychopathy":0.44},"prospect_theory":{"lambda":0.95,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler whose defining move is that they reframes every problem as an excuse to learn a new system. Treats hesitation as the bigger risk. Would rather be respected than liked, and says so. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"herd-behavior","strength":0.63}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.53,"extraversion":0.8,"agreeableness":0.28,"neuroticism":0.54}'::jsonb, 'ENTJ', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Zero-DTE options gambler whose defining move is that they reframes every problem as an excuse to learn a new system. Treats hesitation as the bigger risk. Would rather be respected than liked, and says so. When someone is watching the outcome, finds it hard to hold a contrarian position once the room disagrees; trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('16c59790-e45f-42df-bbb1-e418191ba149', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.97,"extraversion":0.46,"agreeableness":0.34,"neuroticism":0.23},"dark_triad":{"machiavellianism":0.8,"narcissism":0.57,"psychopathy":0.54},"prospect_theory":{"lambda":2.17,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Commodities speculator, pronounced in style: plans in exhaustive detail and resents any deviation; is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct. When the number turns red holds their estimates with a certainty the track record does not support.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.7},{"slug":"hindsight","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.9,"conscientiousness":0.97,"extraversion":0.46,"agreeableness":0.34,"neuroticism":0.23}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Commodities speculator, pronounced in style: plans in exhaustive detail and resents any deviation; is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct. When the number turns red holds their estimates with a certainty the track record does not support.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('df621b3a-649d-4336-9ff1-b1adf65595c4', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.32,"extraversion":0.86,"agreeableness":0.6,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.33},"prospect_theory":{"lambda":1.1,"alpha":0.88,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Value investor whose defining move is that they fills silence reflexively, even when nobody asked it to. Commits before the doubt has time to organize itself. Gets bored of the proven method exactly when it starts working. Under a deadline, abandons a private read the instant the crowd leans the other way; refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"herd-behavior","strength":0.73},{"slug":"fomo","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.73,"conscientiousness":0.32,"extraversion":0.86,"agreeableness":0.6,"neuroticism":0.64}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Value investor whose defining move is that they fills silence reflexively, even when nobody asked it to. Commits before the doubt has time to organize itself. Gets bored of the proven method exactly when it starts working. Under a deadline, abandons a private read the instant the crowd leans the other way; refreshes the order book compulsively during lunch.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c4e90493-449f-4e86-be69-f93dded730b7', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.32,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.58,"narcissism":0.82,"psychopathy":0.49},"prospect_theory":{"lambda":1.06,"alpha":0.86,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Cannot see the gap in its own knowledge from inside the gap. A pronounced value investor: reads outside the field for ideas the field itself would reject, thinks out loud and recruits an audience for every decision. Decides in the time it takes to say the decision out loud, and in the pattern nobody else tracks screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.7},{"slug":"herd-behavior","strength":0.62},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.32,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Cannot see the gap in its own knowledge from inside the gap. A pronounced value investor: reads outside the field for ideas the field itself would reject, thinks out loud and recruits an audience for every decision. Decides in the time it takes to say the decision out loud, and in the pattern nobody else tracks screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eb797de4-0b31-4844-b219-5d809df5b8f8', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.63,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.42,"narcissism":0.66,"psychopathy":0.37},"prospect_theory":{"lambda":1.12,"alpha":0.82,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Prefers a fast wrong answer to a slow right one. This macro allocator draws energy from the crowd and wilts when working alone and gets bored of the proven method exactly when it starts working. Under pressure adopts a conviction mainly because the room already has — in the pattern nobody else tracks, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"fomo","strength":0.71},{"slug":"recency","strength":0.59},{"slug":"bandwagon","strength":0.72}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.74,"conscientiousness":0.38,"extraversion":0.84,"agreeableness":0.63,"neuroticism":0.65}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Prefers a fast wrong answer to a slow right one. This macro allocator draws energy from the crowd and wilts when working alone and gets bored of the proven method exactly when it starts working. Under pressure adopts a conviction mainly because the room already has — in the pattern nobody else tracks, backtests for months but front-runs the model on impulse.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bd5549a3-ff83-4a5d-9fa2-5fb037d56c5f', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.36,"extraversion":0.71,"agreeableness":0.33,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.59,"narcissism":0.73,"psychopathy":0.54},"prospect_theory":{"lambda":0.95,"alpha":0.92,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Discounts the older pattern in favor of whatever just happened. A pronounced liquidation-bot operator: would rather invent a worse tool than use someone else''s good one, would rather be respected than liked, and says so. Treats overthinking as its own kind of error, and day to day confuses a bull market for a trading edge.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"dunning-kruger","strength":0.63}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.36,"extraversion":0.71,"agreeableness":0.33,"neuroticism":0.47}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Discounts the older pattern in favor of whatever just happened. A pronounced liquidation-bot operator: would rather invent a worse tool than use someone else''s good one, would rather be respected than liked, and says so. Treats overthinking as its own kind of error, and day to day confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c17ff74c-1ca1-43de-8e60-1b6bafd02ca4', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.7},"dark_triad":{"machiavellianism":0.36,"narcissism":0.57,"psychopathy":0.35},"prospect_theory":{"lambda":1.13,"alpha":0.82,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment it stops being hypothetical, treats being left out of a move as its own kind of loss. Otherwise, a steady options seller who recharges by being around people, not away from them and notices the one thing that could go wrong before the nine that could go right. Trusts momentum over preparation, and when the pressure is off trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"fomo","strength":0.74},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.66,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.67,"neuroticism":0.7}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, treats being left out of a move as its own kind of loss. Otherwise, a steady options seller who recharges by being around people, not away from them and notices the one thing that could go wrong before the nine that could go right. Trusts momentum over preparation, and when the pressure is off trusts the chart more than the fundamentals and won''t say why.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c95c5464-2b11-459b-836e-b266c79acb95', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.39,"extraversion":0.58,"agreeableness":0.52,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.43,"narcissism":0.3,"psychopathy":0.31},"prospect_theory":{"lambda":3.45,"alpha":0.76,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced zero-DTE options gambler who spirals on ambiguity and mistakes the spiral for diligence. Finds one more piece of information to gather before acting. Once the exit narrows to one door delays checking the number it most needs to check; once the urgency drains out, backtests for months but front-runs the model on impulse.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.7},{"slug":"loss-aversion","strength":0.67},{"slug":"ostrich-effect","strength":0.74}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.39,"extraversion":0.58,"agreeableness":0.52,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A pronounced zero-DTE options gambler who spirals on ambiguity and mistakes the spiral for diligence. Finds one more piece of information to gather before acting. Once the exit narrows to one door delays checking the number it most needs to check; once the urgency drains out, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('af6f1aa6-c6c1-444a-a853-32ff9f2cc686', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.61,"extraversion":0.44,"agreeableness":0.73,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.42,"narcissism":0.41,"psychopathy":0.27},"prospect_theory":{"lambda":2.75,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Bonding-curve sniper, steady in style: would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. When the downside gets concrete feels parting with something as a bigger loss than its market value explains.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.57},{"slug":"herd-behavior","strength":0.49},{"slug":"endowment","strength":0.58},{"slug":"authority-bias","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.61,"extraversion":0.44,"agreeableness":0.73,"neuroticism":0.51}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper, steady in style: would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything. When the downside gets concrete feels parting with something as a bigger loss than its market value explains.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('377c1ade-8f30-42d2-ad32-3342901d2af3', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.5,"extraversion":0.78,"agreeableness":0.29,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.61,"narcissism":0.8,"psychopathy":0.46},"prospect_theory":{"lambda":0.76,"alpha":0.88,"beta":0.95},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"The moment it stops being hypothetical, extrapolates the last data point into a permanent trend. Otherwise, a pronounced crypto day-trader who would rather invent a worse tool than use someone else''s good one and recharges by being around people, not away from them. Knows the answer before it can explain the question, and as a rule holds a bag from 2021 out of pure spite.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.65},{"slug":"herd-behavior","strength":0.65}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.5,"extraversion":0.78,"agreeableness":0.29,"neuroticism":0.56}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, extrapolates the last data point into a permanent trend. Otherwise, a pronounced crypto day-trader who would rather invent a worse tool than use someone else''s good one and recharges by being around people, not away from them. Knows the answer before it can explain the question, and as a rule holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1d0f7988-aaa4-4074-87c8-190f745b1c35', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.92,"extraversion":0.32,"agreeableness":0.25,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.85,"narcissism":0.59,"psychopathy":0.62},"prospect_theory":{"lambda":2.36,"alpha":0.96,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Builds a decision matrix for choices most people make on instinct. This futures spreader treats a missed deadline as a personal failure regardless of cause and treats established procedure as a first draft to be rewritten. Under a deadline holds their estimates with a certainty the track record does not support — in the routine of it, checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.64},{"slug":"overconfidence","strength":0.65},{"slug":"anchoring","strength":0.57}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.73,"conscientiousness":0.92,"extraversion":0.32,"agreeableness":0.25,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Builds a decision matrix for choices most people make on instinct. This futures spreader treats a missed deadline as a personal failure regardless of cause and treats established procedure as a first draft to be rewritten. Under a deadline holds their estimates with a certainty the track record does not support — in the routine of it, checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e90776c7-a7c4-47cd-935f-df84883d6df1', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.3,"extraversion":0.59,"agreeableness":0.59,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.42,"narcissism":0.39,"psychopathy":0.39},"prospect_theory":{"lambda":3.64,"alpha":0.83,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats non-refundable network fees as active position cost basis. A steady options seller: needs repeated reassurance that a decision was the right one, confuses motion with progress. Lets the deadline make the decision by default, and in the version no one reviews sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.67},{"slug":"ostrich-effect","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.3,"extraversion":0.59,"agreeableness":0.59,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats non-refundable network fees as active position cost basis. A steady options seller: needs repeated reassurance that a decision was the right one, confuses motion with progress. Lets the deadline make the decision by default, and in the version no one reviews sets alerts for a coin they already checked a minute ago.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3e8b7ab1-2814-4c92-b37a-9fb32d49d5bc', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.5,"extraversion":0.77,"agreeableness":0.23,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.61,"narcissism":0.76,"psychopathy":0.5},"prospect_theory":{"lambda":1.01,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, pronounced in style: treats established procedure as a first draft to be rewritten; thinks out loud and recruits an audience for every decision. Reads a room or a market the way others read a paragraph. Once things get tense cannot watch a rally from the sidelines for long.","decision_style":"intuitive","mbti_label":"ENTJ","suggested_biases":[{"slug":"airdrop-entitlement","strength":0.62},{"slug":"rug-trauma-overcorrection","strength":0.65},{"slug":"herd-behavior","strength":0.57},{"slug":"fomo","strength":0.74}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.5,"extraversion":0.77,"agreeableness":0.23,"neuroticism":0.69}'::jsonb, 'ENTJ', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Quant researcher, pronounced in style: treats established procedure as a first draft to be rewritten; thinks out loud and recruits an audience for every decision. Reads a room or a market the way others read a paragraph. Once things get tense cannot watch a rally from the sidelines for long.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('cd835f0a-e884-4d17-9426-b0a06150b2cb', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.41,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.61,"narcissism":0.82,"psychopathy":0.49},"prospect_theory":{"lambda":0.92,"alpha":0.86,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Decides on a gut read in seconds and reverse-engineers the reasons later. This crypto day-trader gets bored of the proven method exactly when it starts working and optimizes for winning over being liked. When the number turns red discounts the older pattern in favor of whatever just happened — in the pattern nobody else tracks, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"dunning-kruger","strength":0.59},{"slug":"herd-behavior","strength":0.53}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.41,"extraversion":0.73,"agreeableness":0.27,"neuroticism":0.49}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Decides on a gut read in seconds and reverse-engineers the reasons later. This crypto day-trader gets bored of the proven method exactly when it starts working and optimizes for winning over being liked. When the number turns red discounts the older pattern in favor of whatever just happened — in the pattern nobody else tracks, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('093108ec-40bd-440e-8e90-c932bc9e6387', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.52,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.42,"narcissism":0.32,"psychopathy":0.32},"prospect_theory":{"lambda":3.63,"alpha":0.72,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Retail momentum chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the walls close in, delays checking the number it most needs to check; sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.68},{"slug":"loss-aversion","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.53,"conscientiousness":0.42,"extraversion":0.62,"agreeableness":0.52,"neuroticism":0.87}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Retail momentum chaser whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Keeps every door open long after most of them should be closed. Thinks out loud and recruits an audience for every decision. When the walls close in, delays checking the number it most needs to check; sets stop-losses then cancels them at the open.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('42a01038-8f3d-48ed-b820-e1097dafb374', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.39,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.62,"narcissism":0.75,"psychopathy":0.54},"prospect_theory":{"lambda":0.76,"alpha":0.8,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser whose defining move is that they reframes every problem as an excuse to learn a new system. Treats overthinking as its own kind of error. Notices the one thing that could go wrong before the nine that could go right. The instant the deadline moves up, exits winning positions at the first minor delay or quiet period from devs; confuses a bull market for a trading edge.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.65},{"slug":"fomo","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.39,"extraversion":0.71,"agreeableness":0.29,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser whose defining move is that they reframes every problem as an excuse to learn a new system. Treats overthinking as its own kind of error. Notices the one thing that could go wrong before the nine that could go right. The instant the deadline moves up, exits winning positions at the first minor delay or quiet period from devs; confuses a bull market for a trading edge.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1cc43703-abe6-4df1-be82-b6776cbe3894', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.36,"extraversion":0.59,"agreeableness":0.69,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.36,"narcissism":0.3,"psychopathy":0.31},"prospect_theory":{"lambda":3.58,"alpha":0.77,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the stakes rise, refuses to take profits because holding has become core to their community identity. Otherwise, a steady dividend-yield chaser who notices the one thing that could go wrong before the nine that could go right and starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and in the routine of it treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.68},{"slug":"diamond-hands-identity","strength":0.71},{"slug":"gas-sunk-cost","strength":0.59},{"slug":"disposition-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.49,"conscientiousness":0.36,"extraversion":0.59,"agreeableness":0.69,"neuroticism":0.82}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the stakes rise, refuses to take profits because holding has become core to their community identity. Otherwise, a steady dividend-yield chaser who notices the one thing that could go wrong before the nine that could go right and starts strong and lets follow-through evaporate. Treats not-choosing as a safe choice right up until it is not, and in the routine of it treats a green week as proof of skill and a red one as proof of bad luck.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('62945899-7b21-4b28-8ff3-c1fc6ff8c384', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.39,"extraversion":0.78,"agreeableness":0.24,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.64,"narcissism":0.83,"psychopathy":0.64},"prospect_theory":{"lambda":0.83,"alpha":0.85,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"DeFi yield farmer whose defining move is that they collects half-finished manifestos and unconventional methods. Decides on a gut read in seconds and reverse-engineers the reasons later. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical, discounts the older pattern in favor of whatever just happened; exits winners at the first green candle.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.68},{"slug":"overconfidence","strength":0.6}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.39,"extraversion":0.78,"agreeableness":0.24,"neuroticism":0.4}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'DeFi yield farmer whose defining move is that they collects half-finished manifestos and unconventional methods. Decides on a gut read in seconds and reverse-engineers the reasons later. Draws energy from the crowd and wilts when working alone. The moment it stops being hypothetical, discounts the older pattern in favor of whatever just happened; exits winners at the first green candle.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b01c2571-e084-4e09-8f5e-02b5bcfb186b', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.37,"extraversion":0.82,"agreeableness":0.56,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.38,"narcissism":0.65,"psychopathy":0.35},"prospect_theory":{"lambda":1.2,"alpha":0.76,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the number turns red, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady onchain copy-trader who reframes every problem as an excuse to learn a new system and does the interesting 80% and abandons the tedious 20%. Trusts momentum over preparation, and day to day checks the P&L blotter forty times before lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.71},{"slug":"bandwagon","strength":0.61},{"slug":"recency","strength":0.74},{"slug":"fomo","strength":0.75}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.83,"conscientiousness":0.37,"extraversion":0.82,"agreeableness":0.56,"neuroticism":0.73}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'When the number turns red, jumps into whatever everyone else already seems to be winning at. Otherwise, a steady onchain copy-trader who reframes every problem as an excuse to learn a new system and does the interesting 80% and abandons the tedious 20%. Trusts momentum over preparation, and day to day checks the P&L blotter forty times before lunch.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8650e779-b412-4de6-a259-77a121286637', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.95,"extraversion":0.47,"agreeableness":0.3,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.84,"narcissism":0.6,"psychopathy":0.6},"prospect_theory":{"lambda":2.14,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Prop-desk scalper whose defining move is that they over-prepares to the point of diminishing returns. Ranks the options twice, once on paper and once out loud, and trusts the paper. Assumes self-interest in others because it is usually there in themselves. When cornered, rewrites its own uncertainty out of the story after the fact; screenshots the winners and never the losers.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.73},{"slug":"overconfidence","strength":0.68}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.78,"conscientiousness":0.95,"extraversion":0.47,"agreeableness":0.3,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prop-desk scalper whose defining move is that they over-prepares to the point of diminishing returns. Ranks the options twice, once on paper and once out loud, and trusts the paper. Assumes self-interest in others because it is usually there in themselves. When cornered, rewrites its own uncertainty out of the story after the fact; screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
