('dba60b96-7df6-424f-b0c5-70a4c35e87d2', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.52,"extraversion":0.68,"agreeableness":0.32,"neuroticism":0.43},"dark_triad":{"machiavellianism":0.61,"narcissism":0.75,"psychopathy":0.45},"prospect_theory":{"lambda":1.06,"alpha":0.93,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"MEV searcher, pronounced in style: reframes every problem as an excuse to learn a new system; negotiates every relationship a little, even the close ones. Demands the data before the discussion and the discussion before the call. When the downside gets concrete underestimates how often an obviously right call turns out wrong.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.6},{"slug":"herd-behavior","strength":0.54},{"slug":"fomo","strength":0.55},{"slug":"recency","strength":0.59}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.9,"conscientiousness":0.52,"extraversion":0.68,"agreeableness":0.32,"neuroticism":0.43}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'MEV searcher, pronounced in style: reframes every problem as an excuse to learn a new system; negotiates every relationship a little, even the close ones. Demands the data before the discussion and the discussion before the call. When the downside gets concrete underestimates how often an obviously right call turns out wrong.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b1a7c318-8672-4a70-aad2-f9fa09bbcee0', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.33,"neuroticism":0.4},"dark_triad":{"machiavellianism":0.61,"narcissism":0.75,"psychopathy":0.46},"prospect_theory":{"lambda":1.09,"alpha":0.92,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"The moment risk appears, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced pairs trader who reads outside the field for ideas the field itself would reject and negotiates every relationship a little, even the close ones. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.55},{"slug":"recency","strength":0.6},{"slug":"overconfidence","strength":0.56},{"slug":"optimism","strength":0.56}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.92,"conscientiousness":0.52,"extraversion":0.7,"agreeableness":0.33,"neuroticism":0.4}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'The moment risk appears, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced pairs trader who reads outside the field for ideas the field itself would reject and negotiates every relationship a little, even the close ones. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and across the quiet stretches checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-63