('d7d9a153-5e63-40e7-9fee-0f303b882bab', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.37,"extraversion":0.57,"agreeableness":0.68,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.35,"narcissism":0.38,"psychopathy":0.32},"prospect_theory":{"lambda":3.4,"alpha":0.76,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady MEV searcher who carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not. Starts strong and lets follow-through evaporate. As soon as real money or reputation is on the line feels a winning position as fragile and a losing one as merely paused; in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.61},{"slug":"disposition-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.37,"extraversion":0.57,"agreeableness":0.68,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady MEV searcher who carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not. Starts strong and lets follow-through evaporate. As soon as real money or reputation is on the line feels a winning position as fragile and a losing one as merely paused; in the pattern nobody else tracks, checks the P&L blotter forty times before lunch.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ba891533-bcc8-4e8f-b410-8ea5ad1d3dcb', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.87,"extraversion":0.49,"agreeableness":0.37,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.86,"narcissism":0.5,"psychopathy":0.56},"prospect_theory":{"lambda":2.28,"alpha":0.96,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Wants the base rate before the anecdote. This retail momentum chaser front-loads the work and double-checks it twice and is difficult to rattle even with genuinely bad news. The instant it becomes irreversible is more certain than the hit rate justifies — when no one is watching, sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.6},{"slug":"overconfidence","strength":0.72}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","temperament","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.76,"conscientiousness":0.87,"extraversion":0.49,"agreeableness":0.37,"neuroticism":0.21}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','temperament','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Wants the base rate before the anecdote. This retail momentum chaser front-loads the work and double-checks it twice and is difficult to rattle even with genuinely bad news. The instant it becomes irreversible is more certain than the hit rate justifies — when no one is watching, sizes every position at exactly 2% risk.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b466e328-11df-4bf2-96e2-c23a5823373a', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.9,"extraversion":0.44,"agreeableness":0.33,"neuroticism":0.31},"dark_triad":{"machiavellianism":0.79,"narcissism":0.54,"psychopathy":0.57},"prospect_theory":{"lambda":2.3,"alpha":0.97,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Ranks the options twice, once on paper and once out loud, and trusts the paper. This algorithmic market-maker front-loads the work and double-checks it twice and treats setbacks as data rather than verdicts. When the downside gets concrete holds their estimates with a certainty the track record does not support — in the small things, keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.56},{"slug":"overconfidence","strength":0.62},{"slug":"recency","strength":0.55}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.85,"conscientiousness":0.9,"extraversion":0.44,"agreeableness":0.33,"neuroticism":0.31}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Ranks the options twice, once on paper and once out loud, and trusts the paper. This algorithmic market-maker front-loads the work and double-checks it twice and treats setbacks as data rather than verdicts. When the downside gets concrete holds their estimates with a certainty the track record does not support — in the small things, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('096f8c37-58fc-431c-9daf-e1206d2dfd73', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.73,"extraversion":0.47,"agreeableness":0.62,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.51,"narcissism":0.39,"psychopathy":0.27},"prospect_theory":{"lambda":2.87,"alpha":0.86,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Is surprised in the moment and certain in the retelling. A steady bonding-curve sniper: plans in exhaustive detail and resents any deviation, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and once the urgency drains out keeps a losing-trade journal they never re-read.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"hindsight","strength":0.56},{"slug":"recency","strength":0.52},{"slug":"ath-anchoring","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.62,"conscientiousness":0.73,"extraversion":0.47,"agreeableness":0.62,"neuroticism":0.59}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Is surprised in the moment and certain in the retelling. A steady bonding-curve sniper: plans in exhaustive detail and resents any deviation, would rather invent a worse tool than use someone else''s good one. Feels the weight of a decision lighten the moment someone else co-signs it, and once the urgency drains out keeps a losing-trade journal they never re-read.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('76baef55-fcde-4e5e-b56d-23d6cf66171d', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.36,"extraversion":0.6,"agreeableness":0.61,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.36,"narcissism":0.4,"psychopathy":0.31},"prospect_theory":{"lambda":3.76,"alpha":0.81,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady retail momentum chaser who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Reframes every problem as an excuse to learn a new system. When there is no clean exit sells the winners early and clings to the losers for far too long; on a slow afternoon, apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.61},{"slug":"recency","strength":0.62},{"slug":"disposition-effect","strength":0.65}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.69,"conscientiousness":0.36,"extraversion":0.6,"agreeableness":0.61,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A steady retail momentum chaser who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Reframes every problem as an excuse to learn a new system. When there is no clean exit sells the winners early and clings to the losers for far too long; on a slow afternoon, apes the launch before the contract is verified.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
