('d73f26ec-dcb7-4d75-a216-0186ce6d8e92', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.65,"extraversion":0.66,"agreeableness":0.59,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.45,"narcissism":0.56,"psychopathy":0.24},"prospect_theory":{"lambda":2.76,"alpha":0.88,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it easier to believe something once it stops being a minority view. A measured prop-desk scalper: gets bored of the proven method exactly when it starts working, treats a missed deadline as a personal failure regardless of cause. Waits for a permission that never quite arrives, and in the version no one reviews holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.57},{"slug":"fomo","strength":0.51},{"slug":"recency","strength":0.56},{"slug":"optimism","strength":0.53}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.66,"conscientiousness":0.65,"extraversion":0.66,"agreeableness":0.59,"neuroticism":0.53}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Finds it easier to believe something once it stops being a minority view. A measured prop-desk scalper: gets bored of the proven method exactly when it starts working, treats a missed deadline as a personal failure regardless of cause. Waits for a permission that never quite arrives, and in the version no one reviews holds a bag from 2021 out of pure spite.', 0.88, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
