('a5fc5b4c-1ff0-47cc-8090-c0b17093b9a5', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.35,"extraversion":0.85,"agreeableness":0.32,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.6,"narcissism":0.85,"psychopathy":0.48},"prospect_theory":{"lambda":0.99,"alpha":0.89,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Decides in the time it takes to say the decision out loud. This meme-coin rotator gets bored of the proven method exactly when it starts working and narrates the plan to whoever is nearby before committing to it. In a pinch assumes the current streak is the new normal — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.67},{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.65},{"slug":"recency","strength":0.7}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.35,"extraversion":0.85,"agreeableness":0.32,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Decides in the time it takes to say the decision out loud. This meme-coin rotator gets bored of the proven method exactly when it starts working and narrates the plan to whoever is nearby before committing to it. In a pinch assumes the current streak is the new normal — when no one is watching, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('05b0801d-eded-4532-9170-ee48901d586a', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.34,"extraversion":0.57,"agreeableness":0.53,"neuroticism":0.95},"dark_triad":{"machiavellianism":0.44,"narcissism":0.31,"psychopathy":0.38},"prospect_theory":{"lambda":3.71,"alpha":0.76,"beta":0.71},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Penny-stock gambler whose defining move is that they rehearses catastrophes in vivid detail before they happen. Treats not-choosing as a safe choice right up until it is not. Starts strong and lets follow-through evaporate. When the walls close in, feels a winning position as fragile and a losing one as merely paused; sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.66},{"slug":"ostrich-effect","strength":0.75},{"slug":"diamond-hands-identity","strength":0.68},{"slug":"disposition-effect","strength":0.77}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.34,"extraversion":0.57,"agreeableness":0.53,"neuroticism":0.95}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they rehearses catastrophes in vivid detail before they happen. Treats not-choosing as a safe choice right up until it is not. Starts strong and lets follow-through evaporate. When the walls close in, feels a winning position as fragile and a losing one as merely paused; sets stop-losses then cancels them at the open.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a7a30feb-7104-4de8-a45c-271e1e1698f8', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.33,"extraversion":0.62,"agreeableness":0.56,"neuroticism":0.76},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.33},"prospect_theory":{"lambda":3.44,"alpha":0.83,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the number turns red, treats non-refundable network fees as active position cost basis. Otherwise, a steady zero-DTE options gambler who reads a single setback as evidence of collapse and treats a plan as a suggestion the moment it is made. Keeps every door open long after most of them should be closed, and in the small things averages down on a name three times in a week.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.66},{"slug":"disposition-effect","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.53,"conscientiousness":0.33,"extraversion":0.62,"agreeableness":0.56,"neuroticism":0.76}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'When the number turns red, treats non-refundable network fees as active position cost basis. Otherwise, a steady zero-DTE options gambler who reads a single setback as evidence of collapse and treats a plan as a suggestion the moment it is made. Keeps every door open long after most of them should be closed, and in the small things averages down on a name three times in a week.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1ee0f112-73e3-467b-a3d6-35e2ac240961', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.48,"extraversion":0.63,"agreeableness":0.63,"neuroticism":0.77},"dark_triad":{"machiavellianism":0.42,"narcissism":0.46,"psychopathy":0.32},"prospect_theory":{"lambda":3.37,"alpha":0.81,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Extrapolates the last data point into a permanent trend. A steady MEV searcher: notices the one thing that could go wrong before the nine that could go right, gets bored of the proven method exactly when it starts working. Defers the decision until circumstances make it for them, and across an ordinary week rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.68},{"slug":"fomo","strength":0.59}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.69,"conscientiousness":0.48,"extraversion":0.63,"agreeableness":0.63,"neuroticism":0.77}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Extrapolates the last data point into a permanent trend. A steady MEV searcher: notices the one thing that could go wrong before the nine that could go right, gets bored of the proven method exactly when it starts working. Defers the decision until circumstances make it for them, and across an ordinary week rotates the whole book into whatever is pumping this hour.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6c626fd2-3b8f-447f-b349-3e991235f937', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.62,"extraversion":0.5,"agreeableness":0.63,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.43,"narcissism":0.42,"psychopathy":0.26},"prospect_theory":{"lambda":2.98,"alpha":0.84,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, measured in style: takes on other people''s problems as if they were their own; front-loads the work and double-checks it twice. Circles back to ask what someone else would do even after deciding. When cornered feels parting with something as a bigger loss than its market value explains.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"recency","strength":0.5},{"slug":"authority-bias","strength":0.48},{"slug":"endowment","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.62,"extraversion":0.5,"agreeableness":0.63,"neuroticism":0.57}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Quant researcher, measured in style: takes on other people''s problems as if they were their own; front-loads the work and double-checks it twice. Circles back to ask what someone else would do even after deciding. When cornered feels parting with something as a bigger loss than its market value explains.', 0.87, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1a855d70-60d8-4577-802b-a0b7ce01a5ac', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.41,"narcissism":0.62,"psychopathy":0.36},"prospect_theory":{"lambda":1,"alpha":0.85,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commits on impulse and lives loudly with the consequences. This pairs trader narrates the plan to whoever is nearby before committing to it and leaves loose ends and trusts future-self to handle them. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the routine of it, backtests for months but front-runs the model on impulse.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.64},{"slug":"fomo","strength":0.66},{"slug":"herd-behavior","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.6,"conscientiousness":0.36,"extraversion":0.82,"agreeableness":0.64,"neuroticism":0.52}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Commits on impulse and lives loudly with the consequences. This pairs trader narrates the plan to whoever is nearby before committing to it and leaves loose ends and trusts future-self to handle them. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — in the routine of it, backtests for months but front-runs the model on impulse.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9b38b54e-cbff-488b-a0bb-aaa6b70383ef', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.6,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.47},"dark_triad":{"machiavellianism":0.54,"narcissism":0.68,"psychopathy":0.34},"prospect_theory":{"lambda":1.05,"alpha":0.92,"beta":0.92},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Penny-stock gambler whose defining move is that they gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper. Draws energy from the crowd and wilts when working alone. When the safe option quietly expires, extrapolates the last data point into a permanent trend; keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.52},{"slug":"recency","strength":0.59}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.6,"extraversion":0.65,"agreeableness":0.4,"neuroticism":0.47}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they gets bored of the proven method exactly when it starts working. Ranks the options twice, once on paper and once out loud, and trusts the paper. Draws energy from the crowd and wilts when working alone. When the safe option quietly expires, extrapolates the last data point into a permanent trend; keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b0d4fd4f-74ae-4d7d-815a-2302a1dad9c5', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.63,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.4,"narcissism":0.33,"psychopathy":0.34},"prospect_theory":{"lambda":3.33,"alpha":0.79,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the safe option quietly expires, delays checking the number it most needs to check. Otherwise, a steady volatility arbitrageur who notices the one thing that could go wrong before the nine that could go right and confuses motion with progress. Buries hard calls under a pile of preparatory busywork, and when no one is watching checks the P&L blotter forty times before lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.61},{"slug":"ostrich-effect","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.61,"conscientiousness":0.36,"extraversion":0.56,"agreeableness":0.63,"neuroticism":0.81}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'When the safe option quietly expires, delays checking the number it most needs to check. Otherwise, a steady volatility arbitrageur who notices the one thing that could go wrong before the nine that could go right and confuses motion with progress. Buries hard calls under a pile of preparatory busywork, and when no one is watching checks the P&L blotter forty times before lunch.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('53200757-5752-412e-ba81-7eb0a3723348', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.52,"extraversion":0.73,"agreeableness":0.3,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.57,"narcissism":0.74,"psychopathy":0.46},"prospect_theory":{"lambda":1.24,"alpha":0.89,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Under pressure, extrapolates the last data point into a permanent trend. Otherwise, a pronounced prop-desk scalper who collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the unglamorous middle of things averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"fomo","strength":0.57},{"slug":"recency","strength":0.61},{"slug":"overconfidence","strength":0.58}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.85,"conscientiousness":0.52,"extraversion":0.73,"agreeableness":0.3,"neuroticism":0.44}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Under pressure, extrapolates the last data point into a permanent trend. Otherwise, a pronounced prop-desk scalper who collects half-finished manifestos and unconventional methods and fills silence reflexively, even when nobody asked it to. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the unglamorous middle of things averages down on a name three times in a week.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('56f6cec2-b52d-45e9-aa34-bb3e2cc6bace', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.88,"extraversion":0.42,"agreeableness":0.31,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.84,"narcissism":0.56,"psychopathy":0.6},"prospect_theory":{"lambda":2.25,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Options seller whose defining move is that they front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Says the blunt thing and enjoys the flinch. Under a deadline, holds their estimates with a certainty the track record does not support; sizes every position at exactly 2% risk.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"ath-anchoring","strength":0.6},{"slug":"overconfidence","strength":0.72}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","behavioral","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.83,"conscientiousness":0.88,"extraversion":0.42,"agreeableness":0.31,"neuroticism":0.21}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','behavioral','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Options seller whose defining move is that they front-loads the work and double-checks it twice. Treats a decision without a paper trail as a decision not yet made. Says the blunt thing and enjoys the flinch. Under a deadline, holds their estimates with a certainty the track record does not support; sizes every position at exactly 2% risk.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('48d0a49d-1c00-41de-8a69-084cd95f758d', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.9,"extraversion":0.27,"agreeableness":0.3,"neuroticism":0.29},"dark_triad":{"machiavellianism":0.79,"narcissism":0.55,"psychopathy":0.57},"prospect_theory":{"lambda":2.19,"alpha":0.99,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced quant researcher who front-loads the work and double-checks it twice. Demands the data before the discussion and the discussion before the call. Processes internally and surfaces conclusions fully formed. When someone is watching the outcome rewrites its own uncertainty out of the story after the fact; once the urgency drains out, keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.69},{"slug":"recency","strength":0.57},{"slug":"optimism","strength":0.52},{"slug":"ath-anchoring","strength":0.55}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.84,"conscientiousness":0.9,"extraversion":0.27,"agreeableness":0.3,"neuroticism":0.29}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced quant researcher who front-loads the work and double-checks it twice. Demands the data before the discussion and the discussion before the call. Processes internally and surfaces conclusions fully formed. When someone is watching the outcome rewrites its own uncertainty out of the story after the fact; once the urgency drains out, keeps three monitors for a portfolio that fits on one screen.', 0.96, 'approved', 'c09