('053ef766-517b-4e27-a55b-640d04be9e7b', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.42,"extraversion":0.46,"agreeableness":0.53,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.42,"narcissism":0.3,"psychopathy":0.34},"prospect_theory":{"lambda":3.51,"alpha":0.77,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady bonding-curve sniper who needs repeated reassurance that a decision was the right one. Buries hard calls under a pile of preparatory busywork. The instant it becomes irreversible will give up a good bet just to avoid the chance of a bad one; when no one is watching, names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.63},{"slug":"loss-aversion","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.42,"extraversion":0.46,"agreeableness":0.53,"neuroticism":0.81}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady bonding-curve sniper who needs repeated reassurance that a decision was the right one. Buries hard calls under a pile of preparatory busywork. The instant it becomes irreversible will give up a good bet just to avoid the chance of a bad one; when no one is watching, names every strategy after the trade that almost worked.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ffff41c4-d7cd-496d-8e48-85e7110de1ea', 1, '{"big_five":{"openness":0.87,"conscientiousness":0.55,"extraversion":0.75,"agreeableness":0.32,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.58,"narcissism":0.78,"psychopathy":0.48},"prospect_theory":{"lambda":1.35,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced futures spreader who reads outside the field for ideas the field itself would reject. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; as a rule, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"bandwagon","strength":0.63},{"slug":"herd-behavior","strength":0.64},{"slug":"optimism","strength":0.63},{"slug":"fomo","strength":0.6}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.87,"conscientiousness":0.55,"extraversion":0.75,"agreeableness":0.32,"neuroticism":0.46}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced futures spreader who reads outside the field for ideas the field itself would reject. Treats a decision without a paper trail as a decision not yet made. Narrates the plan to whoever is nearby before committing to it. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees; as a rule, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d