('defa7b5c-6ffa-4f81-ab89-0b4726fee5d0', 1, '{"big_five":{"openness":0.76,"conscientiousness":0.46,"extraversion":0.82,"agreeableness":0.7,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.4,"narcissism":0.62,"psychopathy":0.31},"prospect_theory":{"lambda":0.93,"alpha":0.83,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady futures spreader: recharges by being around people, not away from them, treats established procedure as a first draft to be rewritten. Decides in the time it takes to say the decision out loud, and on an ordinary week holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"recency","strength":0.58},{"slug":"dunning-kruger","strength":0.62},{"slug":"bandwagon","strength":0.68}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.76,"conscientiousness":0.46,"extraversion":0.82,"agreeableness":0.7,"neuroticism":0.66}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady futures spreader: recharges by being around people, not away from them, treats established procedure as a first draft to be rewritten. Decides in the time it takes to say the decision out loud, and on an ordinary week holds a bag from 2021 out of pure spite.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
