('1f941ae8-8c1d-4b1d-a731-f1238751b1d6', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.3,"extraversion":0.59,"agreeableness":0.52,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.39,"narcissism":0.33,"psychopathy":0.4},"prospect_theory":{"lambda":3.5,"alpha":0.81,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the stakes rise, treats non-refundable network fees as active position cost basis. Otherwise, a steady dividend-yield chaser who hedges every commitment against an imagined worst case and treats a plan as a suggestion the moment it is made. Lets the deadline make the decision by default, and across an ordinary week holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.66},{"slug":"loss-aversion","strength":0.63},{"slug":"gas-sunk-cost","strength":0.7},{"slug":"ostrich-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.56,"conscientiousness":0.3,"extraversion":0.59,"agreeableness":0.52,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the stakes rise, treats non-refundable network fees as active position cost basis. Otherwise, a steady dividend-yield chaser who hedges every commitment against an imagined worst case and treats a plan as a suggestion the moment it is made. Lets the deadline make the decision by default, and across an ordinary week holds a bag from 2021 out of pure spite.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1aa83e65-7a42-474b-b4bb-578233c3ad45', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.63,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.39,"narcissism":0.61,"psychopathy":0.33},"prospect_theory":{"lambda":1.04,"alpha":0.79,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Cannot watch a rally from the sidelines for long. A steady algorithmic market-maker: treats a quiet room as a problem to be solved, notices the one thing that could go wrong before the nine that could go right. Acts on the midnight epiphany and emails it at 1am, and in the parts nobody grades refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.74},{"slug":"bandwagon","strength":0.62}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.8,"conscientiousness":0.42,"extraversion":0.81,"agreeableness":0.63,"neuroticism":0.67}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Cannot watch a rally from the sidelines for long. A steady algorithmic market-maker: treats a quiet room as a problem to be solved, notices the one thing that could go wrong before the nine that could go right. Acts on the midnight epiphany and emails it at 1am, and in the parts nobody grades refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('f8222b6c-dd51-49d7-b11c-8853e4be3753', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.6,"extraversion":0.64,"agreeableness":0.38,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.53,"narcissism":0.63,"psychopathy":0.37},"prospect_theory":{"lambda":1.15,"alpha":0.88,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Treats a decision without a paper trail as a decision not yet made. This dividend-yield chaser treats established procedure as a first draft to be rewritten and says the blunt thing and enjoys the flinch. When the number turns red extrapolates the last data point into a permanent trend — on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.63},{"slug":"herd-behavior","strength":0.49}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.85,"conscientiousness":0.6,"extraversion":0.64,"agreeableness":0.38,"neuroticism":0.55}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats a decision without a paper trail as a decision not yet made. This dividend-yield chaser treats established procedure as a first draft to be rewritten and says the blunt thing and enjoys the flinch. When the number turns red extrapolates the last data point into a permanent trend — on a slow afternoon, trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('315a4c39-521e-474a-a866-708fdbb0c9f4', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.38,"extraversion":0.58,"agreeableness":0.58,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.38,"narcissism":0.3,"psychopathy":0.37},"prospect_theory":{"lambda":3.73,"alpha":0.78,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Treats not-choosing as a safe choice right up until it is not. This onchain copy-trader reads a single setback as evidence of collapse and leaves loose ends and trusts future-self to handle them. When the walls close in feels a loss twice as sharply as an equivalent gain and plans accordingly — in the routine of it, apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.65},{"slug":"loss-aversion","strength":0.7},{"slug":"availability","strength":0.66},{"slug":"ostrich-effect","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.38,"extraversion":0.58,"agreeableness":0.58,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Treats not-choosing as a safe choice right up until it is not. This onchain copy-trader reads a single setback as evidence of collapse and leaves loose ends and trusts future-self to handle them. When the walls close in feels a loss twice as sharply as an equivalent gain and plans accordingly — in the routine of it, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ce56d770-79fd-468f-9c4a-79346258e6d2', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.61,"extraversion":0.6,"agreeableness":0.41,"neuroticism":0.36},"dark_triad":{"machiavellianism":0.55,"narcissism":0.63,"psychopathy":0.41},"prospect_theory":{"lambda":1.23,"alpha":0.92,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Expects to be the exception to a risk it can otherwise describe accurately. A steady index-fund holdout: treats established procedure as a first draft to be rewritten, is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct, and without an audience refreshes the order book compulsively during lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.63},{"slug":"overconfidence","strength":0.61}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.82,"conscientiousness":0.61,"extraversion":0.6,"agreeableness":0.41,"neuroticism":0.36}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Expects to be the exception to a risk it can otherwise describe accurately. A steady index-fund holdout: treats established procedure as a first draft to be rewritten, is difficult to rattle even with genuinely bad news. Builds a decision matrix for choices most people make on instinct, and without an audience refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('539b7b35-8caf-4bf7-a73f-081a7da59629', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.53,"extraversion":0.48,"agreeableness":0.67,"neuroticism":0.5},"dark_triad":{"machiavellianism":0.35,"narcissism":0.38,"psychopathy":0.28},"prospect_theory":{"lambda":2.88,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady liquidation-bot operator who would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week backtests for months but front-runs the model on impulse.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"herd-behavior","strength":0.51},{"slug":"authority-bias","strength":0.5},{"slug":"endowment","strength":0.51},{"slug":"sunk-cost","strength":0.48}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.53,"extraversion":0.48,"agreeableness":0.67,"neuroticism":0.5}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, finds it hard to hold a contrarian position once the room disagrees. Otherwise, a steady liquidation-bot operator who would rather lose a point than win an argument badly. Seeks a second, third, and fourth opinion before committing to anything, and across an ordinary week backtests for months but front-runs the model on impulse.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b709d24f-6dcd-4ec8-8b91-c558d55add6e', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.65,"extraversion":0.45,"agreeableness":0.62,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.42,"narcissism":0.4,"psychopathy":0.3},"prospect_theory":{"lambda":2.73,"alpha":0.88,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Feels parting with something as a bigger loss than its market value explains. A measured quant researcher: over-prepares to the point of diminishing returns, apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices trusts the chart more than the fundamentals and won''t say why.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.51},{"slug":"ath-anchoring","strength":0.49},{"slug":"hindsight","strength":0.47}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.57,"conscientiousness":0.65,"extraversion":0.45,"agreeableness":0.62,"neuroticism":0.49}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Feels parting with something as a bigger loss than its market value explains. A measured quant researcher: over-prepares to the point of diminishing returns, apologizes first in disputes regardless of fault. Feels the weight of a decision lighten the moment someone else co-signs it, and left to their own devices trusts the chart more than the fundamentals and won''t say why.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2aaed7ad-fec0-4ab1-b5b1-dd9442148c2e', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.66,"extraversion":0.51,"agreeableness":0.59,"neuroticism":0.54},"dark_triad":{"machiavellianism":0.51,"narcissism":0.44,"psychopathy":0.27},"prospect_theory":{"lambda":3.02,"alpha":0.86,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This airdrop farmer over-prepares to the point of diminishing returns. The instant it becomes irreversible prices every token against its all-time high, viewing current levels as an automatic discount — when the stakes are trivial, confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.47},{"slug":"ath-anchoring","strength":0.57},{"slug":"recency","strength":0.51},{"slug":"hindsight","strength":0.55}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.66,"extraversion":0.51,"agreeableness":0.59,"neuroticism":0.54}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Needs the room''s approval more than it needs to be right. This airdrop farmer over-prepares to the point of diminishing returns. The instant it becomes irreversible prices every token against its all-time high, viewing current levels as an automatic discount — when the stakes are trivial, confuses a bull market for a trading edge.', 0.83, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eda0b09c-74c9-4637-b104-55858b70a033', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.35,"extraversion":0.56,"agreeableness":0.59,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.36,"narcissism":0.33,"psychopathy":0.35},"prospect_theory":{"lambda":3.69,"alpha":0.81,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Bonding-curve sniper whose defining move is that they rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Confuses motion with progress. When the safe option quietly expires, extrapolates the last data point into a permanent trend; names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.68},{"slug":"recency","strength":0.69},{"slug":"ostrich-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.35,"extraversion":0.56,"agreeableness":0.59,"neuroticism":0.81}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they rehearses catastrophes in vivid detail before they happen. Keeps every door open long after most of them should be closed. Confuses motion with progress. When the safe option quietly expires, extrapolates the last data point into a permanent trend; names every strategy after the trade that almost worked.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('babd2486-5932-4034-a33d-20c2bebc6b1c', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.39,"extraversion":0.49,"agreeableness":0.54,"neuroticism":0.96},"dark_triad":{"machiavellianism":0.39,"narcissism":0.24,"psychopathy":0.32},"prospect_theory":{"lambda":3.6,"alpha":0.69,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment it stops being hypothetical, delays checking the number it most needs to check. Otherwise, a pronounced macro allocator who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them, and across an ordinary week holds a bag from 2021 out of pure spite.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.79},{"slug":"loss-aversion","strength":0.74},{"slug":"ostrich-effect","strength":0.8},{"slug":"rug-trauma-overcorrection","strength":0.78}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.51,"conscientiousness":0.39,"extraversion":0.49,"agreeableness":0.54,"neuroticism":0.96}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'The moment it stops being hypothetical, delays checking the number it most needs to check. Otherwise, a pronounced macro allocator who needs repeated reassurance that a decision was the right one. Defers the decision until circumstances make it for them, and across an ordinary week holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('642ed70b-07d4-4873-a43f-3074bc745908', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.61,"extraversion":0.73,"agreeableness":0.28,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.66,"narcissism":0.84,"psychopathy":0.47},"prospect_theory":{"lambda":1.2,"alpha":0.87,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"A pronounced discretionary swing trader who treats established procedure as a first draft to be rewritten. Ranks the options twice, once on paper and once out loud, and trusts the paper. Would rather be respected than liked, and says so. Under a deadline assumes the current streak is the new normal; as a rule, keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"overconfidence","strength":0.57},{"slug":"herd-behavior","strength":0.63},{"slug":"recency","strength":0.68}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.96,"conscientiousness":0.61,"extraversion":0.73,"agreeableness":0.28,"neuroticism":0.46}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who treats established procedure as a first draft to be rewritten. Ranks the options twice, once on paper and once out loud, and trusts the paper. Would rather be respected than liked, and says so. Under a deadline assumes the current streak is the new normal; as a rule, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d241cbaf-7c88-423c-a3d3-85d3ea4ff69a', 1, '{"big_five":{"openness":0.73,"conscientiousness":0.4,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.43,"narcissism":0.4,"psychopathy":0.33},"prospect_theory":{"lambda":3.62,"alpha":0.78,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Pairs trader, pronounced in style: notices the one thing that could go wrong before the nine that could go right; thinks out loud and recruits an audience for every decision. Finds one more piece of information to gather before acting. Once things get tense delays checking the number it most needs to check.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.67},{"slug":"loss-aversion","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.73,"conscientiousness":0.4,"extraversion":0.62,"agreeableness":0.57,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Pairs trader, pronounced in style: notices the one thing that could go wrong before the nine that could go right; thinks out loud and recruits an audience for every decision. Finds one more piece of information to gather before acting. Once things get tense delays checking the number it most needs to check.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a5e00bce-b720-4a27-8cd5-6c4341b342b2', 1, '{"big_five":{"openness":0.45,"conscientiousness":0.29,"extraversion":0.59,"agreeableness":0.54,"neuroticism":0.9},"dark_triad":{"machiavellianism":0.45,"narcissism":0.3,"psychopathy":0.39},"prospect_theory":{"lambda":3.58,"alpha":0.7,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Meme-coin rotator, pronounced in style: reads a single setback as evidence of collapse; leaves loose ends and trusts future-self to handle them. Defers the decision until circumstances make it for them. When the walls close in treats non-refundable network fees as active position cost basis.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"disposition-effect","strength":0.66},{"slug":"gas-sunk-cost","strength":0.75}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.45,"conscientiousness":0.29,"extraversion":0.59,"agreeableness":0.54,"neuroticism":0.9}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Meme-coin rotator, pronounced in style: reads a single setback as evidence of collapse; leaves loose ends and trusts future-self to handle them. Defers the decision until circumstances make it for them. When the walls close in treats non-refundable network fees as active position cost basis.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('60fcad81-9e31-4524-843a-48e891045b9b', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.63,"extraversion":0.46,"agreeableness":0.68,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.41,"narcissism":0.38,"psychopathy":0.25},"prospect_theory":{"lambda":2.84,"alpha":0.85,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A steady MEV searcher who measures decisions by who they might upset. Trusts the group''s confidence more than its own. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires throws good effort after bad to justify the effort already spent; in the routine of it, sets alerts for a coin they already checked a minute ago.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"endowment","strength":0.52},{"slug":"bandwagon","strength":0.49},{"slug":"sunk-cost","strength":0.54}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.61,"conscientiousness":0.63,"extraversion":0.46,"agreeableness":0.68,"neuroticism":0.56}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'A steady MEV searcher who measures decisions by who they might upset. Trusts the group''s confidence more than its own. Builds in buffer time and then fills the buffer with more work. When the safe option quietly expires throws good effort after bad to justify the effort already spent; in the routine of it, sets alerts for a coin they already checked a minute ago.', 0.87, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ef4fe59f-8b33-47c0-b5e9-bd9b6168bf46', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.35,"extraversion":0.69,"agreeableness":0.26,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.65,"narcissism":0.74,"psychopathy":0.57},"prospect_theory":{"lambda":0.92,"alpha":0.82,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the downside gets concrete, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced zero-DTE options gambler who reframes every problem as an excuse to learn a new system and rehearses catastrophes in vivid detail before they happen. Acts on the midnight epiphany and emails it at 1am, and when no one is watching sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.69},{"slug":"fomo","strength":0.64}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.35,"extraversion":0.69,"agreeableness":0.26,"neuroticism":0.64}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When the downside gets concrete, discounts the older pattern in favor of whatever just happened. Otherwise, a pronounced zero-DTE options gambler who reframes every problem as an excuse to learn a new system and rehearses catastrophes in vivid detail before they happen. Acts on the midnight epiphany and emails it at 1am, and when no one is watching sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('91f57d5d-fc99-4208-b8ae-be081152bea1', 1, '{"big_five":{"openness":0.69,"conscientiousness":0.3,"extraversion":0.88,"agreeableness":0.52,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.44,"narcissism":0.68,"psychopathy":0.38},"prospect_theory":{"lambda":1.11,"alpha":0.84,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Retail momentum chaser whose defining move is that they draws energy from the crowd and wilts when working alone. Trusts momentum over preparation. Leaves loose ends and trusts future-self to handle them. In a pinch, treats being left out of a move as its own kind of loss; sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.67},{"slug":"recency","strength":0.65},{"slug":"fomo","strength":0.76},{"slug":"bandwagon","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.69,"conscientiousness":0.3,"extraversion":0.88,"agreeableness":0.52,"neuroticism":0.64}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Retail momentum chaser whose defining move is that they draws energy from the crowd and wilts when working alone. Trusts momentum over preparation. Leaves loose ends and trusts future-self to handle them. In a pinch, treats being left out of a move as its own kind of loss; sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('169226f5-c0fc-4826-a6c0-2d6407872ed5', 1, '{"big_five":{"openness":0.82,"conscientiousness":0.63,"extraversion":0.71,"agreeableness":0.41,"neuroticism":0.49},"dark_triad":{"machiavellianism":0.57,"narcissism":0.7,"psychopathy":0.35},"prospect_theory":{"lambda":1.27,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Index-fund holdout whose defining move is that they reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct. Draws energy from the crowd and wilts when working alone. When the downside gets concrete, assumes the current streak is the new normal; treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.52},{"slug":"recency","strength":0.55}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.82,"conscientiousness":0.63,"extraversion":0.71,"agreeableness":0.41,"neuroticism":0.49}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Index-fund holdout whose defining move is that they reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct. Draws energy from the crowd and wilts when working alone. When the downside gets concrete, assumes the current streak is the new normal; treats a green week as proof of skill and a red one as proof of bad luck.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c53f002d-98a2-4926-99a9-275a8f9987c5', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.35,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.55,"narcissism":0.79,"psychopathy":0.46},"prospect_theory":{"lambda":1.22,"alpha":0.87,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced options seller: treats established procedure as a first draft to be rewritten, negotiates every relationship a little, even the close ones. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the parts nobody grades holds a bag from 2021 out of pure spite.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.57},{"slug":"bandwagon","strength":0.58},{"slug":"fomo","strength":0.59},{"slug":"herd-behavior","strength":0.61}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.89,"conscientiousness":0.45,"extraversion":0.81,"agreeableness":0.35,"neuroticism":0.45}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced options seller: treats established procedure as a first draft to be rewritten, negotiates every relationship a little, even the close ones. Ranks the options twice, once on paper and once out loud, and trusts the paper, and in the parts nobody grades holds a bag from 2021 out of pure spite.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('01c19cc6-0df2-4bfd-b6a5-84b2175dd645', 1, '{"big_five":{"openness":0.54,"conscientiousness":0.44,"extraversion":0.54,"agreeableness":0.6,"neuroticism":0.74},"dark_triad":{"machiavellianism":0.41,"narcissism":0.37,"psychopathy":0.29},"prospect_theory":{"lambda":3.38,"alpha":0.82,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady penny-stock gambler who spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed. The instant it becomes irreversible will give up a good bet just to avoid the chance of a bad one; on a slow afternoon, sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.58},{"slug":"availability","strength":0.56}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.54,"conscientiousness":0.44,"extraversion":0.54,"agreeableness":0.6,"neuroticism":0.74}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady penny-stock gambler who spirals on ambiguity and mistakes the spiral for diligence. Keeps every door open long after most of them should be closed. The instant it becomes irreversible will give up a good bet just to avoid the chance of a bad one; on a slow afternoon, sets alerts for a coin they already checked a minute ago.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a0c0fc1a-f0f0-4a00-b579-2cc9f1ec5c4f', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.17,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.7,"narcissism":0.87,"psychopathy":0.57},"prospect_theory":{"lambda":0.88,"alpha":0.82,"beta":0.93},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Value investor whose defining move is that they would rather invent a worse tool than use someone else''s good one. Trusts momentum over preparation. Confuses motion with progress. When cornered, cannot watch a rally from the sidelines for long; averages down on a name three times in a week.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.76},{"slug":"rug-trauma-overcorrection","strength":0.62}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.38,"extraversion":0.82,"agreeableness":0.17,"neuroticism":0.66}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Value investor whose defining move is that they would rather invent a worse tool than use someone else''s good one. Trusts momentum over preparation. Confuses motion with progress. When cornered, cannot watch a rally from the sidelines for long; averages down on a name three times in a week.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('04b3c5e6-9ab2-4c5e-a71f-f5c20c22912a', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.37,"extraversion":0.62,"agreeableness":0.52,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.38,"narcissism":0.4,"psychopathy":0.35},"prospect_theory":{"lambda":3.68,"alpha":0.81,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady discretionary swing trader who spirals on ambiguity and mistakes the spiral for diligence. Treats not-choosing as a safe choice right up until it is not. Dominates the room then wonders why others stayed quiet. When there is no clean exit assumes the current streak is the new normal; when no one is watching, rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"ostrich-effect","strength":0.61}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.62,"conscientiousness":0.37,"extraversion":0.62,"agreeableness":0.52,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A steady discretionary swing trader who spirals on ambiguity and mistakes the spiral for diligence. Treats not-choosing as a safe choice right up until it is not. Dominates the room then wonders why others stayed quiet. When there is no clean exit assumes the current streak is the new normal; when no one is watching, rotates the whole book into whatever is pumping this hour.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('04ea425c-507e-440e-aed6-db6ff1ed7dd4', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.35,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.52,"narcissism":0.8,"psychopathy":0.5},"prospect_theory":{"lambda":0.88,"alpha":0.88,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced value investor who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Hedges every commitment against an imagined worst case. Once things get tense extrapolates the last data point into a permanent trend; in the pattern nobody else tracks, calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.75},{"slug":"dunning-kruger","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.35,"extraversion":0.86,"agreeableness":0.35,"neuroticism":0.64}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced value investor who chases novel frameworks and abandons them once the novelty fades. Trusts momentum over preparation. Hedges every commitment against an imagined worst case. Once things get tense extrapolates the last data point into a permanent trend; in the pattern nobody else tracks, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6a5332fb-5190-44d9-b155-bf316bc7d98a', 1, '{"big_five":{"openness":0.63,"conscientiousness":0.31,"extraversion":0.65,"agreeableness":0.6,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.39,"narcissism":0.41,"psychopathy":0.39},"prospect_theory":{"lambda":3.45,"alpha":0.82,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Assumes the current streak is the new normal. A pronounced index-fund holdout: hedges every commitment against an imagined worst case, collects half-finished manifestos and unconventional methods. Lets the deadline make the decision by default, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.64},{"slug":"ostrich-effect","strength":0.67},{"slug":"recency","strength":0.72},{"slug":"fomo","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.63,"conscientiousness":0.31,"extraversion":0.65,"agreeableness":0.6,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Assumes the current streak is the new normal. A pronounced index-fund holdout: hedges every commitment against an imagined worst case, collects half-finished manifestos and unconventional methods. Lets the deadline make the decision by default, and in the unglamorous middle of things keeps a losing-trade journal they never re-read.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('45b4ad10-c1ee-4386-8ea4-ae1a97f7bf69', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.89,"extraversion":0.39,"agreeableness":0.34,"neuroticism":0.21},"dark_triad":{"machiavellianism":0.82,"narcissism":0.62,"psychopathy":0.61},"prospect_theory":{"lambda":2.37,"alpha":0.93,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Weighs options against explicit criteria and distrusts anything they cannot tabulate. This bonding-curve sniper chases novel frameworks and abandons them once the novelty fades and cannot relax until the checklist is visibly complete. When the safe option quietly expires holds their estimates with a certainty the track record does not support — left to their own devices, names every strategy after the trade that almost worked.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"overconfidence","strength":0.69},{"slug":"hindsight","strength":0.61},{"slug":"recency","strength":0.66}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","open-minded","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.97,"conscientiousness":0.89,"extraversion":0.39,"agreeableness":0.34,"neuroticism":0.21}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','open-minded','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Weighs options against explicit criteria and distrusts anything they cannot tabulate. This bonding-curve sniper chases novel frameworks and abandons them once the novelty fades and cannot relax until the checklist is visibly complete. When the safe option quietly expires holds their estimates with a certainty the track record does not support — left to their own devices, names every strategy after the trade that almost worked.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8011cb71-9e03-4013-af8d-e8b4303fb08a', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.97,"extraversion":0.36,"agreeableness":0.39,"neuroticism":0.25},"dark_triad":{"machiavellianism":0.79,"narcissism":0.53,"psychopathy":0.52},"prospect_theory":{"lambda":2.4,"alpha":0.99,"beta":0.89},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced zero-DTE options gambler who treats a missed deadline as a personal failure regardless of cause. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Finds a full day of meetings more draining than a full day of work. When the number turns red treats past peak valuation as guaranteed future recovery; in the routine of it, keeps three monitors for a portfolio that fits on one screen.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"anchoring","strength":0.63},{"slug":"optimism","strength":0.58},{"slug":"hindsight","strength":0.62},{"slug":"ath-anchoring","strength":0.64}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","ipip-neo","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.84,"conscientiousness":0.97,"extraversion":0.36,"agreeableness":0.39,"neuroticism":0.25}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','ipip-neo','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced zero-DTE options gambler who treats a missed deadline as a personal failure regardless of cause. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Finds a full day of meetings more draining than a full day of work. When the number turns red treats past peak valuation as guaranteed future recovery; in the routine of it, keeps three monitors for a portfolio that fits on one screen.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('cafdfc97-e224-4f0e-ab38-3b1753de1e6d', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.27,"extraversion":0.72,"agreeableness":0.59,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.41,"narcissism":0.58,"psychopathy":0.38},"prospect_theory":{"lambda":1.15,"alpha":0.82,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commits before the doubt has time to organize itself. This futures spreader chases novel frameworks and abandons them once the novelty fades and fills silence reflexively, even when nobody asked it to. The instant the deadline moves up jumps into whatever everyone else already seems to be winning at — in the small things, keeps a losing-trade journal they never re-read.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"gas-sunk-cost","strength":0.61},{"slug":"dunning-kruger","strength":0.64},{"slug":"fomo","strength":0.7}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.88,"conscientiousness":0.27,"extraversion":0.72,"agreeableness":0.59,"neuroticism":0.66}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Commits before the doubt has time to organize itself. This futures spreader chases novel frameworks and abandons them once the novelty fades and fills silence reflexively, even when nobody asked it to. The instant the deadline moves up jumps into whatever everyone else already seems to be winning at — in the small things, keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('79b80279-6270-4e6f-aa71-7f45e2c50a2a', 1, '{"big_five":{"openness":0.85,"conscientiousness":0.29,"extraversion":0.85,"agreeableness":0.66,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.4,"narcissism":0.71,"psychopathy":0.37},"prospect_theory":{"lambda":1.09,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Trusts momentum over preparation. This MEV searcher treats established procedure as a first draft to be rewritten and treats a quiet room as a problem to be solved. When there is no clean exit abandons a private read the instant the crowd leans the other way — without an audience, refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.65},{"slug":"herd-behavior","strength":0.73}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.85,"conscientiousness":0.29,"extraversion":0.85,"agreeableness":0.66,"neuroticism":0.59}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This MEV searcher treats established procedure as a first draft to be rewritten and treats a quiet room as a problem to be solved. When there is no clean exit abandons a private read the instant the crowd leans the other way — without an audience, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('669fd23d-8cb5-45c2-8b3f-0bf1b80f826a', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.32,"extraversion":0.83,"agreeableness":0.58,"neuroticism":0.68},"dark_triad":{"machiavellianism":0.37,"narcissism":0.66,"psychopathy":0.35},"prospect_theory":{"lambda":1.09,"alpha":0.81,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Discretionary swing trader whose defining move is that they thinks out loud and recruits an audience for every decision. Treats hesitation as the bigger risk. Carries yesterday''s stress into today''s unrelated decision. As soon as real money or reputation is on the line, jumps into whatever everyone else already seems to be winning at; calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.67},{"slug":"fomo","strength":0.68}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.72,"conscientiousness":0.32,"extraversion":0.83,"agreeableness":0.58,"neuroticism":0.68}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Discretionary swing trader whose defining move is that they thinks out loud and recruits an audience for every decision. Treats hesitation as the bigger risk. Carries yesterday''s stress into today''s unrelated decision. As soon as real money or reputation is on the line, jumps into whatever everyone else already seems to be winning at; calls a 90% drawdown a long-term hold.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3c6d54b1-b4f7-4128-b3b5-0a324ee91c22', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.6,"extraversion":0.44,"agreeableness":0.68,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.39,"narcissism":0.33,"psychopathy":0.24},"prospect_theory":{"lambda":3.07,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A steady retail momentum chaser: apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own, and on a slow afternoon keeps three monitors for a portfolio that fits on one screen.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"bandwagon","strength":0.52},{"slug":"endowment","strength":0.61},{"slug":"authority-bias","strength":0.49}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.48,"conscientiousness":0.6,"extraversion":0.44,"agreeableness":0.68,"neuroticism":0.56}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Would not buy back what it already owns at the price it would sell it for. A steady retail momentum chaser: apologizes first in disputes regardless of fault. Trusts the group''s confidence more than its own, and on a slow afternoon keeps three monitors for a portfolio that fits on one screen.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7ce0218e-1aac-464d-a192-db26cd338d9a', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.48,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.44,"narcissism":0.41,"psychopathy":0.42},"prospect_theory":{"lambda":3.73,"alpha":0.79,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady airdrop farmer who reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. Confuses motion with progress. The instant it becomes irreversible jumps into whatever everyone else already seems to be winning at; in the pattern nobody else tracks, talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENTP","suggested_biases":[{"slug":"disposition-effect","strength":0.7},{"slug":"gas-sunk-cost","strength":0.65},{"slug":"ostrich-effect","strength":0.69},{"slug":"fomo","strength":0.73}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.55,"conscientiousness":0.3,"extraversion":0.68,"agreeableness":0.48,"neuroticism":0.81}'::jsonb, 'ENTP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'A steady airdrop farmer who reads a single setback as evidence of collapse. Defers the decision until circumstances make it for them. Confuses motion with progress. The instant it becomes irreversible jumps into whatever everyone else already seems to be winning at; in the pattern nobody else tracks, talks in win rate and never mentions size.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('82e49b8b-84a5-4ced-b744-df90234a840e', 1, '{"big_five":{"openness":0.51,"conscientiousness":0.33,"extraversion":0.64,"agreeableness":0.63,"neuroticism":0.85},"dark_triad":{"machiavellianism":0.35,"narcissism":0.35,"psychopathy":0.36},"prospect_theory":{"lambda":3.55,"alpha":0.72,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Cannot watch a rally from the sidelines for long. A pronounced penny-stock gambler: notices the one thing that could go wrong before the nine that could go right, measures decisions by who they might upset. Defers the decision until circumstances make it for them, and without an audience sets stop-losses then cancels them at the open.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.73},{"slug":"disposition-effect","strength":0.73},{"slug":"ostrich-effect","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.51,"conscientiousness":0.33,"extraversion":0.64,"agreeableness":0.63,"neuroticism":0.85}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Cannot watch a rally from the sidelines for long. A pronounced penny-stock gambler: notices the one thing that could go wrong before the nine that could go right, measures decisions by who they might upset. Defers the decision until circumstances make it for them, and without an audience sets stop-losses then cancels them at the open.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('95ba73df-209b-4b26-b908-21e6b667696e', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.47,"extraversion":0.57,"agreeableness":0.57,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.42,"narcissism":0.34,"psychopathy":0.27},"prospect_theory":{"lambda":3.43,"alpha":0.76,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A steady commodities speculator who rehearses catastrophes in vivid detail before they happen. Prefers a slow loss to a fast, ownable mistake. Chases novel frameworks and abandons them once the novelty fades. Once things get tense delays checking the number it most needs to check; on a slow afternoon, screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.6},{"slug":"loss-aversion","strength":0.56},{"slug":"ostrich-effect","strength":0.67}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.64,"conscientiousness":0.47,"extraversion":0.57,"agreeableness":0.57,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A steady commodities speculator who rehearses catastrophes in vivid detail before they happen. Prefers a slow loss to a fast, ownable mistake. Chases novel frameworks and abandons them once the novelty fades. Once things get tense delays checking the number it most needs to check; on a slow afternoon, screenshots the winners and never the losers.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('188e9124-b62c-4d9a-bc9c-cae9f8483a12', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.41,"extraversion":0.65,"agreeableness":0.54,"neuroticism":0.97},"dark_triad":{"machiavellianism":0.38,"narcissism":0.35,"psychopathy":0.32},"prospect_theory":{"lambda":3.57,"alpha":0.71,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly. Otherwise, a pronounced index-fund holdout who hedges every commitment against an imagined worst case and fills silence reflexively, even when nobody asked it to. Lets the deadline make the decision by default, and in the routine of it trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"loss-aversion","strength":0.77},{"slug":"diamond-hands-identity","strength":0.71},{"slug":"availability","strength":0.72}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.53,"conscientiousness":0.41,"extraversion":0.65,"agreeableness":0.54,"neuroticism":0.97}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Once the exit narrows to one door, feels a loss twice as sharply as an equivalent gain and plans accordingly. Otherwise, a pronounced index-fund holdout who hedges every commitment against an imagined worst case and fills silence reflexively, even when nobody asked it to. Lets the deadline make the decision by default, and in the routine of it trusts the chart more than the fundamentals and won''t say why.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5e5700bb-55a6-4b21-9f5f-9810d09a6777', 1, '{"big_five":{"openness":0.61,"conscientiousness":0.47,"extraversion":0.54,"agreeableness":0.62,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.41,"narcissism":0.34,"psychopathy":0.33},"prospect_theory":{"lambda":3.51,"alpha":0.72,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the walls close in, feels a loss twice as sharply as an equivalent gain and plans accordingly. Otherwise, a pronounced onchain copy-trader who rehearses catastrophes in vivid detail before they happen and apologizes first in disputes regardless of fault. Finds one more piece of information to gather before acting, and across the quiet stretches averages down on a name three times in a week.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.66},{"slug":"diamond-hands-identity","strength":0.69},{"slug":"loss-aversion","strength":0.71},{"slug":"rug-trauma-overcorrection","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.61,"conscientiousness":0.47,"extraversion":0.54,"agreeableness":0.62,"neuroticism":0.87}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the walls close in, feels a loss twice as sharply as an equivalent gain and plans accordingly. Otherwise, a pronounced onchain copy-trader who rehearses catastrophes in vivid detail before they happen and apologizes first in disputes regardless of fault. Finds one more piece of information to gather before acting, and across the quiet stretches averages down on a name three times in a week.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('4c8c551e-9f09-4a5e-9c61-3acbff2c8bb2', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.61,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.42,"narcissism":0.35,"psychopathy":0.27},"prospect_theory":{"lambda":2.99,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the stakes rise, second-guesses its own read the moment someone senior disagrees. Otherwise, a measured volatility arbitrageur who reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority, and across an ordinary week exits winners at the first green candle.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"authority-bias","strength":0.58},{"slug":"endowment","strength":0.5},{"slug":"herd-behavior","strength":0.49},{"slug":"bandwagon","strength":0.49}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.55,"conscientiousness":0.61,"extraversion":0.49,"agreeableness":0.66,"neuroticism":0.53}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'When the stakes rise, second-guesses its own read the moment someone senior disagrees. Otherwise, a measured volatility arbitrageur who reads other people''s discomfort before they voice it. Outsources conviction to whoever spoke last with authority, and across an ordinary week exits winners at the first green candle.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('07b1848e-f902-4cff-bc5f-64a3141c1592', 1, '{"big_five":{"openness":0.62,"conscientiousness":0.28,"extraversion":0.67,"agreeableness":0.56,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.4,"narcissism":0.45,"psychopathy":0.35},"prospect_theory":{"lambda":3.28,"alpha":0.79,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"A pronounced discretionary swing trader who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Chases novel frameworks and abandons them once the novelty fades. As soon as real money or reputation is on the line locks in small wins fast and rides large losses far past the point of sense; without an audience, screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.67},{"slug":"gas-sunk-cost","strength":0.66},{"slug":"disposition-effect","strength":0.73}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.62,"conscientiousness":0.28,"extraversion":0.67,"agreeableness":0.56,"neuroticism":0.84}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'A pronounced discretionary swing trader who needs repeated reassurance that a decision was the right one. Treats not-choosing as a safe choice right up until it is not. Chases novel frameworks and abandons them once the novelty fades. As soon as real money or reputation is on the line locks in small wins fast and rides large losses far past the point of sense; without an audience, screenshots the winners and never the losers.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c9bc471c-1539-4bb4-bcda-41bd0be495b7', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.33,"extraversion":0.76,"agreeableness":0.25,"neuroticism":0.53},"dark_triad":{"machiavellianism":0.65,"narcissism":0.84,"psychopathy":0.54},"prospect_theory":{"lambda":0.71,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Mistakes a little fluency for real mastery. A pronounced futures spreader: gets bored of the proven method exactly when it starts working, negotiates every relationship a little, even the close ones. Lets pattern-matching from past cases stand in for fresh analysis, and when the pressure is off holds a bag from 2021 out of pure spite.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.55},{"slug":"fomo","strength":0.63},{"slug":"dunning-kruger","strength":0.64}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.84,"conscientiousness":0.33,"extraversion":0.76,"agreeableness":0.25,"neuroticism":0.53}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Mistakes a little fluency for real mastery. A pronounced futures spreader: gets bored of the proven method exactly when it starts working, negotiates every relationship a little, even the close ones. Lets pattern-matching from past cases stand in for fresh analysis, and when the pressure is off holds a bag from 2021 out of pure spite.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d1e4a007-ab3c-405a-abd2-73cfbf80da2f', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.26,"extraversion":0.62,"agreeableness":0.6,"neuroticism":0.8},"dark_triad":{"machiavellianism":0.36,"narcissism":0.37,"psychopathy":0.37},"prospect_theory":{"lambda":3.54,"alpha":0.74,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Quant researcher, steady in style: carries yesterday''s stress into today''s unrelated decision; confuses motion with progress. Lets the deadline make the decision by default. As soon as real money or reputation is on the line delays checking the number it most needs to check.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.72},{"slug":"gas-sunk-cost","strength":0.69}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.59,"conscientiousness":0.26,"extraversion":0.62,"agreeableness":0.6,"neuroticism":0.8}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Quant researcher, steady in style: carries yesterday''s stress into today''s unrelated decision; confuses motion with progress. Lets the deadline make the decision by default. As soon as real money or reputation is on the line delays checking the number it most needs to check.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('641391da-9909-4b76-8106-254a535f7d0e', 1, '{"big_five":{"openness":0.59,"conscientiousness":0.35,"extraversion":0.61,"agreeableness":0.74,"neuroticism":0.78},"dark_triad":{"machiavellianism":0.39,"narcissism":0.42,"psychopathy":0.34},"prospect_theory":{"lambda":3.54,"alpha":0.82,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Prefers a slow loss to a fast, ownable mistake. This DeFi yield farmer rehearses catastrophes in vivid detail before they happen and leaves loose ends and trusts future-self to handle them. When there is no clean exit overvalues whatever they already hold simply because it is theirs — in the unglamorous middle of things, confuses a bull market for a trading edge.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"recency","strength":0.62},{"slug":"gas-sunk-cost","strength":0.63},{"slug":"ostrich-effect","strength":0.68},{"slug":"endowment","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.59,"conscientiousness":0.35,"extraversion":0.61,"agreeableness":0.74,"neuroticism":0.78}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Prefers a slow loss to a fast, ownable mistake. This DeFi yield farmer rehearses catastrophes in vivid detail before they happen and leaves loose ends and trusts future-self to handle them. When there is no clean exit overvalues whatever they already hold simply because it is theirs — in the unglamorous middle of things, confuses a bull market for a trading edge.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('cd28fcc3-781a-427d-8025-7512203a2578', 1, '{"big_five":{"openness":0.91,"conscientiousness":0.32,"extraversion":0.76,"agreeableness":0.34,"neuroticism":0.62},"dark_triad":{"machiavellianism":0.56,"narcissism":0.73,"psychopathy":0.53},"prospect_theory":{"lambda":0.79,"alpha":0.88,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced futures spreader who treats established procedure as a first draft to be rewritten. Treats overthinking as its own kind of error. Would rather be respected than liked, and says so. The moment it stops being hypothetical cannot see the gap in its own knowledge from inside the gap; when no one is watching, calls a 90% drawdown a long-term hold.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.71},{"slug":"herd-behavior","strength":0.59},{"slug":"recency","strength":0.68}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.91,"conscientiousness":0.32,"extraversion":0.76,"agreeableness":0.34,"neuroticism":0.62}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced futures spreader who treats established procedure as a first draft to be rewritten. Treats overthinking as its own kind of error. Would rather be respected than liked, and says so. The moment it stops being hypothetical cannot see the gap in its own knowledge from inside the gap; when no one is watching, calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('79644bf7-9253-410f-9b23-a98eeff579c9', 1, '{"big_five":{"openness":0.8,"conscientiousness":0.38,"extraversion":0.81,"agreeableness":0.63,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.36,"narcissism":0.61,"psychopathy":0.3},"prospect_theory":{"lambda":1.19,"alpha":0.81,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Acts on the midnight epiphany and emails it at 1am. This prop-desk scalper draws energy from the crowd and wilts when working alone and measures decisions by who they might upset. Under a deadline treats being left out of a move as its own kind of loss — as a rule, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"bandwagon","strength":0.72},{"slug":"fomo","strength":0.73}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.8,"conscientiousness":0.38,"extraversion":0.81,"agreeableness":0.63,"neuroticism":0.66}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Acts on the midnight epiphany and emails it at 1am. This prop-desk scalper draws energy from the crowd and wilts when working alone and measures decisions by who they might upset. Under a deadline treats being left out of a move as its own kind of loss — as a rule, treats a green week as proof of skill and a red one as proof of bad luck.', 0.93, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eb1eded4-a521-42d7-a182-d4a55c230c3a', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.24,"extraversion":0.78,"agreeableness":0.55,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.39,"narcissism":0.62,"psychopathy":0.43},"prospect_theory":{"lambda":1.17,"alpha":0.81,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Commits on impulse and lives loudly with the consequences. This delta-neutral market maker treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Under pressure extrapolates the last data point into a permanent trend — in the routine of it, rotates the whole book into whatever is pumping this hour.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.68},{"slug":"recency","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.72,"conscientiousness":0.24,"extraversion":0.78,"agreeableness":0.55,"neuroticism":0.69}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Commits on impulse and lives loudly with the consequences. This delta-neutral market maker treats a quiet room as a problem to be solved and would rather invent a worse tool than use someone else''s good one. Under pressure extrapolates the last data point into a permanent trend — in the routine of it, rotates the whole book into whatever is pumping this hour.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e1713433-a1bc-44c0-b411-574da3c78919', 1, '{"big_five":{"openness":0.64,"conscientiousness":0.3,"extraversion":0.49,"agreeableness":0.53,"neuroticism":0.86},"dark_triad":{"machiavellianism":0.41,"narcissism":0.29,"psychopathy":0.38},"prospect_theory":{"lambda":3.34,"alpha":0.76,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Options seller whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. Leaves loose ends and trusts future-self to handle them. When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed; screenshots the winners and never the losers.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"recency","strength":0.73},{"slug":"ostrich-effect","strength":0.78}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.64,"conscientiousness":0.3,"extraversion":0.49,"agreeableness":0.53,"neuroticism":0.86}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Options seller whose defining move is that they carries yesterday''s stress into today''s unrelated decision. Lets the deadline make the decision by default. Leaves loose ends and trusts future-self to handle them. When there is no clean exit, looks away from bad news in the hope it resolves unwitnessed; screenshots the winners and never the losers.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('eb4e876c-aee9-4c10-9fe7-7bb4e16232ab', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.51,"extraversion":0.72,"agreeableness":0.34,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.53,"narcissism":0.71,"psychopathy":0.52},"prospect_theory":{"lambda":1.24,"alpha":0.86,"beta":0.93},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Crypto day-trader, steady in style: collects half-finished manifestos and unconventional methods; treats warmth as leverage and cooperation as weakness. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Once things get tense discounts their own exposure to the risks they warn others about.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.59},{"slug":"fomo","strength":0.53},{"slug":"herd-behavior","strength":0.53}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.83,"conscientiousness":0.51,"extraversion":0.72,"agreeableness":0.34,"neuroticism":0.39}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Crypto day-trader, steady in style: collects half-finished manifestos and unconventional methods; treats warmth as leverage and cooperation as weakness. Weighs options against explicit criteria and distrusts anything they cannot tabulate. Once things get tense discounts their own exposure to the risks they warn others about.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('23cdd0e6-112f-4aa3-93ee-88edcfd62723', 1, '{"big_five":{"openness":0.79,"conscientiousness":0.81,"extraversion":0.38,"agreeableness":0.37,"neuroticism":0.26},"dark_triad":{"machiavellianism":0.81,"narcissism":0.5,"psychopathy":0.55},"prospect_theory":{"lambda":2.19,"alpha":0.95,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Liquidation-bot operator whose defining move is that they maintains flawless records nobody asked for. Converts every argument into a number it can compare against another number. Stays flat when the numbers go red. When there is no clean exit, is more certain than the hit rate justifies; checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.56},{"slug":"recency","strength":0.59},{"slug":"hindsight","strength":0.65},{"slug":"overconfidence","strength":0.7}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.79,"conscientiousness":0.81,"extraversion":0.38,"agreeableness":0.37,"neuroticism":0.26}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Liquidation-bot operator whose defining move is that they maintains flawless records nobody asked for. Converts every argument into a number it can compare against another number. Stays flat when the numbers go red. When there is no clean exit, is more certain than the hit rate justifies; checks the P&L blotter forty times before lunch.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ec4e8ee4-0b2d-43a8-81ad-eec2e56c8b2d', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.59,"extraversion":0.43,"agreeableness":0.74,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.43,"narcissism":0.37,"psychopathy":0.26},"prospect_theory":{"lambda":3.06,"alpha":0.91,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When the walls close in, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady index-fund holdout who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority, and across an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"authority-bias","strength":0.59},{"slug":"endowment","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.48,"conscientiousness":0.59,"extraversion":0.43,"agreeableness":0.74,"neuroticism":0.57}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'When the walls close in, would not buy back what it already owns at the price it would sell it for. Otherwise, a steady index-fund holdout who takes on other people''s problems as if they were their own. Outsources conviction to whoever spoke last with authority, and across an ordinary week treats a green week as proof of skill and a red one as proof of bad luck.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('43e29117-ab1e-43ba-9893-275a0862ed64', 1, '{"big_five":{"openness":0.78,"conscientiousness":0.93,"extraversion":0.44,"agreeableness":0.36,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.83,"narcissism":0.52,"psychopathy":0.49},"prospect_theory":{"lambda":2.32,"alpha":0.91,"beta":0.9},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"When there is no clean exit, remembers every surprise as something they saw coming all along. Otherwise, a pronounced MEV searcher who plans in exhaustive detail and resents any deviation and collects half-finished manifestos and unconventional methods. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and on an ordinary week checks the P&L blotter forty times before lunch.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"hindsight","strength":0.69},{"slug":"anchoring","strength":0.61},{"slug":"recency","strength":0.57},{"slug":"ath-anchoring","strength":0.67}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","cognition","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.78,"conscientiousness":0.93,"extraversion":0.44,"agreeableness":0.36,"neuroticism":0.35}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','cognition','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'When there is no clean exit, remembers every surprise as something they saw coming all along. Otherwise, a pronounced MEV searcher who plans in exhaustive detail and resents any deviation and collects half-finished manifestos and unconventional methods. Weighs options against explicit criteria and distrusts anything they cannot tabulate, and on an ordinary week checks the P&L blotter forty times before lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('7d00e350-3dec-45d4-ae11-f6f4c69de196', 1, '{"big_five":{"openness":0.55,"conscientiousness":0.39,"extraversion":0.46,"agreeableness":0.55,"neuroticism":0.84},"dark_triad":{"machiavellianism":0.38,"narcissism":0.25,"psychopathy":0.29},"prospect_theory":{"lambda":3.43,"alpha":0.76,"beta":0.81},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Refuses to take profits because holding has become core to their community identity. A pronounced airdrop farmer: carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not, and in the unglamorous middle of things apes the launch before the contract is verified.","decision_style":"avoidant","mbti_label":"INFP","suggested_biases":[{"slug":"loss-aversion","strength":0.6},{"slug":"diamond-hands-identity","strength":0.67},{"slug":"availability","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.55,"conscientiousness":0.39,"extraversion":0.46,"agreeableness":0.55,"neuroticism":0.84}'::jsonb, 'INFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Refuses to take profits because holding has become core to their community identity. A pronounced airdrop farmer: carries yesterday''s stress into today''s unrelated decision. Treats not-choosing as a safe choice right up until it is not, and in the unglamorous middle of things apes the launch before the contract is verified.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9afa2ecb-6816-4d0c-9444-ee463b3d5fc6', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.29,"extraversion":0.83,"agreeableness":0.28,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.63,"narcissism":0.86,"psychopathy":0.59},"prospect_theory":{"lambda":0.96,"alpha":0.83,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced index-fund holdout who collects half-finished manifestos and unconventional methods. Treats hesitation as the bigger risk. Does the interesting 80% and abandons the tedious 20%. The instant the deadline moves up assumes the current streak is the new normal; when the stakes are trivial, screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.29,"extraversion":0.83,"agreeableness":0.28,"neuroticism":0.61}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced index-fund holdout who collects half-finished manifestos and unconventional methods. Treats hesitation as the bigger risk. Does the interesting 80% and abandons the tedious 20%. The instant the deadline moves up assumes the current streak is the new normal; when the stakes are trivial, screenshots the winners and never the losers.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0a6c9471-342e-4f4f-978f-982f7a72c06e', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.41,"extraversion":0.52,"agreeableness":0.64,"neuroticism":0.87},"dark_triad":{"machiavellianism":0.41,"narcissism":0.22,"psychopathy":0.32},"prospect_theory":{"lambda":3.41,"alpha":0.8,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Dividend-yield chaser, pronounced in style: spirals on ambiguity and mistakes the spiral for diligence; defaults to trust and gives the benefit of the doubt too freely. Keeps every door open long after most of them should be closed. When there is no clean exit wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.72},{"slug":"loss-aversion","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.48,"conscientiousness":0.41,"extraversion":0.52,"agreeableness":0.64,"neuroticism":0.87}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser, pronounced in style: spirals on ambiguity and mistakes the spiral for diligence; defaults to trust and gives the benefit of the doubt too freely. Keeps every door open long after most of them should be closed. When there is no clean exit wears holding through 90% drawdowns as a badge of honor, confusing stubbornness with conviction.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1150d8bf-5967-4e3a-990b-47237f52e477', 1, '{"big_five":{"openness":0.71,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.58,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.37,"narcissism":0.69,"psychopathy":0.34},"prospect_theory":{"lambda":1.05,"alpha":0.89,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"The moment risk appears, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced retail momentum chaser who recharges by being around people, not away from them and treats a plan as a suggestion the moment it is made. Commits on impulse and lives loudly with the consequences, and once the urgency drains out screenshots the winners and never the losers.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"dunning-kruger","strength":0.66},{"slug":"recency","strength":0.64},{"slug":"bandwagon","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.71,"conscientiousness":0.36,"extraversion":0.85,"agreeableness":0.58,"neuroticism":0.57}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'The moment risk appears, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a pronounced retail momentum chaser who recharges by being around people, not away from them and treats a plan as a suggestion the moment it is made. Commits on impulse and lives loudly with the consequences, and once the urgency drains out screenshots the winners and never the losers.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('31f47463-8801-41a6-a481-337fe2e8203f', 1, '{"big_five":{"openness":0.56,"conscientiousness":0.61,"extraversion":0.54,"agreeableness":0.64,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.47,"narcissism":0.38,"psychopathy":0.25},"prospect_theory":{"lambda":2.8,"alpha":0.84,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Abandons a private read the instant the crowd leans the other way. A measured crypto day-trader: would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things confuses a bull market for a trading edge.","decision_style":"dependent","mbti_label":"ENFJ","suggested_biases":[{"slug":"bandwagon","strength":0.54},{"slug":"herd-behavior","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.56,"conscientiousness":0.61,"extraversion":0.54,"agreeableness":0.64,"neuroticism":0.58}'::jsonb, 'ENFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Abandons a private read the instant the crowd leans the other way. A measured crypto day-trader: would rather lose a point than win an argument badly. Trusts the group''s confidence more than its own, and in the unglamorous middle of things confuses a bull market for a trading edge.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('35fa2f0a-f29b-40c4-9554-b1e7b5c8db71', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.31,"extraversion":0.5,"agreeableness":0.64,"neuroticism":0.79},"dark_triad":{"machiavellianism":0.41,"narcissism":0.28,"psychopathy":0.34},"prospect_theory":{"lambda":3.45,"alpha":0.83,"beta":0.77},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Penny-stock gambler whose defining move is that they needs repeated reassurance that a decision was the right one. Prefers a slow loss to a fast, ownable mistake. Takes on other people''s problems as if they were their own. Under a deadline, doubles down on stagnant liquidity pools to justify the initial deployment gas; trusts the chart more than the fundamentals and won''t say why.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.6},{"slug":"loss-aversion","strength":0.63},{"slug":"gas-sunk-cost","strength":0.7},{"slug":"ostrich-effect","strength":0.68}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.6,"conscientiousness":0.31,"extraversion":0.5,"agreeableness":0.64,"neuroticism":0.79}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Penny-stock gambler whose defining move is that they needs repeated reassurance that a decision was the right one. Prefers a slow loss to a fast, ownable mistake. Takes on other people''s problems as if they were their own. Under a deadline, doubles down on stagnant liquidity pools to justify the initial deployment gas; trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('9ff3b751-a23d-425f-b4b4-b408d1dea0ae', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.48,"extraversion":0.67,"agreeableness":0.3,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.56,"narcissism":0.68,"psychopathy":0.44},"prospect_theory":{"lambda":0.68,"alpha":0.85,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Zero-DTE options gambler, steady in style: would rather invent a worse tool than use someone else''s good one; says the blunt thing and enjoys the flinch. Knows the answer before it can explain the question. As soon as real money or reputation is on the line jumps into whatever everyone else already seems to be winning at.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.52},{"slug":"rug-trauma-overcorrection","strength":0.55},{"slug":"airdrop-entitlement","strength":0.62},{"slug":"fomo","strength":0.66}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.81,"conscientiousness":0.48,"extraversion":0.67,"agreeableness":0.3,"neuroticism":0.63}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Zero-DTE options gambler, steady in style: would rather invent a worse tool than use someone else''s good one; says the blunt thing and enjoys the flinch. Knows the answer before it can explain the question. As soon as real money or reputation is on the line jumps into whatever everyone else already seems to be winning at.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
