('23886085-162e-4130-9168-5d783a6ec9cd', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.28,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.64,"narcissism":0.84,"psychopathy":0.59},"prospect_theory":{"lambda":0.86,"alpha":0.89,"beta":0.91},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Is most certain precisely where their competence is thinnest. A pronounced algorithmic market-maker: collects half-finished manifestos and unconventional methods, recharges by being around people, not away from them. Treats hesitation as the bigger risk, and in the small things holds a bag from 2021 out of pure spite.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.69},{"slug":"recency","strength":0.62},{"slug":"herd-behavior","strength":0.66},{"slug":"fomo","strength":0.63}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.84,"conscientiousness":0.28,"extraversion":0.81,"agreeableness":0.22,"neuroticism":0.59}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Is most certain precisely where their competence is thinnest. A pronounced algorithmic market-maker: collects half-finished manifestos and unconventional methods, recharges by being around people, not away from them. Treats hesitation as the bigger risk, and in the small things holds a bag from 2021 out of pure spite.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
