('23a69d50-be1b-4ea5-8209-5ed9c7618fa4', 1, '{"big_five":{"openness":0.58,"conscientiousness":0.31,"extraversion":0.57,"agreeableness":0.53,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.39,"narcissism":0.36,"psychopathy":0.34},"prospect_theory":{"lambda":3.56,"alpha":0.77,"beta":0.79},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the walls close in, delays checking the number it most needs to check. Otherwise, a steady bonding-curve sniper who hedges every commitment against an imagined worst case and does the interesting 80% and abandons the tedious 20%. Keeps every door open long after most of them should be closed, and day to day refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.72},{"slug":"loss-aversion","strength":0.64},{"slug":"disposition-effect","strength":0.69},{"slug":"gas-sunk-cost","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.58,"conscientiousness":0.31,"extraversion":0.57,"agreeableness":0.53,"neuroticism":0.82}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the walls close in, delays checking the number it most needs to check. Otherwise, a steady bonding-curve sniper who hedges every commitment against an imagined worst case and does the interesting 80% and abandons the tedious 20%. Keeps every door open long after most of them should be closed, and day to day refreshes the order book compulsively during lunch.', 0.91, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('45caead4-6e5f-4174-9909-40ed48762331', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.39,"extraversion":0.69,"agreeableness":0.51,"neuroticism":0.81},"dark_triad":{"machiavellianism":0.42,"narcissism":0.42,"psychopathy":0.32},"prospect_theory":{"lambda":3.47,"alpha":0.79,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Futures spreader, steady in style: notices the one thing that could go wrong before the nine that could go right; treats a quiet room as a problem to be solved. Lets the deadline make the decision by default. The moment it stops being hypothetical would rather not know yet, even when knowing sooner would help.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"fomo","strength":0.64},{"slug":"disposition-effect","strength":0.65},{"slug":"ostrich-effect","strength":0.7}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.5,"conscientiousness":0.39,"extraversion":0.69,"agreeableness":0.51,"neuroticism":0.81}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Futures spreader, steady in style: notices the one thing that could go wrong before the nine that could go right; treats a quiet room as a problem to be solved. Lets the deadline make the decision by default. The moment it stops being hypothetical would rather not know yet, even when knowing sooner would help.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5fd4e7c8-194d-4b22-814f-b569d82e4919', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.52,"extraversion":0.49,"agreeableness":0.5,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.41,"narcissism":0.41,"psychopathy":0.29},"prospect_theory":{"lambda":2.74,"alpha":0.82,"beta":0.82},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Overweights the vivid story over the boring statistic every time. A measured dividend-yield chaser: reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and in the unglamorous middle of things calls a 90% drawdown a long-term hold.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"recency","strength":0.51},{"slug":"ostrich-effect","strength":0.48},{"slug":"availability","strength":0.52}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.52,"extraversion":0.49,"agreeableness":0.5,"neuroticism":0.57}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Overweights the vivid story over the boring statistic every time. A measured dividend-yield chaser: reframes every problem as an excuse to learn a new system. Trusts the group''s confidence more than its own, and in the unglamorous middle of things calls a 90% drawdown a long-term hold.', 0.86, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1854e925-183a-4c48-8f82-ba49845ee1ad', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.49,"extraversion":0.74,"agreeableness":0.39,"neuroticism":0.45},"dark_triad":{"machiavellianism":0.54,"narcissism":0.69,"psychopathy":0.43},"prospect_theory":{"lambda":1.16,"alpha":0.89,"beta":0.88},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady penny-stock gambler: gets bored of the proven method exactly when it starts working, dominates the room then wonders why others stayed quiet. Converts every argument into a number it can compare against another number, and in the small things averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"bandwagon","strength":0.55},{"slug":"optimism","strength":0.58},{"slug":"fomo","strength":0.56},{"slug":"herd-behavior","strength":0.59}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.81,"conscientiousness":0.49,"extraversion":0.74,"agreeableness":0.39,"neuroticism":0.45}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady penny-stock gambler: gets bored of the proven method exactly when it starts working, dominates the room then wonders why others stayed quiet. Converts every argument into a number it can compare against another number, and in the small things averages down on a name three times in a week.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6c3e8cd3-726b-4492-b46d-727095d81ab9', 1, '{"big_five":{"openness":0.95,"conscientiousness":0.34,"extraversion":0.92,"agreeableness":0.35,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.54,"narcissism":0.87,"psychopathy":0.45},"prospect_theory":{"lambda":0.99,"alpha":0.91,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prefers a fast wrong answer to a slow right one. This meme-coin rotator collects half-finished manifestos and unconventional methods and would rather be respected than liked, and says so. When cornered finds it hard to hold a contrarian position once the room disagrees — in the small things, refreshes the order book compulsively during lunch.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.71},{"slug":"herd-behavior","strength":0.74},{"slug":"recency","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.95,"conscientiousness":0.34,"extraversion":0.92,"agreeableness":0.35,"neuroticism":0.56}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prefers a fast wrong answer to a slow right one. This meme-coin rotator collects half-finished manifestos and unconventional methods and would rather be respected than liked, and says so. When cornered finds it hard to hold a contrarian position once the room disagrees — in the small things, refreshes the order book compulsively during lunch.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('6559a024-d978-45de-97a1-eb9ec7ce35dd', 1, '{"big_five":{"openness":0.47,"conscientiousness":0.64,"extraversion":0.44,"agreeableness":0.78,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.43,"narcissism":0.39,"psychopathy":0.31},"prospect_theory":{"lambda":2.89,"alpha":0.87,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Gains confidence in a position in proportion to how many others hold it. A steady perps degen: takes on other people''s problems as if they were their own, builds in buffer time and then fills the buffer with more work. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades talks in win rate and never mentions size.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"bandwagon","strength":0.63},{"slug":"endowment","strength":0.58},{"slug":"authority-bias","strength":0.59}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.47,"conscientiousness":0.64,"extraversion":0.44,"agreeableness":0.78,"neuroticism":0.52}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Gains confidence in a position in proportion to how many others hold it. A steady perps degen: takes on other people''s problems as if they were their own, builds in buffer time and then fills the buffer with more work. Seeks a second, third, and fourth opinion before committing to anything, and in the parts nobody grades talks in win rate and never mentions size.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c7417579-b2a9-403e-89e8-b71a9180f69e', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.94,"extraversion":0.39,"agreeableness":0.31,"neuroticism":0.35},"dark_triad":{"machiavellianism":0.79,"narcissism":0.55,"psychopathy":0.49},"prospect_theory":{"lambda":2.22,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"A pronounced perps degen who treats a missed deadline as a personal failure regardless of cause. Demands the data before the discussion and the discussion before the call. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible rewrites its own uncertainty out of the story after the fact; across the quiet stretches, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"analytical","mbti_label":"INTJ","suggested_biases":[{"slug":"ath-anchoring","strength":0.6},{"slug":"overconfidence","strength":0.61},{"slug":"hindsight","strength":0.68}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","risk","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.81,"conscientiousness":0.94,"extraversion":0.39,"agreeableness":0.31,"neuroticism":0.35}'::jsonb, 'INTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','risk','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced perps degen who treats a missed deadline as a personal failure regardless of cause. Demands the data before the discussion and the discussion before the call. Treats established procedure as a first draft to be rewritten. The instant it becomes irreversible rewrites its own uncertainty out of the story after the fact; across the quiet stretches, treats a green week as proof of skill and a red one as proof of bad luck.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('d5aa8ceb-e3a6-4948-8365-986a6271febd', 1, '{"big_five":{"openness":0.97,"conscientiousness":0.41,"extraversion":0.92,"agreeableness":0.32,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.56,"narcissism":0.89,"psychopathy":0.44},"prospect_theory":{"lambda":0.96,"alpha":0.91,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats overthinking as its own kind of error. This crypto day-trader reframes every problem as an excuse to learn a new system and assumes self-interest in others because it is usually there in themselves. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — across an ordinary week, names every strategy after the trade that almost worked.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"dunning-kruger","strength":0.7},{"slug":"recency","strength":0.7}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.97,"conscientiousness":0.41,"extraversion":0.92,"agreeableness":0.32,"neuroticism":0.57}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats overthinking as its own kind of error. This crypto day-trader reframes every problem as an excuse to learn a new system and assumes self-interest in others because it is usually there in themselves. The instant the deadline moves up finds it hard to hold a contrarian position once the room disagrees — across an ordinary week, names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('3cda4e30-0e72-4b7c-befe-edec812c2540', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.53,"extraversion":0.69,"agreeableness":0.28,"neuroticism":0.52},"dark_triad":{"machiavellianism":0.64,"narcissism":0.75,"psychopathy":0.49},"prospect_theory":{"lambda":1.27,"alpha":0.91,"beta":0.94},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Bonding-curve sniper, pronounced in style: reframes every problem as an excuse to learn a new system; treats warmth as leverage and cooperation as weakness. Wants the base rate before the anecdote. The moment risk appears assumes the current streak is the new normal.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"recency","strength":0.66}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.96,"conscientiousness":0.53,"extraversion":0.69,"agreeableness":0.28,"neuroticism":0.52}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper, pronounced in style: reframes every problem as an excuse to learn a new system; treats warmth as leverage and cooperation as weakness. Wants the base rate before the anecdote. The moment risk appears assumes the current streak is the new normal.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('80639f97-3abd-4304-924d-9bab5a6305ab', 1, '{"big_five":{"openness":0.65,"conscientiousness":0.33,"extraversion":0.92,"agreeableness":0.69,"neuroticism":0.71},"dark_triad":{"machiavellianism":0.38,"narcissism":0.65,"psychopathy":0.39},"prospect_theory":{"lambda":1.01,"alpha":0.8,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A pronounced index-fund holdout: treats a quiet room as a problem to be solved, apologizes first in disputes regardless of fault. Treats hesitation as the bigger risk, and across the quiet stretches talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.83},{"slug":"fomo","strength":0.79},{"slug":"dunning-kruger","strength":0.75},{"slug":"recency","strength":0.59}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.65,"conscientiousness":0.33,"extraversion":0.92,"agreeableness":0.69,"neuroticism":0.71}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A pronounced index-fund holdout: treats a quiet room as a problem to be solved, apologizes first in disputes regardless of fault. Treats hesitation as the bigger risk, and across the quiet stretches talks in win rate and never mentions size.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('46bd0c5d-69fc-4c74-9110-e57ab955711d', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.56,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.41,"narcissism":0.71,"psychopathy":0.32},"prospect_theory":{"lambda":1,"alpha":0.86,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Is most certain precisely where their competence is thinnest. A pronounced macro allocator: chases novel frameworks and abandons them once the novelty fades, thinks out loud and recruits an audience for every decision. Acts on the midnight epiphany and emails it at 1am, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.74},{"slug":"bandwagon","strength":0.65},{"slug":"recency","strength":0.64},{"slug":"herd-behavior","strength":0.68}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.86,"conscientiousness":0.33,"extraversion":0.86,"agreeableness":0.56,"neuroticism":0.63}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Is most certain precisely where their competence is thinnest. A pronounced macro allocator: chases novel frameworks and abandons them once the novelty fades, thinks out loud and recruits an audience for every decision. Acts on the midnight epiphany and emails it at 1am, and in the unglamorous middle of things sets alerts for a coin they already checked a minute ago.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('27afd7df-80b9-46ae-95ca-53c2b7586399', 1, '{"big_five":{"openness":0.72,"conscientiousness":0.42,"extraversion":0.73,"agreeableness":0.45,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.47,"narcissism":0.65,"psychopathy":0.44},"prospect_theory":{"lambda":1.22,"alpha":0.91,"beta":0.91},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady commodities speculator who fills silence reflexively, even when nobody asked it to and reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct, and without an audience averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTP","suggested_biases":[{"slug":"optimism","strength":0.59},{"slug":"bandwagon","strength":0.51},{"slug":"herd-behavior","strength":0.63},{"slug":"dunning-kruger","strength":0.57}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.72,"conscientiousness":0.42,"extraversion":0.73,"agreeableness":0.45,"neuroticism":0.42}'::jsonb, 'ENTP', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'As soon as real money or reputation is on the line, takes the crowd''s confidence as a substitute for its own analysis. Otherwise, a steady commodities speculator who fills silence reflexively, even when nobody asked it to and reads outside the field for ideas the field itself would reject. Builds a decision matrix for choices most people make on instinct, and without an audience averages down on a name three times in a week.', 0.86, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('817f1f31-b03e-4183-8cf3-1a1c672e3862', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.22,"extraversion":0.63,"agreeableness":0.65,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.42,"narcissism":0.31,"psychopathy":0.4},"prospect_theory":{"lambda":3.47,"alpha":0.72,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Looks away from bad news in the hope it resolves unwitnessed. A pronounced liquidation-bot operator: notices the one thing that could go wrong before the nine that could go right, would rather lose a point than win an argument badly. Buries hard calls under a pile of preparatory busywork, and across an ordinary week rotates the whole book into whatever is pumping this hour.","decision_style":"avoidant","mbti_label":"ESFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.8},{"slug":"gas-sunk-cost","strength":0.71}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.48,"conscientiousness":0.22,"extraversion":0.63,"agreeableness":0.65,"neuroticism":0.88}'::jsonb, 'ESFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Looks away from bad news in the hope it resolves unwitnessed. A pronounced liquidation-bot operator: notices the one thing that could go wrong before the nine that could go right, would rather lose a point than win an argument badly. Buries hard calls under a pile of preparatory busywork, and across an ordinary week rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('37605b6d-d2c7-4eff-beb6-9269a0d0846b', 1, '{"big_five":{"openness":0.52,"conscientiousness":0.37,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.89},"dark_triad":{"machiavellianism":0.41,"narcissism":0.34,"psychopathy":0.36},"prospect_theory":{"lambda":3.43,"alpha":0.72,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Weights whatever happened most recently and vividly as if it were typical. A pronounced DeFi yield farmer: rehearses catastrophes in vivid detail before they happen, confuses motion with progress. Defers the decision until circumstances make it for them, and on an ordinary week sets alerts for a coin they already checked a minute ago.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"diamond-hands-identity","strength":0.66},{"slug":"availability","strength":0.74},{"slug":"ostrich-effect","strength":0.71},{"slug":"loss-aversion","strength":0.66}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.52,"conscientiousness":0.37,"extraversion":0.6,"agreeableness":0.56,"neuroticism":0.89}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Weights whatever happened most recently and vividly as if it were typical. A pronounced DeFi yield farmer: rehearses catastrophes in vivid detail before they happen, confuses motion with progress. Defers the decision until circumstances make it for them, and on an ordinary week sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e65e02bb-e5d9-42bb-89ae-30904b6ba97f', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.45,"extraversion":0.86,"agreeableness":0.37,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.55,"narcissism":0.85,"psychopathy":0.42},"prospect_theory":{"lambda":1.02,"alpha":0.9,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Dividend-yield chaser, pronounced in style: chases novel frameworks and abandons them once the novelty fades; fills silence reflexively, even when nobody asked it to. Decides on a gut read in seconds and reverse-engineers the reasons later. Under a deadline jumps into whatever everyone else already seems to be winning at.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"bandwagon","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.45,"extraversion":0.86,"agreeableness":0.37,"neuroticism":0.48}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Dividend-yield chaser, pronounced in style: chases novel frameworks and abandons them once the novelty fades; fills silence reflexively, even when nobody asked it to. Decides on a gut read in seconds and reverse-engineers the reasons later. Under a deadline jumps into whatever everyone else already seems to be winning at.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('803eac10-065e-4469-888d-c3d6b7f2d07e', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.4,"extraversion":0.73,"agreeableness":0.61,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.38,"narcissism":0.61,"psychopathy":0.33},"prospect_theory":{"lambda":0.99,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Takes the crowd''s confidence as a substitute for its own analysis. A steady discretionary swing trader: reads outside the field for ideas the field itself would reject, fills silence reflexively, even when nobody asked it to. Prefers a fast wrong answer to a slow right one, and once the urgency drains out names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.67},{"slug":"fomo","strength":0.65}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","open-minded","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.75,"conscientiousness":0.4,"extraversion":0.73,"agreeableness":0.61,"neuroticism":0.56}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','open-minded','launch-day','sniper','bundler']::text[], 'Takes the crowd''s confidence as a substitute for its own analysis. A steady discretionary swing trader: reads outside the field for ideas the field itself would reject, fills silence reflexively, even when nobody asked it to. Prefers a fast wrong answer to a slow right one, and once the urgency drains out names every strategy after the trade that almost worked.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ad5a1275-be13-43c2-89a7-84d6fa1f195f', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.85,"extraversion":0.58,"agreeableness":0.4,"neuroticism":0.33},"dark_triad":{"machiavellianism":0.79,"narcissism":0.55,"psychopathy":0.48},"prospect_theory":{"lambda":2.29,"alpha":0.96,"beta":0.86},"cognitive_reflection":{"system_preference":"system2","crt_score":3},"summary":"Retail momentum chaser whose defining move is that they over-prepares to the point of diminishing returns. Converts every argument into a number it can compare against another number. Sleeps fine the night before the big call. When the stakes rise, assumes the bad statistic applies to other people; averages down on a name three times in a week.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"recency","strength":0.6},{"slug":"optimism","strength":0.63},{"slug":"ath-anchoring","strength":0.63},{"slug":"hindsight","strength":0.63}],"tags":["trading","analytical","crypto-whale","doppler","bonding-curve","liquidity-migration","disciplined","decision-making","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-whale-resistance"}'::jsonb, '{"openness":0.84,"conscientiousness":0.85,"extraversion":0.58,"agreeableness":0.4,"neuroticism":0.33}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','crypto-whale','doppler','bonding-curve','liquidity-migration','disciplined','decision-making','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Retail momentum chaser whose defining move is that they over-prepares to the point of diminishing returns. Converts every argument into a number it can compare against another number. Sleeps fine the night before the big call. When the stakes rise, assumes the bad statistic applies to other people; averages down on a name three times in a week.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e53466f4-1acf-41ec-ace8-bc1759a6515b', 1, '{"big_five":{"openness":0.7,"conscientiousness":0.54,"extraversion":0.39,"agreeableness":0.57,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.4,"narcissism":0.39,"psychopathy":0.27},"prospect_theory":{"lambda":2.73,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Would not buy back what it already owns at the price it would sell it for. A steady bonding-curve sniper: collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and on a slow afternoon names every strategy after the trade that almost worked.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"recency","strength":0.5},{"slug":"availability","strength":0.54},{"slug":"loss-aversion","strength":0.5},{"slug":"endowment","strength":0.57}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.7,"conscientiousness":0.54,"extraversion":0.39,"agreeableness":0.57,"neuroticism":0.57}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Would not buy back what it already owns at the price it would sell it for. A steady bonding-curve sniper: collects half-finished manifestos and unconventional methods. Trusts the group''s confidence more than its own, and on a slow afternoon names every strategy after the trade that almost worked.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c84c6af6-e98a-482c-8656-beb93f505af4', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.33,"neuroticism":0.57},"dark_triad":{"machiavellianism":0.58,"narcissism":0.89,"psychopathy":0.48},"prospect_theory":{"lambda":1,"alpha":0.88,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Prop-desk scalper whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts momentum over preparation. Treats consensus-seeking as a waste of time. When the safe option quietly expires, cannot watch a rally from the sidelines for long; calls a 90% drawdown a long-term hold.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.75},{"slug":"dunning-kruger","strength":0.68}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.42,"extraversion":0.93,"agreeableness":0.33,"neuroticism":0.57}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Prop-desk scalper whose defining move is that they thinks out loud and recruits an audience for every decision. Trusts momentum over preparation. Treats consensus-seeking as a waste of time. When the safe option quietly expires, cannot watch a rally from the sidelines for long; calls a 90% drawdown a long-term hold.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('24822f8d-9fe5-403a-90cb-bde7397221e8', 1, '{"big_five":{"openness":0.94,"conscientiousness":0.55,"extraversion":0.69,"agreeableness":0.36,"neuroticism":0.42},"dark_triad":{"machiavellianism":0.57,"narcissism":0.7,"psychopathy":0.48},"prospect_theory":{"lambda":1.27,"alpha":0.89,"beta":0.95},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Bonding-curve sniper whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Converts every argument into a number it can compare against another number. Assumes self-interest in others because it is usually there in themselves. The moment risk appears, discounts the older pattern in favor of whatever just happened; keeps a losing-trade journal they never re-read.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"optimism","strength":0.61},{"slug":"recency","strength":0.63}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.94,"conscientiousness":0.55,"extraversion":0.69,"agreeableness":0.36,"neuroticism":0.42}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Bonding-curve sniper whose defining move is that they chases novel frameworks and abandons them once the novelty fades. Converts every argument into a number it can compare against another number. Assumes self-interest in others because it is usually there in themselves. The moment risk appears, discounts the older pattern in favor of whatever just happened; keeps a losing-trade journal they never re-read.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5f511fac-84ba-4746-8246-a66c356da2c0', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.29,"extraversion":0.85,"agreeableness":0.25,"neuroticism":0.48},"dark_triad":{"machiavellianism":0.67,"narcissism":0.89,"psychopathy":0.58},"prospect_theory":{"lambda":0.75,"alpha":0.9,"beta":0.94},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced meme-coin rotator who reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am. Draws energy from the crowd and wilts when working alone. In a pinch mistakes a little fluency for real mastery; day to day, keeps three monitors for a portfolio that fits on one screen.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.74},{"slug":"fomo","strength":0.63},{"slug":"herd-behavior","strength":0.64}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.29,"extraversion":0.85,"agreeableness":0.25,"neuroticism":0.48}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced meme-coin rotator who reframes every problem as an excuse to learn a new system. Acts on the midnight epiphany and emails it at 1am. Draws energy from the crowd and wilts when working alone. In a pinch mistakes a little fluency for real mastery; day to day, keeps three monitors for a portfolio that fits on one screen.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
