('f55936fd-137b-466b-8999-a06a3d2093bf', 1, '{"big_five":{"openness":0.75,"conscientiousness":0.31,"extraversion":0.78,"agreeableness":0.25,"neuroticism":0.51},"dark_triad":{"machiavellianism":0.61,"narcissism":0.83,"psychopathy":0.55},"prospect_theory":{"lambda":0.87,"alpha":0.9,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Finds it hard to hold a contrarian position once the room disagrees. A steady algorithmic market-maker: fills silence reflexively, even when nobody asked it to, confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and in the pattern nobody else tracks talks in win rate and never mentions size.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.59},{"slug":"herd-behavior","strength":0.66}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.75,"conscientiousness":0.31,"extraversion":0.78,"agreeableness":0.25,"neuroticism":0.51}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Finds it hard to hold a contrarian position once the room disagrees. A steady algorithmic market-maker: fills silence reflexively, even when nobody asked it to, confuses motion with progress. Acts on the midnight epiphany and emails it at 1am, and in the pattern nobody else tracks talks in win rate and never mentions size.', 0.89, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('654b0621-d34e-47ac-9447-6f474c8f3ace', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.48,"extraversion":0.47,"agreeableness":0.78,"neuroticism":0.63},"dark_triad":{"machiavellianism":0.35,"narcissism":0.34,"psychopathy":0.29},"prospect_theory":{"lambda":2.83,"alpha":0.83,"beta":0.78},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Second-guesses its own read the moment someone senior disagrees. A steady crypto day-trader: would rather lose a point than win an argument badly, notices the one thing that could go wrong before the nine that could go right. Trusts the group''s confidence more than its own, and day to day exits winners at the first green candle.","decision_style":"dependent","mbti_label":"INFP","suggested_biases":[{"slug":"bandwagon","strength":0.6},{"slug":"authority-bias","strength":0.61}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.53,"conscientiousness":0.48,"extraversion":0.47,"agreeableness":0.78,"neuroticism":0.63}'::jsonb, 'INFP', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Second-guesses its own read the moment someone senior disagrees. A steady crypto day-trader: would rather lose a point than win an argument badly, notices the one thing that could go wrong before the nine that could go right. Trusts the group''s confidence more than its own, and day to day exits winners at the first green candle.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1080b899-3521-4b46-bf18-bc9f89e7158e', 1, '{"big_five":{"openness":0.86,"conscientiousness":0.37,"extraversion":0.88,"agreeableness":0.32,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.57,"narcissism":0.83,"psychopathy":0.46},"prospect_theory":{"lambda":0.94,"alpha":0.87,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced index-fund holdout who recharges by being around people, not away from them. Acts on the midnight epiphany and emails it at 1am. Does the interesting 80% and abandons the tedious 20%. When there is no clean exit abandons a private read the instant the crowd leans the other way; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.65},{"slug":"dunning-kruger","strength":0.65}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.86,"conscientiousness":0.37,"extraversion":0.88,"agreeableness":0.32,"neuroticism":0.61}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced index-fund holdout who recharges by being around people, not away from them. Acts on the midnight epiphany and emails it at 1am. Does the interesting 80% and abandons the tedious 20%. When there is no clean exit abandons a private read the instant the crowd leans the other way; in the version no one reviews, trusts the chart more than the fundamentals and won''t say why.', 0.95, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('63e5978b-999a-4845-82b7-daaed4d7a2e6', 1, '{"big_five":{"openness":0.9,"conscientiousness":0.48,"extraversion":0.8,"agreeableness":0.26,"neuroticism":0.58},"dark_triad":{"machiavellianism":0.65,"narcissism":0.84,"psychopathy":0.5},"prospect_theory":{"lambda":0.69,"alpha":0.89,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Pairs trader whose defining move is that they reframes every problem as an excuse to learn a new system. Knows the answer before it can explain the question. Recharges by being around people, not away from them. The instant the deadline moves up, assumes the current streak is the new normal; sets alerts for a coin they already checked a minute ago.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.69},{"slug":"bandwagon","strength":0.62},{"slug":"herd-behavior","strength":0.62}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.9,"conscientiousness":0.48,"extraversion":0.8,"agreeableness":0.26,"neuroticism":0.58}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Pairs trader whose defining move is that they reframes every problem as an excuse to learn a new system. Knows the answer before it can explain the question. Recharges by being around people, not away from them. The instant the deadline moves up, assumes the current streak is the new normal; sets alerts for a coin they already checked a minute ago.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5fe59651-a706-41b2-9317-298ba3b919ab', 1, '{"big_five":{"openness":0.66,"conscientiousness":0.27,"extraversion":0.78,"agreeableness":0.61,"neuroticism":0.72},"dark_triad":{"machiavellianism":0.38,"narcissism":0.59,"psychopathy":0.35},"prospect_theory":{"lambda":1.12,"alpha":0.79,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Mistakes a little fluency for real mastery. A steady commodities speculator: treats a quiet room as a problem to be solved, is reliably surprised by deadlines that were never hidden. Commits before the doubt has time to organize itself, and when the pressure is off exits winners at the first green candle.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"dunning-kruger","strength":0.75},{"slug":"fomo","strength":0.71}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.66,"conscientiousness":0.27,"extraversion":0.78,"agreeableness":0.61,"neuroticism":0.72}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Mistakes a little fluency for real mastery. A steady commodities speculator: treats a quiet room as a problem to be solved, is reliably surprised by deadlines that were never hidden. Commits before the doubt has time to organize itself, and when the pressure is off exits winners at the first green candle.', 0.9, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c3e9c04c-e673-4d43-9d7c-8b89e7096b46', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.2,"neuroticism":0.66},"dark_triad":{"machiavellianism":0.69,"narcissism":0.8,"psychopathy":0.63},"prospect_theory":{"lambda":0.78,"alpha":0.86,"beta":0.88},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced liquidation-bot operator who gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. Does the interesting 80% and abandons the tedious 20%. As soon as real money or reputation is on the line assumes the current streak is the new normal; when no one is watching, names every strategy after the trade that almost worked.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.63},{"slug":"rug-trauma-overcorrection","strength":0.66},{"slug":"recency","strength":0.76}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.35,"extraversion":0.78,"agreeableness":0.2,"neuroticism":0.66}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced liquidation-bot operator who gets bored of the proven method exactly when it starts working. Decides in the time it takes to say the decision out loud. Does the interesting 80% and abandons the tedious 20%. As soon as real money or reputation is on the line assumes the current streak is the new normal; when no one is watching, names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1746fecc-335a-4100-994a-e62d5ca3cfef', 1, '{"big_five":{"openness":0.83,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.16,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.73,"narcissism":0.88,"psychopathy":0.62},"prospect_theory":{"lambda":0.89,"alpha":0.87,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Meme-coin rotator, pronounced in style: treats a quiet room as a problem to be solved; treats warmth as leverage and cooperation as weakness. Decides in the time it takes to say the decision out loud. When the walls close in cannot watch a rally from the sidelines for long.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"fomo","strength":0.72},{"slug":"recency","strength":0.7},{"slug":"herd-behavior","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","outgoing","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.83,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.16,"neuroticism":0.64}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','outgoing','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Meme-coin rotator, pronounced in style: treats a quiet room as a problem to be solved; treats warmth as leverage and cooperation as weakness. Decides in the time it takes to say the decision out loud. When the walls close in cannot watch a rally from the sidelines for long.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('633ff1ec-99e4-44c1-ab50-d3a5624378f2', 1, '{"big_five":{"openness":0.88,"conscientiousness":0.43,"extraversion":0.78,"agreeableness":0.18,"neuroticism":0.46},"dark_triad":{"machiavellianism":0.66,"narcissism":0.93,"psychopathy":0.62},"prospect_theory":{"lambda":0.86,"alpha":0.85,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced futures spreader who would rather invent a worse tool than use someone else''s good one. Decides on a gut read in seconds and reverse-engineers the reasons later. Negotiates every relationship a little, even the close ones. The instant it becomes irreversible holds their estimates with a certainty the track record does not support; in the version no one reviews, apes the launch before the contract is verified.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"dunning-kruger","strength":0.56},{"slug":"recency","strength":0.67},{"slug":"overconfidence","strength":0.69},{"slug":"fomo","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.88,"conscientiousness":0.43,"extraversion":0.78,"agreeableness":0.18,"neuroticism":0.46}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced futures spreader who would rather invent a worse tool than use someone else''s good one. Decides on a gut read in seconds and reverse-engineers the reasons later. Negotiates every relationship a little, even the close ones. The instant it becomes irreversible holds their estimates with a certainty the track record does not support; in the version no one reviews, apes the launch before the contract is verified.', 0.98, 'approved', 'c09637