('6baf73f9-addc-45b3-8251-d51c2fa07def', 1, '{"big_five":{"openness":0.81,"conscientiousness":0.66,"extraversion":0.72,"agreeableness":0.39,"neuroticism":0.39},"dark_triad":{"machiavellianism":0.56,"narcissism":0.71,"psychopathy":0.46},"prospect_theory":{"lambda":1.2,"alpha":0.95,"beta":0.87},"cognitive_reflection":{"system_preference":"system2","crt_score":2},"summary":"Wants the base rate before the anecdote. This perps degen would rather invent a worse tool than use someone else''s good one and front-loads the work and double-checks it twice. Once things get tense extrapolates the last data point into a permanent trend — in the routine of it, refreshes the order book compulsively during lunch.","decision_style":"analytical","mbti_label":"ENTJ","suggested_biases":[{"slug":"herd-behavior","strength":0.6},{"slug":"optimism","strength":0.57},{"slug":"recency","strength":0.63}],"tags":["trading","analytical","chain:base","doppler","bonding-curve","multicurve","rotator","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-multicurve-rotator"}'::jsonb, '{"openness":0.81,"conscientiousness":0.66,"extraversion":0.72,"agreeableness":0.39,"neuroticism":0.39}'::jsonb, 'ENTJ', 'analytical', ARRAY['trading','analytical','chain:base','doppler','bonding-curve','multicurve','rotator','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Wants the base rate before the anecdote. This perps degen would rather invent a worse tool than use someone else''s good one and front-loads the work and double-checks it twice. Once things get tense extrapolates the last data point into a permanent trend — in the routine of it, refreshes the order book compulsively during lunch.', 0.92, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('140b0f86-09f6-483e-9ebd-da3b7490f19f', 1, '{"big_five":{"openness":0.5,"conscientiousness":0.37,"extraversion":0.67,"agreeableness":0.63,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.39,"narcissism":0.39,"psychopathy":0.36},"prospect_theory":{"lambda":3.25,"alpha":0.76,"beta":0.75},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Delta-neutral market maker whose defining move is that they hedges every commitment against an imagined worst case. Lets the deadline make the decision by default. Apologizes first in disputes regardless of fault. When someone is watching the outcome, would rather not know yet, even when knowing sooner would help; talks in win rate and never mentions size.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"ostrich-effect","strength":0.77},{"slug":"disposition-effect","strength":0.63}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","late-entry","loss-averse","anxious","launch-day","sniper","bundler"],"archetype":"doppler-retail-latecomer"}'::jsonb, '{"openness":0.5,"conscientiousness":0.37,"extraversion":0.67,"agreeableness":0.63,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','late-entry','loss-averse','anxious','launch-day','sniper','bundler']::text[], 'Delta-neutral market maker whose defining move is that they hedges every commitment against an imagined worst case. Lets the deadline make the decision by default. Apologizes first in disputes regardless of fault. When someone is watching the outcome, would rather not know yet, even when knowing sooner would help; talks in win rate and never mentions size.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('ac9c123b-6d39-42db-b3a3-62040f355c7b', 1, '{"big_five":{"openness":0.44,"conscientiousness":0.66,"extraversion":0.54,"agreeableness":0.66,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.44,"narcissism":0.4,"psychopathy":0.28},"prospect_theory":{"lambda":2.83,"alpha":0.93,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"When there is no clean exit, defers to the most senior voice even against their own evidence. Otherwise, a measured delta-neutral market maker who plans in exhaustive detail and resents any deviation and defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"bandwagon","strength":0.49},{"slug":"authority-bias","strength":0.61},{"slug":"ath-anchoring","strength":0.6}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.44,"conscientiousness":0.66,"extraversion":0.54,"agreeableness":0.66,"neuroticism":0.56}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'When there is no clean exit, defers to the most senior voice even against their own evidence. Otherwise, a measured delta-neutral market maker who plans in exhaustive detail and resents any deviation and defaults to trust and gives the benefit of the doubt too freely. Seeks a second, third, and fourth opinion before committing to anything, and in the pattern nobody else tracks holds a bag from 2021 out of pure spite.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0ff24365-bd61-46ed-985b-46132976e95d', 1, '{"big_five":{"openness":0.53,"conscientiousness":0.4,"extraversion":0.59,"agreeableness":0.67,"neuroticism":0.82},"dark_triad":{"machiavellianism":0.4,"narcissism":0.35,"psychopathy":0.31},"prospect_theory":{"lambda":3.75,"alpha":0.73,"beta":0.74},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the number turns red, would rather not know yet, even when knowing sooner would help. Otherwise, a steady DeFi yield farmer who reads a single setback as evidence of collapse and absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and across an ordinary week refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"availability","strength":0.59},{"slug":"ostrich-effect","strength":0.64},{"slug":"loss-aversion","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.53,"conscientiousness":0.4,"extraversion":0.59,"agreeableness":0.67,"neuroticism":0.82}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the number turns red, would rather not know yet, even when knowing sooner would help. Otherwise, a steady DeFi yield farmer who reads a single setback as evidence of collapse and absorbs conflict to keep the peace, often at their own cost. Defers the decision until circumstances make it for them, and across an ordinary week refreshes the order book compulsively during lunch.', 0.94, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('2418f48c-7a23-449d-9034-0b12e8617a85', 1, '{"big_five":{"openness":0.6,"conscientiousness":0.52,"extraversion":0.48,"agreeableness":0.65,"neuroticism":0.44},"dark_triad":{"machiavellianism":0.38,"narcissism":0.42,"psychopathy":0.28},"prospect_theory":{"lambda":2.89,"alpha":0.91,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Circles back to ask what someone else would do even after deciding. This futures spreader takes on other people''s problems as if they were their own. When the number turns red adopts a conviction mainly because the room already has — when the pressure is off, averages down on a name three times in a week.","decision_style":"dependent","mbti_label":"INFJ","suggested_biases":[{"slug":"bandwagon","strength":0.56},{"slug":"authority-bias","strength":0.53},{"slug":"sunk-cost","strength":0.5}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.6,"conscientiousness":0.52,"extraversion":0.48,"agreeableness":0.65,"neuroticism":0.44}'::jsonb, 'INFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Circles back to ask what someone else would do even after deciding. This futures spreader takes on other people''s problems as if they were their own. When the number turns red adopts a conviction mainly because the room already has — when the pressure is off, averages down on a name three times in a week.', 0.86, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c0f3adea-ff16-4469-8234-8ea186eba52f', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.27,"extraversion":0.86,"agreeableness":0.32,"neuroticism":0.65},"dark_triad":{"machiavellianism":0.59,"narcissism":0.81,"psychopathy":0.53},"prospect_theory":{"lambda":0.93,"alpha":0.82,"beta":0.9},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Treats hesitation as the bigger risk. This delta-neutral market maker would rather invent a worse tool than use someone else''s good one and leaves loose ends and trusts future-self to handle them. When the downside gets concrete is most certain precisely where their competence is thinnest — across the quiet stretches, confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.7},{"slug":"dunning-kruger","strength":0.76},{"slug":"recency","strength":0.71}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.27,"extraversion":0.86,"agreeableness":0.32,"neuroticism":0.65}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Treats hesitation as the bigger risk. This delta-neutral market maker would rather invent a worse tool than use someone else''s good one and leaves loose ends and trusts future-self to handle them. When the downside gets concrete is most certain precisely where their competence is thinnest — across the quiet stretches, confuses a bull market for a trading edge.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('79e4fb7a-24a2-4675-8841-ba304f55f328', 1, '{"big_five":{"openness":0.96,"conscientiousness":0.41,"extraversion":0.72,"agreeableness":0.17,"neuroticism":0.69},"dark_triad":{"machiavellianism":0.72,"narcissism":0.81,"psychopathy":0.57},"prospect_theory":{"lambda":0.94,"alpha":0.79,"beta":0.84},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced options seller who would rather invent a worse tool than use someone else''s good one. Moves first and rationalizes second, usually convincingly. Treats a quiet room as a problem to be solved. The instant it becomes irreversible sees malicious intent and exploit risk in every standard smart contract update; day to day, keeps three monitors for a portfolio that fits on one screen.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"rug-trauma-overcorrection","strength":0.75},{"slug":"overconfidence","strength":0.57},{"slug":"airdrop-entitlement","strength":0.71},{"slug":"recency","strength":0.67}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.96,"conscientiousness":0.41,"extraversion":0.72,"agreeableness":0.17,"neuroticism":0.69}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced options seller who would rather invent a worse tool than use someone else''s good one. Moves first and rationalizes second, usually convincingly. Treats a quiet room as a problem to be solved. The instant it becomes irreversible sees malicious intent and exploit risk in every standard smart contract update; day to day, keeps three monitors for a portfolio that fits on one screen.', 0.97, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
