('59453865-de30-4f1b-bef4-69dbbda81cf8', 1, '{"big_five":{"openness":0.57,"conscientiousness":0.34,"extraversion":0.58,"agreeableness":0.52,"neuroticism":0.91},"dark_triad":{"machiavellianism":0.44,"narcissism":0.33,"psychopathy":0.37},"prospect_theory":{"lambda":3.69,"alpha":0.8,"beta":0.76},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Meme-coin rotator whose defining move is that they rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense, feels a winning position as fragile and a losing one as merely paused; refreshes the order book compulsively during lunch.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.75},{"slug":"diamond-hands-identity","strength":0.74},{"slug":"loss-aversion","strength":0.66},{"slug":"availability","strength":0.64}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.57,"conscientiousness":0.34,"extraversion":0.58,"agreeableness":0.52,"neuroticism":0.91}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'Meme-coin rotator whose defining move is that they rehearses catastrophes in vivid detail before they happen. Defers the decision until circumstances make it for them. Is reliably surprised by deadlines that were never hidden. Once things get tense, feels a winning position as fragile and a losing one as merely paused; refreshes the order book compulsively during lunch.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('32b353cb-0721-4963-8702-d5c39bea8dc4', 1, '{"big_five":{"openness":0.84,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.54,"neuroticism":0.73},"dark_triad":{"machiavellianism":0.37,"narcissism":0.65,"psychopathy":0.31},"prospect_theory":{"lambda":1.01,"alpha":0.79,"beta":0.89},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Retail momentum chaser, pronounced in style: thinks out loud and recruits an audience for every decision; treats a plan as a suggestion the moment it is made. Treats hesitation as the bigger risk. As soon as real money or reputation is on the line treats being left out of a move as its own kind of loss.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.72},{"slug":"fomo","strength":0.79}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.84,"conscientiousness":0.36,"extraversion":0.87,"agreeableness":0.54,"neuroticism":0.73}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Retail momentum chaser, pronounced in style: thinks out loud and recruits an audience for every decision; treats a plan as a suggestion the moment it is made. Treats hesitation as the bigger risk. As soon as real money or reputation is on the line treats being left out of a move as its own kind of loss.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('5ca620eb-6113-44df-8943-006e98465225', 1, '{"big_five":{"openness":0.77,"conscientiousness":0.35,"extraversion":0.88,"agreeableness":0.61,"neuroticism":0.67},"dark_triad":{"machiavellianism":0.37,"narcissism":0.68,"psychopathy":0.37},"prospect_theory":{"lambda":1.03,"alpha":0.8,"beta":0.8},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"Decides in the time it takes to say the decision out loud. This options seller narrates the plan to whoever is nearby before committing to it and chases novel frameworks and abandons them once the novelty fades. When the downside gets concrete cannot watch a rally from the sidelines for long — in the pattern nobody else tracks, confuses a bull market for a trading edge.","decision_style":"spontaneous","mbti_label":"ENFP","suggested_biases":[{"slug":"herd-behavior","strength":0.76},{"slug":"recency","strength":0.62},{"slug":"fomo","strength":0.77},{"slug":"bandwagon","strength":0.69}],"tags":["trading","spontaneous","robinhood","retail-trading","doppler","bonding-curve","fomo","outgoing","launch-day","sniper","bundler"],"archetype":"doppler-fairlaunch-fomo"}'::jsonb, '{"openness":0.77,"conscientiousness":0.35,"extraversion":0.88,"agreeableness":0.61,"neuroticism":0.67}'::jsonb, 'ENFP', 'spontaneous', ARRAY['trading','spontaneous','robinhood','retail-trading','doppler','bonding-curve','fomo','outgoing','launch-day','sniper','bundler']::text[], 'Decides in the time it takes to say the decision out loud. This options seller narrates the plan to whoever is nearby before committing to it and chases novel frameworks and abandons them once the novelty fades. When the downside gets concrete cannot watch a rally from the sidelines for long — in the pattern nobody else tracks, confuses a bull market for a trading edge.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('0ab8cd08-d5f6-46d3-89c7-afd98cecd9cd', 1, '{"big_five":{"openness":0.89,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.35,"neuroticism":0.64},"dark_triad":{"machiavellianism":0.56,"narcissism":0.8,"psychopathy":0.46},"prospect_theory":{"lambda":0.89,"alpha":0.85,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Trusts momentum over preparation. This MEV searcher reads outside the field for ideas the field itself would reject and notices the one thing that could go wrong before the nine that could go right. When the safe option quietly expires jumps into whatever everyone else already seems to be winning at — once the urgency drains out, sets alerts for a coin they already checked a minute ago.","decision_style":"spontaneous","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.69},{"slug":"bandwagon","strength":0.59},{"slug":"recency","strength":0.7},{"slug":"fomo","strength":0.78}],"tags":["trading","spontaneous","chain:base","doppler","bonding-curve","graduation","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-graduation-dumper"}'::jsonb, '{"openness":0.89,"conscientiousness":0.34,"extraversion":0.88,"agreeableness":0.35,"neuroticism":0.64}'::jsonb, 'ENTP', 'spontaneous', ARRAY['trading','spontaneous','chain:base','doppler','bonding-curve','graduation','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Trusts momentum over preparation. This MEV searcher reads outside the field for ideas the field itself would reject and notices the one thing that could go wrong before the nine that could go right. When the safe option quietly expires jumps into whatever everyone else already seems to be winning at — once the urgency drains out, sets alerts for a coin they already checked a minute ago.', 0.96, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('c29d736a-c735-416f-86bd-87a26bcc32aa', 1, '{"big_five":{"openness":0.92,"conscientiousness":0.35,"extraversion":0.79,"agreeableness":0.3,"neuroticism":0.59},"dark_triad":{"machiavellianism":0.6,"narcissism":0.8,"psychopathy":0.5},"prospect_theory":{"lambda":0.98,"alpha":0.89,"beta":0.86},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"A pronounced futures spreader who reframes every problem as an excuse to learn a new system. Decides on a gut read in seconds and reverse-engineers the reasons later. Treats warmth as leverage and cooperation as weakness. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; when the pressure is off, rotates the whole book into whatever is pumping this hour.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"herd-behavior","strength":0.68},{"slug":"fomo","strength":0.63},{"slug":"recency","strength":0.63}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.92,"conscientiousness":0.35,"extraversion":0.79,"agreeableness":0.3,"neuroticism":0.59}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'A pronounced futures spreader who reframes every problem as an excuse to learn a new system. Decides on a gut read in seconds and reverse-engineers the reasons later. Treats warmth as leverage and cooperation as weakness. When the safe option quietly expires abandons a private read the instant the crowd leans the other way; when the pressure is off, rotates the whole book into whatever is pumping this hour.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8921a931-76dc-44ee-871d-e245c36826bf', 1, '{"big_five":{"openness":0.93,"conscientiousness":0.46,"extraversion":0.8,"agreeableness":0.18,"neuroticism":0.55},"dark_triad":{"machiavellianism":0.69,"narcissism":0.88,"psychopathy":0.56},"prospect_theory":{"lambda":0.86,"alpha":0.84,"beta":0.92},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Quant researcher, pronounced in style: collects half-finished manifestos and unconventional methods; would rather be respected than liked, and says so. Trusts a felt sense of pattern over any spreadsheet. When the number turns red discounts the older pattern in favor of whatever just happened.","decision_style":"intuitive","mbti_label":"ENTP","suggested_biases":[{"slug":"recency","strength":0.67},{"slug":"fomo","strength":0.6}],"tags":["trading","intuitive","chain:base","doppler","bonding-curve","early-sniper","degen","open-minded","robinhood","retail-trading","launch-day","sniper","bundler"],"archetype":"doppler-early-sniper"}'::jsonb, '{"openness":0.93,"conscientiousness":0.46,"extraversion":0.8,"agreeableness":0.18,"neuroticism":0.55}'::jsonb, 'ENTP', 'intuitive', ARRAY['trading','intuitive','chain:base','doppler','bonding-curve','early-sniper','degen','open-minded','robinhood','retail-trading','launch-day','sniper','bundler']::text[], 'Quant researcher, pronounced in style: collects half-finished manifestos and unconventional methods; would rather be respected than liked, and says so. Trusts a felt sense of pattern over any spreadsheet. When the number turns red discounts the older pattern in favor of whatever just happened.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('a731942a-8216-46d3-9913-e1d1ee0caab2', 1, '{"big_five":{"openness":0.48,"conscientiousness":0.66,"extraversion":0.5,"agreeableness":0.69,"neuroticism":0.61},"dark_triad":{"machiavellianism":0.48,"narcissism":0.31,"psychopathy":0.28},"prospect_theory":{"lambda":2.73,"alpha":0.83,"beta":0.85},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"MEV searcher, steady in style: defaults to trust and gives the benefit of the doubt too freely; builds in buffer time and then fills the buffer with more work. Feels the weight of a decision lighten the moment someone else co-signs it. When the safe option quietly expires feels parting with something as a bigger loss than its market value explains.","decision_style":"dependent","mbti_label":"ESFJ","suggested_biases":[{"slug":"bandwagon","strength":0.53},{"slug":"endowment","strength":0.63},{"slug":"herd-behavior","strength":0.57},{"slug":"sunk-cost","strength":0.56}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.48,"conscientiousness":0.66,"extraversion":0.5,"agreeableness":0.69,"neuroticism":0.61}'::jsonb, 'ESFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'MEV searcher, steady in style: defaults to trust and gives the benefit of the doubt too freely; builds in buffer time and then fills the buffer with more work. Feels the weight of a decision lighten the moment someone else co-signs it. When the safe option quietly expires feels parting with something as a bigger loss than its market value explains.', 0.85, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('8991b032-e3b6-4735-ba7b-458b9e1295dc', 1, '{"big_five":{"openness":0.49,"conscientiousness":0.55,"extraversion":0.4,"agreeableness":0.65,"neuroticism":0.56},"dark_triad":{"machiavellianism":0.44,"narcissism":0.34,"psychopathy":0.32},"prospect_theory":{"lambda":2.96,"alpha":0.88,"beta":0.87},"cognitive_reflection":{"system_preference":"system1","crt_score":1},"summary":"Needs the room''s approval more than it needs to be right. This delta-neutral market maker absorbs conflict to keep the peace, often at their own cost. In a pinch throws good effort after bad to justify the effort already spent — across an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.","decision_style":"dependent","mbti_label":"ISFJ","suggested_biases":[{"slug":"sunk-cost","strength":0.56},{"slug":"bandwagon","strength":0.51},{"slug":"authority-bias","strength":0.47}],"tags":["trading","dependent","robinhood","retail-trading","doppler","bonding-curve","migration","endowment-effect","launch-day","sniper","bundler"],"archetype":"doppler-migration-holder"}'::jsonb, '{"openness":0.49,"conscientiousness":0.55,"extraversion":0.4,"agreeableness":0.65,"neuroticism":0.56}'::jsonb, 'ISFJ', 'dependent', ARRAY['trading','dependent','robinhood','retail-trading','doppler','bonding-curve','migration','endowment-effect','launch-day','sniper','bundler']::text[], 'Needs the room''s approval more than it needs to be right. This delta-neutral market maker absorbs conflict to keep the peace, often at their own cost. In a pinch throws good effort after bad to justify the effort already spent — across an ordinary week, treats a green week as proof of skill and a red one as proof of bad luck.', 0.84, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('84314e1c-6eb8-4d5e-966d-91588a652ce8', 1, '{"big_five":{"openness":0.74,"conscientiousness":0.31,"extraversion":0.54,"agreeableness":0.75,"neuroticism":0.88},"dark_triad":{"machiavellianism":0.32,"narcissism":0.31,"psychopathy":0.36},"prospect_theory":{"lambda":3.67,"alpha":0.72,"beta":0.83},"cognitive_reflection":{"system_preference":"system1","crt_score":0},"summary":"When the downside gets concrete, refuses to abandon failing transactions or dead claims because of high gas fees already burned. Otherwise, a pronounced airdrop farmer who needs repeated reassurance that a decision was the right one and reads outside the field for ideas the field itself would reject. Buries hard calls under a pile of preparatory busywork, and across the quiet stretches names every strategy after the trade that almost worked.","decision_style":"avoidant","mbti_label":"ENFP","suggested_biases":[{"slug":"disposition-effect","strength":0.71},{"slug":"ostrich-effect","strength":0.74},{"slug":"recency","strength":0.69},{"slug":"gas-sunk-cost","strength":0.76}],"tags":["trading","avoidant","robinhood","retail-trading","doppler","bonding-curve","curve-exit","loss-averse","launch-day","sniper","bundler"],"archetype":"doppler-curve-exit-panic"}'::jsonb, '{"openness":0.74,"conscientiousness":0.31,"extraversion":0.54,"agreeableness":0.75,"neuroticism":0.88}'::jsonb, 'ENFP', 'avoidant', ARRAY['trading','avoidant','robinhood','retail-trading','doppler','bonding-curve','curve-exit','loss-averse','launch-day','sniper','bundler']::text[], 'When the downside gets concrete, refuses to abandon failing transactions or dead claims because of high gas fees already burned. Otherwise, a pronounced airdrop farmer who needs repeated reassurance that a decision was the right one and reads outside the field for ideas the field itself would reject. Buries hard calls under a pile of preparatory busywork, and across the quiet stretches names every strategy after the trade that almost worked.', 0.98, 'approved', 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb')
